#[inline]
fn is_hard_stop_error(err: &VmError) -> bool {
  matches!(err, VmError::Termination(_) | VmError::OutOfMemory)
}

/// A `throw` completion value paired with a captured stack trace.
#[derive(Clone, Debug, PartialEq)]
pub struct Thrown {
  pub value: Value,
  pub stack: Vec<StackFrame>,
}

impl Trace for Thrown {
  fn trace(&self, tracer: &mut Tracer<'_>) {
    tracer.trace_value(self.value);
  }
}

/// An ECMAScript completion record (ECMA-262).
///
/// We model the "empty" completion value explicitly as `None` so statement-list evaluation can
/// implement `UpdateEmpty` correctly (e.g. `1; if (true) {}` should evaluate to `1`).
#[derive(Clone, Debug, PartialEq)]
pub enum Completion {
  Normal(Option<Value>),
  Throw(Thrown),
  Return(Value),
  Break(Option<String>, Option<Value>),
  Continue(Option<String>, Option<Value>),
}

impl Completion {
  pub fn empty() -> Self {
    Completion::Normal(None)
  }

  pub fn normal(value: Value) -> Self {
    Completion::Normal(Some(value))
  }

  pub fn value(&self) -> Option<Value> {
    match self {
      Completion::Normal(v) => *v,
      Completion::Throw(thrown) => Some(thrown.value),
      Completion::Return(v) => Some(*v),
      Completion::Break(_, v) => *v,
      Completion::Continue(_, v) => *v,
    }
  }

  pub fn is_abrupt(&self) -> bool {
    !matches!(self, Completion::Normal(_))
  }

  /// Implements `UpdateEmpty(completion, value)` from ECMA-262.
  pub fn update_empty(self, value: Option<Value>) -> Self {
    match self {
      Completion::Normal(None) => Completion::Normal(value),
      Completion::Break(target, None) => Completion::Break(target, value),
      Completion::Continue(target, None) => Completion::Continue(target, value),
      other => other,
    }
  }
}

impl Trace for Completion {
  fn trace(&self, tracer: &mut Tracer<'_>) {
    match self {
      Completion::Normal(v) => {
        if let Some(v) = v {
          tracer.trace_value(*v);
        }
      }
      Completion::Throw(thrown) => thrown.trace(tracer),
      Completion::Return(v) => tracer.trace_value(*v),
      Completion::Break(_, v) | Completion::Continue(_, v) => {
        if let Some(v) = v {
          tracer.trace_value(*v);
        }
      }
    }
  }
}

fn global_var_desc(value: Value) -> PropertyDescriptor {
  PropertyDescriptor {
    enumerable: true,
    configurable: true,
    kind: PropertyKind::Data {
      value,
      writable: true,
    },
  }
}

fn global_var_binding_desc(value: Value) -> PropertyDescriptor {
  PropertyDescriptor {
    enumerable: true,
    configurable: false,
    kind: PropertyKind::Data {
      value,
      writable: true,
    },
  }
}

fn detect_use_strict_directive(
  source: &str,
  base_offset: usize,
  prefix_len: usize,
  stmts: &[Node<Stmt>],
  mut tick: impl FnMut() -> Result<(), VmError>,
) -> Result<bool, VmError> {
  const TICK_EVERY: usize = 32;
  for (i, stmt) in stmts.iter().enumerate() {
    if i % TICK_EVERY == 0 {
      tick()?;
    }
    let Stmt::Expr(expr_stmt) = &*stmt.stx else {
      break;
    };

    let expr = &expr_stmt.stx.expr;

    // Parenthesized string literals are not directive prologues.
    if expr.assoc.get::<ParenthesizedExpr>().is_some() {
      break;
    }

    let Expr::LitStr(lit) = &*expr.stx else {
      break;
    };

    // Strict mode directives are matched against the *raw* string literal token text.
    // For example, `"use\\x20strict"` evaluates to `"use strict"` at runtime, but it does **not**
    // enable strict mode.
    if lit.stx.value == "use strict" {
      // `parse-js` AST node locations are relative to the snippet that was parsed (for example a
      // lazily-reparsed function body). Use the runtime source metadata to translate the local
      // location into an absolute source slice:
      //   abs = base_offset + (loc - prefix_len)
      //
      // `prefix_len` accounts for wrapper prefixes used to parse non-script snippets such as
      // function expressions (`(<expr>)`) and object/class member definitions.
      let abs_start = base_offset.saturating_add(expr.loc.0.saturating_sub(prefix_len));
      let abs_end = base_offset.saturating_add(expr.loc.1.saturating_sub(prefix_len));
      let start = abs_start.min(source.len());
      let end = abs_end.min(source.len());
      let raw = source.get(start..end).unwrap_or("");
      if raw == "\"use strict\"" || raw == "'use strict'" {
        return Ok(true);
      }
    }
  }
  Ok(false)
}

/// Converts an ECMAScript String value (UTF-16 code units) to a Rust UTF-8 `String` lossily.
///
/// This is used for parsing eval source: Rust `String` cannot represent unpaired UTF-16 surrogate
/// code units, so they are replaced with U+FFFD (matching `String::from_utf16_lossy`).
///
/// Unlike `String::from_utf16_lossy`, this conversion:
/// - ticks the VM budget periodically, and
/// - uses fallible allocation (`try_reserve`) so hostile inputs can't abort the host on OOM.
fn eval_string_to_utf8_lossy_with_tick(
  vm: &mut Vm,
  heap: &Heap,
  source_string: GcString,
) -> Result<String, VmError> {
  let units = heap.get_string(source_string)?.as_code_units();

  const TICK_EVERY: usize = 1024;

  // Compute the exact UTF-8 length up-front so we can pre-reserve without over-allocating.
  //
  // This keeps large ASCII eval sources (like huge RegExp literals) from reserving 3x more memory
  // than needed, while still ensuring all allocations remain fallible (no `String` growth during
  // `push`).
  let mut needed_bytes: usize = 0;
  {
    let mut i = 0usize;
    while i < units.len() {
      if i % TICK_EVERY == 0 {
        vm.tick()?;
      }
      let u = units[i];
      let (ch, consumed) = if (0xD800..=0xDBFF).contains(&u) {
        if let Some(&u2) = units.get(i + 1) {
          if (0xDC00..=0xDFFF).contains(&u2) {
            let hi = (u as u32) - 0xD800;
            let lo = (u2 as u32) - 0xDC00;
            let cp = (hi << 10) + lo + 0x10000;
            (char::from_u32(cp).unwrap_or('\u{FFFD}'), 2)
          } else {
            ('\u{FFFD}', 1)
          }
        } else {
          ('\u{FFFD}', 1)
        }
      } else if (0xDC00..=0xDFFF).contains(&u) {
        ('\u{FFFD}', 1)
      } else {
        (char::from_u32(u as u32).unwrap_or('\u{FFFD}'), 1)
      };

      needed_bytes = needed_bytes
        .checked_add(ch.len_utf8())
        .ok_or(VmError::OutOfMemory)?;
      i = i.saturating_add(consumed);
    }
  }

  let mut out = String::new();
  out
    .try_reserve_exact(needed_bytes)
    .map_err(|_| VmError::OutOfMemory)?;

  // Second pass: write the actual UTF-8 text.
  let mut i = 0usize;
  while i < units.len() {
    if i % TICK_EVERY == 0 {
      vm.tick()?;
    }

    let u = units[i];

    // High surrogate.
    if (0xD800..=0xDBFF).contains(&u) {
      if let Some(&u2) = units.get(i + 1) {
        if (0xDC00..=0xDFFF).contains(&u2) {
          let hi = (u as u32) - 0xD800;
          let lo = (u2 as u32) - 0xDC00;
          let cp = (hi << 10) + lo + 0x10000;
          out.push(char::from_u32(cp).unwrap_or('\u{FFFD}'));
          i += 2;
          continue;
        }
      }

      // Unpaired high surrogate.
      out.push('\u{FFFD}');
      i += 1;
      continue;
    }

    // Unpaired low surrogate.
    if (0xDC00..=0xDFFF).contains(&u) {
      out.push('\u{FFFD}');
      i += 1;
      continue;
    }

    out.push(char::from_u32(u as u32).unwrap_or('\u{FFFD}'));
    i += 1;
  }

  Ok(out)
}

/// Implements indirect eval (ECMA-262 `PerformEval` with `direct = false`) for Script source.
///
/// This is used by the global `%eval%` builtin; direct eval is handled by the evaluator's call
/// semantics (it needs access to the caller's lexical environment).
pub(crate) fn perform_indirect_eval(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  global_object: GcObject,
  global_lexical_env: GcEnv,
  source_string: GcString,
) -> Result<Value, VmError> {
  // If the input is not a String, `eval` returns it unchanged (caller handles this for direct eval).
  let source_text = eval_string_to_utf8_lossy_with_tick(vm, scope.heap(), source_string)?;
  let source = arc_try_new_vm(SourceText::new_charged(
    scope.heap_mut(),
    "<eval>",
    source_text,
  )?)?;

  let opts = ParseOptions {
    dialect: Dialect::Ecma,
    source_type: SourceType::Script,
  };
  // `eval` parses at runtime, so syntax errors must be catchable as thrown `SyntaxError` instances.
  let top = match vm.parse_top_level_with_budget(&source.text, opts) {
    Ok(top) => top,
    Err(VmError::Syntax(diags)) => {
      let intr = vm
        .intrinsics()
        .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;
      let message = diags
        .first()
        .map(|d| d.message.as_str())
        .unwrap_or("Invalid or unexpected token");
      let err_obj = crate::error_object::new_syntax_error_object(scope, &intr, message)?;
      return Err(VmError::Throw(err_obj));
    }
    Err(err) => return Err(err),
  };

  // Indirect eval does not inherit strictness from the caller; it is strict only if its source
  // begins with a `"use strict"` directive.
  let strict = detect_use_strict_directive(source.text.as_ref(), 0, 0, &top.stx.body, || vm.tick())?;
  {
    let mut tick = || vm.tick();
    match crate::early_errors::validate_top_level(
      &top.stx.body,
      crate::early_errors::EarlyErrorOptions::script(strict),
      Some(source.text.as_ref()),
      &mut tick,
    ) {
      Ok(()) => {}
      Err(VmError::Syntax(diags)) => {
        let intr = vm
          .intrinsics()
          .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;
        let message = diags
          .first()
          .map(|d| d.message.as_str())
          .unwrap_or("Invalid or unexpected token");
        let err_obj = crate::error_object::new_syntax_error_object(scope, &intr, message)?;
        return Err(VmError::Throw(err_obj));
      }
      Err(err) => return Err(err),
    }
  }

  // Create the Eval lexical environment as an inner declarative env nested in the global lexical
  // environment (so eval code sees global `let`/`const`, but its own lexical declarations remain
  // scoped to the eval itself).
  let eval_lex = scope.env_create(Some(global_lexical_env))?;

  // Variable environment depends on strictness:
  // - non-strict indirect eval: var/function declarations create global var bindings
  // - strict indirect eval: var/function declarations are scoped to the eval
  let mut eval_env = if strict {
    RuntimeEnv::new_with_var_env(scope.heap_mut(), global_object, eval_lex, eval_lex)?
  } else {
    RuntimeEnv::new_with_lexical_env(scope.heap_mut(), global_object, eval_lex)?
  };
  eval_env.set_source_info(source.clone(), 0, 0);

  let mut evaluator = Evaluator {
    vm,
    host,
    hooks,
    env: &mut eval_env,
    strict,
    this: Value::Object(global_object),
    new_target: Value::Undefined,
    home_object: None,
    class_constructor: None,
    derived_constructor: false,
    this_initialized: true,
    this_root_idx: None,
  };

  let result = (|| {
    evaluator.instantiate_script(scope, &top.stx.body)?;

    let completion = evaluator.eval_stmt_list(scope, &top.stx.body)?;
    match completion {
      Completion::Normal(v) => Ok(v.unwrap_or(Value::Undefined)),
      Completion::Throw(thrown) => Err(VmError::ThrowWithStack {
        value: thrown.value,
        stack: thrown.stack,
      }),
      Completion::Return(_) => Err(VmError::InvariantViolation(
        "eval produced Return completion (early errors should prevent this)",
      )),
      Completion::Break(..) => Err(VmError::InvariantViolation(
        "eval produced Break completion (early errors should prevent this)",
      )),
      Completion::Continue(..) => Err(VmError::InvariantViolation(
        "eval produced Continue completion (early errors should prevent this)",
      )),
    }
  })();

  eval_env.teardown(scope.heap_mut());
  match result {
    Err(VmError::Syntax(diags)) => {
      let intr = vm
        .intrinsics()
        .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;
      let message = diags
        .first()
        .map(|d| d.message.as_str())
        .unwrap_or("Invalid or unexpected token");
      let err_obj = crate::error_object::new_syntax_error_object(scope, &intr, message)?;
      Err(VmError::Throw(err_obj))
    }
    other => other,
  }
}

/// Implements direct eval (ECMA-262 `PerformEval` with `direct = true`) for Script source.
///
/// This is used by evaluators that detect a **syntactic** direct-eval call (`eval(...)`) and then
/// confirm that the callee resolves to the intrinsic `%eval%` function object (i.e. it wasn't
/// shadowed).
///
/// Direct eval executes in the caller's current lexical/variable environments and inherits
/// strictness from the caller: eval code is strict if either the caller is strict or the eval source
/// begins with a `"use strict"` directive.
pub(crate) fn perform_direct_eval_with_host_and_hooks(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  env: &mut RuntimeEnv,
  caller_strict: bool,
  this: Value,
  new_target: Value,
  home_object: Option<GcObject>,
  source_string: GcString,
) -> Result<Value, VmError> {
  // Root the global object, the input string, and caller `this` / `new.target` across allocations
  // and potential nested calls.
  let global_object = env.global_object();
  let mut scope = scope.reborrow();
  if let Some(home) = home_object {
    scope.push_roots(&[
      Value::Object(global_object),
      Value::String(source_string),
      this,
      new_target,
      Value::Object(home),
    ])?;
  } else {
    scope.push_roots(&[
      Value::Object(global_object),
      Value::String(source_string),
      this,
      new_target,
    ])?;
  }

  let source_text = eval_string_to_utf8_lossy_with_tick(vm, scope.heap(), source_string)?;
  let source = arc_try_new_vm(SourceText::new_charged(
    scope.heap_mut(),
    "<eval>",
    source_text,
  )?)?;
  let opts = ParseOptions {
    dialect: Dialect::Ecma,
    source_type: SourceType::Script,
  };
  let meta_property_context = env.meta_property_context();
  // Like the Function constructor, `eval("...")` parse/early errors are JS-catchable.
  let top = match vm.parse_top_level_with_budget_with_meta_property_context(&source.text, opts, meta_property_context) {
    Ok(top) => top,
    Err(VmError::Syntax(diags)) => {
      let intr = vm
        .intrinsics()
        .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;
      let message = diags
        .first()
        .map(|d| d.message.as_str())
        .unwrap_or("Invalid or unexpected token");
      let err_obj = crate::error_object::new_syntax_error_object(&mut scope, &intr, message)?;
      return Err(VmError::Throw(err_obj));
    }
    Err(err) => return Err(err),
  };
  let strict = caller_strict
    || detect_use_strict_directive(source.text.as_ref(), 0, 0, &top.stx.body, || vm.tick())?;
  {
    // Direct eval inherits the caller's lexical private-name environment.
    //
    // This is required so code like:
    //   class C { #x; m(){ return eval("this.#x"); } }
    // can successfully resolve `#x`.
    //
    // Note that indirect eval does *not* inherit private names (see `perform_indirect_eval`).
    let enclosing_private_names: Option<HashSet<String>> = {
      let mut names: HashSet<String> = HashSet::new();
      let mut current = Some(env.lexical_env);
      while let Some(e) = current {
        match scope.heap().get_env_record(e)? {
          crate::env::EnvRecord::Declarative(rec) => {
            if let Some(private_names) = rec.private_names.as_deref() {
              for entry in private_names {
                let name = entry.name.as_ref();
                if !names.contains(name) {
                  names
                    .try_reserve(1)
                    .map_err(|_| VmError::OutOfMemory)?;
                  names.insert(try_clone_string(name)?);
                }
              }
            }
            current = rec.outer;
          }
          crate::env::EnvRecord::Object(rec) => {
            current = rec.outer;
          }
        }
      }
      if names.is_empty() { None } else { Some(names) }
    };

    let mut tick = || vm.tick();
    match crate::early_errors::validate_top_level_with_enclosing_private_names(
      &top.stx.body,
      crate::early_errors::EarlyErrorOptions::script_with_super_call(
        strict,
        meta_property_context.allow_super_call(),
        meta_property_context.allow_super_property(),
      ),
      Some(source.text.as_ref()),
      enclosing_private_names,
      &mut tick,
    ) {
      Ok(()) => {}
      Err(VmError::Syntax(diags)) => {
        let intr = vm
          .intrinsics()
          .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;
        let message = diags
          .first()
          .map(|d| d.message.as_str())
          .unwrap_or("Invalid or unexpected token");
        let err_obj = crate::error_object::new_syntax_error_object(&mut scope, &intr, message)?;
        return Err(VmError::Throw(err_obj));
      }
      Err(err) => return Err(err),
    }
  }

  // Save and restore the runtime's source and environments while running eval code. This keeps
  // nested function source spans aligned with the eval input and preserves the caller's execution
  // state.
  let prev_source = env.source();
  let prev_base_offset = env.base_offset();
  let prev_prefix_len = env.prefix_len();
  let prev_lexical_env = env.lexical_env;
  let prev_var_env = env.var_env();
  let prev_global_var_deletable = env.global_var_deletable();

  // In strict eval code, var/function declarations are scoped to the eval itself. In non-strict
  // direct eval, they are scoped to the caller's VariableEnvironment.
  //
  // Spec-wise, strict eval uses a single declarative environment record for both lexical and
  // variable bindings. However, vm-js represents `var`-scoped bindings and lexical (`let`/`const`)
  // bindings as separate environment records in most execution contexts (functions, class static
  // blocks, ...), and `RuntimeEnv::declare_var` assumes the variable environment is distinct from
  // the var-scope lexical environment.
  //
  // If we reuse a single env record for strict eval, repeated `declare_var` calls for a `var`
  // binding (e.g. during `var x = 1` initialization) can incorrectly treat the existing *var*
  // binding as a lexical collision and throw a `SyntaxError`.
  //
  // Avoid this by modeling strict eval like a function body: create a fresh var environment record
  // (outer = caller lexical env), then a fresh lexical environment record (outer = that var env).
  let (eval_lex, eval_var_env) = if strict {
    let eval_var = scope.env_create(Some(prev_lexical_env))?;
    let eval_lex = scope.env_create(Some(eval_var))?;
    (eval_lex, VarEnv::Env(eval_var))
  } else {
    let eval_lex = scope.env_create(Some(prev_lexical_env))?;
    (eval_lex, prev_var_env)
  };
  env.set_source_info(source.clone(), 0, 0);
  env.set_lexical_env(scope.heap_mut(), eval_lex);
  env.set_var_env(eval_var_env);
  // Annex B: non-strict *direct* eval in the global scope creates deletable (configurable) global
  // var/function bindings.
  env.set_global_var_deletable(!strict && matches!(prev_var_env, VarEnv::GlobalObject));

  let result = {
    let mut evaluator = Evaluator {
      vm,
      host,
      hooks,
      env,
      strict,
      this,
      new_target,
      home_object,
      class_constructor: None,
      derived_constructor: false,
      this_initialized: true,
      this_root_idx: None,
    };

    (|| {
      evaluator.instantiate_script(&mut scope, &top.stx.body)?;

      let completion = evaluator.eval_stmt_list(&mut scope, &top.stx.body)?;
      match completion {
        Completion::Normal(v) => Ok(v.unwrap_or(Value::Undefined)),
        Completion::Throw(thrown) => Err(VmError::ThrowWithStack {
          value: thrown.value,
          stack: thrown.stack,
        }),
        Completion::Return(_) => Err(VmError::InvariantViolation(
          "eval produced Return completion (early errors should prevent this)",
        )),
        Completion::Break(..) => Err(VmError::InvariantViolation(
          "eval produced Break completion (early errors should prevent this)",
        )),
        Completion::Continue(..) => Err(VmError::InvariantViolation(
          "eval produced Continue completion (early errors should prevent this)",
        )),
      }
    })()
  };

  env.set_lexical_env(scope.heap_mut(), prev_lexical_env);
  env.set_var_env(prev_var_env);
  env.set_global_var_deletable(prev_global_var_deletable);
  env.set_source_info(prev_source, prev_base_offset, prev_prefix_len);

  match result {
    Err(VmError::Syntax(diags)) => {
      let intr = vm
        .intrinsics()
        .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;
      let message = diags
        .first()
        .map(|d| d.message.as_str())
        .unwrap_or("Invalid or unexpected token");
      let err_obj = crate::error_object::new_syntax_error_object(&mut scope, &intr, message)?;
      Err(VmError::Throw(err_obj))
    }
    other => other,
  }
}

/// Execute a *script* provided as a JavaScript String value in the current realm's global
/// environment.
///
/// This is host-facing glue for test harnesses (notably test262's `$262.evalScript`) that need to
/// run additional global scripts at runtime.
///
/// Unlike indirect `eval`, this uses classic Script semantics (GlobalDeclarationInstantiation):
/// top-level lexical declarations (`let`/`const`/`class`) create bindings in the realm's global
/// lexical environment and persist after this call returns.
///
/// Parse/early errors are surfaced as a thrown `SyntaxError` value so they are catchable in user
/// code.
pub fn eval_script_with_host_and_hooks(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  source_string: GcString,
) -> Result<Value, VmError> {
  let intr = vm
    .intrinsics()
    .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;

  // Derive the realm's global object + global lexical environment from the intrinsic `eval`
  // function's metadata (populated by `Realm::new`).
  let (global_object, global_lexical_env) = {
    let f = scope.heap().get_function(intr.eval())?;
    let global_object = f
      .realm
      .ok_or(VmError::Unimplemented("eval missing [[Realm]]"))?;
    let global_lexical_env = f
      .closure_env
      .ok_or(VmError::Unimplemented("eval missing [[Environment]]"))?;
    (global_object, global_lexical_env)
  };

  // Root the global object, global lexical environment, and the input string across allocations.
  let mut scope = scope.reborrow();
  scope.push_roots(&[Value::Object(global_object), Value::String(source_string)])?;
  scope.push_env_root(global_lexical_env)?;

  // Ensure heap-level allocation defaults (notably `Heap::default_object_prototype`) match the
  // current realm while running the script so newly-created constructor `.prototype` objects inherit
  // from the correct `%Object.prototype%` even when multiple realms share one heap.
  let realm_id = vm
    .current_realm()
    .or_else(|| scope.heap().get_function_job_realm(intr.eval()))
    .or_else(|| vm.intrinsics_realm());
  let (loaded_realm, prev_state) = match realm_id {
    Some(id) => (true, vm.load_realm_state(scope.heap_mut(), id)?),
    None => (false, None),
  };

  let result: Result<Value, VmError> = (|| {
    let source_text = eval_string_to_utf8_lossy_with_tick(vm, scope.heap(), source_string)?;
    let source = arc_try_new_vm(SourceText::new_charged(
      scope.heap_mut(),
      "<evalScript>",
      source_text,
    )?)?;

    let (line, col) = source.line_col(0);
    let frame = StackFrame {
      function: None,
      source: source.name.clone(),
      line,
      col,
    };
    let mut vm_frame = vm.enter_frame(frame)?;

    // Charge at least one tick at entry so even an empty script respects fuel/deadline/interrupt
    // budgets.
    vm_frame.tick()?;

    // Parse as a script and convert syntax errors into a thrown `SyntaxError`.
    let opts = ParseOptions {
      dialect: Dialect::Ecma,
      source_type: SourceType::Script,
    };
    let top = match vm_frame.parse_top_level_with_budget(&source.text, opts) {
      Ok(top) => top,
      Err(VmError::Syntax(diags)) => {
        let message = diags
          .first()
          .map(|d| d.message.as_str())
          .unwrap_or("Invalid or unexpected token");
        let err_obj = crate::error_object::new_syntax_error_object(&mut scope, &intr, message)?;
        return Err(VmError::Throw(err_obj));
      }
      Err(err) => return Err(err),
    };

    let strict = detect_use_strict_directive(
      source.text.as_ref(),
      0,
      0,
      &top.stx.body,
      || vm_frame.tick(),
    )?;
    {
      let mut tick = || vm_frame.tick();
      match crate::early_errors::validate_top_level(
        &top.stx.body,
        crate::early_errors::EarlyErrorOptions::script(strict),
        Some(source.text.as_ref()),
        &mut tick,
      ) {
        Ok(()) => {}
        Err(VmError::Syntax(diags)) => {
          let message = diags
            .first()
            .map(|d| d.message.as_str())
            .unwrap_or("Invalid or unexpected token");
          let err_obj = crate::error_object::new_syntax_error_object(&mut scope, &intr, message)?;
          return Err(VmError::Throw(err_obj));
        }
        Err(err) => return Err(err),
      }
    }

    let mut env = RuntimeEnv::new(scope.heap_mut(), global_object, global_lexical_env)?;
    env.set_source_info(source.clone(), 0, 0);

    let result = (|| {
      // In classic scripts, top-level `this` is the global object (even in strict mode).
      let global_this = Value::Object(global_object);
      let mut evaluator = Evaluator {
        vm: &mut *vm_frame,
        host,
        hooks,
        env: &mut env,
        strict,
        this: global_this,
        new_target: Value::Undefined,
        home_object: None,
        class_constructor: None,
        derived_constructor: false,
        this_initialized: true,
        this_root_idx: None,
      };

      evaluator.instantiate_script(&mut scope, &top.stx.body)?;

      let completion = evaluator.eval_stmt_list(&mut scope, &top.stx.body)?;
      match completion {
        Completion::Normal(v) => Ok(v.unwrap_or(Value::Undefined)),
        Completion::Throw(thrown) => Err(VmError::ThrowWithStack {
          value: thrown.value,
          stack: thrown.stack,
        }),
        Completion::Return(_) => Err(VmError::InvariantViolation(
          "script evaluation produced Return completion (early errors should prevent this)",
        )),
        Completion::Break(..) => Err(VmError::InvariantViolation(
          "script evaluation produced Break completion (early errors should prevent this)",
        )),
        Completion::Continue(..) => Err(VmError::InvariantViolation(
          "script evaluation produced Continue completion (early errors should prevent this)",
        )),
      }
    })();

    env.teardown(scope.heap_mut());

    // Syntax errors from instantiation/evaluation should also be catchable.
    let result = match result {
      Err(VmError::Syntax(diags)) => {
        let message = diags
          .first()
          .map(|d| d.message.as_str())
          .unwrap_or("Invalid or unexpected token");
        let err_obj = crate::error_object::new_syntax_error_object(&mut scope, &intr, message)?;
        Err(VmError::Throw(err_obj))
      }
      other => other,
    };

    // Ensure host-visible failures never leak internal helper errors (TypeError, NotCallable, etc.)
    // when intrinsics are available.
    match result {
      Err(err) if err.is_throw_completion() => Err(crate::vm::coerce_error_to_throw_with_stack(
        &*vm_frame,
        &mut scope,
        err,
      )),
      other => other,
    }
  })();

  let restore_res = if loaded_realm {
    vm.restore_realm_state(scope.heap_mut(), prev_state)
  } else {
    Ok(())
  };

  match (result, restore_res) {
    (Ok(v), Ok(())) => Ok(v),
    (Err(err), Ok(())) => Err(err),
    (Ok(_), Err(err)) => Err(err),
    (Err(err), Err(_)) => Err(err),
  }
}

fn throw_type_error(vm: &Vm, scope: &mut Scope<'_>, message: &str) -> Result<VmError, VmError> {
  let intr = vm
    .intrinsics()
    .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;
  let value =
    crate::error_object::new_error(scope, intr.type_error_prototype(), "TypeError", message)?;
  Ok(VmError::Throw(value))
}

#[inline]
fn check_disposable_resource_value(vm: &Vm, scope: &mut Scope<'_>, value: Value) -> Result<(), VmError> {
  match value {
    Value::Null | Value::Undefined => Ok(()),
    Value::Object(_) => Ok(()),
    _ => Err(throw_type_error(
      vm,
      scope,
      "Using declaration initializer must be an object",
    )?),
  }
}

fn throw_syntax_error(vm: &Vm, scope: &mut Scope<'_>, message: &str) -> Result<VmError, VmError> {
  let intr = vm
    .intrinsics()
    .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;
  let value = crate::error_object::new_syntax_error_object(scope, &intr, message)?;
  Ok(VmError::Throw(value))
}

fn throw_range_error(vm: &Vm, scope: &mut Scope<'_>, message: &str) -> Result<VmError, VmError> {
  let intr = vm
    .intrinsics()
    .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;
  let value =
    crate::error_object::new_error(scope, intr.range_error_prototype(), "RangeError", message)?;
  Ok(VmError::Throw(value))
}

fn throw_reference_error(
  vm: &Vm,
  scope: &mut Scope<'_>,
  message: &str,
) -> Result<VmError, VmError> {
  let intr = vm
    .intrinsics()
    .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;
  let value = crate::error_object::new_error(
    scope,
    intr.reference_error_prototype(),
    "ReferenceError",
    message,
  )?;
  Ok(VmError::Throw(value))
}

#[inline]
fn try_clone_string(value: &str) -> Result<String, VmError> {
  let mut out = String::new();
  out
    .try_reserve_exact(value.len())
    .map_err(|_| VmError::OutOfMemory)?;
  out.push_str(value);
  Ok(out)
}

fn syntax_error(loc: parse_js::loc::Loc, message: impl Into<String>) -> VmError {
  let span = loc.to_diagnostics_span(FileId(0));
  VmError::Syntax(vec![Diagnostic::error("VMJS0002", message, span)])
}

#[derive(Clone, Copy, Debug)]
pub(crate) enum VarEnv {
  GlobalObject,
  Env(GcEnv),
}

#[derive(Clone, Copy, Debug)]
enum ClassBinding<'a> {
  None,
  Immutable(&'a str),
}

#[derive(Debug, Clone)]
pub(crate) struct RuntimeEnv {
  global_object: GcObject,
  lexical_env: GcEnv,
  /// Persistent env root used while this `RuntimeEnv` is stored outside the GC heap (e.g. on the
  /// Rust stack during normal execution, or in `AsyncContinuation`).
  ///
  /// Generator continuations are GC-owned, so they must not keep persistent roots alive across
  /// yields; generator code sets this to `None` before storing the env in the heap, and may attach a
  /// temporary root only for the duration of a single `.next/.throw/.return` call.
  lexical_root: Option<EnvRootId>,
  var_env: VarEnv,
  /// Whether new global `var`/function declarations should create **deletable** (configurable)
  /// bindings on the global object.
  ///
  /// This is used for Annex B semantics of **non-strict direct eval** in the global scope, where
  /// `var`/function declarations are introduced as configurable properties and must not count as
  /// `[[VarNames]]` for future global lexical declaration collisions.
  ///
  /// For ordinary scripts and indirect eval, this remains `false`.
  global_var_deletable: bool,
  source: Arc<SourceText>,
  base_offset: u32,
  prefix_len: u32,
  meta_property_context: MetaPropertyContext,
}

impl Trace for RuntimeEnv {
  fn trace(&self, tracer: &mut Tracer<'_>) {
    tracer.trace_value(Value::Object(self.global_object));
    tracer.trace_env(self.lexical_env);
    if let VarEnv::Env(env) = self.var_env {
      tracer.trace_env(env);
    }
  }
}

/// A pre-resolved identifier reference for assignment.
///
/// This is used by destructuring assignment to preserve spec evaluation order:
/// - The assignment target reference is evaluated (including `ResolveBinding` / `HasBinding`)
///   *before* consuming RHS iterator values or accessing RHS properties.
/// - The resulting reference is then used for `PutValue` without re-resolving the binding.
#[derive(Clone, Copy, Debug)]
pub(crate) enum ResolvedBinding<'a> {
  /// A binding in a declarative environment record.
  Declarative { env: GcEnv, name: &'a str },
  /// A binding in an object environment record (`with`), backed by a property on `binding_object`.
  Object {
    binding_object: GcObject,
    name: &'a str,
  },
  /// A global-object property that existed at reference-evaluation time.
  GlobalProperty { name: &'a str },
  /// No lexical binding and no existing global-object property at reference-evaluation time.
  Unresolvable { name: &'a str },
}

impl<'a> ResolvedBinding<'a> {
  pub(crate) fn name(self) -> &'a str {
    match self {
      ResolvedBinding::Declarative { name, .. }
      | ResolvedBinding::Object { name, .. }
      | ResolvedBinding::GlobalProperty { name }
      | ResolvedBinding::Unresolvable { name } => name,
    }
  }
}

impl RuntimeEnv {
  fn new(heap: &mut Heap, global_object: GcObject, lexical_env: GcEnv) -> Result<Self, VmError> {
    let mut scope = heap.scope();
    // Root the global object and lexical environment across root registration in case it triggers
    // GC.
    //
    // Note: pushing stack roots can grow `root_stack`, which may trigger a GC. Ensure the freshly
    // created `lexical_env` is treated as a root during that operation; otherwise it could be
    // collected before we register the persistent env root.
    let values = [Value::Object(global_object)];
    let envs = [lexical_env];
    scope.push_roots_with_extra_roots(&values, &[], &envs)?;
    scope.push_env_root(lexical_env)?;
    let source = arc_try_new_vm(SourceText::new("<init>", ""))?;
    let lexical_root = Some(scope.heap_mut().add_env_root(lexical_env)?);

    Ok(Self {
      global_object,
      lexical_env,
      lexical_root,
      var_env: VarEnv::GlobalObject,
      global_var_deletable: false,
      source,
      base_offset: 0,
      prefix_len: 0,
      meta_property_context: MetaPropertyContext::SCRIPT,
    })
  }

  pub(crate) fn new_with_var_env(
    heap: &mut Heap,
    global_object: GcObject,
    lexical_env: GcEnv,
    var_env: GcEnv,
  ) -> Result<Self, VmError> {
    let mut scope = heap.scope();
    // Root the global object and env records across root registration in case it triggers GC.
    //
    // See `RuntimeEnv::new` for why `lexical_env`/`var_env` must be treated as roots while growing
    // `root_stack`.
    let values = [Value::Object(global_object)];
    let envs = [lexical_env, var_env];
    scope.push_roots_with_extra_roots(&values, &[], &envs)?;
    scope.push_env_roots(&envs)?;

    let source = arc_try_new_vm(SourceText::new("<init>", ""))?;
    let lexical_root = Some(scope.heap_mut().add_env_root(lexical_env)?);

    Ok(Self {
      global_object,
      lexical_env,
      lexical_root,
      var_env: VarEnv::Env(var_env),
      global_var_deletable: false,
      source,
      base_offset: 0,
      prefix_len: 0,
      meta_property_context: MetaPropertyContext::SCRIPT,
    })
  }

  pub(crate) fn new_with_lexical_env(
    heap: &mut Heap,
    global_object: GcObject,
    lexical_env: GcEnv,
  ) -> Result<Self, VmError> {
    let mut scope = heap.scope();
    // Root the global object and lexical env across root registration in case it triggers GC. See
    // `RuntimeEnv::new` for details.
    let values = [Value::Object(global_object)];
    let envs = [lexical_env];
    scope.push_roots_with_extra_roots(&values, &[], &envs)?;
    scope.push_env_root(lexical_env)?;
    let source = arc_try_new_vm(SourceText::new("<init>", ""))?;
    let lexical_root = Some(scope.heap_mut().add_env_root(lexical_env)?);

    Ok(Self {
      global_object,
      lexical_env,
      lexical_root,
      var_env: VarEnv::GlobalObject,
      global_var_deletable: false,
      source,
      base_offset: 0,
      prefix_len: 0,
      meta_property_context: MetaPropertyContext::SCRIPT,
    })
  }

  pub(crate) fn teardown(&mut self, heap: &mut Heap) {
    if let Some(root) = self.lexical_root.take() {
      heap.remove_env_root(root);
    }
  }

  pub(crate) fn set_lexical_env(&mut self, heap: &mut Heap, env: GcEnv) {
    self.lexical_env = env;
    if let Some(root) = self.lexical_root {
      heap.set_env_root(root, env);
    }
  }

  pub(crate) fn set_source_info(
    &mut self,
    source: Arc<SourceText>,
    base_offset: u32,
    prefix_len: u32,
  ) {
    self.source = source;
    self.base_offset = base_offset;
    self.prefix_len = prefix_len;
  }

  pub(crate) fn source(&self) -> Arc<SourceText> {
    self.source.clone()
  }

  pub(crate) fn base_offset(&self) -> u32 {
    self.base_offset
  }

  pub(crate) fn prefix_len(&self) -> u32 {
    self.prefix_len
  }

  pub(crate) fn meta_property_context(&self) -> MetaPropertyContext {
    self.meta_property_context
  }

  pub(crate) fn set_meta_property_context(&mut self, ctx: MetaPropertyContext) {
    self.meta_property_context = ctx;
  }

  pub(crate) fn global_object(&self) -> GcObject {
    self.global_object
  }

  pub(crate) fn lexical_env(&self) -> GcEnv {
    self.lexical_env
  }

  /// Resolves an identifier reference for assignment without reading its value.
  ///
  /// This mirrors ECMA-262 `ResolveBinding` / `GetIdentifierReference` for the subset needed by
  /// vm-js:
  /// - search the lexical environment chain (including `with` object env records)
  /// - if not found, check whether the global object currently has the property
  ///
  /// The returned [`ResolvedBinding`] can then be passed to [`RuntimeEnv::set_resolved_binding`] to
  /// perform `PutValue` without performing a second binding resolution step.
  pub(crate) fn resolve_binding_reference<'a>(
    &self,
    vm: &mut Vm,
    host: &mut dyn VmHost,
    hooks: &mut dyn VmHostHooks,
    scope: &mut Scope<'_>,
    name: &'a str,
  ) -> Result<ResolvedBinding<'a>, VmError> {
    if let Some(env) = self.resolve_lexical_binding(vm, host, hooks, scope, name)? {
      return match scope.heap().get_env_record(env)? {
        crate::env::EnvRecord::Declarative(_) => Ok(ResolvedBinding::Declarative { env, name }),
        crate::env::EnvRecord::Object(obj) => Ok(ResolvedBinding::Object {
          binding_object: obj.binding_object,
          name,
        }),
      };
    }

    // No lexical binding. Check whether the global object currently has a property binding.
    let global_object = self.global_object;
    let mut key_scope = scope.reborrow();
    key_scope.push_root(Value::Object(global_object))?;
    let key_s = key_scope.alloc_string(name)?;
    key_scope.push_root(Value::String(key_s))?;
    let key = PropertyKey::from_string(key_s);
    let has_binding = crate::spec_ops::internal_has_property_with_host_and_hooks(
      vm,
      &mut key_scope,
      host,
      hooks,
      global_object,
      key,
    )?;
    if has_binding {
      Ok(ResolvedBinding::GlobalProperty { name })
    } else {
      Ok(ResolvedBinding::Unresolvable { name })
    }
  }

  /// Assigns to a pre-resolved identifier reference (ECMA-262 `PutValue`).
  pub(crate) fn set_resolved_binding(
    &mut self,
    vm: &mut Vm,
    host: &mut dyn VmHost,
    hooks: &mut dyn VmHostHooks,
    scope: &mut Scope<'_>,
    reference: ResolvedBinding<'_>,
    value: Value,
    strict: bool,
  ) -> Result<(), VmError> {
    match reference {
      ResolvedBinding::Declarative { env, name } => match scope
        .heap_mut()
        .env_set_mutable_binding(env, name, value, strict)
      {
        Ok(()) => Ok(()),
        // TDZ sentinel from `Heap::{env_get_binding_value, env_set_mutable_binding}`.
        Err(VmError::Throw(Value::Null)) => {
          let msg = crate::fallible_format::try_format_error_message(
            "Cannot access '",
            name,
            "' before initialization",
          )?;
          Err(throw_reference_error(vm, scope, &msg)?)
        }
        // `const` assignment sentinel from `Heap::env_set_mutable_binding`.
        Err(VmError::Throw(Value::Undefined)) => Err(throw_type_error(
          vm,
          scope,
          "Assignment to constant variable.",
        )?),
        Err(err) => Err(err),
      },
      ResolvedBinding::Object {
        binding_object,
        name,
      } => {
        let receiver = Value::Object(binding_object);
        let mut key_scope = scope.reborrow();
        key_scope.push_root(receiver)?;
        // Root `value` across key allocation and property assignment in case it triggers a GC.
        key_scope.push_root(value)?;
        let key_s = key_scope.alloc_string(name)?;
        key_scope.push_root(Value::String(key_s))?;
        let key = PropertyKey::from_string(key_s);
        let ok = crate::spec_ops::internal_set_with_host_and_hooks(
          vm,
          &mut key_scope,
          host,
          hooks,
          binding_object,
          key,
          value,
          receiver,
        )?;
        if ok {
          Ok(())
        } else if strict {
          Err(throw_type_error(
            vm,
            &mut key_scope,
            "Cannot assign to read-only property",
          )?)
        } else {
          Ok(())
        }
      }
      ResolvedBinding::GlobalProperty { name } => {
        let global_object = self.global_object;
        let receiver = Value::Object(global_object);
        let mut key_scope = scope.reborrow();
        key_scope.push_root(receiver)?;
        // Root `value` across key allocation and `[[Set]]` in case they trigger a GC.
        key_scope.push_root(value)?;
        let key_s = key_scope.alloc_string(name)?;
        key_scope.push_root(Value::String(key_s))?;
        let key = PropertyKey::from_string(key_s);
        let ok = crate::spec_ops::internal_set_with_host_and_hooks(
          vm,
          &mut key_scope,
          host,
          hooks,
          global_object,
          key,
          value,
          receiver,
        )?;
        if ok {
          Ok(())
        } else if strict {
          Err(throw_type_error(
            vm,
            &mut key_scope,
            "Cannot assign to read-only property",
          )?)
        } else {
          Ok(())
        }
      }
      ResolvedBinding::Unresolvable { name } => {
        if strict {
          let msg = crate::fallible_format::try_format_error_message("", name, " is not defined")?;
          return Err(throw_reference_error(vm, scope, &msg)?);
        }

        // Sloppy-mode unresolvable assignment performs `Set(globalThis, name, value, false)`.
        let global_object = self.global_object;
        let receiver = Value::Object(global_object);
        let mut key_scope = scope.reborrow();
        key_scope.push_root(receiver)?;
        // Root `value` across key allocation and `[[Set]]` in case they trigger a GC.
        key_scope.push_root(value)?;
        let key_s = key_scope.alloc_string(name)?;
        key_scope.push_root(Value::String(key_s))?;
        let key = PropertyKey::from_string(key_s);
        let ok = crate::spec_ops::internal_set_with_host_and_hooks(
          vm,
          &mut key_scope,
          host,
          hooks,
          global_object,
          key,
          value,
          receiver,
        )?;
        if ok {
          Ok(())
        } else {
          Ok(())
        }
      }
    }
  }

  pub(crate) fn var_env(&self) -> VarEnv {
    self.var_env
  }

  pub(crate) fn set_var_env(&mut self, var_env: VarEnv) {
    self.var_env = var_env;
  }

  fn global_var_deletable(&self) -> bool {
    self.global_var_deletable
  }

  fn set_global_var_deletable(&mut self, deletable: bool) {
    self.global_var_deletable = deletable;
  }

  fn resolve_lexical_binding(
    &self,
    vm: &mut Vm,
    host: &mut dyn VmHost,
    hooks: &mut dyn VmHostHooks,
    scope: &mut Scope<'_>,
    name: &str,
  ) -> Result<Option<GcEnv>, VmError> {
    enum EnvKind {
      Declarative,
      Object {
        binding_object: GcObject,
        with_environment: bool,
      },
    }

    let mut current = Some(self.lexical_env);
    while let Some(env) = current {
      let kind = match scope.heap().get_env_record(env)? {
        crate::env::EnvRecord::Declarative(_) => EnvKind::Declarative,
        crate::env::EnvRecord::Object(obj) => EnvKind::Object {
          binding_object: obj.binding_object,
          with_environment: obj.with_environment,
        },
      };

      match kind {
        EnvKind::Declarative => {
          if scope.heap().env_has_binding(env, name)? {
            return Ok(Some(env));
          }
        }
        EnvKind::Object {
          binding_object,
          with_environment,
        } => {
          if self.object_env_has_binding(
            vm,
            host,
            hooks,
            scope,
            binding_object,
            with_environment,
            name,
          )? {
            return Ok(Some(env));
          }
        }
      }

      current = scope.heap().env_outer(env)?;
    }

    Ok(None)
  }

  fn object_env_has_binding(
    &self,
    vm: &mut Vm,
    host: &mut dyn VmHost,
    hooks: &mut dyn VmHostHooks,
    scope: &mut Scope<'_>,
    binding_object: GcObject,
    with_environment: bool,
    name: &str,
  ) -> Result<bool, VmError> {
    // ObjectEnvironmentRecord.HasBinding (ECMA-262).
    //
    // This is only used for `with` environments today, but we keep the generic shape since the heap
    // supports ObjectEnvRecord independently.
    let mut check_scope = scope.reborrow();
    check_scope.push_root(Value::Object(binding_object))?;
    let name_s = check_scope.alloc_string(name)?;
    check_scope.push_root(Value::String(name_s))?;
    let name_key = PropertyKey::from_string(name_s);

    // HasProperty(O, N)
    if !crate::spec_ops::internal_has_property_with_host_and_hooks(
      vm,
      &mut check_scope,
      host,
      hooks,
      binding_object,
      name_key,
    )? {
      return Ok(false);
    }

    if !with_environment {
      return Ok(true);
    }

    // If `@@unscopables` blocks this name, treat it as not present so resolution falls back to the
    // outer environment.
    let intr = vm
      .intrinsics()
      .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;
    let unscopables_key = PropertyKey::from_symbol(intr.well_known_symbols().unscopables);
    let receiver = Value::Object(binding_object);

    let unscopables = check_scope.get_with_host_and_hooks(
      vm,
      host,
      hooks,
      binding_object,
      unscopables_key,
      receiver,
    )?;
    check_scope.push_root(unscopables)?;
    let Value::Object(unscopables_obj) = unscopables else {
      return Ok(true);
    };

    check_scope.push_root(Value::Object(unscopables_obj))?;
    let blocked = check_scope.get_with_host_and_hooks(
      vm,
      host,
      hooks,
      unscopables_obj,
      name_key,
      Value::Object(unscopables_obj),
    )?;
    Ok(!check_scope.heap().to_boolean(blocked)?)
  }

  pub(crate) fn declare_var(
    &mut self,
    vm: &mut Vm,
    scope: &mut Scope<'_>,
    name: &str,
  ) -> Result<(), VmError> {
    // `var` declarations can be introduced dynamically via `eval` (direct or indirect). Those
    // declarations must not conflict with existing lexical bindings in the same variable scope.
    //
    // For example (Node.js):
    //   function f(){ let x = 1; eval("var x = 2"); }
    //
    // This is not an early error in the *caller* because the `var` declaration is parsed at runtime
    // from the eval string. The engine must reject it by throwing a catchable `SyntaxError`.
    match self.var_env {
      VarEnv::GlobalObject => {
        // Global `var` declarations must not collide with existing global lexical bindings.
        //
        // vm-js models the global lexical environment as a standalone declarative env record whose
        // outer is `None` (identifier resolution falls back to the global object separately), so we
        // recover it by walking to the outermost env.
        let mut current = self.lexical_env;
        loop {
          let outer = scope.heap().env_outer(current)?;
          let Some(outer) = outer else {
            break;
          };
          current = outer;
        }

        // Only declarative env records can contain lexical bindings (`let`/`const`/`class`).
        if matches!(
          scope.heap().get_env_record(current)?,
          crate::env::EnvRecord::Declarative(_)
        ) && scope.heap().env_has_binding(current, name)?
        {
          let intr = vm
            .intrinsics()
            .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;
          let err_obj = crate::error_object::new_syntax_error_object(
            scope,
            &intr,
            "Identifier has already been declared",
          )?;
          return Err(VmError::Throw(err_obj));
        }
      }
      VarEnv::Env(var_env) => {
        // Function `var` declarations must not collide with lexical bindings in the function-body
        // lexical environment record (which is the env whose outer is the VariableEnvironment).
        //
        // Note: This intentionally does *not* consider inner block/catch env records, which are
        // separate lexical scopes and are allowed to shadow var bindings.
        let mut current = Some(self.lexical_env);
        let mut var_scope_lex: Option<GcEnv> = None;
        while let Some(env) = current {
          let outer = scope.heap().env_outer(env)?;
          if outer == Some(var_env) {
            var_scope_lex = Some(env);
            break;
          }
          current = outer;
        }

        // If the current lexical environment is the variable environment itself, there may be no
        // dedicated "var-scope lexical env" record yet (for example, during parameter
        // initialization). In that case, fall back to checking the current lexical env directly so
        // direct eval `var` declarations still reject collisions with existing bindings.
        if var_scope_lex.is_none() && self.lexical_env == var_env {
          var_scope_lex = Some(self.lexical_env);
        }

        if let Some(var_scope_lex) = var_scope_lex {
          if matches!(
            scope.heap().get_env_record(var_scope_lex)?,
            crate::env::EnvRecord::Declarative(_)
          ) && scope.heap().env_has_binding(var_scope_lex, name)?
          {
            let intr = vm
              .intrinsics()
              .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;
            let err_obj = crate::error_object::new_syntax_error_object(
              scope,
              &intr,
              "Identifier has already been declared",
            )?;
            return Err(VmError::Throw(err_obj));
          }
        }
      }
    }

    match self.var_env {
      VarEnv::GlobalObject => {
        let global_object = self.global_object;

        // Root the global object across property-key allocation in case it triggers GC.
        let mut key_scope = scope.reborrow();
        key_scope.push_root(Value::Object(global_object))?;

        let key = PropertyKey::from_string(key_scope.alloc_string(name)?);
        if key_scope
          .heap()
          .object_get_own_property_with_tick(global_object, &key, || vm.tick())?
          .is_some()
        {
          return Ok(());
        }

        key_scope.define_property(
          global_object,
          key,
          if self.global_var_deletable {
            global_var_desc(Value::Undefined)
          } else {
            global_var_binding_desc(Value::Undefined)
          },
        )?;
        Ok(())
      }
      VarEnv::Env(env) => {
        if scope.heap().env_has_binding(env, name)? {
          return Ok(());
        }
        scope.env_create_mutable_binding(env, name)?;
        scope
          .heap_mut()
          .env_initialize_binding(env, name, Value::Undefined)?;
        Ok(())
      }
    }
  }

  pub(crate) fn get(
    &self,
    vm: &mut Vm,
    host: &mut dyn VmHost,
    hooks: &mut dyn VmHostHooks,
    scope: &mut Scope<'_>,
    name: &str,
  ) -> Result<Option<Value>, VmError> {
    if let Some(env) = self.resolve_lexical_binding(vm, host, hooks, scope, name)? {
      let binding_object = match scope.heap().get_env_record(env)? {
        crate::env::EnvRecord::Declarative(_) => None,
        crate::env::EnvRecord::Object(obj) => Some(obj.binding_object),
      };

      if let Some(binding_object) = binding_object {
        // Object environment record (e.g. `with (obj) { ... }`): resolve the binding via `Get(O, N)`.
        let mut key_scope = scope.reborrow();
        key_scope.push_root(Value::Object(binding_object))?;
        let key_s = key_scope.alloc_string(name)?;
        key_scope.push_root(Value::String(key_s))?;
        let key = PropertyKey::from_string(key_s);
        let receiver = Value::Object(binding_object);
        let value =
          key_scope.get_with_host_and_hooks(vm, host, hooks, binding_object, key, receiver)?;
        return Ok(Some(value));
      }

      match scope.heap().env_get_binding_value(env, name, false) {
        Ok(v) => return Ok(Some(v)),
        // TDZ sentinel from `Heap::{env_get_binding_value, env_set_mutable_binding}`.
        Err(VmError::Throw(Value::Null)) => {
          let msg = crate::fallible_format::try_format_error_message(
            "Cannot access '",
            name,
            "' before initialization",
          )?;
          return Err(throw_reference_error(vm, scope, &msg)?);
        }
        Err(err) => return Err(err),
      }
    }

    // Fall back to global object property lookup.
    let global_object = self.global_object;
    let mut key_scope = scope.reborrow();
    key_scope.push_root(Value::Object(global_object))?;
    let key_s = key_scope.alloc_string(name)?;
    key_scope.push_root(Value::String(key_s))?;
    let key = PropertyKey::from_string(key_s);

    // Distinguish between a missing property (unbound identifier) and a present property whose
    // value is actually `undefined`.
    if !crate::spec_ops::internal_has_property_with_host_and_hooks(
      vm,
      &mut key_scope,
      host,
      hooks,
      global_object,
      key,
    )? {
      return Ok(None);
    }

    let receiver = Value::Object(global_object);
    Ok(Some(key_scope.get_with_host_and_hooks(
      vm,
      host,
      hooks,
      global_object,
      key,
      receiver,
    )?))
  }

  pub(crate) fn set(
    &mut self,
    vm: &mut Vm,
    host: &mut dyn VmHost,
    hooks: &mut dyn VmHostHooks,
    scope: &mut Scope<'_>,
    name: &str,
    value: Value,
    strict: bool,
  ) -> Result<(), VmError> {
    if let Some(env) = self.resolve_lexical_binding(vm, host, hooks, scope, name)? {
      let binding_object = match scope.heap().get_env_record(env)? {
        crate::env::EnvRecord::Declarative(_) => None,
        crate::env::EnvRecord::Object(obj) => Some(obj.binding_object),
      };

      if let Some(binding_object) = binding_object {
        let receiver = Value::Object(binding_object);
        let mut key_scope = scope.reborrow();
        key_scope.push_root(receiver)?;
        // Root `value` across key allocation and property assignment in case it triggers a GC.
        key_scope.push_root(value)?;
        let key_s = key_scope.alloc_string(name)?;
        key_scope.push_root(Value::String(key_s))?;
        let key = PropertyKey::from_string(key_s);
        let ok = crate::spec_ops::internal_set_with_host_and_hooks(
          vm,
          &mut key_scope,
          host,
          hooks,
          binding_object,
          key,
          value,
          receiver,
        )?;
        if ok {
          return Ok(());
        }
        if strict {
          return Err(throw_type_error(
            vm,
            &mut key_scope,
            "Cannot assign to read-only property",
          )?);
        }
        return Ok(());
      }

      match scope
        .heap_mut()
        .env_set_mutable_binding(env, name, value, strict)
      {
        Ok(()) => return Ok(()),
        // TDZ sentinel from `Heap::{env_get_binding_value, env_set_mutable_binding}`.
        Err(VmError::Throw(Value::Null)) => {
          let msg = crate::fallible_format::try_format_error_message(
            "Cannot access '",
            name,
            "' before initialization",
          )?;
          return Err(throw_reference_error(vm, scope, &msg)?);
        }
        // `const` assignment sentinel from `Heap::env_set_mutable_binding`.
        Err(VmError::Throw(Value::Undefined)) => {
          return Err(throw_type_error(
            vm,
            scope,
            "Assignment to constant variable.",
          )?);
        }
        Err(err) => return Err(err),
      }
    }

    // Assignment to global (var) bindings is backed by the global object.
    let global_object = self.global_object;
    let mut key_scope = scope.reborrow();
    key_scope.push_root(Value::Object(global_object))?;
    // Root `value` across key allocation and property definition in case they trigger GC.
    key_scope.push_root(value)?;
    let key = PropertyKey::from_string(key_scope.alloc_string(name)?);

    let has_binding = crate::spec_ops::internal_has_property_with_host_and_hooks(
      vm,
      &mut key_scope,
      host,
      hooks,
      global_object,
      key,
    )?;
    if !has_binding {
      if strict {
        let msg = crate::fallible_format::try_format_error_message("", name, " is not defined")?;
        return Err(throw_reference_error(vm, &mut key_scope, &msg)?);
      }

      // Sloppy-mode: create a new global `var` property.
      key_scope.define_property(global_object, key, global_var_desc(value))?;
      return Ok(());
    }

    if let Some(desc) =
      key_scope
        .heap()
        .object_get_own_property_with_tick(global_object, &key, || vm.tick())?
    {
      match desc.kind {
        PropertyKind::Data { writable: true, .. } => {
          key_scope
            .heap_mut()
            .object_set_existing_data_property_value(global_object, &key, value)?;
          return Ok(());
        }
        PropertyKind::Data {
          writable: false, ..
        } => {
          if strict {
            let msg = crate::fallible_format::try_format_error_message(
              "Cannot assign to read only property '",
              name,
              "'",
            )?;
            return Err(throw_type_error(vm, &mut key_scope, &msg)?);
          }
          return Ok(());
        }
        PropertyKind::Accessor { .. } => {
          let receiver = Value::Object(global_object);
          let ok = crate::spec_ops::internal_set_with_host_and_hooks(
            vm,
            &mut key_scope,
            host,
            hooks,
            global_object,
            key,
            value,
            receiver,
          )?;
          if ok {
            return Ok(());
          }
          if strict {
            let msg = crate::fallible_format::try_format_error_message(
              "Cannot assign to read only property '",
              name,
              "'",
            )?;
            return Err(throw_type_error(vm, &mut key_scope, &msg)?);
          }
          return Ok(());
        }
      }
    }

    // Property is inherited through the prototype chain: define an own data property.
    key_scope.define_property(global_object, key, global_var_desc(value))?;
    Ok(())
  }

  pub(crate) fn set_var(
    &mut self,
    vm: &mut Vm,
    host: &mut dyn VmHost,
    hooks: &mut dyn VmHostHooks,
    scope: &mut Scope<'_>,
    name: &str,
    value: Value,
  ) -> Result<(), VmError> {
    // `var` declarations always assign to the global/function var environment, even when a lexical
    // binding shadows the identifier (e.g. a `catch(e)` parameter).
    // Root the initializer value across var-env binding creation/assignment in case it triggers GC.
    let mut outer_scope = scope.reborrow();
    outer_scope.push_root(value)?;
    self.declare_var(vm, &mut outer_scope, name)?;

    match self.var_env {
      VarEnv::GlobalObject => {
        let global_object = self.global_object;
        let mut key_scope = outer_scope.reborrow();
        key_scope.push_root(Value::Object(global_object))?;
        let key = PropertyKey::from_string(key_scope.alloc_string(name)?);

        if let Some(desc) =
          key_scope
            .heap()
            .object_get_own_property_with_tick(global_object, &key, || vm.tick())?
        {
          match desc.kind {
            PropertyKind::Data { writable: true, .. } => {
              key_scope
                .heap_mut()
                .object_set_existing_data_property_value(global_object, &key, value)?;
              return Ok(());
            }
            PropertyKind::Data {
              writable: false, ..
            } => {
              return Err(VmError::Unimplemented(
                "assignment to non-writable global property",
              ));
            }
            PropertyKind::Accessor { .. } => {
              let receiver = Value::Object(global_object);
              let ok = crate::spec_ops::internal_set_with_host_and_hooks(
                vm,
                &mut key_scope,
                host,
                hooks,
                global_object,
                key,
                value,
                receiver,
              )?;
              if ok {
                return Ok(());
              }
              return Err(VmError::Unimplemented(
                "assignment to non-writable global property",
              ));
            }
          }
        }

        // If the binding was inherited through the prototype chain, define an own data property.
        key_scope.define_property(
          global_object,
          key,
          if self.global_var_deletable {
            global_var_desc(value)
          } else {
            global_var_binding_desc(value)
          },
        )?;
        Ok(())
      }
      VarEnv::Env(env) => outer_scope
        .heap_mut()
        .env_set_mutable_binding(env, name, value, false),
    }
  }
}

/// An (early, incomplete) AST-interpreting execution engine for `parse-js` syntax trees.
pub struct JsRuntime {
  pub vm: Vm,
  pub heap: Heap,
  realm: Realm,
  env: RuntimeEnv,
  modules: Box<ModuleGraph>,
}

impl JsRuntime {
  pub fn new(vm: Vm, heap: Heap) -> Result<Self, VmError> {
    let mut vm = vm;
    let mut heap = heap;
    let realm = Realm::new(&mut vm, &mut heap)?;
    let env = RuntimeEnv::new(&mut heap, realm.global_object(), realm.global_lexical_env())?;
    // Avoid `Box::new`, which can abort the process on allocator OOM.
    let mut modules = box_try_new_vm(ModuleGraph::new())?;
    modules.set_global_lexical_env(env.lexical_env());
    // Make the runtime-owned module graph available to nested ECMAScript function calls (and other
    // VM entry points that do not naturally thread an explicit `&mut ModuleGraph` parameter).
    vm.set_module_graph(modules.as_mut());
    // Realm initialization uses nested `Scope`s that can temporarily grow the heap's stack root
    // vectors. Once initialization is complete there should be no active stack roots, so we can
    // drop any excess capacity to reduce baseline heap footprint under tight `HeapLimits`.
    //
    // This is particularly important for tests and embeddings that configure small heaps:
    // otherwise the runtime can end up with large `root_stack`/`env_root_stack` capacity that counts
    // against `Heap::estimated_total_bytes` even when the stacks are empty.
    debug_assert!(
      heap.root_stack.is_empty() && heap.env_root_stack.is_empty(),
      "expected runtime initialization to leave no active stack roots"
    );
    heap.root_stack = Vec::new();
    heap.env_root_stack = Vec::new();

    Ok(Self {
      vm,
      heap,
      realm,
      env,
      modules,
    })
  }

  pub fn realm(&self) -> &Realm {
    &self.realm
  }

  /// Borrow-split the runtime into its core components: the VM, the current realm, and the heap.
  ///
  /// Embeddings often need `&mut Vm` + `&mut Heap` to execute code, allocate, and/or run GC, while
  /// also needing immutable access to realm metadata (global object, intrinsics, realm id). Doing
  /// this via `JsRuntime::{vm, heap}` + `JsRuntime::realm()` requires an embedder-side raw-pointer
  /// workaround to satisfy the borrow checker.
  ///
  /// This accessor is safe because `vm`, `realm`, and `heap` are stored as disjoint fields inside
  /// [`JsRuntime`].
  pub fn vm_realm_and_heap_mut(&mut self) -> (&mut Vm, &Realm, &mut Heap) {
    let vm = &mut self.vm;
    let realm = &self.realm;
    let heap = &mut self.heap;
    (vm, realm, heap)
  }

  /// Borrow-split the runtime into its core components: the VM, the module graph, and the heap.
  pub fn vm_modules_and_heap_mut(&mut self) -> (&mut Vm, &mut ModuleGraph, &mut Heap) {
    let vm = &mut self.vm;
    let modules = &mut *self.modules;
    let heap = &mut self.heap;
    (vm, modules, heap)
  }

  /// Discard all queued Promise jobs in the VM-owned microtask queue without running them.
  ///
  /// This is intended for embeddings that need to abandon any queued microtasks (for example when
  /// aborting execution or returning early on an error) while still leaving the VM/heap in a
  /// reusable state.
  ///
  /// Note: this also tears down any in-progress async continuations stored in the VM. Async
  /// continuations are resumed exclusively via Promise jobs; if the host discards the microtask
  /// queue, keeping suspended continuations around would leak their persistent roots and leave the
  /// VM in an inconsistent state for heap reuse.
  ///
  /// This tears down jobs via [`MicrotaskQueue::teardown`](crate::MicrotaskQueue::teardown), which
  /// calls [`Job::discard`](crate::Job::discard) for each queued job to ensure any persistent roots
  /// owned by those jobs are unregistered.
  ///
  /// Note: [`JsRuntime`] also calls this from its `Drop` implementation as a safety net, so
  /// dropping a runtime with pending microtasks does not trigger `Job` debug assertions about
  /// leaked roots.
  pub fn teardown_microtasks(&mut self) {
    self.vm.teardown_microtasks(&mut self.heap);
  }

  pub fn heap(&self) -> &Heap {
    &self.heap
  }

  pub fn heap_mut(&mut self) -> &mut Heap {
    &mut self.heap
  }

  /// Returns this runtime's module graph.
  pub fn modules(&self) -> &ModuleGraph {
    &self.modules
  }

  /// Borrows this runtime's module graph mutably.
  pub fn modules_mut(&mut self) -> &mut ModuleGraph {
    &mut self.modules
  }

  /// Registers a native call handler and exposes it as a global binding.
  ///
  /// This is a convenience API for embeddings (e.g. FastRender) that need to expose host functions
  /// (`setTimeout`, DOM bindings, etc.) to interpreted scripts.
  pub fn register_global_native_function(
    &mut self,
    name: &str,
    call: NativeCall,
    length: u32,
  ) -> Result<GcObject, VmError> {
    let call_id = self.vm.register_native_call(call)?;

    let mut scope = self.heap.scope();
    let func_name = scope.alloc_string(name)?;
    let func = scope.alloc_native_function(call_id, None, func_name, length)?;

    // Root the function object across allocations while defining it on the global object.
    scope.push_root(Value::Object(func))?;

    let key = PropertyKey::from_string(scope.alloc_string(name)?);
    scope.define_property(
      self.env.global_object(),
      key,
      global_var_desc(Value::Object(func)),
    )?;

    Ok(func)
  }

  /// Parse and execute a classic script (ECMAScript dialect, `SourceType::Script`).
  ///
  /// ## Host context
  ///
  /// This convenience wrapper passes a **dummy host context** (`()`) to native call/construct
  /// handlers.
  ///
  /// Embeddings that need native handlers to observe real host state should use
  /// [`JsRuntime::exec_script_with_host`] (explicit host; VM-owned microtask queue) or
  /// [`JsRuntime::exec_script_with_host_and_hooks`] (explicit host + custom hooks).
  pub fn exec_script(&mut self, source: &str) -> Result<Value, VmError> {
    let mut host = ();
    self.exec_script_with_host(&mut host, source)
  }

  /// Execute a pre-compiled classic script (HIR) produced by [`crate::CompiledScript`].
  ///
  /// This uses the same VM budget/interrupt model as [`JsRuntime::exec_script`].
  ///
  /// ## Host context
  ///
  /// This convenience wrapper passes a **dummy host context** (`()`) to native call/construct
  /// handlers.
  pub fn exec_compiled_script(
    &mut self,
    script: Arc<crate::CompiledScript>,
  ) -> Result<Value, VmError> {
    let mut host = ();
    self.exec_compiled_script_with_host(&mut host, script)
  }

  /// Execute a pre-compiled classic script (HIR) produced by [`crate::CompiledScript`], using an
  /// explicit embedder host context.
  pub fn exec_compiled_script_with_host(
    &mut self,
    host: &mut dyn VmHost,
    script: Arc<crate::CompiledScript>,
  ) -> Result<Value, VmError> {
    if script.requires_ast_fallback
      || (script.contains_top_level_await && script.top_level_await_requires_ast_fallback)
    {
      // Some script bodies are not yet supported by the compiled (HIR) executor.
      //
      // Async function bodies execute via the AST interpreter at call-time (see
      // `Vm::call_user_function`).
      //
      // Fall back to the AST interpreter path using the original `SourceText`. This ensures scripts
      // can still execute correctly without partially executing any HIR code (which could introduce
      // side effects before a retry).
      let source = script.source.clone();
      // Move the VM-owned microtask queue out so it can be passed as `hooks` while still holding
      // `&mut self`.
      let mut hooks = mem::take(self.vm.microtask_queue_mut());
      let result = self.exec_script_source_with_host_and_hooks(host, &mut hooks, source);
      // Drain any Promise jobs that were enqueued onto the VM-owned queue while it was moved out.
      struct DrainCtx<'a> {
        heap: &'a mut Heap,
      }
      impl VmJobContext for DrainCtx<'_> {
        fn call(
          &mut self,
          _hooks: &mut dyn VmHostHooks,
          _callee: Value,
          _this: Value,
          _args: &[Value],
        ) -> Result<Value, VmError> {
          Err(VmError::Unimplemented("DrainCtx::call"))
        }

        fn construct(
          &mut self,
          _hooks: &mut dyn VmHostHooks,
          _callee: Value,
          _args: &[Value],
          _new_target: Value,
        ) -> Result<Value, VmError> {
          Err(VmError::Unimplemented("DrainCtx::construct"))
        }

        fn add_root(&mut self, value: Value) -> Result<RootId, VmError> {
          self.heap.add_root(value)
        }

        fn remove_root(&mut self, id: RootId) {
          self.heap.remove_root(id);
        }
      }

      let mut ctx = DrainCtx { heap: &mut self.heap };
      let mut drain_err: Option<VmError> = None;
      while let Some((realm, job)) = self.vm.microtask_queue_mut().pop_front() {
        if let Err(err) = hooks.host_enqueue_promise_job_fallible(&mut ctx, job, realm) {
          drain_err = Some(err);
          break;
        }
      }
      if drain_err.is_some() {
        // Discard any remaining jobs in the temporary VM-owned queue so we don't leak persistent
        // roots when we restore/overwrite it below.
        self.vm.microtask_queue_mut().teardown(&mut ctx);
      }
      *self.vm.microtask_queue_mut() = hooks;

      if let Some(err) = drain_err {
        // Treat allocator OOM while draining as a hard stop: discard any queued jobs so persistent
        // roots are cleaned up.
        self.vm.teardown_microtasks(&mut self.heap);
        return Err(err);
      }

      if let Err(err) = &result {
        if is_hard_stop_error(err) {
          self.vm.teardown_microtasks(&mut self.heap);
        }
      }
      return result;
    }

    let source = script.source.clone();

    let (line, col) = source.line_col(0);
    let frame = StackFrame {
      function: None,
      source: source.name.clone(),
      line,
      col,
    };

    let script_id = self.vm.fresh_script_id()?;
    let exec_ctx = crate::ExecutionContext {
      realm: self.realm.id(),
      script_or_module: Some(ScriptOrModule::Script(script_id)),
    };
    let result: Result<Value, VmError> = (|| {
      let mut vm_ctx = self.vm.execution_context_guard(exec_ctx)?;
      let prev_state = vm_ctx.load_realm_state(&mut self.heap, exec_ctx.realm)?;

      // Script evaluation needs a host hook implementation for Promise jobs. `Vm` stores a default
      // microtask queue inside itself, but we need to hold `&mut Vm` and `&mut dyn VmHostHooks`
      // simultaneously. Temporarily move the queue out so it can be passed as `hooks`.
      let mut hooks = mem::take(vm_ctx.microtask_queue_mut());
      let result: Result<Value, VmError> = {
        let mut vm_hooks = vm_ctx.push_active_host_hooks_guard(&mut hooks);
        (|| {
          let mut vm_frame = vm_hooks.enter_frame(frame)?;

          // Charge at least one tick at script entry so even an empty script respects fuel/deadline /
          // interrupt budgets.
          vm_frame.tick()?;

          let mut scope = self.heap.scope();
          let res = crate::hir_exec::run_compiled_script(
            &mut *vm_frame,
            &mut scope,
            host,
            &mut hooks,
            &mut self.env,
            script,
          );

          match res {
            Err(err) if err.is_throw_completion() => Err(crate::vm::coerce_error_to_throw_with_stack(
              &*vm_frame,
              &mut scope,
              err,
            )),
            other => other,
          }
        })()
      };

      // As a safety net, drain any Promise jobs that were enqueued onto the VM-owned microtask queue
      // (for example by native handlers calling `vm.microtask_queue_mut()` while the queue was moved
      // out) into `hooks` before restoring it.
      struct DrainCtx<'a> {
        heap: &'a mut Heap,
      }
      impl VmJobContext for DrainCtx<'_> {
        fn call(
          &mut self,
          _hooks: &mut dyn VmHostHooks,
          _callee: Value,
          _this: Value,
          _args: &[Value],
        ) -> Result<Value, VmError> {
          Err(VmError::Unimplemented("DrainCtx::call"))
        }

        fn construct(
          &mut self,
          _hooks: &mut dyn VmHostHooks,
          _callee: Value,
          _args: &[Value],
          _new_target: Value,
        ) -> Result<Value, VmError> {
          Err(VmError::Unimplemented("DrainCtx::construct"))
        }

        fn add_root(&mut self, value: Value) -> Result<RootId, VmError> {
          self.heap.add_root(value)
        }

        fn remove_root(&mut self, id: RootId) {
          self.heap.remove_root(id);
        }
      }

      let mut ctx = DrainCtx { heap: &mut self.heap };
      let mut drain_err: Option<VmError> = None;
      while let Some((realm, job)) = vm_ctx.microtask_queue_mut().pop_front() {
        if let Err(err) = hooks.host_enqueue_promise_job_fallible(&mut ctx, job, realm) {
          drain_err = Some(err);
          break;
        }
      }
      if drain_err.is_some() {
        vm_ctx.microtask_queue_mut().teardown(&mut ctx);
      }
      // Restore the VM's microtask queue so the embedding can run a microtask checkpoint later.
      *vm_ctx.microtask_queue_mut() = hooks;

      let result = match drain_err {
        Some(err) => Err(err),
        None => result,
      };

      drop(vm_ctx);
      let restore_res = self.vm.restore_realm_state(&mut self.heap, prev_state);
      match (result, restore_res) {
        (Ok(v), Ok(())) => Ok(v),
        (Err(err), Ok(())) => Err(err),
        (Ok(_), Err(err)) => Err(err),
        (Err(err), Err(_)) => Err(err),
      }
    })();

    if let Err(err) = &result {
      if is_hard_stop_error(err) {
        self.vm.teardown_microtasks(&mut self.heap);
      }
    }
    result
  }

  /// Execute a pre-compiled classic script (HIR) produced by [`crate::CompiledScript`], using an
  /// explicit embedder host context and host hook implementation.
  ///
  /// This is analogous to [`JsRuntime::exec_script_source_with_host_and_hooks`], but runs the
  /// pre-lowered HIR instead of parsing source text at runtime.
  pub fn exec_compiled_script_with_hooks(
    &mut self,
    host: &mut dyn VmHost,
    hooks: &mut dyn VmHostHooks,
    script: Arc<crate::CompiledScript>,
  ) -> Result<Value, VmError> {
    if script.requires_ast_fallback {
      // See `exec_compiled_script_with_host`: some script bodies are not yet supported by the
      // compiled (HIR) executor (e.g. generator bodies, private names, unsupported top-level await
      // patterns).
      //
      // Note: scripts that merely *define* async functions can still execute via HIR; async function
      // bodies fall back to the AST interpreter at call-time (see `Vm::call_user_function`).
      let source = script.source.clone();
      return self.exec_script_source_with_host_and_hooks(host, hooks, source);
    }

    let source = script.source.clone();
    let (line, col) = source.line_col(0);
    let frame = StackFrame {
      function: None,
      source: source.name.clone(),
      line,
      col,
    };
    let script_id = self.vm.fresh_script_id()?;
    let exec_ctx = crate::ExecutionContext {
      realm: self.realm.id(),
      script_or_module: Some(ScriptOrModule::Script(script_id)),
    };
    let result: Result<Value, VmError> = (|| {
      let mut vm_ctx = self.vm.execution_context_guard(exec_ctx)?;
      let prev_state = vm_ctx.load_realm_state(&mut self.heap, exec_ctx.realm)?;
      let result: Result<Value, VmError> = {
        let mut vm_hooks = vm_ctx.push_active_host_hooks_guard(hooks);
        (|| {
          let mut vm_frame = vm_hooks.enter_frame(frame)?;

          // Charge at least one tick at script entry so even an empty script respects fuel/deadline /
          // interrupt budgets.
          vm_frame.tick()?;

          let mut scope = self.heap.scope();
          let res = crate::hir_exec::run_compiled_script(
            &mut *vm_frame,
            &mut scope,
            host,
            hooks,
            &mut self.env,
            script,
          );

          match res {
            Err(err) if err.is_throw_completion() => Err(crate::vm::coerce_error_to_throw_with_stack(
              &*vm_frame,
              &mut scope,
              err,
            )),
            other => other,
          }
        })()
      };
      drop(vm_ctx);
      let restore_res = self.vm.restore_realm_state(&mut self.heap, prev_state);
      match (result, restore_res) {
        (Ok(v), Ok(())) => Ok(v),
        (Err(err), Ok(())) => Err(err),
        (Ok(_), Err(err)) => Err(err),
        (Err(err), Err(_)) => Err(err),
      }
    })();

    if let Err(err) = &result {
      if is_hard_stop_error(err) {
        self.vm.teardown_microtasks(&mut self.heap);
      }
    }

    // As a safety net, drain any Promise jobs that were enqueued onto the VM-owned microtask queue
    // into the embedding's host hook implementation.
    struct DrainCtx<'a> {
      heap: &'a mut Heap,
    }
    impl VmJobContext for DrainCtx<'_> {
      fn call(
        &mut self,
        _host: &mut dyn VmHostHooks,
        _callee: Value,
        _this: Value,
        _args: &[Value],
      ) -> Result<Value, VmError> {
        Err(VmError::Unimplemented("DrainCtx::call"))
      }

      fn construct(
        &mut self,
        _host: &mut dyn VmHostHooks,
        _callee: Value,
        _args: &[Value],
        _new_target: Value,
      ) -> Result<Value, VmError> {
        Err(VmError::Unimplemented("DrainCtx::construct"))
      }

      fn add_root(&mut self, value: Value) -> Result<RootId, VmError> {
        self.heap.add_root(value)
      }

      fn remove_root(&mut self, id: RootId) {
        self.heap.remove_root(id);
      }
    }

    let mut ctx = DrainCtx { heap: &mut self.heap };
    let mut drain_err: Option<VmError> = None;
    while let Some((realm, job)) = self.vm.microtask_queue_mut().pop_front() {
      if let Err(err) = hooks.host_enqueue_promise_job_fallible(&mut ctx, job, realm) {
        drain_err = Some(err);
        break;
      }
    }
    if drain_err.is_some() {
      self.vm.microtask_queue_mut().teardown(&mut ctx);
    }
    if let Some(err) = drain_err {
      return Err(err);
    }

    // Ensure host-visible failures never leak uncaptured `VmError::Throw` completions. When
    // intrinsics are available, attach a best-effort stack trace so the embedder sees a proper
    // Error object and stack frames.
    match result {
      Err(err) if err.is_throw_completion() => Err(self.coerce_error_to_throw_with_stack(err)),
      other => other,
    }
  }

  /// Alias for [`JsRuntime::exec_compiled_script_with_hooks`], provided for API consistency with
  /// [`JsRuntime::exec_script_source_with_host_and_hooks`].
  pub fn exec_compiled_script_with_host_and_hooks(
    &mut self,
    host: &mut dyn VmHost,
    hooks: &mut dyn VmHostHooks,
    script: Arc<crate::CompiledScript>,
  ) -> Result<Value, VmError> {
    self.exec_compiled_script_with_hooks(host, hooks, script)
  }

  /// Parse and execute a classic script (ECMAScript dialect, `SourceType::Script`) using an explicit
  /// embedder host context and host hook implementation.
  ///
  /// This is the string-source convenience wrapper for
  /// [`JsRuntime::exec_script_source_with_host_and_hooks`].
  pub fn exec_script_with_host_and_hooks(
    &mut self,
    host: &mut dyn VmHost,
    hooks: &mut dyn VmHostHooks,
    source: &str,
  ) -> Result<Value, VmError> {
    let source = match SourceText::new_charged(&mut self.heap, "<inline>", source)
      .and_then(arc_try_new_vm)
    {
      Ok(source) => source,
      Err(err) => {
        if is_hard_stop_error(&err) {
          self.vm.teardown_microtasks(&mut self.heap);
        }
        return Err(err);
      }
    };
    self.exec_script_source_with_host_and_hooks(
      host,
      hooks,
      source,
    )
  }

  /// Parse and execute a classic script, using a custom host hook implementation.
  ///
  /// This is intended for embeddings that need Promise jobs enqueued by the script to be routed via
  /// `VmHostHooks::host_enqueue_promise_job` (for example, an HTML microtask queue) instead of the
  /// VM-owned microtask queue used by [`JsRuntime::exec_script`].
  ///
  /// ## Host context
  ///
  /// This hook-only API passes a **dummy host context** (`()`) to native call/construct handlers.
  /// It is intended for unit tests and lightweight embeddings.
  ///
  /// Embeddings that need native handlers to downcast and mutate real host state should use
  /// [`JsRuntime::exec_script_with_host_and_hooks`] /
  /// [`JsRuntime::exec_script_source_with_host_and_hooks`].
  pub fn exec_script_with_hooks(
    &mut self,
    hooks: &mut dyn VmHostHooks,
    source: &str,
  ) -> Result<Value, VmError> {
    let source = match SourceText::new_charged(&mut self.heap, "<inline>", source)
      .and_then(arc_try_new_vm)
    {
      Ok(source) => source,
      Err(err) => {
        if is_hard_stop_error(&err) {
          self.vm.teardown_microtasks(&mut self.heap);
        }
        return Err(err);
      }
    };
    self.exec_script_source_with_hooks(hooks, source)
  }

  /// Parse and execute a classic script (ECMAScript dialect, `SourceType::Script`).
  ///
  /// ## Host context
  ///
  /// This convenience wrapper passes a **dummy host context** (`()`) to native call/construct
  /// handlers.
  ///
  /// Embeddings that need native handlers to observe real host state should use
  /// [`JsRuntime::exec_script_source_with_host`] (explicit host; VM-owned microtask queue) or
  /// [`JsRuntime::exec_script_source_with_host_and_hooks`] (explicit host + custom hooks).
  pub fn exec_script_source(&mut self, source: Arc<SourceText>) -> Result<Value, VmError> {
    let mut host = ();
    self.exec_script_source_with_host(&mut host, source)
  }

  /// Parse and execute a classic script (ECMAScript dialect, `SourceType::Script`) with an explicit
  /// embedder host context.
  pub fn exec_script_with_host(
    &mut self,
    host: &mut dyn VmHost,
    source: &str,
  ) -> Result<Value, VmError> {
    let source = match SourceText::new_charged(&mut self.heap, "<inline>", source)
      .and_then(arc_try_new_vm)
    {
      Ok(source) => source,
      Err(err) => {
        if is_hard_stop_error(&err) {
          self.vm.teardown_microtasks(&mut self.heap);
        }
        return Err(err);
      }
    };
    self.exec_script_source_with_host(host, source)
  }

  fn parse_classic_script_source_for_exec(
    &mut self,
    source: &Arc<SourceText>,
  ) -> Result<Arc<Node<parse_js::ast::stx::TopLevel>>, VmError> {
    let opts = ParseOptions {
      dialect: Dialect::Ecma,
      source_type: SourceType::Script,
    };
    match self
      .vm
      .parse_top_level_with_budget(&source.text, opts)
      .and_then(arc_try_new_vm)
    {
      Ok(top) => Ok(top),
      Err(VmError::Syntax(script_diags)) => {
        // `parse-js` only enables `AwaitExpression` parsing at top-level in module mode. To support
        // classic-script top-level await, fall back to parsing using the module grammar.
        let opts = ParseOptions {
          dialect: Dialect::Ecma,
          source_type: SourceType::Module,
        };
        match self.vm.parse_top_level_with_budget(&source.text, opts) {
          Ok(top) => {
            let has_await = top.stx.body.iter().any(stmt_contains_await);
            let has_module_syntax = top.stx.body.iter().any(stmt_is_module_only);
            if has_await && !has_module_syntax {
              arc_try_new_vm(top)
            } else {
              Err(VmError::Syntax(script_diags))
            }
          }
          Err(err) if is_hard_stop_error(&err) => Err(err),
          Err(_) => Err(VmError::Syntax(script_diags)),
        }
      }
      Err(err) => Err(err),
    }
  }

  /// Parse and execute a classic script (ECMAScript dialect, `SourceType::Script`) with an explicit
  /// embedder host context.
  pub fn exec_script_source_with_host(
    &mut self,
    host: &mut dyn VmHost,
    source: Arc<SourceText>,
  ) -> Result<Value, VmError> {
    let top = match self.parse_classic_script_source_for_exec(&source) {
      Ok(top) => top,
      Err(err) => {
        if is_hard_stop_error(&err) {
          self.vm.teardown_microtasks(&mut self.heap);
        }
        return Err(err);
      }
    };

    let global_object = self.realm.global_object();
    self.env.set_source_info(source.clone(), 0, 0);

    let (line, col) = source.line_col(0);
    let frame = StackFrame {
      function: None,
      source: source.name.clone(),
      line,
      col,
    };

    let script_id = self.vm.fresh_script_id()?;
    let exec_ctx = crate::ExecutionContext {
      realm: self.realm.id(),
      script_or_module: Some(ScriptOrModule::Script(script_id)),
    };
    let result: Result<Value, VmError> = (|| {
      let mut vm_ctx = self.vm.execution_context_guard(exec_ctx)?;
      let prev_state = vm_ctx.load_realm_state(&mut self.heap, exec_ctx.realm)?;

      // Script evaluation needs a host hook implementation for Promise jobs. `Vm` stores a default
      // microtask queue inside itself, but we need to hold `&mut Vm` and `&mut dyn VmHostHooks`
      // simultaneously. Temporarily move the queue out so it can be passed as `hooks`.
      let mut hooks = mem::take(vm_ctx.microtask_queue_mut());
      let result: Result<Value, VmError> = {
        let mut vm_hooks = vm_ctx.push_active_host_hooks_guard(&mut hooks);
        (|| {
          let mut vm_frame = vm_hooks.enter_frame(frame)?;
          // Charge at least one tick at script entry so even an empty script respects fuel/deadline /
          // interrupt budgets.
          vm_frame.tick()?;

          let strict = detect_use_strict_directive(
            source.text.as_ref(),
            0,
            0,
            &top.stx.body,
            || vm_frame.tick(),
          )?;
          let has_await = top.stx.body.iter().any(stmt_contains_await);
          {
            let mut tick = || vm_frame.tick();
            crate::early_errors::validate_top_level(
              &top.stx.body,
              crate::early_errors::EarlyErrorOptions {
                strict,
                // `vm-js` supports async classic scripts when `await` appears anywhere in the
                // evaluated statement list (including inside class static blocks). This is
                // detected without descending into nested functions, so scripts that use `await`
                // as an identifier remain valid.
                allow_top_level_await: has_await,
                is_module: false,
                allow_super_call: false,
                allow_super_property: false,
              },
              Some(source.text.as_ref()),
              &mut tick,
            )?;
          }

          let mut scope = self.heap.scope();
          let res: Result<Value, VmError> = (|| {
            // In classic scripts, top-level `this` is the global object (even in strict mode).
            let global_this = Value::Object(global_object);
            if !has_await {
              let mut evaluator = Evaluator {
                vm: &mut *vm_frame,
                host,
                hooks: &mut hooks,
                env: &mut self.env,
                strict,
                this: global_this,
                new_target: Value::Undefined,
                home_object: None,
                class_constructor: None,
                derived_constructor: false,
                this_initialized: true,
                this_root_idx: None,
              };

              evaluator.instantiate_script(&mut scope, &top.stx.body)?;

              let completion = evaluator.eval_stmt_list(&mut scope, &top.stx.body)?;
              return match completion {
                Completion::Normal(v) => Ok(v.unwrap_or(Value::Undefined)),
                Completion::Throw(thrown) => Err(VmError::ThrowWithStack {
                  value: thrown.value,
                  stack: thrown.stack,
                }),
                Completion::Return(_) => Err(VmError::InvariantViolation(
                  "script evaluation produced Return completion (early errors should prevent this)",
                )),
                Completion::Break(..) => Err(VmError::InvariantViolation(
                  "script evaluation produced Break completion (early errors should prevent this)",
                )),
                Completion::Continue(..) => Err(VmError::InvariantViolation(
                  "script evaluation produced Continue completion (early errors should prevent this)",
                )),
              };
            }

          // Async classic script execution: evaluate the statement list using the async evaluator and
          // return a Promise representing completion.
          let cap = crate::promise_ops::new_promise_capability_with_host_and_hooks(
            &mut *vm_frame,
            &mut scope,
            host,
            &mut hooks,
          )?;
          let promise = cap.promise;

      // Use a distinct `RuntimeEnv` for async script evaluation. Async continuations tear down their
      // env roots on completion; classic scripts must not tear down the runtime's global env.
      let mut env =
        RuntimeEnv::new_with_lexical_env(scope.heap_mut(), global_object, self.env.lexical_env())?;
      env.set_source_info(source.clone(), 0, 0);

      // Capture the evaluator state after the async evaluation attempt.
      //
      // Some nested constructs can temporarily override runtime semantics (e.g. class definition
      // evaluation forces strict mode; class static blocks override `this` / `new.target`) and may
      // suspend. This state must be preserved in the async continuation so resumed execution uses
      // the correct semantics.
      let body_eval: Result<(AsyncEval<Completion>, bool, Value, Value, Value), VmError> = (|| {
        let mut evaluator = Evaluator {
          vm: &mut *vm_frame,
          host,
          hooks: &mut hooks,
          env: &mut env,
          strict,
          this: global_this,
          new_target: Value::Undefined,
          home_object: None,
          class_constructor: None,
          derived_constructor: false,
          this_initialized: true,
          this_root_idx: None,
        };

        evaluator.instantiate_script(&mut scope, &top.stx.body)?;
        let eval = async_eval_stmt_list(&mut evaluator, &mut scope, &top.stx.body)?;
        let home_object = evaluator
          .home_object
          .map(Value::Object)
          .unwrap_or(Value::Undefined);
        Ok((eval, evaluator.strict, evaluator.this, evaluator.new_target, home_object))
      })();

      match body_eval {
        Ok((
          AsyncEval::Complete(completion),
          _strict_at_suspend,
          _this_at_suspend,
          _new_target_at_suspend,
          _home_object_at_suspend,
        )) => {
          let promise_result = match completion {
            Completion::Normal(v) => {
              let v = v.unwrap_or(Value::Undefined);
              let mut call_scope = scope.reborrow();
              if let Err(err) = call_scope.push_roots(&[cap.resolve, v]) {
                env.teardown(call_scope.heap_mut());
                return Err(err);
              }
              let res = vm_frame.call_with_host_and_hooks(
                host,
                &mut call_scope,
                &mut hooks,
                cap.resolve,
                Value::Undefined,
                &[v],
              );
              env.teardown(call_scope.heap_mut());
              res.map(|_| promise)
            }
            Completion::Throw(thrown) => {
              let reason = thrown.value;
              let mut call_scope = scope.reborrow();
              if let Err(err) = call_scope.push_roots(&[cap.reject, reason]) {
                env.teardown(call_scope.heap_mut());
                return Err(err);
              }
              let res = vm_frame.call_with_host_and_hooks(
                host,
                &mut call_scope,
                &mut hooks,
                cap.reject,
                Value::Undefined,
                &[reason],
              );
              env.teardown(call_scope.heap_mut());
              res.map(|_| promise)
            }
            Completion::Return(_) => Err(VmError::InvariantViolation(
              "script evaluation produced Return completion (early errors should prevent this)",
            )),
            Completion::Break(..) => Err(VmError::InvariantViolation(
              "script evaluation produced Break completion (early errors should prevent this)",
            )),
            Completion::Continue(..) => Err(VmError::InvariantViolation(
              "script evaluation produced Continue completion (early errors should prevent this)",
            )),
          };
          promise_result
        }
        Ok((
          AsyncEval::Suspend(mut suspend),
          strict_at_suspend,
          this_at_suspend,
          new_target_at_suspend,
          home_object_at_suspend,
        )) => {
          if let Err(err) = async_frames_push(&mut suspend.frames, AsyncFrame::RootScriptBody) {
            env.teardown(scope.heap_mut());
            for mut frame in suspend.frames {
              async_teardown_frame(scope.heap_mut(), &mut frame);
            }
            return Err(err);
          }

          let AsyncSuspend { kind, await_value, frames } = suspend;

          // Root all GC-managed values while we create persistent roots and schedule the resumption.
          let mut root_scope = scope.reborrow();
          if let Err(err) = root_scope.push_roots(&[
            promise,
            cap.resolve,
            cap.reject,
            this_at_suspend,
            new_target_at_suspend,
            home_object_at_suspend,
            await_value,
          ]) {
            env.teardown(root_scope.heap_mut());
            for mut frame in frames {
              async_teardown_frame(root_scope.heap_mut(), &mut frame);
            }
            return Err(err);
          }

          let awaited_promise_res: Result<Value, VmError> = match kind {
            AsyncSuspendKind::Await => promise_resolve_for_await_with_host_and_hooks(
              &mut *vm_frame,
              &mut root_scope,
              host,
              &mut hooks,
              await_value,
            )
            .map_err(|err| coerce_error_to_throw_for_async(&mut *vm_frame, &mut root_scope, err)),
            AsyncSuspendKind::AwaitResolved => Ok(await_value),
            AsyncSuspendKind::Yield | AsyncSuspendKind::YieldIteratorResult => Err(VmError::InvariantViolation(
              "unexpected async generator yield suspension in async script evaluation",
            )),
          };

          let awaited_promise = match awaited_promise_res {
            Ok(p) => p,
            Err(VmError::Throw(reason) | VmError::ThrowWithStack { value: reason, .. }) => {
              let reason = match root_scope.push_root(reason) {
                Ok(v) => v,
                Err(err) => {
                  env.teardown(root_scope.heap_mut());
                  for mut frame in frames {
                    async_teardown_frame(root_scope.heap_mut(), &mut frame);
                  }
                  return Err(err);
                }
              };

              let reject_result = vm_frame.call_with_host_and_hooks(
                host,
                &mut root_scope,
                &mut hooks,
                cap.reject,
                Value::Undefined,
                &[reason],
              );

              env.teardown(root_scope.heap_mut());
              for mut frame in frames {
                async_teardown_frame(root_scope.heap_mut(), &mut frame);
              }
              return reject_result.map(|_| promise);
            }
            Err(err) => {
              env.teardown(root_scope.heap_mut());
              for mut frame in frames {
                async_teardown_frame(root_scope.heap_mut(), &mut frame);
              }
              return Err(err);
            }
          };

          if let Err(err) = root_scope.push_root(awaited_promise) {
            env.teardown(root_scope.heap_mut());
            for mut frame in frames {
              async_teardown_frame(root_scope.heap_mut(), &mut frame);
            }
            return Err(err);
          }

          // Create persistent roots for the async continuation.
          //
          // Async classic scripts normally have no `[[HomeObject]]` context, but nested constructs
          // (e.g. class static blocks) can temporarily override it and may suspend. Preserve it so
          // `super` property references resume correctly across `await`.
          let values = [
            this_at_suspend,
            new_target_at_suspend,
            home_object_at_suspend,
            promise,
            cap.resolve,
            cap.reject,
            awaited_promise,
          ];
          let mut roots: Vec<RootId> = Vec::new();
          if let Err(_) = roots.try_reserve_exact(values.len()) {
            env.teardown(root_scope.heap_mut());
            for mut frame in frames {
              async_teardown_frame(root_scope.heap_mut(), &mut frame);
            }
            return Err(VmError::OutOfMemory);
          }
          for &value in &values {
            match root_scope.heap_mut().add_root(value) {
              Ok(id) => roots.push(id),
              Err(e) => {
                for id in roots.drain(..) {
                  root_scope.heap_mut().remove_root(id);
                }
                env.teardown(root_scope.heap_mut());
                for mut frame in frames {
                  async_teardown_frame(root_scope.heap_mut(), &mut frame);
                }
                return Err(e);
              }
            }
          }

          let this_root = roots[0];
          let new_target_root = roots[1];
          let home_object_root = roots[2];
          let promise_root = roots[3];
          let resolve_root = roots[4];
          let reject_root = roots[5];
          let awaited_root = roots[6];

          // Reserve continuation capacity before moving `frames` into `cont` so insertion cannot fail
          // and leak any rooted async frames.
          if let Err(err) = vm_frame.reserve_async_continuations(1) {
            for id in roots.drain(..) {
              root_scope.heap_mut().remove_root(id);
            }
            env.teardown(root_scope.heap_mut());
            for mut frame in frames {
              async_teardown_frame(root_scope.heap_mut(), &mut frame);
            }
            return Err(err);
          }

          // `parse-js` AST nodes can be significantly larger than the original source. Charge a
          // conservative estimate so async classic scripts can't bypass heap limits by suspending
          // with an untracked retained AST.
          let script_ast_bytes = source.text.len().saturating_mul(4);
          let script_ast_memory = match root_scope.heap_mut().charge_external(script_ast_bytes) {
            Ok(token) => Some(token),
            Err(err) => {
              for id in roots.drain(..) {
                root_scope.heap_mut().remove_root(id);
              }
              env.teardown(root_scope.heap_mut());
              for mut frame in frames {
                async_teardown_frame(root_scope.heap_mut(), &mut frame);
              }
              return Err(err);
            }
          };

          let cont = AsyncContinuation {
            env: env.clone(),
            strict: strict_at_suspend,
            exec_ctx: Some(exec_ctx),
            script_ast: Some(top.clone()),
            script_ast_memory,
            this_root,
            new_target_root,
            home_object_root,
            promise_root,
            resolve_root,
            reject_root,
            awaited_promise_root: Some(awaited_root),
            frames,
          };
          let id = vm_frame.insert_async_continuation_reserved(VmAsyncContinuation::Ast(cont));

          let schedule_res = (|| -> Result<(), VmError> {
            let call_id = vm_frame.async_resume_call_id()?;
            let intr = vm_frame
              .intrinsics()
              .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;
            let job_realm = vm_frame.current_realm();

            let name = root_scope.alloc_string("")?;
            let slots_fulfill = [Value::Number(id as f64), Value::Bool(false)];
            let on_fulfilled = root_scope.alloc_native_function_with_slots(
              call_id,
              None,
              name,
              1,
              &slots_fulfill,
            )?;
            root_scope.push_root(Value::Object(on_fulfilled))?;

            let name = root_scope.alloc_string("")?;
            let slots_reject = [Value::Number(id as f64), Value::Bool(true)];
            let on_rejected =
              root_scope.alloc_native_function_with_slots(call_id, None, name, 1, &slots_reject)?;
            root_scope.push_root(Value::Object(on_rejected))?;

            for cb in [on_fulfilled, on_rejected] {
              root_scope
                .heap_mut()
                .object_set_prototype(cb, Some(intr.function_prototype()))?;
              root_scope
                .heap_mut()
                .set_function_realm(cb, global_object)?;
              if let Some(realm) = job_realm {
                root_scope.heap_mut().set_function_job_realm(cb, realm)?;
              }
            }

            crate::promise_ops::perform_promise_then_no_capability_with_host_and_hooks(
              &mut *vm_frame,
              &mut root_scope,
              host,
              &mut hooks,
              awaited_promise,
              Value::Object(on_fulfilled),
              Value::Object(on_rejected),
            )?;
            Ok(())
          })();

          if let Err(err) = schedule_res {
            // Best-effort cleanup: take the continuation back out and tear down its persistent roots
            // (including any roots held by async frames).
            if let Some(cont) = vm_frame.take_async_continuation(id) {
              match cont {
                VmAsyncContinuation::Ast(cont) => async_teardown_continuation(&mut root_scope, cont),
                VmAsyncContinuation::Hir(cont) => {
                  crate::hir_exec::hir_async_teardown_continuation(&mut root_scope, cont)
                }
              }
            }
            return Err(err);
          }

          Ok(promise)
        }
        Err(err) => {
          env.teardown(scope.heap_mut());
          Err(err)
        }
      }
      })();

      match res {
        Err(err) if err.is_throw_completion() => Err(crate::vm::coerce_error_to_throw_with_stack(
          &*vm_frame,
          &mut scope,
          err,
        )),
        other => other,
      }
    })()
    };

      // As a safety net, drain any Promise jobs that were enqueued onto the VM-owned microtask queue
      // (for example by native handlers calling `vm.microtask_queue_mut()` while the queue was moved
      // out) into `hooks` before restoring it.
      struct DrainCtx<'a> {
        heap: &'a mut Heap,
      }
      impl VmJobContext for DrainCtx<'_> {
        fn call(
          &mut self,
          _hooks: &mut dyn VmHostHooks,
          _callee: Value,
          _this: Value,
          _args: &[Value],
        ) -> Result<Value, VmError> {
          Err(VmError::Unimplemented("DrainCtx::call"))
        }

        fn construct(
          &mut self,
          _hooks: &mut dyn VmHostHooks,
          _callee: Value,
          _args: &[Value],
          _new_target: Value,
        ) -> Result<Value, VmError> {
          Err(VmError::Unimplemented("DrainCtx::construct"))
        }

        fn add_root(&mut self, value: Value) -> Result<RootId, VmError> {
          self.heap.add_root(value)
        }

        fn remove_root(&mut self, id: RootId) {
          self.heap.remove_root(id);
        }
      }

      let mut ctx = DrainCtx { heap: &mut self.heap };
      let mut drain_err: Option<VmError> = None;
      while let Some((realm, job)) = vm_ctx.microtask_queue_mut().pop_front() {
        if let Err(err) = hooks.host_enqueue_promise_job_fallible(&mut ctx, job, realm) {
          drain_err = Some(err);
          break;
        }
      }
      if drain_err.is_some() {
        vm_ctx.microtask_queue_mut().teardown(&mut ctx);
      }
      // Restore the VM's microtask queue so the embedding can run a microtask checkpoint later.
      *vm_ctx.microtask_queue_mut() = hooks;

      let result = match drain_err {
        Some(err) => Err(err),
        None => result,
      };

      drop(vm_ctx);
      let restore_res = self.vm.restore_realm_state(&mut self.heap, prev_state);
      match (result, restore_res) {
        (Ok(v), Ok(())) => Ok(v),
        (Err(err), Ok(())) => Err(err),
        (Ok(_), Err(err)) => Err(err),
        (Err(err), Err(_)) => Err(err),
      }
    })();

    if let Err(err) = &result {
      if is_hard_stop_error(err) {
        self.vm.teardown_microtasks(&mut self.heap);
      }
    }
    result
  }

  /// Parse and execute a classic script (ECMAScript dialect, `SourceType::Script`) using an explicit
  /// embedder host context and host hook implementation.
  pub fn exec_script_source_with_host_and_hooks(
    &mut self,
    host: &mut dyn VmHost,
    hooks: &mut dyn VmHostHooks,
    source: Arc<SourceText>,
  ) -> Result<Value, VmError> {
    let top = match self.parse_classic_script_source_for_exec(&source) {
      Ok(top) => top,
      Err(err) => {
        if is_hard_stop_error(&err) {
          self.vm.teardown_microtasks(&mut self.heap);
        }
        return Err(err);
      }
    };

    let global_object = self.realm.global_object();
    self.env.set_source_info(source.clone(), 0, 0);

    let (line, col) = source.line_col(0);
    let frame = StackFrame {
      function: None,
      source: source.name.clone(),
      line,
      col,
    };

    let script_id = self.vm.fresh_script_id()?;
    let exec_ctx = crate::ExecutionContext {
      realm: self.realm.id(),
      script_or_module: Some(ScriptOrModule::Script(script_id)),
    };
    let result: Result<Value, VmError> = (|| {
      let mut vm_ctx = self.vm.execution_context_guard(exec_ctx)?;
      let prev_state = vm_ctx.load_realm_state(&mut self.heap, exec_ctx.realm)?;
      let result = {
        let mut vm_hooks = vm_ctx.push_active_host_hooks_guard(hooks);
        (|| {
          let mut vm_frame = vm_hooks.enter_frame(frame)?;

        // Charge at least one tick at script entry so even an empty script respects fuel/deadline /
        // interrupt budgets.
        vm_frame.tick()?;

      let strict = detect_use_strict_directive(source.text.as_ref(), 0, 0, &top.stx.body, || vm_frame.tick())?;
      let has_await = top.stx.body.iter().any(stmt_contains_await);
      {
        let mut tick = || vm_frame.tick();
        crate::early_errors::validate_top_level(
          &top.stx.body,
          crate::early_errors::EarlyErrorOptions {
            strict,
            allow_top_level_await: has_await,
            is_module: false,
            allow_super_call: false,
            allow_super_property: false,
          },
          Some(source.text.as_ref()),
          &mut tick,
        )?;
      }

      let mut scope = self.heap.scope();
      let res: Result<Value, VmError> = (|| {
      // In classic scripts, top-level `this` is the global object (even in strict mode).
      let global_this = Value::Object(global_object);

      if !has_await {
        let mut evaluator = Evaluator {
          vm: &mut *vm_frame,
          host,
          hooks,
          env: &mut self.env,
          strict,
          this: global_this,
          new_target: Value::Undefined,
          home_object: None,
          class_constructor: None,
          derived_constructor: false,
          this_initialized: true,
          this_root_idx: None,
        };

        evaluator.instantiate_script(&mut scope, &top.stx.body)?;

        let completion = evaluator.eval_stmt_list(&mut scope, &top.stx.body)?;
        return match completion {
          Completion::Normal(v) => Ok(v.unwrap_or(Value::Undefined)),
          Completion::Throw(thrown) => Err(VmError::ThrowWithStack {
            value: thrown.value,
            stack: thrown.stack,
          }),
          Completion::Return(_) => Err(VmError::InvariantViolation(
            "script evaluation produced Return completion (early errors should prevent this)",
          )),
          Completion::Break(..) => Err(VmError::InvariantViolation(
            "script evaluation produced Break completion (early errors should prevent this)",
          )),
          Completion::Continue(..) => Err(VmError::InvariantViolation(
            "script evaluation produced Continue completion (early errors should prevent this)",
          )),
        };
      }

      // Async classic script execution: evaluate the statement list using the async evaluator and
      // return a Promise representing completion.
      let cap = crate::promise_ops::new_promise_capability_with_host_and_hooks(
        &mut *vm_frame,
        &mut scope,
        host,
        hooks,
      )?;
      let promise = cap.promise;

      // Use a distinct `RuntimeEnv` for async script evaluation. Async continuations tear down their
      // env roots on completion; classic scripts must not tear down the runtime's global env.
      let mut env =
        RuntimeEnv::new_with_lexical_env(scope.heap_mut(), global_object, self.env.lexical_env())?;
      env.set_source_info(source.clone(), 0, 0);

      // Capture the evaluator state after the async evaluation attempt.
      //
      // Some nested constructs can temporarily override runtime semantics (e.g. class definition
      // evaluation forces strict mode; class static blocks override `this` / `new.target`) and may
      // suspend. This state must be preserved in the async continuation so resumed execution uses
      // the correct semantics.
      let body_eval: Result<(AsyncEval<Completion>, bool, Value, Value, Value), VmError> = (|| {
        let mut evaluator = Evaluator {
          vm: &mut *vm_frame,
          host,
          hooks,
          env: &mut env,
          strict,
          this: global_this,
          new_target: Value::Undefined,
          home_object: None,
          class_constructor: None,
          derived_constructor: false,
          this_initialized: true,
          this_root_idx: None,
        };

        evaluator.instantiate_script(&mut scope, &top.stx.body)?;
        let eval = async_eval_stmt_list(&mut evaluator, &mut scope, &top.stx.body)?;
        let home_object = evaluator
          .home_object
          .map(Value::Object)
          .unwrap_or(Value::Undefined);
        Ok((eval, evaluator.strict, evaluator.this, evaluator.new_target, home_object))
      })();

      match body_eval {
        Ok((
          AsyncEval::Complete(completion),
          _strict_at_suspend,
          _this_at_suspend,
          _new_target_at_suspend,
          _home_object_at_suspend,
        )) => {
          let promise_result = match completion {
            Completion::Normal(v) => {
              let v = v.unwrap_or(Value::Undefined);
              let mut call_scope = scope.reborrow();
              if let Err(err) = call_scope.push_roots(&[cap.resolve, v]) {
                env.teardown(call_scope.heap_mut());
                return Err(err);
              }
              let res = vm_frame.call_with_host_and_hooks(
                host,
                &mut call_scope,
                hooks,
                cap.resolve,
                Value::Undefined,
                &[v],
              );
              env.teardown(call_scope.heap_mut());
              res.map(|_| promise)
            }
            Completion::Throw(thrown) => {
              let reason = thrown.value;
              let mut call_scope = scope.reborrow();
              if let Err(err) = call_scope.push_roots(&[cap.reject, reason]) {
                env.teardown(call_scope.heap_mut());
                return Err(err);
              }
              let res = vm_frame.call_with_host_and_hooks(
                host,
                &mut call_scope,
                hooks,
                cap.reject,
                Value::Undefined,
                &[reason],
              );
              env.teardown(call_scope.heap_mut());
              res.map(|_| promise)
            }
            Completion::Return(_) => Err(VmError::InvariantViolation(
              "script evaluation produced Return completion (early errors should prevent this)",
            )),
            Completion::Break(..) => Err(VmError::InvariantViolation(
              "script evaluation produced Break completion (early errors should prevent this)",
            )),
            Completion::Continue(..) => Err(VmError::InvariantViolation(
              "script evaluation produced Continue completion (early errors should prevent this)",
            )),
          };
          promise_result
        }
        Ok((
          AsyncEval::Suspend(mut suspend),
          strict_at_suspend,
          this_at_suspend,
          new_target_at_suspend,
          home_object_at_suspend,
        )) => {
          if let Err(err) = async_frames_push(&mut suspend.frames, AsyncFrame::RootScriptBody) {
            env.teardown(scope.heap_mut());
            for mut frame in suspend.frames {
              async_teardown_frame(scope.heap_mut(), &mut frame);
            }
            return Err(err);
          }

          let AsyncSuspend { kind, await_value, frames } = suspend;

          // Root all GC-managed values while we create persistent roots and schedule the resumption.
          let mut root_scope = scope.reborrow();
          if let Err(err) = root_scope.push_roots(&[
            promise,
            cap.resolve,
            cap.reject,
            this_at_suspend,
            new_target_at_suspend,
            home_object_at_suspend,
            await_value,
          ]) {
            env.teardown(root_scope.heap_mut());
            for mut frame in frames {
              async_teardown_frame(root_scope.heap_mut(), &mut frame);
            }
            return Err(err);
          }

          let awaited_promise_res: Result<Value, VmError> = match kind {
            AsyncSuspendKind::Await => promise_resolve_for_await_with_host_and_hooks(
              &mut *vm_frame,
              &mut root_scope,
              host,
              hooks,
              await_value,
            )
            .map_err(|err| coerce_error_to_throw_for_async(&mut *vm_frame, &mut root_scope, err)),
            AsyncSuspendKind::AwaitResolved => Ok(await_value),
            AsyncSuspendKind::Yield | AsyncSuspendKind::YieldIteratorResult => Err(VmError::InvariantViolation(
              "unexpected async generator yield suspension in async script evaluation",
            )),
          };

          let awaited_promise = match awaited_promise_res {
            Ok(p) => p,
            Err(VmError::Throw(reason) | VmError::ThrowWithStack { value: reason, .. }) => {
              let reason = match root_scope.push_root(reason) {
                Ok(v) => v,
                Err(err) => {
                  env.teardown(root_scope.heap_mut());
                  for mut frame in frames {
                    async_teardown_frame(root_scope.heap_mut(), &mut frame);
                  }
                  return Err(err);
                }
              };

              let reject_result = vm_frame.call_with_host_and_hooks(
                host,
                &mut root_scope,
                hooks,
                cap.reject,
                Value::Undefined,
                &[reason],
              );

              env.teardown(root_scope.heap_mut());
              for mut frame in frames {
                async_teardown_frame(root_scope.heap_mut(), &mut frame);
              }
              return reject_result.map(|_| promise);
            }
            Err(err) => {
              env.teardown(root_scope.heap_mut());
              for mut frame in frames {
                async_teardown_frame(root_scope.heap_mut(), &mut frame);
              }
              return Err(err);
            }
          };

          if let Err(err) = root_scope.push_root(awaited_promise) {
            env.teardown(root_scope.heap_mut());
            for mut frame in frames {
              async_teardown_frame(root_scope.heap_mut(), &mut frame);
            }
            return Err(err);
          }

          // Create persistent roots for the async continuation.
          //
          // Async classic scripts normally have no `[[HomeObject]]` context, but nested constructs
          // (e.g. class static blocks) can temporarily override it and may suspend.
          let values = [
            this_at_suspend,
            new_target_at_suspend,
            home_object_at_suspend,
            promise,
            cap.resolve,
            cap.reject,
            awaited_promise,
          ];
          let mut roots: Vec<RootId> = Vec::new();
          if let Err(_) = roots.try_reserve_exact(values.len()) {
            env.teardown(root_scope.heap_mut());
            for mut frame in frames {
              async_teardown_frame(root_scope.heap_mut(), &mut frame);
            }
            return Err(VmError::OutOfMemory);
          }
          for &value in &values {
            match root_scope.heap_mut().add_root(value) {
              Ok(id) => roots.push(id),
              Err(e) => {
                for id in roots.drain(..) {
                  root_scope.heap_mut().remove_root(id);
                }
                env.teardown(root_scope.heap_mut());
                for mut frame in frames {
                  async_teardown_frame(root_scope.heap_mut(), &mut frame);
                }
                return Err(e);
              }
            }
          }

          let this_root = roots[0];
          let new_target_root = roots[1];
          let home_object_root = roots[2];
          let promise_root = roots[3];
          let resolve_root = roots[4];
          let reject_root = roots[5];
          let awaited_root = roots[6];

          // Reserve continuation capacity before moving `frames` into `cont` so insertion cannot fail
          // and leak any rooted async frames.
          if let Err(err) = vm_frame.reserve_async_continuations(1) {
            for id in roots.drain(..) {
              root_scope.heap_mut().remove_root(id);
            }
            env.teardown(root_scope.heap_mut());
            for mut frame in frames {
              async_teardown_frame(root_scope.heap_mut(), &mut frame);
            }
            return Err(err);
          }

          // `parse-js` AST nodes can be significantly larger than the original source. Charge a
          // conservative estimate so async classic scripts can't bypass heap limits by suspending
          // with an untracked retained AST.
          let script_ast_bytes = source.text.len().saturating_mul(4);
          let script_ast_memory = match root_scope.heap_mut().charge_external(script_ast_bytes) {
            Ok(token) => Some(token),
            Err(err) => {
              for id in roots.drain(..) {
                root_scope.heap_mut().remove_root(id);
              }
              env.teardown(root_scope.heap_mut());
              for mut frame in frames {
                async_teardown_frame(root_scope.heap_mut(), &mut frame);
              }
              return Err(err);
            }
          };

          let cont = AsyncContinuation {
            env: env.clone(),
            strict: strict_at_suspend,
            exec_ctx: Some(exec_ctx),
            script_ast: Some(top.clone()),
            script_ast_memory,
            this_root,
            new_target_root,
            home_object_root,
            promise_root,
            resolve_root,
            reject_root,
            awaited_promise_root: Some(awaited_root),
            frames,
          };
          let id = vm_frame.insert_async_continuation_reserved(VmAsyncContinuation::Ast(cont));

          let schedule_res = (|| -> Result<(), VmError> {
            let call_id = vm_frame.async_resume_call_id()?;
            let intr = vm_frame
              .intrinsics()
              .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;
            let job_realm = vm_frame.current_realm();

            let name = root_scope.alloc_string("")?;
            let slots_fulfill = [Value::Number(id as f64), Value::Bool(false)];
            let on_fulfilled = root_scope.alloc_native_function_with_slots(
              call_id,
              None,
              name,
              1,
              &slots_fulfill,
            )?;
            root_scope.push_root(Value::Object(on_fulfilled))?;

            let name = root_scope.alloc_string("")?;
            let slots_reject = [Value::Number(id as f64), Value::Bool(true)];
            let on_rejected =
              root_scope.alloc_native_function_with_slots(call_id, None, name, 1, &slots_reject)?;
            root_scope.push_root(Value::Object(on_rejected))?;

            for cb in [on_fulfilled, on_rejected] {
              root_scope
                .heap_mut()
                .object_set_prototype(cb, Some(intr.function_prototype()))?;
              root_scope
                .heap_mut()
                .set_function_realm(cb, global_object)?;
              if let Some(realm) = job_realm {
                root_scope.heap_mut().set_function_job_realm(cb, realm)?;
              }
            }

            crate::promise_ops::perform_promise_then_no_capability_with_host_and_hooks(
              &mut *vm_frame,
              &mut root_scope,
              host,
              hooks,
              awaited_promise,
              Value::Object(on_fulfilled),
              Value::Object(on_rejected),
            )?;
            Ok(())
          })();

          if let Err(err) = schedule_res {
            // Best-effort cleanup: take the continuation back out and tear down its persistent roots
            // (including any roots held by async frames).
            if let Some(cont) = vm_frame.take_async_continuation(id) {
              match cont {
                VmAsyncContinuation::Ast(cont) => async_teardown_continuation(&mut root_scope, cont),
                VmAsyncContinuation::Hir(cont) => {
                  crate::hir_exec::hir_async_teardown_continuation(&mut root_scope, cont)
                }
              }
            }
            return Err(err);
          }

          Ok(promise)
        }
        Err(err) => {
          env.teardown(scope.heap_mut());
          Err(err)
        }
      }
      })();

      match res {
        Err(err) if err.is_throw_completion() => Err(crate::vm::coerce_error_to_throw_with_stack(
          &*vm_frame,
          &mut scope,
          err,
        )),
        other => other,
      }
        })()
      };
      drop(vm_ctx);
      let restore_res = self.vm.restore_realm_state(&mut self.heap, prev_state);
      match (result, restore_res) {
        (Ok(v), Ok(())) => Ok(v),
        (Err(err), Ok(())) => Err(err),
        (Ok(_), Err(err)) => Err(err),
        (Err(err), Err(_)) => Err(err),
      }
    })();

    if let Err(err) = &result {
      if is_hard_stop_error(err) {
        self.vm.teardown_microtasks(&mut self.heap);
      }
    }

    // As a safety net, drain any Promise jobs that were enqueued onto the VM-owned microtask queue
    // into the embedding's host hook implementation.
    struct DrainCtx<'a> {
      heap: &'a mut Heap,
    }
    impl VmJobContext for DrainCtx<'_> {
      fn call(
        &mut self,
        _host: &mut dyn VmHostHooks,
        _callee: Value,
        _this: Value,
        _args: &[Value],
      ) -> Result<Value, VmError> {
        Err(VmError::Unimplemented("DrainCtx::call"))
      }

      fn construct(
        &mut self,
        _host: &mut dyn VmHostHooks,
        _callee: Value,
        _args: &[Value],
        _new_target: Value,
      ) -> Result<Value, VmError> {
        Err(VmError::Unimplemented("DrainCtx::construct"))
      }

      fn add_root(&mut self, value: Value) -> Result<RootId, VmError> {
        self.heap.add_root(value)
      }

      fn remove_root(&mut self, id: RootId) {
        self.heap.remove_root(id);
      }
    }

    let mut ctx = DrainCtx { heap: &mut self.heap };
    let mut drain_err: Option<VmError> = None;
    while let Some((realm, job)) = self.vm.microtask_queue_mut().pop_front() {
      if let Err(err) = hooks.host_enqueue_promise_job_fallible(&mut ctx, job, realm) {
        drain_err = Some(err);
        break;
      }
    }
    if drain_err.is_some() {
      self.vm.microtask_queue_mut().teardown(&mut ctx);
    }
    if let Some(err) = drain_err {
      return Err(err);
    }

    result
  }

  /// Parse and execute a classic script (ECMAScript dialect, `SourceType::Script`) using a custom
  /// host hook implementation.
  ///
  /// ## Host context
  ///
  /// This hook-only API passes a **dummy host context** (`()`) to native call/construct handlers.
  /// It is intended for unit tests and lightweight embeddings.
  ///
  /// Embeddings that need native handlers to downcast and mutate real host state should use
  /// [`JsRuntime::exec_script_source_with_host_and_hooks`].
  pub fn exec_script_source_with_hooks(
    &mut self,
    hooks: &mut dyn VmHostHooks,
    source: Arc<SourceText>,
  ) -> Result<Value, VmError> {
    let mut dummy_host = ();
    self.exec_script_source_with_host_and_hooks(&mut dummy_host, hooks, source)
  }

  /// Parse, load, link, and evaluate an ECMAScript module, returning its evaluation Promise.
  ///
  /// This is the module analogue of [`JsRuntime::exec_script_source_with_host_and_hooks`]. Unlike
  /// classic scripts, module evaluation is **always** Promise-returning (even when it contains no
  /// top-level `await`).
  ///
  /// ## Top-level await
  ///
  /// This API does **not** run Promise jobs. Embeddings must drive the microtask queue until the
  /// returned Promise settles (fulfilled or rejected).
  ///
  /// If an embedding cannot run microtasks (for example, aborting execution mid-task), it should
  /// call [`ModuleGraph::abort_tla_evaluation`] on this runtime's module graph to tear down any
  /// in-progress top-level-await continuations and avoid leaking persistent roots.
  pub fn exec_module_source_with_host_and_hooks(
    &mut self,
    host: &mut dyn VmHost,
    hooks: &mut dyn VmHostHooks,
    source: Arc<SourceText>,
  ) -> Result<Value, VmError> {
    let result: Result<Value, VmError> = (|| {
      // Parse as a Source Text Module Record using VM budget state.
      let record =
        SourceTextModuleRecord::parse_source_with_vm(&mut self.vm, &mut self.heap, source.clone())?;

      // Register the module under its source name/specifier so tests and embeddings can easily
      // associate `import` specifiers with graph modules.
      let module = self.modules.add_module_with_specifier(&source.name, record)?;

      // Start loading the static import graph.
      let mut scope = self.heap.scope();
      let load_promise = crate::load_requested_modules_with_host_and_hooks(
        &mut self.vm,
        &mut scope,
        &mut *self.modules,
        host,
        hooks,
        module,
        HostDefined::default(),
      )?;

      // Root the load promise while inspecting its state and attaching reactions: these operations
      // allocate and may trigger GC.
      scope.push_root(load_promise)?;

      let Value::Object(load_promise_obj) = load_promise else {
        return Err(VmError::InvariantViolation(
          "LoadRequestedModules did not return a Promise object",
        ));
      };
      if !scope.heap().is_promise_object(load_promise_obj) {
        return Err(VmError::InvariantViolation(
          "LoadRequestedModules did not return a Promise object",
        ));
      }

      // Fast path: if loading completed synchronously, evaluate the module immediately and return
      // the module evaluation promise.
      if scope.heap().promise_state(load_promise_obj)? == crate::PromiseState::Fulfilled {
        let promise = self.modules.evaluate_with_scope(
          &mut self.vm,
          &mut scope,
          self.realm.global_object(),
          self.realm.id(),
          module,
          host,
          hooks,
        )?;
        return Ok(promise);
      }

      // Loading did not complete synchronously. Create an embedder-visible Promise that will be
      // resolved (adopting) the module evaluation promise once loading completes.
      let cap = crate::promise_ops::new_promise_capability_with_host_and_hooks(
        &mut self.vm,
        &mut scope,
        host,
        hooks,
      )?;
      let result_promise = cap.promise;

      let attach_result = (|| -> Result<(), VmError> {
        let intr = self.vm.intrinsics().ok_or(VmError::Unimplemented(
          "module execution requires intrinsics (create a Realm first)",
        ))?;

        // Root all captured values while allocating callback functions and attaching Promise
        // reactions.
        let mut attach_scope = scope.reborrow();
        attach_scope.push_roots(&[load_promise, cap.resolve, cap.reject, result_promise])?;

        let on_fulfilled_call = self.vm.exec_module_load_on_fulfilled_call_id()?;
        let on_rejected_call = self.vm.exec_module_load_on_rejected_call_id()?;

        let on_fulfilled_name = attach_scope.alloc_string("execModuleOnLoaded")?;
        attach_scope.push_root(Value::String(on_fulfilled_name))?;
        let on_rejected_name = attach_scope.alloc_string("execModuleOnLoadRejected")?;
        attach_scope.push_root(Value::String(on_rejected_name))?;

        // Slots: [module_id, realm_id, global_object, resolve, reject]
        let slots = [
          Value::Number(module.to_raw() as f64),
          Value::Number(self.realm.id().to_raw() as f64),
          Value::Object(self.realm.global_object()),
          cap.resolve,
          cap.reject,
        ];

        let on_fulfilled = attach_scope.alloc_native_function_with_slots(
          on_fulfilled_call,
          None,
          on_fulfilled_name,
          1,
          &slots,
        )?;
        attach_scope
          .heap_mut()
          .object_set_prototype(on_fulfilled, Some(intr.function_prototype()))?;
        attach_scope
          .heap_mut()
          .set_function_realm(on_fulfilled, self.realm.global_object())?;
        attach_scope
          .heap_mut()
          .set_function_job_realm(on_fulfilled, self.realm.id())?;
        attach_scope.push_root(Value::Object(on_fulfilled))?;

        let on_rejected = attach_scope.alloc_native_function_with_slots(
          on_rejected_call,
          None,
          on_rejected_name,
          1,
          &slots,
        )?;
        attach_scope
          .heap_mut()
          .object_set_prototype(on_rejected, Some(intr.function_prototype()))?;
        attach_scope
          .heap_mut()
          .set_function_realm(on_rejected, self.realm.global_object())?;
        attach_scope
          .heap_mut()
          .set_function_job_realm(on_rejected, self.realm.id())?;
        attach_scope.push_root(Value::Object(on_rejected))?;

        crate::promise_ops::perform_promise_then_no_capability_with_host_and_hooks(
          &mut self.vm,
          &mut attach_scope,
          host,
          hooks,
          load_promise,
          Value::Object(on_fulfilled),
          Value::Object(on_rejected),
        )?;
        Ok(())
      })();

      if let Err(err) = attach_result {
        // Best-effort cleanup: reject the returned promise. If we cannot allocate, propagate the
        // error to the embedder.
        if let Some(reason) = err.thrown_value() {
          let _ = (|| -> Result<(), VmError> {
            let mut call_scope = scope.reborrow();
            call_scope.push_roots(&[cap.reject, reason])?;
            let _ = self.vm.call_with_host_and_hooks(
              host,
              &mut call_scope,
              hooks,
              cap.reject,
              Value::Undefined,
              &[reason],
            )?;
            Ok(())
          })();
        }
        return Err(err);
      }

      Ok(result_promise)
    })();

    if let Err(err) = &result {
      if is_hard_stop_error(err) {
        self.vm.teardown_microtasks(&mut self.heap);
      }
    }

    // As a safety net, drain any Promise jobs that were enqueued onto the VM-owned microtask queue
    // into the embedding's host hook implementation.
    struct DrainCtx<'a> {
      heap: &'a mut Heap,
    }
    impl VmJobContext for DrainCtx<'_> {
      fn call(
        &mut self,
        _host: &mut dyn VmHostHooks,
        _callee: Value,
        _this: Value,
        _args: &[Value],
      ) -> Result<Value, VmError> {
        Err(VmError::Unimplemented("DrainCtx::call"))
      }

      fn construct(
        &mut self,
        _host: &mut dyn VmHostHooks,
        _callee: Value,
        _args: &[Value],
        _new_target: Value,
      ) -> Result<Value, VmError> {
        Err(VmError::Unimplemented("DrainCtx::construct"))
      }

      fn add_root(&mut self, value: Value) -> Result<RootId, VmError> {
        self.heap.add_root(value)
      }

      fn remove_root(&mut self, id: RootId) {
        self.heap.remove_root(id);
      }
    }

    let mut ctx = DrainCtx { heap: &mut self.heap };
    let mut drain_err: Option<VmError> = None;
    while let Some((realm, job)) = self.vm.microtask_queue_mut().pop_front() {
      if let Err(err) = hooks.host_enqueue_promise_job_fallible(&mut ctx, job, realm) {
        drain_err = Some(err);
        break;
      }
    }
    if drain_err.is_some() {
      self.vm.microtask_queue_mut().teardown(&mut ctx);
    }
    if let Some(err) = drain_err {
      // Treat enqueue failures as a hard stop and tear down queued jobs/continuations so persistent
      // roots are cleaned up.
      self.vm.teardown_microtasks(&mut self.heap);
      return Err(err);
    }

    // Ensure host-visible failures never leak internal helper errors (TypeError, NotCallable, etc.)
    // when intrinsics are available.
    match result {
      Err(err) if err.is_throw_completion() => Err(self.coerce_error_to_throw_with_stack(err)),
      other => other,
    }
  }

  /// Convenience wrapper around [`JsRuntime::exec_module_source_with_host_and_hooks`] for string
  /// module sources.
  pub fn exec_module_with_host_and_hooks(
    &mut self,
    host: &mut dyn VmHost,
    hooks: &mut dyn VmHostHooks,
    name: &str,
    source: &str,
  ) -> Result<Value, VmError> {
    // `Arc::new` aborts the process on allocator OOM; allocate the `Arc<SourceText>` fallibly so
    // hostile module sources can surface `VmError::OutOfMemory` instead of crashing.
    let source = match SourceText::new_charged(&mut self.heap, name, source).and_then(arc_try_new_vm) {
      Ok(source) => source,
      Err(err) => {
        if is_hard_stop_error(&err) {
          self.vm.teardown_microtasks(&mut self.heap);
        }
        return Err(err);
      }
    };
    self.exec_module_source_with_host_and_hooks(host, hooks, source)
  }

  /// Hook-only variant of [`JsRuntime::exec_module_with_host_and_hooks`].
  ///
  /// This passes a dummy host context (`()`) to native call/construct handlers.
  pub fn exec_module_with_hooks(
    &mut self,
    hooks: &mut dyn VmHostHooks,
    name: &str,
    source: &str,
  ) -> Result<Value, VmError> {
    let mut dummy_host = ();
    self.exec_module_with_host_and_hooks(&mut dummy_host, hooks, name, source)
  }

  /// Parse and execute an ECMAScript module (string source), using the VM-owned microtask queue.
  ///
  /// This passes a dummy host context (`()`) to native call/construct handlers.
  pub fn exec_module(&mut self, name: &str, source: &str) -> Result<Value, VmError> {
    let mut host = ();
    self.exec_module_with_host(&mut host, name, source)
  }

  /// Parse and execute an ECMAScript module (string source), using an explicit host context and the
  /// VM-owned microtask queue.
  pub fn exec_module_with_host(
    &mut self,
    host: &mut dyn VmHost,
    name: &str,
    source: &str,
  ) -> Result<Value, VmError> {
    // `Arc::new` aborts the process on allocator OOM; allocate the `Arc<SourceText>` fallibly so
    // hostile module sources can surface `VmError::OutOfMemory` instead of crashing.
    let source = match SourceText::new_charged(&mut self.heap, name, source).and_then(arc_try_new_vm) {
      Ok(source) => source,
      Err(err) => {
        if is_hard_stop_error(&err) {
          self.vm.teardown_microtasks(&mut self.heap);
        }
        return Err(err);
      }
    };
    self.exec_module_source_with_host(host, source)
  }

  /// Execute an ECMAScript module using a pre-constructed [`SourceText`], passing a dummy host
  /// context (`()`).
  pub fn exec_module_source(&mut self, source: Arc<SourceText>) -> Result<Value, VmError> {
    let mut host = ();
    self.exec_module_source_with_host(&mut host, source)
  }

  /// Execute an ECMAScript module using a pre-constructed [`SourceText`], using an explicit host
  /// context and the VM-owned microtask queue.
  pub fn exec_module_source_with_host(
    &mut self,
    host: &mut dyn VmHost,
    source: Arc<SourceText>,
  ) -> Result<Value, VmError> {
    // Move the VM-owned microtask queue out so we can borrow both `&mut Vm` and `&mut dyn VmHostHooks`
    // simultaneously.
    let mut hooks = mem::take(self.vm.microtask_queue_mut());
    let result = self.exec_module_source_with_host_and_hooks(host, &mut hooks, source);

    // Drain any Promise jobs that were enqueued onto the VM-owned queue while it was moved out.
    struct DrainCtx<'a> {
      heap: &'a mut Heap,
    }
    impl VmJobContext for DrainCtx<'_> {
      fn call(
        &mut self,
        _host: &mut dyn VmHostHooks,
        _callee: Value,
        _this: Value,
        _args: &[Value],
      ) -> Result<Value, VmError> {
        Err(VmError::Unimplemented("DrainCtx::call"))
      }

      fn construct(
        &mut self,
        _host: &mut dyn VmHostHooks,
        _callee: Value,
        _args: &[Value],
        _new_target: Value,
      ) -> Result<Value, VmError> {
        Err(VmError::Unimplemented("DrainCtx::construct"))
      }

      fn add_root(&mut self, value: Value) -> Result<RootId, VmError> {
        self.heap.add_root(value)
      }

      fn remove_root(&mut self, id: RootId) {
        self.heap.remove_root(id);
      }
    }

    let mut ctx = DrainCtx { heap: &mut self.heap };
    let mut drain_err: Option<VmError> = None;
    while let Some((realm, job)) = self.vm.microtask_queue_mut().pop_front() {
      if let Err(err) = hooks.host_enqueue_promise_job_fallible(&mut ctx, job, realm) {
        drain_err = Some(err);
        break;
      }
    }
    if drain_err.is_some() {
      self.vm.microtask_queue_mut().teardown(&mut ctx);
    }
    *self.vm.microtask_queue_mut() = hooks;
    let result = match drain_err {
      Some(err) => Err(err),
      None => result,
    };

    if let Err(err) = &result {
      if is_hard_stop_error(err) {
        self.vm.teardown_microtasks(&mut self.heap);
      }
    }
    result
  }

  /// Hook-only variant of [`JsRuntime::exec_module_source_with_host_and_hooks`].
  pub fn exec_module_source_with_hooks(
    &mut self,
    hooks: &mut dyn VmHostHooks,
    source: Arc<SourceText>,
  ) -> Result<Value, VmError> {
    let mut dummy_host = ();
    self.exec_module_source_with_host_and_hooks(&mut dummy_host, hooks, source)
  }
}

struct ExecModuleLoadSlots {
  module: ModuleId,
  realm_id: RealmId,
  global_object: GcObject,
  resolve: Value,
  reject: Value,
}

fn exec_module_load_slots(scope: &Scope<'_>, callee: GcObject) -> Result<ExecModuleLoadSlots, VmError> {
  let slots = scope.heap().get_function_native_slots(callee)?;
  let module_raw = match slots.get(0).copied().unwrap_or(Value::Undefined) {
    Value::Number(n) if n.is_finite() && n >= 0.0 && n <= u64::MAX as f64 => n as u64,
    _ => return Err(VmError::InvariantViolation("execModule callback missing module id slot")),
  };
  let realm_raw = match slots.get(1).copied().unwrap_or(Value::Undefined) {
    Value::Number(n) if n.is_finite() && n >= 0.0 && n <= u64::MAX as f64 => n as u64,
    _ => return Err(VmError::InvariantViolation("execModule callback missing realm id slot")),
  };
  let global_object = match slots.get(2).copied().unwrap_or(Value::Undefined) {
    Value::Object(obj) => obj,
    _ => {
      return Err(VmError::InvariantViolation(
        "execModule callback missing global object slot",
      ))
    }
  };
  let resolve = slots.get(3).copied().unwrap_or(Value::Undefined);
  let reject = slots.get(4).copied().unwrap_or(Value::Undefined);

  Ok(ExecModuleLoadSlots {
    module: ModuleId::from_raw(module_raw),
    realm_id: RealmId::from_raw(realm_raw),
    global_object,
    resolve,
    reject,
  })
}

/// Promise reaction callback used by [`JsRuntime::exec_module_source_with_host_and_hooks`].
pub(crate) fn exec_module_load_on_fulfilled(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  callee: GcObject,
  _this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  let slots = exec_module_load_slots(scope, callee)?;
  let Some(modules_ptr) = vm.module_graph_ptr() else {
    return Err(VmError::InvariantViolation(
      "execModule callback requires an attached module graph",
    ));
  };
  // Safety: `Vm::module_graph_ptr` is only set by embeddings that ensure the graph outlives the VM.
  let modules = unsafe { &mut *modules_ptr };

  let promise = match modules.evaluate_with_scope(
    vm,
    scope,
    slots.global_object,
    slots.realm_id,
    slots.module,
    host,
    hooks,
  ) {
    Ok(promise) => promise,
    Err(err) => {
      if let Some(reason) = err.thrown_value() {
        let mut call_scope = scope.reborrow();
        call_scope.push_roots(&[slots.reject, reason])?;
        let _ = vm.call_with_host_and_hooks(
          host,
          &mut call_scope,
          hooks,
          slots.reject,
          Value::Undefined,
          &[reason],
        )?;
        return Ok(Value::Undefined);
      }
      return Err(err);
    }
  };

  let mut call_scope = scope.reborrow();
  call_scope.push_roots(&[slots.resolve, promise])?;
  let _ = vm.call_with_host_and_hooks(
    host,
    &mut call_scope,
    hooks,
    slots.resolve,
    Value::Undefined,
    &[promise],
  )?;
  Ok(Value::Undefined)
}

/// Promise reaction callback used by [`JsRuntime::exec_module_source_with_host_and_hooks`].
pub(crate) fn exec_module_load_on_rejected(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  callee: GcObject,
  _this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let slots = exec_module_load_slots(scope, callee)?;
  let reason = args.get(0).copied().unwrap_or(Value::Undefined);

  let mut call_scope = scope.reborrow();
  call_scope.push_roots(&[slots.reject, reason])?;
  let _ = vm.call_with_host_and_hooks(
    host,
    &mut call_scope,
    hooks,
    slots.reject,
    Value::Undefined,
    &[reason],
  )?;
  Ok(Value::Undefined)
}

impl Drop for JsRuntime {
  fn drop(&mut self) {
    let realm_id = self.realm.id();

    // Discard any pending Promise jobs so we don't drop `Job`s that still own persistent roots.
    //
    // This matters in tests/embedders that early-return on errors (including OOM) without running a
    // microtask checkpoint.
    self.teardown_microtasks();

    // Unregister persistent roots created by the module graph, global lexical bindings, and the
    // realm. This keeps heap reuse in tests/embeddings from accumulating roots and satisfies
    // `Realm`'s debug assertion.
    self.modules.teardown(&mut self.vm, &mut self.heap);
    self.env.teardown(&mut self.heap);
    self.realm.teardown(&mut self.heap);
    self.vm.teardown_realm(&mut self.heap, realm_id);
  }
}

impl VmJobContext for JsRuntime {
  fn call(
    &mut self,
    host: &mut dyn VmHostHooks,
    callee: Value,
    this: Value,
    args: &[Value],
  ) -> Result<Value, VmError> {
    // Borrow-split `vm` and `heap` so we can hold a `Scope` while calling into the VM.
    let vm = &mut self.vm;
    let heap = &mut self.heap;
    let mut scope = heap.scope();
    vm.call_with_host(&mut scope, host, callee, this, args)
  }

  fn construct(
    &mut self,
    host: &mut dyn VmHostHooks,
    callee: Value,
    args: &[Value],
    new_target: Value,
  ) -> Result<Value, VmError> {
    let vm = &mut self.vm;
    let heap = &mut self.heap;
    let mut scope = heap.scope();
    vm.construct_with_host(&mut scope, host, callee, args, new_target)
  }

  fn add_root(&mut self, value: Value) -> Result<RootId, VmError> {
    self.heap.add_root(value)
  }

  fn remove_root(&mut self, id: RootId) {
    self.heap.remove_root(id)
  }

  fn coerce_error_to_throw_with_stack(&mut self, err: VmError) -> VmError {
    // Borrow-split `vm` and `heap` so we can create a `Scope` while accessing the VM for stack
    // capture and intrinsics.
    let vm = &self.vm;
    let heap = &mut self.heap;
    let mut scope = heap.scope();
    crate::vm::coerce_error_to_throw_with_stack(vm, &mut scope, err)
  }
}

struct Evaluator<'a> {
  vm: &'a mut Vm,
  host: &'a mut dyn VmHost,
  hooks: &'a mut dyn VmHostHooks,
  env: &'a mut RuntimeEnv,
  strict: bool,
  this: Value,
  new_target: Value,
  /// The current lexical `[[HomeObject]]`, used for `super` property references and inherited by
  /// arrow functions.
  home_object: Option<GcObject>,
  /// If executing a user-defined class constructor body, this links back to the containing class
  /// constructor function object (the native wrapper that holds field metadata).
  class_constructor: Option<GcObject>,
  /// Whether the current class constructor body is a *derived* constructor (i.e. has an `extends`
  /// clause). In derived constructors, `this` is uninitialized until `super()` returns.
  derived_constructor: bool,
  /// Whether `this` has been initialized (only meaningful when `derived_constructor` is `true`).
  this_initialized: bool,
  /// Root-stack slot index used to keep derived-constructor `this` state alive across nested
  /// scopes.
  ///
  /// For derived constructors, `self.this` is set to a shared heap cell (see
  /// [`crate::heap::DerivedConstructorState`]) so nested arrow functions and eval code can observe
  /// `super()` initializing the enclosing constructor's `this` binding.
  this_root_idx: Option<usize>,
}

#[derive(Clone, Copy, Debug)]
enum Reference<'a> {
  Binding(&'a str),
  /// A property reference.
  ///
  /// Note: per ECMA-262, the reference stores the *base value* (which may be a primitive). Property
  /// access/assignment performs `ToObject(base)` for the actual `[[Get]]`/`[[Set]]` operation, but
  /// the `receiver` (the `this` value for `[[Get]]`/`[[Set]]`) can differ from the base:
  /// - for ordinary property references, `receiver == base`
  /// - for `super` property references, `base` is `GetPrototypeOf([[HomeObject]])` while `receiver`
  ///   is the current `this` binding.
  Property {
    base: Value,
    receiver: Value,
    key: PropertyKey,
  },
  /// A `super` property reference (`super.x` / `super[expr]`).
  ///
  /// Per ECMA-262, a Super Reference carries both:
  /// - the *base* object used for property lookup (`GetSuperBase()`), and
  /// - the *receiver* (`GetThisBinding()`), used as `this` for accessors and for `super.m()` calls.
  ///
  /// Note: `base` is stored as a `Value` (not `GcObject`) because `[[HomeObject]].[[Prototype]]`
  /// can be `null` (e.g. `class C extends null {}`), in which case dereferencing the reference
  /// must throw a TypeError (via `ToObject(null)`).
  SuperProperty {
    base: Value,
    key: PropertyKey,
    receiver: Value,
  },
  /// A private-name reference (`obj.#x`).
  ///
  /// Private-name references:
  /// - never perform `ToObject` on the base value (the base must be an Object at dereference time),
  /// - never consult the prototype chain,
  /// - never dispatch to Proxy traps.
  Private {
    base: Value,
    sym: GcSymbol,
    name: &'a str,
  },
}

#[derive(Clone, Copy, Debug)]
enum NumericValue {
  Number(f64),
  BigInt(GcBigInt),
}

#[derive(Clone, Copy, Debug)]
enum OptionalChainEval {
  /// A normal evaluation result.
  Value(Value),
  /// Indicates that an optional chain has short-circuited and the current chain expression should
  /// evaluate to `undefined`.
  ///
  /// This is distinct from `Value::Undefined` so that chain continuations like `a?.b.c` can avoid
  /// confusing an *actual* `undefined` value (e.g. the property value of `a.b`) with an optional
  /// chain short-circuit (e.g. `a` was nullish).
  ShortCircuit,
}

impl OptionalChainEval {
  #[inline]
  fn into_value(self) -> Value {
    match self {
      OptionalChainEval::Value(v) => v,
      OptionalChainEval::ShortCircuit => Value::Undefined,
    }
  }
}

impl<'a> Evaluator<'a> {
  /// Runs one VM "tick".
  ///
  /// ## Tick policy (AST evaluator)
  ///
  /// This interpreter charges **one tick** at the start of every statement evaluation
  /// ([`Evaluator::eval_stmt`]) and every expression evaluation ([`Evaluator::eval_expr`]).
  ///
  /// Some constructs (e.g. `for(;;){}` with an empty body and no condition/update expressions) may
  /// otherwise loop without evaluating any statements/expressions per iteration; those paths tick
  /// explicitly as well.
  ///
  /// Additional ticks are also charged inside some literal-construction loops (for example: holey
  /// array literals, object literals with shorthand/method members, tagged template objects) to
  /// ensure that large `O(N)` literal processing cannot run for an unbounded amount of time within
  /// a single expression tick.
  #[inline]
  fn tick(&mut self) -> Result<(), VmError> {
    self.vm.tick()
  }

  /// Implements `GetThisBinding` for the current execution context.
  ///
  /// Derived class constructors have an uninitialized `this` binding until `super()` returns.
  /// `vm-js` represents that shared state as a heap object (`DerivedConstructorState`) so nested
  /// arrow functions and direct eval code can observe initialization.
  ///
  /// All operations that need the *actual* `this` value (including `this` expressions and
  /// `super.prop` / `super[expr]` receiver resolution) should go through this helper.
  fn get_this_binding(&mut self, scope: &mut Scope<'_>) -> Result<Value, VmError> {
    if let Value::Object(obj) = self.this {
      if scope.heap().is_derived_constructor_state(obj) {
        let state = scope.heap().get_derived_constructor_state(obj)?;
        if let Some(this_obj) = state.this_value {
          return Ok(Value::Object(this_obj));
        }
        return Err(throw_reference_error(
          self.vm,
          scope,
          "Must call super constructor in derived class before accessing 'this'",
        )?);
      }
    }

    if self.derived_constructor && !self.this_initialized {
      return Err(throw_reference_error(
        self.vm,
        scope,
        "Must call super constructor in derived class before accessing 'this'",
      )?);
    }

    Ok(self.this)
  }

  #[inline]
  fn call(
    &mut self,
    scope: &mut Scope<'_>,
    callee: Value,
    this: Value,
    args: &[Value],
  ) -> Result<Value, VmError> {
    self
      .vm
      .call_with_host_and_hooks(&mut *self.host, scope, &mut *self.hooks, callee, this, args)
  }

  fn super_base(&mut self, scope: &mut Scope<'_>) -> Result<Value, VmError> {
    let Some(home_object) = self.home_object else {
      // `super` is only valid inside methods/class constructors, so reaching this at runtime
      // indicates an early-error mismatch. Prefer a recoverable runtime error over panicking.
      return Err(VmError::Unimplemented("super property access without home object"));
    };

    let mut proto_scope = scope.reborrow();
    proto_scope.push_root(Value::Object(home_object))?;
    let proto = proto_scope.get_prototype_of_with_host_and_hooks(
      self.vm,
      &mut *self.host,
      &mut *self.hooks,
      home_object,
    )?;
    Ok(proto.map(Value::Object).unwrap_or(Value::Null))
  }

  /// Implements `IteratorClose` error precedence for operations that return `Result<_, VmError>`.
  ///
  /// Per ECMA-262 `IteratorClose(iteratorRecord, completion)`, errors thrown while getting/calling
  /// `iterator.return` override the incoming completion. The only special-case for throw
  /// completions is that the non-object return-result TypeError check is skipped after a
  /// successful close.
  ///
  /// `vm-js` also has non-catchable VM failures (termination, OOM, etc) which must never be
  /// replaced by a JavaScript catchable exception from iterator closing.
  fn iterator_close_on_error(
    &mut self,
    scope: &mut Scope<'_>,
    record: &iterator::IteratorRecord,
    err: VmError,
  ) -> VmError {
    if record.done {
      return err;
    }

    let original_is_throw = err.is_throw_completion();
    let completion = Completion::Throw(Thrown {
      value: err.thrown_value().unwrap_or(Value::Undefined),
      stack: Vec::new(),
    });

    match iterator::iterator_close_with_completion(
      self.vm,
      &mut *self.host,
      &mut *self.hooks,
      scope,
      record,
      completion,
    ) {
      Ok(_) => err,
      Err(close_err) => {
        if original_is_throw {
          close_err
        } else {
          err
        }
      }
    }
  }

  /// Implements `IteratorClose` for operations that return a `Completion` record.
  fn iterator_close_on_completion(
    &mut self,
    scope: &mut Scope<'_>,
    record: &iterator::IteratorRecord,
    completion: Completion,
  ) -> Result<Completion, VmError> {
    iterator::iterator_close_with_completion(
      self.vm,
      &mut *self.host,
      &mut *self.hooks,
      scope,
      record,
      completion,
    )
  }

  fn function_length(&mut self, func: &parse_js::ast::func::Func) -> Result<u32, VmError> {
    // ECMA-262 `length` is the number of parameters before the first one with a default/rest.
    //
    // This scan can be `O(N)` in the number of parameters, and function expressions/declarations
    // can have very large parameter lists (bounded by source size). Budget it explicitly so a
    // single function literal can't do unbounded work within a single statement/expression tick.
    const TICK_EVERY: usize = 32;
    let mut len: u32 = 0;
    for (i, param) in func.parameters.iter().enumerate() {
      if i % TICK_EVERY == 0 {
        self.tick()?;
      }
      if param.stx.rest || param.stx.default_value.is_some() {
        break;
      }
      len = len.saturating_add(1);
    }
    Ok(len)
  }

  fn object_member_span_start(
    &self,
    member_loc_start: u32,
    key_loc_start: u32,
    func: &parse_js::ast::func::Func,
  ) -> u32 {
    let prefix_len = self.env.prefix_len();
    let base_offset = self.env.base_offset();
    let key_span_start = base_offset.saturating_add(key_loc_start.saturating_sub(prefix_len));

    // For non-async, non-generator methods, the key's start location is sufficient (and avoids
    // including class-only modifiers like `static` that are not valid in the object literal wrapper
    // used by `Vm::ecma_function_ast` for `EcmaFunctionKind::ObjectMember`).
    if !func.async_ && !func.generator {
      return key_span_start;
    }

    // For async/generator methods, the `async`/`*` modifiers appear before the key. `parse-js` does
    // not include these modifiers in the key's `Loc`, so slicing from the key would cause the VM's
    // lazy function reparse to lose the async/generator flags and reject `await`/`yield` in the
    // body.
    //
    // Scan the original source between the full member start and the key start to find the
    // modifier token(s), skipping class-only modifiers like `static` which occur before them.
    let member_span_start = base_offset.saturating_add(member_loc_start.saturating_sub(prefix_len));

    let source = self.env.source();
    let text = source.text.as_bytes();
    let start = (member_span_start as usize).min(text.len());
    let end = (key_span_start as usize).min(text.len());
    if start >= end {
      return key_span_start;
    }
    let slice = &text[start..end];

    let mut best = key_span_start;
    if func.async_ {
      let async_bytes = b"async";
      if let Some(pos) = slice
        .windows(async_bytes.len())
        .rposition(|w| w == async_bytes)
      {
        best = best.min(member_span_start.saturating_add(pos as u32));
      }
    }
    if func.generator {
      if let Some(pos) = slice.iter().rposition(|&b| b == b'*') {
        best = best.min(member_span_start.saturating_add(pos as u32));
      }
    }

    best
  }

  fn class_member_span_start(
    &self,
    member_loc_start: u32,
    key_loc_start: u32,
    key_is_computed: bool,
    func: Option<&parse_js::ast::func::Func>,
    accessor_keyword: Option<&'static [u8]>,
  ) -> u32 {
    let prefix_len = self.env.prefix_len();
    let base_offset = self.env.base_offset();

    let key_span_start = base_offset.saturating_add(key_loc_start.saturating_sub(prefix_len));
    let member_span_start = base_offset.saturating_add(member_loc_start.saturating_sub(prefix_len));

    // For non-async, non-generator methods, the key's start location is sufficient and avoids
    // including `static` from `static <method>` class elements (which is not part of the
    // `Function.prototype.toString` source text for the resulting function object).
    let Some(func) = func else {
      return self.class_member_span_start_scan(
        member_span_start,
        key_span_start,
        key_is_computed,
        accessor_keyword,
        /* async_ */ false,
        /* generator */ false,
      );
    };

    self.class_member_span_start_scan(
      member_span_start,
      key_span_start,
      key_is_computed,
      accessor_keyword,
      func.async_,
      func.generator,
    )
  }

  fn class_member_span_start_scan(
    &self,
    member_span_start: u32,
    key_span_start: u32,
    key_is_computed: bool,
    accessor_keyword: Option<&'static [u8]>,
    is_async: bool,
    is_generator: bool,
  ) -> u32 {
    let source = self.env.source();
    let text = source.text.as_bytes();
    let start = (member_span_start as usize).min(text.len());
    let end = (key_span_start as usize).min(text.len());
    if start >= end {
      return key_span_start;
    }
    let slice = &text[start..end];

    let mut best = key_span_start;

    // `ClassOrObjKey::Computed` locs point at the expression *inside* the brackets, so include the
    // `[` token itself when slicing source spans for `Function.prototype.toString` and lazy
    // function reparsing.
    if key_is_computed {
      if let Some(pos) = slice.iter().rposition(|&b| b == b'[') {
        best = best.min(member_span_start.saturating_add(pos as u32));
      }
    }

    if let Some(keyword) = accessor_keyword {
      if let Some(pos) = slice.windows(keyword.len()).rposition(|w| w == keyword) {
        best = best.min(member_span_start.saturating_add(pos as u32));
      }
    }

    if is_async {
      let async_bytes = b"async";
      if let Some(pos) = slice
        .windows(async_bytes.len())
        .rposition(|w| w == async_bytes)
      {
        best = best.min(member_span_start.saturating_add(pos as u32));
      }
    }

    if is_generator {
      if let Some(pos) = slice.iter().rposition(|&b| b == b'*') {
        best = best.min(member_span_start.saturating_add(pos as u32));
      }
    }

    best
  }

  fn class_field_initializer_span_start_scan(
    &self,
    member_span_start: u32,
    expr_span_start: u32,
    expr_span_end: u32,
  ) -> u32 {
    // `parse-js` expression `Loc` values intentionally exclude parentheses, instead storing them via
    // the `ParenthesizedExpr` association marker.
    //
    // For class field initializers, we lazily reparse the initializer expression by slicing its
    // source span and wrapping it in a synthetic class method:
    //
    //   (class extends null {m(){return <expr>;}})
    //
    // If the initializer begins with a parenthesized subexpression whose closing `)` appears
    // *inside* the initializer (e.g. `(() => super.m())()` or `(x) + y`), the initializer's `Loc`
    // start will point at the inner expression token, causing the slice to lose the opening `(` but
    // keep the closing `)`. That results in an invalid snippet when reparsed.
    //
    // Detect the number of missing opening parentheses by computing the parenthesis balance of the
    // snippet (ignoring those in strings/comments/template raw text), then scan backwards in the
    // original source to include the required `(` token(s).
    let source = self.env.source();
    let text = source.text.as_bytes();
    let member_start = (member_span_start as usize).min(text.len());
    let start = (expr_span_start as usize).min(text.len());
    let end = (expr_span_end as usize).min(text.len());
    if start >= end || member_start >= start {
      return expr_span_start;
    }

    // If the expression start is not preceded by an opening parenthesis (ignoring whitespace and
    // block comments), its `Loc` is not missing a leading `(` so there is nothing to fix.
    let mut probe = start;
    loop {
      while probe > member_start && text[probe - 1].is_ascii_whitespace() {
        probe -= 1;
      }

      // Skip a block comment (`/* ... */`) directly before the current position.
      if probe >= member_start + 2 && &text[probe - 2..probe] == b"*/" {
        probe = probe.saturating_sub(2);
        while probe >= member_start + 2 {
          if &text[probe - 2..probe] == b"/*" {
            probe = probe.saturating_sub(2);
            break;
          }
          probe = probe.saturating_sub(1);
        }
        continue;
      }
      break;
    }
    if probe <= member_start || text[probe - 1] != b'(' {
      return expr_span_start;
    }

    #[derive(Clone, Copy, Debug)]
    enum ScanState {
      Normal,
      SingleQuote,
      DoubleQuote,
      LineComment,
      BlockComment,
      TemplateRaw,
      TemplateExpr { brace_depth: u32 },
    }

    let mut balance: i32 = 0;
    let mut stack: Vec<ScanState> = Vec::new();
    stack.push(ScanState::Normal);

    let mut i = start;
    while i < end {
      let b = text[i];
      match stack.last_mut().unwrap() {
        ScanState::Normal => match b {
          b'\'' => {
            stack.push(ScanState::SingleQuote);
            i += 1;
          }
          b'"' => {
            stack.push(ScanState::DoubleQuote);
            i += 1;
          }
          b'`' => {
            stack.push(ScanState::TemplateRaw);
            i += 1;
          }
          b'/' if i + 1 < end && text[i + 1] == b'/' => {
            stack.push(ScanState::LineComment);
            i += 2;
          }
          b'/' if i + 1 < end && text[i + 1] == b'*' => {
            stack.push(ScanState::BlockComment);
            i += 2;
          }
          b'(' => {
            balance = balance.saturating_add(1);
            i += 1;
          }
          b')' => {
            balance = balance.saturating_sub(1);
            i += 1;
          }
          _ => i += 1,
        },
        ScanState::TemplateExpr { brace_depth } => match b {
          b'\'' => {
            stack.push(ScanState::SingleQuote);
            i += 1;
          }
          b'"' => {
            stack.push(ScanState::DoubleQuote);
            i += 1;
          }
          b'`' => {
            stack.push(ScanState::TemplateRaw);
            i += 1;
          }
          b'/' if i + 1 < end && text[i + 1] == b'/' => {
            stack.push(ScanState::LineComment);
            i += 2;
          }
          b'/' if i + 1 < end && text[i + 1] == b'*' => {
            stack.push(ScanState::BlockComment);
            i += 2;
          }
          b'{' => {
            *brace_depth = brace_depth.saturating_add(1);
            i += 1;
          }
          b'}' => {
            if *brace_depth == 0 {
              stack.pop();
            } else {
              *brace_depth = brace_depth.saturating_sub(1);
            }
            i += 1;
          }
          b'(' => {
            balance = balance.saturating_add(1);
            i += 1;
          }
          b')' => {
            balance = balance.saturating_sub(1);
            i += 1;
          }
          _ => i += 1,
        },
        ScanState::SingleQuote => match b {
          b'\\' => i = (i + 2).min(end),
          b'\'' => {
            stack.pop();
            i += 1;
          }
          _ => i += 1,
        },
        ScanState::DoubleQuote => match b {
          b'\\' => i = (i + 2).min(end),
          b'"' => {
            stack.pop();
            i += 1;
          }
          _ => i += 1,
        },
        ScanState::LineComment => match b {
          b'\n' | b'\r' => {
            stack.pop();
            i += 1;
          }
          _ => i += 1,
        },
        ScanState::BlockComment => {
          if b == b'*' && i + 1 < end && text[i + 1] == b'/' {
            stack.pop();
            i += 2;
          } else {
            i += 1;
          }
        }
        ScanState::TemplateRaw => match b {
          b'\\' => i = (i + 2).min(end),
          b'`' => {
            stack.pop();
            i += 1;
          }
          b'$' if i + 1 < end && text[i + 1] == b'{' => {
            stack.push(ScanState::TemplateExpr { brace_depth: 0 });
            i += 2;
          }
          _ => i += 1,
        },
      }
    }

    if balance >= 0 {
      return expr_span_start;
    }
    let mut missing = (-balance) as usize;

    let mut best = start;
    while missing > 0 {
      // Skip whitespace before each parenthesis.
      while best > member_start && text[best - 1].is_ascii_whitespace() {
        best -= 1;
      }

      // Skip a block comment (`/* ... */`) directly before the current position.
      if best >= member_start + 2 && &text[best - 2..best] == b"*/" {
        best = best.saturating_sub(2);
        while best >= member_start + 2 {
          if &text[best - 2..best] == b"/*" {
            best = best.saturating_sub(2);
            break;
          }
          best = best.saturating_sub(1);
        }
        continue;
      }

      if best > member_start && text[best - 1] == b'(' {
        best -= 1;
        missing -= 1;
      } else {
        break;
      }
    }

    if missing == 0 {
      best as u32
    } else {
      expr_span_start
    }
  }

  fn instantiate_script(
    &mut self,
    scope: &mut Scope<'_>,
    stmts: &[Node<Stmt>],
  ) -> Result<(), VmError> {
    // Detect classic script execution in the realm's global environment:
    // - var environment is the global object, and
    // - lexical environment is the realm's global lexical environment (outermost env record).
    //
    // This is distinct from non-strict eval-in-global, which also uses `VarEnv::GlobalObject` but
    // executes with a fresh inner lexical environment whose outer is the global lexical env.
    if matches!(self.env.var_env(), VarEnv::GlobalObject)
      && scope.heap().env_outer(self.env.lexical_env)? == None
    {
      return self.instantiate_global_script(scope, stmts);
    }

    self.instantiate_stmt_list(scope, stmts)
  }

  fn instantiate_function(
    &mut self,
    scope: &mut Scope<'_>,
    func: &Node<Func>,
    args: &[Value],
  ) -> Result<(), VmError> {
    const PROLOGUE_TICK_EVERY: usize = 32;

    fn pat_contains_expression(pat: &Pat) -> bool {
      match pat {
        Pat::Id(_) => false,
        // Binding patterns should never use this variant, but treat it as containing expressions for
        // robustness against parse error recovery.
        Pat::AssignTarget(_) => true,
        Pat::Arr(arr) => {
          for elem in &arr.stx.elements {
            let Some(elem) = elem else {
              continue;
            };
            if elem.default_value.is_some() {
              return true;
            }
            if pat_contains_expression(&elem.target.stx) {
              return true;
            }
          }
          if let Some(rest) = &arr.stx.rest {
            if pat_contains_expression(&rest.stx) {
              return true;
            }
          }
          false
        }
        Pat::Obj(obj) => {
          for prop in &obj.stx.properties {
            if matches!(&prop.stx.key, ClassOrObjKey::Computed(_)) {
              return true;
            }
            if prop.stx.default_value.is_some() {
              return true;
            }
            if pat_contains_expression(&prop.stx.target.stx) {
              return true;
            }
          }
          if let Some(rest) = &obj.stx.rest {
            if pat_contains_expression(&rest.stx) {
              return true;
            }
          }
          false
        }
      }
    }

    let simple_parameter_list = func.stx.parameters.iter().all(|param| {
      !param.stx.rest
        && param.stx.default_value.is_none()
        && matches!(&*param.stx.pattern.stx.pat.stx, Pat::Id(_))
    });
    let has_parameter_expressions = func.stx.parameters.iter().any(|param| {
      param.stx.default_value.is_some() || pat_contains_expression(&param.stx.pattern.stx.pat.stx)
    });

    // Functions with default parameter expressions (and other parameter-list expressions like
    // computed destructuring keys) evaluate their parameter list in a dedicated Environment Record
    // nested within the function's `var` Environment.
    //
    // This matches ECMA-262's `FunctionDeclarationInstantiation` split between `paramEnv` and
    // `varEnv`, and ensures direct eval `var` declarations are rejected when they collide with
    // parameter bindings (test262: `eval-var-scope-syntax-err.js`).
    if has_parameter_expressions {
      if let VarEnv::Env(var_env) = self.env.var_env() {
        let param_env = scope.env_create(Some(var_env))?;
        self.env.set_lexical_env(scope.heap_mut(), param_env);
      }
    }

    // Pre-create all parameter bindings before evaluating default initializers so identifier
    // references during parameter evaluation observe TDZ semantics.
    let env_rec = self.env.lexical_env;
    for param in &func.stx.parameters {
      self.tick()?;
      // Parameter lists can legally contain duplicate names in sloppy mode when the parameter list
      // is "simple" (e.g. `function f(a, a) { ... }`). Unlike lexical declarations, duplicate
      // parameter names do not create duplicate bindings; later parameters simply update the same
      // binding.
      //
      // Create each identifier binding at most once here so parameter binding evaluation can
      // initialize/update it later.
      self.instantiate_param_names_from_pat(
        scope,
        env_rec,
        &param.stx.pattern.stx.pat.stx,
        param.loc,
      )?;
    }

    // Create a minimal `arguments` object for non-arrow functions.
    //
    // test262's harness expects `arguments` to exist and be array-like (`length`, indexed elements).
    // When the function has a simple parameter list and is non-strict, use a mapped arguments
    // object so `arguments[i]` aliases the corresponding parameter binding (ECMA-262).
    //
    // `arguments` must be created before default parameter initializers run so defaults can read it.
    if !func.stx.arrow
      && !scope
        .heap()
        .env_has_binding(self.env.lexical_env, "arguments")?
    {
      let intr = self
        .vm
        .intrinsics()
        .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;

      let args_obj = scope.alloc_arguments_object()?;
      scope.push_root(Value::Object(args_obj))?;
      scope
        .heap_mut()
        .object_set_prototype(args_obj, Some(intr.object_prototype()))?;

      let len = args.len() as f64;
      let len_key = PropertyKey::from_string(scope.alloc_string("length")?);
      scope.define_property(
        args_obj,
        len_key,
        PropertyDescriptor {
          enumerable: false,
          configurable: true,
          kind: PropertyKind::Data {
            value: Value::Number(len),
            writable: true,
          },
        },
      )?;

      // `arguments[@@iterator]` is `%Array.prototype.values%` (ECMA-262).
      scope.define_property(
        args_obj,
        PropertyKey::Symbol(intr.well_known_symbols().iterator),
        PropertyDescriptor {
          enumerable: false,
          configurable: true,
          kind: PropertyKind::Data {
            value: Value::Object(intr.array_prototype_values()),
            writable: true,
          },
        },
      )?;

      let use_mapped_arguments = !self.strict && simple_parameter_list;
      let mut map_param_index: Vec<bool> = Vec::new();
      if use_mapped_arguments {
        // Per spec, when the parameter list contains duplicates, only the last occurrence is
        // mapped. Build a bool table over parameter indices to reflect that.
        map_param_index
          .try_reserve_exact(func.stx.parameters.len())
          .map_err(|_| VmError::OutOfMemory)?;
        map_param_index.resize(func.stx.parameters.len(), false);
        let mut mapped_names: HashSet<&str> = HashSet::new();
        mapped_names
          .try_reserve(func.stx.parameters.len())
          .map_err(|_| VmError::OutOfMemory)?;
        for (idx, param) in func.stx.parameters.iter().enumerate().rev() {
          let Pat::Id(id) = &*param.stx.pattern.stx.pat.stx else {
            continue;
          };
          let name = id.stx.name.as_str();
          if mapped_names.contains(name) {
            continue;
          }
          mapped_names
            .try_reserve(1)
            .map_err(|_| VmError::OutOfMemory)?;
          mapped_names.insert(name);
          map_param_index[idx] = true;
        }
      }

        for (i, v) in args.iter().copied().enumerate() {
          if i % PROLOGUE_TICK_EVERY == 0 {
            self.tick()?;
          }
          let mut idx_scope = scope.reborrow();
          idx_scope.push_root(v)?;
          let i_u32 = u32::try_from(i).map_err(|_| VmError::OutOfMemory)?;
          // Root the index string because we may allocate (and GC) while constructing mapped
          // `arguments` accessors before we use it in `define_property`.
          let key_s = idx_scope.alloc_u32_index_string(i_u32)?;
          idx_scope.push_root(Value::String(key_s))?;
          let key = PropertyKey::from_string(key_s);
          if use_mapped_arguments
            && i < func.stx.parameters.len()
            && *map_param_index
              .get(i)
              .ok_or(VmError::InvariantViolation(
              "arguments mapping index out of bounds",
            ))?
        {
          let Pat::Id(id) = &*func.stx.parameters[i].stx.pattern.stx.pat.stx else {
            return Err(VmError::InvariantViolation(
              "simple parameter list contains non-identifier pattern",
            ));
          };

          let getter_call_id = self.vm.arguments_param_map_getter_call_id()?;
          let setter_call_id = self.vm.arguments_param_map_setter_call_id()?;
          // Root the function name string because we allocate other strings before passing it into
          // `alloc_native_function_with_slots_and_env`, which can trigger GC.
          let name = idx_scope.alloc_string("")?;
          idx_scope.push_root(Value::String(name))?;

          let param_name_s = idx_scope.alloc_string(id.stx.name.as_str())?;
          let slots = [Value::String(param_name_s)];

          let getter = idx_scope.alloc_native_function_with_slots_and_env(
            getter_call_id,
            None,
            name,
            0,
            &slots,
            Some(env_rec),
          )?;
          idx_scope.push_root(Value::Object(getter))?;
          let setter = idx_scope.alloc_native_function_with_slots_and_env(
            setter_call_id,
            None,
            name,
            1,
            &slots,
            Some(env_rec),
          )?;
          idx_scope.push_root(Value::Object(setter))?;

          for func_obj in [getter, setter] {
            idx_scope
              .heap_mut()
              .object_set_prototype(func_obj, Some(intr.function_prototype()))?;
            idx_scope
              .heap_mut()
              .set_function_realm(func_obj, self.env.global_object())?;
          }

          idx_scope.define_property(
            args_obj,
            key,
            PropertyDescriptor {
              enumerable: true,
              configurable: true,
              kind: PropertyKind::Accessor {
                get: Value::Object(getter),
                set: Value::Object(setter),
              },
            },
          )?;
        } else {
          idx_scope.define_property(args_obj, key, global_var_desc(v))?;
        }
      }

      // Strict-mode `arguments` objects have poison-pill `callee`/`caller` accessors.
      if self.strict {
        let thrower = intr.throw_type_error();
        scope.push_root(Value::Object(thrower))?;
        for prop_name in ["callee", "caller"] {
          let key_s = scope.alloc_string(prop_name)?;
          scope.push_root(Value::String(key_s))?;
          let key = PropertyKey::from_string(key_s);
          scope.define_property(
            args_obj,
            key,
            PropertyDescriptor {
              enumerable: false,
              configurable: false,
              kind: PropertyKind::Accessor {
                get: Value::Object(thrower),
                set: Value::Object(thrower),
              },
            },
          )?;
        }
      }

      scope.env_create_mutable_binding(self.env.lexical_env, "arguments")?;
      scope.heap_mut().env_initialize_binding(
        self.env.lexical_env,
        "arguments",
        Value::Object(args_obj),
      )?;
    }

    // Bind parameters in order, evaluating default initializers as needed.
    for (idx, param) in func.stx.parameters.iter().enumerate() {
      self.tick()?;
      if param.stx.rest {
        // Rest parameter: collect remaining args into an Array.
        let rest_slice = args.get(idx..).unwrap_or(&[]);
        let intr = self
          .vm
          .intrinsics()
          .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;

        let mut rest_scope = scope.reborrow();
        let arr = rest_scope.alloc_array(0)?;
        rest_scope.push_root(Value::Object(arr))?;
        rest_scope
          .heap_mut()
          .object_set_prototype(arr, Some(intr.array_prototype()))?;

        for (i, v) in rest_slice.iter().copied().enumerate() {
          if i % PROLOGUE_TICK_EVERY == 0 {
            self.tick()?;
          }
          let mut elem_scope = rest_scope.reborrow();
          elem_scope.push_root(v)?;
          let i_u32 = u32::try_from(i).map_err(|_| VmError::OutOfMemory)?;
          let key_s = elem_scope.alloc_u32_index_string(i_u32)?;
          elem_scope.push_root(Value::String(key_s))?;
          let key = PropertyKey::from_string(key_s);
          elem_scope.create_data_property_or_throw(arr, key, v)?;
        }

        bind_pattern(
          self.vm,
          &mut *self.host,
          &mut *self.hooks,
          &mut rest_scope,
          self.env,
          &param.stx.pattern.stx.pat.stx,
          Value::Object(arr),
          BindingKind::Param,
          self.strict,
          self.this,
        )?;

        if idx + 1 != func.stx.parameters.len() {
          return Err(VmError::Unimplemented("rest parameter must be last"));
        }
        break;
      }
 
      let mut value = args.get(idx).copied().unwrap_or(Value::Undefined);
      if matches!(value, Value::Undefined) {
        if let Some(default_expr) = &param.stx.default_value {
          // When a default value is evaluated due to a missing argument, use `NamedEvaluation` to
          // infer the `name` of anonymous function/class definitions from the parameter identifier.
          if let Pat::Id(id) = &*param.stx.pattern.stx.pat.stx {
            let name_s = scope.alloc_string(&id.stx.name)?;
            let key = PropertyKey::from_string(name_s);
            value = self.eval_expr_named(scope, default_expr, key)?;
          } else {
            value = self.eval_expr(scope, default_expr)?;
          }
        }
      }

      bind_pattern(
        self.vm,
        &mut *self.host,
        &mut *self.hooks,
        scope,
        self.env,
        &param.stx.pattern.stx.pat.stx,
        value,
        BindingKind::Param,
        self.strict,
        self.this,
      )?;
    }

    if let Some(FuncBody::Block(stmts)) = &func.stx.body {
      // Create a dedicated function-body lexical environment nested inside the function's var/env
      // record.
      //
      // This matches the spec's execution-context split where `var`/parameter bindings live in the
      // VariableEnvironment and `let`/`const`/`class` bindings live in a separate
      // LexicalEnvironment.
      let outer = self.env.lexical_env;
      let body_lex = scope.env_create(Some(outer))?;
      self.env.set_lexical_env(scope.heap_mut(), body_lex);

      self.instantiate_stmt_list(scope, stmts)?;
    }
    Ok(())
  }

  fn instantiate_global_script(
    &mut self,
    scope: &mut Scope<'_>,
    stmts: &[Node<Stmt>],
  ) -> Result<(), VmError> {
    // GlobalDeclarationInstantiation (ECMA-262).
    //
    // vm-js uses a declarative Environment Record (`global_lexical_env`) to store global lexical
    // bindings (`let`/`const`/`class`) and uses the realm global object as the backing store for
    // global var/function bindings.

    // --- Early errors (parse-phase) ---
    //
    // These must run before any binding creation so invalid programs do not partially pollute the
    // global environment.
    for stmt in stmts {
      self.destructuring_decl_without_initializer_early_error(stmt)?;
    }

    if self.strict {
      for stmt in stmts {
        self.strict_mode_with_early_error(stmt)?;
      }
    }

    self.label_early_errors_in_stmt_list(stmts)?;

    // Minimal statement-list early error checks:
    // - Duplicate lexical declarations (let/const/class) in the script body.
    // - Lexical declarations may not collide with var-scoped names (var + function declarations).
    //
    // These are syntax (parse-phase) errors and should surface as `VmError::Syntax`.
    let mut var_names = HashSet::<String>::new();
    for stmt in stmts {
      self.collect_var_names(&stmt.stx, &mut var_names)?;
    }

    if self.strict {
      // Strict mode: only top-level function declarations are var-scoped; block function
      // declarations are instantiated at block entry.
      for stmt in stmts {
        self.tick()?;
        let Stmt::FunctionDecl(decl) = &*stmt.stx else {
          continue;
        };
        let Some(name) = &decl.stx.name else {
          if decl.stx.export_default {
            continue;
          }
          return Err(VmError::Unimplemented("anonymous function declaration"));
        };
        let name_str = name.stx.name.as_str();
        if !var_names.contains(name_str) {
          var_names.try_reserve(1).map_err(|_| VmError::OutOfMemory)?;
          var_names.insert(try_clone_string(name_str)?);
        }
      }
    } else {
      // Non-strict mode: treat block function declarations as var-scoped (Annex B-ish).
      for stmt in stmts {
        self.collect_sloppy_function_decl_names(&stmt.stx, &mut var_names)?;
      }
    }

    let mut lexical_seen = HashSet::<String>::new();
    let mut lexical_bindings: Vec<(String, parse_js::loc::Loc)> = Vec::new();
    for stmt in stmts {
      self.tick()?;
      match &*stmt.stx {
        Stmt::VarDecl(var) => {
          if !matches!(
            var.stx.mode,
            VarDeclMode::Let | VarDeclMode::Const | VarDeclMode::Using | VarDeclMode::AwaitUsing
          ) {
            continue;
          }
          for declarator in &var.stx.declarators {
            self.tick()?;
            if matches!(
              var.stx.mode,
              VarDeclMode::Const | VarDeclMode::Using | VarDeclMode::AwaitUsing
            ) && declarator.initializer.is_none()
            {
              let message = match var.stx.mode {
                VarDeclMode::Const => "Missing initializer in const declaration",
                VarDeclMode::Using => "Missing initializer in using declaration",
                VarDeclMode::AwaitUsing => "Missing initializer in await using declaration",
                _ => unreachable!(),
              };
              return Err(syntax_error(declarator.pattern.loc, message));
            }
            self.collect_lexical_decl_names_from_pat(
              &declarator.pattern.stx.pat.stx,
              stmt.loc,
              &mut lexical_seen,
              &mut lexical_bindings,
            )?;
          }
        }
        Stmt::ClassDecl(class) => {
          let Some(name) = class.stx.name.as_ref() else {
            continue;
          };
          let name_str = name.stx.name.as_str();
          if lexical_seen.contains(name_str) {
            return Err(syntax_error(
              stmt.loc,
              "Identifier has already been declared",
            ));
          }
          lexical_seen
            .try_reserve(1)
            .map_err(|_| VmError::OutOfMemory)?;
          lexical_seen.insert(try_clone_string(name_str)?);
          lexical_bindings
            .try_reserve(1)
            .map_err(|_| VmError::OutOfMemory)?;
          lexical_bindings.push((try_clone_string(name_str)?, stmt.loc));
        }
        _ => {}
      }
    }

    for (name, loc) in &lexical_bindings {
      self.tick()?;
      if var_names.contains(name) {
        return Err(syntax_error(*loc, "Identifier has already been declared"));
      }
    }

    // --- GlobalDeclarationInstantiation runtime checks ---
    let global_object = self.env.global_object();
    let global_lex = self.env.lexical_env;

    // Step 5: For each name in lexNames, validate against the existing global environment.
    for (name, _loc) in &lexical_bindings {
      self.tick()?;

      if self.vm.global_var_names_contains(name) {
        return Err(throw_syntax_error(
          self.vm,
          scope,
          "Identifier has already been declared",
        )?);
      }
      if scope.heap().env_has_binding(global_lex, name)? {
        return Err(throw_syntax_error(
          self.vm,
          scope,
          "Identifier has already been declared",
        )?);
      }
      if self.has_restricted_global_property(scope, global_object, name)? {
        return Err(throw_syntax_error(
          self.vm,
          scope,
          "Identifier has already been declared",
        )?);
      }
    }

    // Collect var-scoped function declarations (in source order) for steps 10/17.
    let mut function_decls: Vec<&Node<FuncDecl>> = Vec::new();
    self.collect_var_scoped_function_decls_in_stmt_list(stmts, &mut function_decls)?;

    // Collect var-declared names (in source order) for steps 6/12/18.
    let mut var_decl_names: Vec<String> = Vec::new();
    self.collect_var_declared_names_in_stmt_list(stmts, &mut var_decl_names)?;

    // Step 6: For each name in varNames, reject collisions with existing lexical declarations.
    let mut var_names_to_check: Vec<&str> = Vec::new();
    let mut seen_var_name: HashSet<&str> = HashSet::new();
    for name in var_decl_names.iter().map(|n| n.as_str()).chain(
      function_decls
        .iter()
        .filter_map(|decl| decl.stx.name.as_ref().map(|n| n.stx.name.as_str())),
    ) {
      if seen_var_name.contains(name) {
        continue;
      }
      seen_var_name
        .try_reserve(1)
        .map_err(|_| VmError::OutOfMemory)?;
      seen_var_name.insert(name);
      var_names_to_check
        .try_reserve(1)
        .map_err(|_| VmError::OutOfMemory)?;
      var_names_to_check.push(name);
    }

    for &name in &var_names_to_check {
      self.tick()?;
      if scope.heap().env_has_binding(global_lex, name)? {
        return Err(throw_syntax_error(
          self.vm,
          scope,
          "Identifier has already been declared",
        )?);
      }
    }

    // Step 10: Determine which function declarations to initialize (last declaration wins), and
    // validate CanDeclareGlobalFunction for each.
    let mut declared_function_names: HashSet<&str> = HashSet::new();
    let mut functions_to_initialize_rev: Vec<&Node<FuncDecl>> = Vec::new();
    for decl in function_decls.iter().rev() {
      self.tick()?;
      let Some(name) = &decl.stx.name else {
        return Err(VmError::Unimplemented("anonymous function declaration"));
      };
      let name_str = name.stx.name.as_str();
      if declared_function_names.contains(name_str) {
        continue;
      }
      if !self.can_declare_global_function(scope, global_object, name_str)? {
        return Err(throw_type_error(
          self.vm,
          scope,
          "Cannot declare global function",
        )?);
      }
      if declared_function_names.try_reserve(1).is_err() {
        return Err(VmError::OutOfMemory);
      }
      declared_function_names.insert(name_str);
      functions_to_initialize_rev
        .try_reserve(1)
        .map_err(|_| VmError::OutOfMemory)?;
      functions_to_initialize_rev.push(*decl);
    }
    let mut functions_to_initialize = functions_to_initialize_rev;
    functions_to_initialize.reverse();

    // Step 12: Validate CanDeclareGlobalVar for each var-declared name (excluding function names),
    // and compute the final `declaredVarNames` list.
    let mut declared_var_names: Vec<&str> = Vec::new();
    let mut declared_var_set: HashSet<&str> = HashSet::new();
    for name in &var_decl_names {
      self.tick()?;
      let name_str = name.as_str();
      if declared_function_names.contains(name_str) {
        continue;
      }
      if declared_var_set.contains(name_str) {
        continue;
      }
      if !self.can_declare_global_var(scope, global_object, name_str)? {
        return Err(throw_type_error(
          self.vm,
          scope,
          "Cannot declare global variable",
        )?);
      }
      if declared_var_set.try_reserve(1).is_err() {
        return Err(VmError::OutOfMemory);
      }
      declared_var_set.insert(name_str);
      declared_var_names
        .try_reserve(1)
        .map_err(|_| VmError::OutOfMemory)?;
      declared_var_names.push(name_str);
    }

    // Step 15/16: Create global lexical bindings (uninitialized).
    self.instantiate_lexical_decls_in_stmt_list(scope, global_lex, stmts)?;

    // Step 17: Instantiate functions and create their global bindings.
    for decl in &functions_to_initialize {
      self.tick()?;
      let Some(name) = &decl.stx.name else {
        return Err(VmError::Unimplemented("anonymous function declaration"));
      };
      let func_obj = self.create_function_object_for_decl(scope, decl, &name.stx.name)?;

      // Root the function object across key allocation and property definition.
      let mut def_scope = scope.reborrow();
      def_scope.push_root(Value::Object(func_obj))?;

      let key = PropertyKey::from_string(def_scope.alloc_string(&name.stx.name)?);
      def_scope.define_property(
        global_object,
        key,
        global_var_binding_desc(Value::Object(func_obj)),
      )?;
    }

    // Step 18: Create global var bindings (undefined-initialized properties on the global object).
    //
    // Track which `var` bindings actually created a new **non-deletable** global property so we
    // can extend the realm-scoped `[[VarNames]]` set accordingly. If the global object already has
    // an own property for `name`, `CreateGlobalVarBinding` is a no-op and must **not** add the name
    // to `[[VarNames]]` (mirroring V8: `var x` on an existing configurable property does not
    // prevent a later `let x` declaration in another script).
    let mut created_var_names: Vec<String> = Vec::new();
    for &name in &declared_var_names {
      self.tick()?;
      // Snapshot whether the global object already has an own property for `name` before we create
      // the global var binding.
      let existed = {
        let mut key_scope = scope.reborrow();
        key_scope.push_root(Value::Object(global_object))?;
        let key = PropertyKey::from_string(key_scope.alloc_string(name)?);
        key_scope
          .heap()
          .object_get_own_property_with_tick(global_object, &key, || self.tick())?
          .is_some()
      };
      self.env.declare_var(self.vm, scope, name)?;
      if !existed {
        created_var_names
          .try_reserve(1)
          .map_err(|_| VmError::OutOfMemory)?;
        created_var_names.push(try_clone_string(name)?);
      }
    }

    // Record `var`/function declaration names for future GlobalDeclarationInstantiation checks.
    let mut record: Vec<String> = Vec::new();
    record
      .try_reserve(
        created_var_names
          .len()
          .saturating_add(functions_to_initialize.len()),
      )
      .map_err(|_| VmError::OutOfMemory)?;
    for name in created_var_names {
      record.push(name);
    }
    for decl in functions_to_initialize {
      // Safe: scripts always have named function declarations here.
      if let Some(name) = &decl.stx.name {
        record.push(try_clone_string(name.stx.name.as_str())?);
      }
    }
    self.vm.global_var_names_insert_all(record)?;

    Ok(())
  }

  fn instantiate_stmt_list(
    &mut self,
    scope: &mut Scope<'_>,
    stmts: &[Node<Stmt>],
  ) -> Result<(), VmError> {
    // Destructuring `var`/`let` declarations always require an initializer (ECMA-262 early error).
    //
    // This must run before any hoisting so invalid declarations do not partially pollute the
    // function/global environment.
    for stmt in stmts {
      self.destructuring_decl_without_initializer_early_error(stmt)?;
    }

    if self.strict {
      for stmt in stmts {
        self.strict_mode_with_early_error(stmt)?;
      }
    }

    self.label_early_errors_in_stmt_list(stmts)?;

    // Minimal early error checks:
    // - Duplicate lexical declarations (let/const) in the same statement list.
    // - Lexical declarations may not collide with var-scoped names (var + function declarations).
    let mut var_names = HashSet::<String>::new();
    for stmt in stmts {
      self.collect_var_names(&stmt.stx, &mut var_names)?;
    }

    if self.strict {
      // Strict mode: only top-level function declarations are var-scoped; block function
      // declarations are instantiated at block entry.
      for stmt in stmts {
        self.tick()?;
        let Stmt::FunctionDecl(decl) = &*stmt.stx else {
          continue;
        };
        let Some(name) = &decl.stx.name else {
          // `export default function() {}` is parsed as an anonymous function declaration with an
          // engine-internal `*default*` binding created during module linking. It does not
          // participate in var-scoped name collision checks.
          if decl.stx.export_default {
            continue;
          }
          return Err(VmError::Unimplemented("anonymous function declaration"));
        };
        let name_str = name.stx.name.as_str();
        if !var_names.contains(name_str) {
          var_names.try_reserve(1).map_err(|_| VmError::OutOfMemory)?;
          var_names.insert(try_clone_string(name_str)?);
        }
      }
    } else {
      // Non-strict mode: treat block function declarations as var-scoped (Annex B-ish).
      for stmt in stmts {
        self.collect_sloppy_function_decl_names(&stmt.stx, &mut var_names)?;
      }
    }

    let mut lexical_seen = HashSet::<String>::new();
    let mut lexical_bindings: Vec<(String, parse_js::loc::Loc)> = Vec::new();
    for stmt in stmts {
      self.tick()?;
      match &*stmt.stx {
        Stmt::VarDecl(var) => {
          if !matches!(
            var.stx.mode,
            VarDeclMode::Let | VarDeclMode::Const | VarDeclMode::Using | VarDeclMode::AwaitUsing
          ) {
            continue;
          }
          for declarator in &var.stx.declarators {
            self.tick()?;
            if matches!(
              var.stx.mode,
              VarDeclMode::Const | VarDeclMode::Using | VarDeclMode::AwaitUsing
            ) && declarator.initializer.is_none()
            {
              let message = match var.stx.mode {
                VarDeclMode::Const => "Missing initializer in const declaration",
                VarDeclMode::Using => "Missing initializer in using declaration",
                VarDeclMode::AwaitUsing => "Missing initializer in await using declaration",
                _ => unreachable!(),
              };
              return Err(syntax_error(declarator.pattern.loc, message));
            }
            self.collect_lexical_decl_names_from_pat(
              &declarator.pattern.stx.pat.stx,
              stmt.loc,
              &mut lexical_seen,
              &mut lexical_bindings,
            )?;
          }
        }
        Stmt::ClassDecl(class) => {
          let Some(name) = class.stx.name.as_ref() else {
            continue;
          };
          let name_str = name.stx.name.as_str();
          if lexical_seen.contains(name_str) {
            return Err(syntax_error(
              stmt.loc,
              "Identifier has already been declared",
            ));
          }
          lexical_seen
            .try_reserve(1)
            .map_err(|_| VmError::OutOfMemory)?;
          lexical_seen.insert(try_clone_string(name_str)?);
          lexical_bindings
            .try_reserve(1)
            .map_err(|_| VmError::OutOfMemory)?;
          lexical_bindings.push((try_clone_string(name_str)?, stmt.loc));
        }
        _ => {}
      }
    }

    for (name, loc) in &lexical_bindings {
      // Budget the lexical-vs-var collision check: a statement list can contain very large numbers
      // of lexical bindings (e.g. `let a0,a1,...`) and we must still observe budgets/interrupts
      // while checking each name against the var-scoped set.
      self.tick()?;
      if var_names.contains(name) {
        return Err(syntax_error(*loc, "Identifier has already been declared"));
      }
    }

    self.instantiate_var_decls(scope, stmts)?;
    let lex = self.env.lexical_env;
    self.instantiate_lexical_decls_in_stmt_list(scope, lex, stmts)?;
    self.instantiate_var_scoped_function_decls_in_stmt_list(scope, stmts)?;
    Ok(())
  }

  fn destructuring_decl_without_initializer_early_error(
    &mut self,
    stmt: &Node<Stmt>,
  ) -> Result<(), VmError> {
    // This mirrors the recursive structure of `VarDeclaredNames`/`strict_mode_with_early_error`
    // traversals so we reject invalid declarations even when they appear in syntactically nested
    // statement lists (e.g. a dead `if (false) { ... }` branch).
    self.tick()?;

    let check_decl = |this: &mut Self, decl: &VarDecl| -> Result<(), VmError> {
      if decl.mode != VarDeclMode::Var && decl.mode != VarDeclMode::Let {
        return Ok(());
      }
      for declarator in &decl.declarators {
        this.tick()?;
        if declarator.initializer.is_none()
          && !matches!(&*declarator.pattern.stx.pat.stx, Pat::Id(_))
        {
          return Err(syntax_error(
            declarator.pattern.loc,
            "Missing initializer in destructuring declaration",
          ));
        }
      }
      Ok(())
    };

    match &*stmt.stx {
      Stmt::VarDecl(var) => check_decl(self, &var.stx),
      Stmt::Block(block) => {
        for s in &block.stx.body {
          self.destructuring_decl_without_initializer_early_error(s)?;
        }
        Ok(())
      }
      Stmt::If(stmt) => {
        self.destructuring_decl_without_initializer_early_error(&stmt.stx.consequent)?;
        if let Some(alt) = &stmt.stx.alternate {
          self.destructuring_decl_without_initializer_early_error(alt)?;
        }
        Ok(())
      }
      Stmt::Try(stmt) => {
        for s in &stmt.stx.wrapped.stx.body {
          self.destructuring_decl_without_initializer_early_error(s)?;
        }
        if let Some(catch) = &stmt.stx.catch {
          for s in &catch.stx.body {
            self.destructuring_decl_without_initializer_early_error(s)?;
          }
        }
        if let Some(finally) = &stmt.stx.finally {
          for s in &finally.stx.body {
            self.destructuring_decl_without_initializer_early_error(s)?;
          }
        }
        Ok(())
      }
      Stmt::With(stmt) => self.destructuring_decl_without_initializer_early_error(&stmt.stx.body),
      Stmt::While(stmt) => self.destructuring_decl_without_initializer_early_error(&stmt.stx.body),
      Stmt::DoWhile(stmt) => {
        self.destructuring_decl_without_initializer_early_error(&stmt.stx.body)
      }
      Stmt::ForTriple(stmt) => {
        if let parse_js::ast::stmt::ForTripleStmtInit::Decl(decl) = &stmt.stx.init {
          check_decl(self, &decl.stx)?;
        }
        for s in &stmt.stx.body.stx.body {
          self.destructuring_decl_without_initializer_early_error(s)?;
        }
        Ok(())
      }
      Stmt::ForIn(stmt) => {
        // `for (var {x} in obj)` / `for (let {x} in obj)` are valid: bindings are per-iteration.
        for s in &stmt.stx.body.stx.body {
          self.destructuring_decl_without_initializer_early_error(s)?;
        }
        Ok(())
      }
      Stmt::ForOf(stmt) => {
        // `for (var {x} of iter)` / `for (let {x} of iter)` are valid: bindings are per-iteration.
        for s in &stmt.stx.body.stx.body {
          self.destructuring_decl_without_initializer_early_error(s)?;
        }
        Ok(())
      }
      Stmt::Label(stmt) => {
        self.destructuring_decl_without_initializer_early_error(&stmt.stx.statement)
      }
      Stmt::Switch(stmt) => {
        const BRANCH_TICK_EVERY: usize = 32;
        for (i, branch) in stmt.stx.branches.iter().enumerate() {
          if i % BRANCH_TICK_EVERY == 0 {
            self.tick()?;
          }
          for s in &branch.stx.body {
            self.destructuring_decl_without_initializer_early_error(s)?;
          }
        }
        Ok(())
      }
      _ => Ok(()),
    }
  }

  fn label_early_errors_in_stmt_list(&mut self, stmts: &[Node<Stmt>]) -> Result<(), VmError> {
    #[derive(Default)]
    struct Ctx<'a> {
      /// Active labels (labelSet).
      labels: HashSet<&'a str>,
      /// Labels that denote an iteration statement (iterationSet).
      iteration_labels: HashSet<&'a str>,
      /// Depth of enclosing iteration statements (`while`, `for`, etc).
      iteration_depth: usize,
      /// Depth of enclosing breakable statements (`switch` + iterations).
      breakable_depth: usize,
    }

    fn is_iteration_stmt(stmt: &Stmt) -> bool {
      matches!(
        stmt,
        Stmt::While(_) | Stmt::DoWhile(_) | Stmt::ForTriple(_) | Stmt::ForIn(_) | Stmt::ForOf(_)
      )
    }

    fn first_non_label_stmt<'a>(mut stmt: &'a Node<Stmt>) -> &'a Node<Stmt> {
      loop {
        match &*stmt.stx {
          Stmt::Label(label) => stmt = &label.stx.statement,
          _ => return stmt,
        }
      }
    }

    fn collect_label_chain<'a>(
      mut stmt: &'a Node<Stmt>,
      out: &mut Vec<(&'a str, parse_js::loc::Loc)>,
    ) -> Result<&'a Node<Stmt>, VmError> {
      loop {
        match &*stmt.stx {
          Stmt::Label(label) => {
            out.try_reserve(1).map_err(|_| VmError::OutOfMemory)?;
            out.push((label.stx.name.as_str(), stmt.loc));
            stmt = &label.stx.statement;
          }
          _ => return Ok(stmt),
        }
      }
    }

    fn pop_label_chain<'a>(
      ctx: &mut Ctx<'a>,
      labels: &[(&'a str, parse_js::loc::Loc)],
      is_iteration: bool,
    ) {
      for (name, _) in labels.iter().rev() {
        ctx.labels.remove(name);
        if is_iteration {
          ctx.iteration_labels.remove(name);
        }
      }
    }

    fn check_stmt<'a>(
      this: &mut Evaluator<'_>,
      stmt: &'a Node<Stmt>,
      ctx: &mut Ctx<'a>,
    ) -> Result<(), VmError> {
      this.tick()?;

      match &*stmt.stx {
        Stmt::Label(_) => {
          let mut labels: Vec<(&'a str, parse_js::loc::Loc)> = Vec::new();
          let base = collect_label_chain(stmt, &mut labels)?;
          let base_non_label = first_non_label_stmt(base);
          let is_iteration = is_iteration_stmt(&base_non_label.stx);

          for (name, loc) in &labels {
            this.tick()?;
            if ctx.labels.contains(name) {
              let message =
                crate::fallible_format::try_format_error_message("Duplicate label '", name, "'")?;
              return Err(syntax_error(*loc, message));
            }
            ctx
              .labels
              .try_reserve(1)
              .map_err(|_| VmError::OutOfMemory)?;
            ctx.labels.insert(*name);
            if is_iteration {
              ctx
                .iteration_labels
                .try_reserve(1)
                .map_err(|_| VmError::OutOfMemory)?;
              ctx.iteration_labels.insert(*name);
            }
          }

          check_stmt(this, base, ctx)?;
          pop_label_chain(ctx, &labels, is_iteration);
          Ok(())
        }
        Stmt::Break(break_stmt) => match break_stmt.stx.label.as_deref() {
          None => {
            if ctx.breakable_depth == 0 {
              return Err(syntax_error(stmt.loc, "Illegal break statement"));
            }
            Ok(())
          }
          Some(label) => {
            if !ctx.labels.contains(label) {
              let message =
                crate::fallible_format::try_format_error_message("Undefined label '", label, "'")?;
              return Err(syntax_error(stmt.loc, message));
            }
            Ok(())
          }
        },
        Stmt::Continue(continue_stmt) => match continue_stmt.stx.label.as_deref() {
          None => {
            if ctx.iteration_depth == 0 {
              return Err(syntax_error(stmt.loc, "Illegal continue statement"));
            }
            Ok(())
          }
          Some(label) => {
            if !ctx.iteration_labels.contains(label) {
              let message = crate::fallible_format::try_format_error_message(
                "Illegal continue statement: '",
                label,
                "' does not denote an iteration statement",
              )?;
              return Err(syntax_error(stmt.loc, message));
            }
            Ok(())
          }
        },
        Stmt::Block(block) => check_stmt_list(this, &block.stx.body, ctx),
        Stmt::If(stmt) => {
          check_stmt(this, &stmt.stx.consequent, ctx)?;
          if let Some(alt) = &stmt.stx.alternate {
            check_stmt(this, alt, ctx)?;
          }
          Ok(())
        }
        Stmt::Try(stmt) => {
          check_stmt_list(this, &stmt.stx.wrapped.stx.body, ctx)?;
          if let Some(catch) = &stmt.stx.catch {
            check_stmt_list(this, &catch.stx.body, ctx)?;
          }
          if let Some(finally) = &stmt.stx.finally {
            check_stmt_list(this, &finally.stx.body, ctx)?;
          }
          Ok(())
        }
        Stmt::With(stmt) => check_stmt(this, &stmt.stx.body, ctx),
        Stmt::While(stmt) => {
          ctx.iteration_depth = ctx.iteration_depth.saturating_add(1);
          ctx.breakable_depth = ctx.breakable_depth.saturating_add(1);
          let res = check_stmt(this, &stmt.stx.body, ctx);
          ctx.iteration_depth = ctx.iteration_depth.saturating_sub(1);
          ctx.breakable_depth = ctx.breakable_depth.saturating_sub(1);
          res
        }
        Stmt::DoWhile(stmt) => {
          ctx.iteration_depth = ctx.iteration_depth.saturating_add(1);
          ctx.breakable_depth = ctx.breakable_depth.saturating_add(1);
          let res = check_stmt(this, &stmt.stx.body, ctx);
          ctx.iteration_depth = ctx.iteration_depth.saturating_sub(1);
          ctx.breakable_depth = ctx.breakable_depth.saturating_sub(1);
          res
        }
        Stmt::ForTriple(stmt) => {
          ctx.iteration_depth = ctx.iteration_depth.saturating_add(1);
          ctx.breakable_depth = ctx.breakable_depth.saturating_add(1);
          let res = check_stmt_list(this, &stmt.stx.body.stx.body, ctx);
          ctx.iteration_depth = ctx.iteration_depth.saturating_sub(1);
          ctx.breakable_depth = ctx.breakable_depth.saturating_sub(1);
          res
        }
        Stmt::ForIn(stmt) => {
          ctx.iteration_depth = ctx.iteration_depth.saturating_add(1);
          ctx.breakable_depth = ctx.breakable_depth.saturating_add(1);
          let res = check_stmt_list(this, &stmt.stx.body.stx.body, ctx);
          ctx.iteration_depth = ctx.iteration_depth.saturating_sub(1);
          ctx.breakable_depth = ctx.breakable_depth.saturating_sub(1);
          res
        }
        Stmt::ForOf(stmt) => {
          ctx.iteration_depth = ctx.iteration_depth.saturating_add(1);
          ctx.breakable_depth = ctx.breakable_depth.saturating_add(1);
          let res = check_stmt_list(this, &stmt.stx.body.stx.body, ctx);
          ctx.iteration_depth = ctx.iteration_depth.saturating_sub(1);
          ctx.breakable_depth = ctx.breakable_depth.saturating_sub(1);
          res
        }
        Stmt::Switch(stmt) => {
          ctx.breakable_depth = ctx.breakable_depth.saturating_add(1);
          const BRANCH_TICK_EVERY: usize = 32;
          let mut result = Ok(());
          for (i, branch) in stmt.stx.branches.iter().enumerate() {
            if i % BRANCH_TICK_EVERY == 0 && i != 0 {
              this.tick()?;
            }
            result = check_stmt_list(this, &branch.stx.body, ctx);
            if result.is_err() {
              break;
            }
          }
          ctx.breakable_depth = ctx.breakable_depth.saturating_sub(1);
          result
        }
        _ => Ok(()),
      }
    }

    fn check_stmt_list<'a>(
      this: &mut Evaluator<'_>,
      stmts: &'a [Node<Stmt>],
      ctx: &mut Ctx<'a>,
    ) -> Result<(), VmError> {
      const TICK_EVERY: usize = 32;
      for (i, stmt) in stmts.iter().enumerate() {
        if i % TICK_EVERY == 0 {
          this.tick()?;
        }
        check_stmt(this, stmt, ctx)?;
      }
      Ok(())
    }

    let mut ctx = Ctx::default();
    check_stmt_list(self, stmts, &mut ctx)
  }

  fn strict_mode_with_early_error(&mut self, stmt: &Node<Stmt>) -> Result<(), VmError> {
    // `with` is a strict mode early error (ECMA-262 14.11.1 Static Semantics: Early Errors).
    //
    // We run this check during instantiation so strict-mode failures do not partially hoist `var`
    // bindings before throwing.
    self.tick()?;

    match &*stmt.stx {
      Stmt::With(_) => Err(syntax_error(
        stmt.loc,
        "with statements are not allowed in strict mode",
      )),
      Stmt::Block(block) => {
        for s in &block.stx.body {
          self.strict_mode_with_early_error(s)?;
        }
        Ok(())
      }
      Stmt::If(stmt) => {
        self.strict_mode_with_early_error(&stmt.stx.consequent)?;
        if let Some(alt) = &stmt.stx.alternate {
          self.strict_mode_with_early_error(alt)?;
        }
        Ok(())
      }
      Stmt::Try(stmt) => {
        for s in &stmt.stx.wrapped.stx.body {
          self.strict_mode_with_early_error(s)?;
        }
        if let Some(catch) = &stmt.stx.catch {
          for s in &catch.stx.body {
            self.strict_mode_with_early_error(s)?;
          }
        }
        if let Some(finally) = &stmt.stx.finally {
          for s in &finally.stx.body {
            self.strict_mode_with_early_error(s)?;
          }
        }
        Ok(())
      }
      Stmt::While(stmt) => self.strict_mode_with_early_error(&stmt.stx.body),
      Stmt::DoWhile(stmt) => self.strict_mode_with_early_error(&stmt.stx.body),
      Stmt::ForTriple(stmt) => {
        for s in &stmt.stx.body.stx.body {
          self.strict_mode_with_early_error(s)?;
        }
        Ok(())
      }
      Stmt::ForIn(stmt) => {
        for s in &stmt.stx.body.stx.body {
          self.strict_mode_with_early_error(s)?;
        }
        Ok(())
      }
      Stmt::ForOf(stmt) => {
        for s in &stmt.stx.body.stx.body {
          self.strict_mode_with_early_error(s)?;
        }
        Ok(())
      }
      Stmt::Label(stmt) => self.strict_mode_with_early_error(&stmt.stx.statement),
      Stmt::Switch(stmt) => {
        const BRANCH_TICK_EVERY: usize = 32;
        for (i, branch) in stmt.stx.branches.iter().enumerate() {
          if i % BRANCH_TICK_EVERY == 0 {
            self.tick()?;
          }
          for s in &branch.stx.body {
            self.strict_mode_with_early_error(s)?;
          }
        }
        Ok(())
      }
      _ => Ok(()),
    }
  }

  fn instantiate_var_decls(
    &mut self,
    scope: &mut Scope<'_>,
    stmts: &[Node<Stmt>],
  ) -> Result<(), VmError> {
    let mut names = HashSet::<String>::new();
    for stmt in stmts {
      self.collect_var_names(&stmt.stx, &mut names)?;
    }
    for name in names {
      self.tick()?;
      self.env.declare_var(self.vm, scope, &name)?;
    }
    Ok(())
  }

  fn instantiate_var_scoped_function_decls_in_stmt_list(
    &mut self,
    scope: &mut Scope<'_>,
    stmts: &[Node<Stmt>],
  ) -> Result<(), VmError> {
    if self.strict {
      for stmt in stmts {
        self.tick()?;
        let Stmt::FunctionDecl(decl) = &*stmt.stx else {
          continue;
        };
        self.instantiate_function_decl(scope, decl)?;
      }
      return Ok(());
    }

    for stmt in stmts {
      self.instantiate_var_scoped_function_decls_in_stmt(scope, &stmt.stx, true, false)?;
    }
    Ok(())
  }

  #[inline]
  fn is_annex_b_eligible_sloppy_function_decl(decl: &Node<FuncDecl>) -> bool {
    // Annex B block-level function hoisting only applies to *ordinary* function declarations.
    // Generator/async/async-generator declarations are always block-scoped, even in non-strict mode.
    let func = &decl.stx.function.stx;
    !func.async_ && !func.generator
  }

  #[inline]
  fn is_non_annex_b_hoistable_decl(decl: &Node<FuncDecl>) -> bool {
    let func = &decl.stx.function.stx;
    func.async_ || func.generator
  }

  fn instantiate_var_scoped_function_decls_in_stmt(
    &mut self,
    scope: &mut Scope<'_>,
    stmt: &Stmt,
    in_stmt_list: bool,
    in_block_stmt_list: bool,
  ) -> Result<(), VmError> {
    self.tick()?;
    match stmt {
      Stmt::FunctionDecl(decl) => {
        // In non-strict mode, Annex B allows certain block-level *ordinary* function declarations to
        // be instantiated in the var environment.
        //
        // For function declarations that appear *directly* in a nested block statement list (e.g.
        // `{ function f() {} }`), instantiating the function object here would capture the *outer*
        // lexical environment instead of the block's lexical environment. Those declarations are
        // instantiated at block entry by `instantiate_block_decls_in_stmt_list`.
        //
        // We still treat function declarations in "statement position" (e.g. `if (cond)
        // function f() {}`) as var-scoped here, since they are not evaluated within an explicit
        // block lexical environment in the current AST representation.
        if in_stmt_list
          || (Self::is_annex_b_eligible_sloppy_function_decl(decl) && !in_block_stmt_list)
        {
          self.instantiate_function_decl(scope, decl)
        } else {
          Ok(())
        }
      }
      Stmt::Block(block) => {
        for stmt in &block.stx.body {
          self.instantiate_var_scoped_function_decls_in_stmt(scope, &stmt.stx, false, true)?;
        }
        Ok(())
      }
      Stmt::If(stmt) => {
        self.instantiate_var_scoped_function_decls_in_stmt(
          scope,
          &stmt.stx.consequent.stx,
          false,
          false,
        )?;
        if let Some(alt) = &stmt.stx.alternate {
          self.instantiate_var_scoped_function_decls_in_stmt(scope, &alt.stx, false, false)?;
        }
        Ok(())
      }
      Stmt::Try(stmt) => {
        for s in &stmt.stx.wrapped.stx.body {
          self.instantiate_var_scoped_function_decls_in_stmt(scope, &s.stx, false, true)?;
        }
        if let Some(catch) = &stmt.stx.catch {
          for s in &catch.stx.body {
            self.instantiate_var_scoped_function_decls_in_stmt(scope, &s.stx, false, true)?;
          }
        }
        if let Some(finally) = &stmt.stx.finally {
          for s in &finally.stx.body {
            self.instantiate_var_scoped_function_decls_in_stmt(scope, &s.stx, false, true)?;
          }
        }
        Ok(())
      }
      Stmt::With(stmt) => {
        self.instantiate_var_scoped_function_decls_in_stmt(scope, &stmt.stx.body.stx, false, false)
      }
      Stmt::While(stmt) => {
        self.instantiate_var_scoped_function_decls_in_stmt(scope, &stmt.stx.body.stx, false, false)
      }
      Stmt::DoWhile(stmt) => {
        self.instantiate_var_scoped_function_decls_in_stmt(scope, &stmt.stx.body.stx, false, false)
      }
      Stmt::ForTriple(stmt) => {
        for s in &stmt.stx.body.stx.body {
          self.instantiate_var_scoped_function_decls_in_stmt(scope, &s.stx, false, true)?;
        }
        Ok(())
      }
      Stmt::ForIn(stmt) => {
        for s in &stmt.stx.body.stx.body {
          self.instantiate_var_scoped_function_decls_in_stmt(scope, &s.stx, false, true)?;
        }
        Ok(())
      }
      Stmt::ForOf(stmt) => {
        for s in &stmt.stx.body.stx.body {
          self.instantiate_var_scoped_function_decls_in_stmt(scope, &s.stx, false, true)?;
        }
        Ok(())
      }
      Stmt::Label(stmt) => {
        self.instantiate_var_scoped_function_decls_in_stmt(
          scope,
          &stmt.stx.statement.stx,
          false,
          false,
        )
      }
      Stmt::Switch(stmt) => {
        const BRANCH_TICK_EVERY: usize = 32;
        for (i, branch) in stmt.stx.branches.iter().enumerate() {
          if i % BRANCH_TICK_EVERY == 0 {
            self.tick()?;
          }
          for s in &branch.stx.body {
            self.instantiate_var_scoped_function_decls_in_stmt(scope, &s.stx, false, true)?;
          }
        }
        Ok(())
      }
      _ => Ok(()),
    }
  }

  fn collect_sloppy_function_decl_names(
    &mut self,
    stmt: &Stmt,
    out: &mut HashSet<String>,
  ) -> Result<(), VmError> {
    self.collect_sloppy_function_decl_names_in_stmt(stmt, out, true)
  }

  fn collect_sloppy_function_decl_names_in_stmt(
    &mut self,
    stmt: &Stmt,
    out: &mut HashSet<String>,
    in_stmt_list: bool,
  ) -> Result<(), VmError> {
    self.tick()?;
    match stmt {
      Stmt::FunctionDecl(decl) => {
        // In non-strict mode, only *ordinary* function declarations participate in Annex B
        // block-level var-scoping. Generator/async declarations are always block-scoped.
        if in_stmt_list || Self::is_annex_b_eligible_sloppy_function_decl(decl) {
          let Some(name) = &decl.stx.name else {
            return Err(VmError::Unimplemented("anonymous function declaration"));
          };
          let name_str = name.stx.name.as_str();
          if !out.contains(name_str) {
            out.try_reserve(1).map_err(|_| VmError::OutOfMemory)?;
            out.insert(try_clone_string(name_str)?);
          }
        }
        Ok(())
      }
      Stmt::Block(block) => {
        for stmt in &block.stx.body {
          self.collect_sloppy_function_decl_names_in_stmt(&stmt.stx, out, false)?;
        }
        Ok(())
      }
      Stmt::If(stmt) => {
        self.collect_sloppy_function_decl_names_in_stmt(&stmt.stx.consequent.stx, out, false)?;
        if let Some(alt) = &stmt.stx.alternate {
          self.collect_sloppy_function_decl_names_in_stmt(&alt.stx, out, false)?;
        }
        Ok(())
      }
      Stmt::Try(stmt) => {
        for s in &stmt.stx.wrapped.stx.body {
          self.collect_sloppy_function_decl_names_in_stmt(&s.stx, out, false)?;
        }
        if let Some(catch) = &stmt.stx.catch {
          for s in &catch.stx.body {
            self.collect_sloppy_function_decl_names_in_stmt(&s.stx, out, false)?;
          }
        }
        if let Some(finally) = &stmt.stx.finally {
          for s in &finally.stx.body {
            self.collect_sloppy_function_decl_names_in_stmt(&s.stx, out, false)?;
          }
        }
        Ok(())
      }
      Stmt::With(stmt) => {
        self.collect_sloppy_function_decl_names_in_stmt(&stmt.stx.body.stx, out, false)
      }
      Stmt::While(stmt) => {
        self.collect_sloppy_function_decl_names_in_stmt(&stmt.stx.body.stx, out, false)
      }
      Stmt::DoWhile(stmt) => {
        self.collect_sloppy_function_decl_names_in_stmt(&stmt.stx.body.stx, out, false)
      }
      Stmt::ForTriple(stmt) => {
        for s in &stmt.stx.body.stx.body {
          self.collect_sloppy_function_decl_names_in_stmt(&s.stx, out, false)?;
        }
        Ok(())
      }
      Stmt::ForIn(stmt) => {
        for s in &stmt.stx.body.stx.body {
          self.collect_sloppy_function_decl_names_in_stmt(&s.stx, out, false)?;
        }
        Ok(())
      }
      Stmt::ForOf(stmt) => {
        for s in &stmt.stx.body.stx.body {
          self.collect_sloppy_function_decl_names_in_stmt(&s.stx, out, false)?;
        }
        Ok(())
      }
      Stmt::Label(stmt) => {
        self.collect_sloppy_function_decl_names_in_stmt(&stmt.stx.statement.stx, out, false)
      }
      Stmt::Switch(stmt) => {
        const BRANCH_TICK_EVERY: usize = 32;
        for (i, branch) in stmt.stx.branches.iter().enumerate() {
          if i % BRANCH_TICK_EVERY == 0 {
            self.tick()?;
          }
          for s in &branch.stx.body {
            self.collect_sloppy_function_decl_names_in_stmt(&s.stx, out, false)?;
          }
        }
        Ok(())
      }
      _ => Ok(()),
    }
  }

  fn collect_lexical_decl_names_from_pat(
    &mut self,
    pat: &Pat,
    loc: parse_js::loc::Loc,
    seen: &mut HashSet<String>,
    out: &mut Vec<(String, parse_js::loc::Loc)>,
  ) -> Result<(), VmError> {
    match pat {
      Pat::Id(id) => {
        let name_str = id.stx.name.as_str();
        if seen.contains(name_str) {
          return Err(syntax_error(loc, "Identifier has already been declared"));
        }
        seen.try_reserve(1).map_err(|_| VmError::OutOfMemory)?;
        out.try_reserve(1).map_err(|_| VmError::OutOfMemory)?;
        seen.insert(try_clone_string(name_str)?);
        out.push((try_clone_string(name_str)?, loc));
        Ok(())
      }
      Pat::Obj(obj) => {
        for prop in &obj.stx.properties {
          self.tick()?;
          self.collect_lexical_decl_names_from_pat(&prop.stx.target.stx, loc, seen, out)?;
        }
        if let Some(rest) = &obj.stx.rest {
          self.tick()?;
          self.collect_lexical_decl_names_from_pat(&rest.stx, loc, seen, out)?;
        }
        Ok(())
      }
      Pat::Arr(arr) => {
        for elem in &arr.stx.elements {
          self.tick()?;
          if let Some(elem) = elem {
            self.collect_lexical_decl_names_from_pat(&elem.target.stx, loc, seen, out)?;
          }
        }
        if let Some(rest) = &arr.stx.rest {
          self.tick()?;
          self.collect_lexical_decl_names_from_pat(&rest.stx, loc, seen, out)?;
        }
        Ok(())
      }
      Pat::AssignTarget(_) => Err(VmError::Unimplemented(
        "lexical declaration assignment targets",
      )),
    }
  }

  fn instantiate_function_decl(
    &mut self,
    scope: &mut Scope<'_>,
    decl: &Node<FuncDecl>,
  ) -> Result<(), VmError> {
    if decl.stx.export_default && decl.stx.name.is_none() {
      // `export default function() {}` is represented by `parse-js` as a function declaration with
      // `export_default = true` and `name = None`.
      //
      // Module linking creates an immutable `*default*` binding; module instantiation is
      // responsible for creating the function object and initializing that binding.
      let func_obj = self.create_function_object_for_decl(scope, decl, "default")?;

      let mut init_scope = scope.reborrow();
      init_scope.push_root(Value::Object(func_obj))?;
      let binding_name = "*default*";
      if !init_scope
        .heap()
        .env_has_binding(self.env.lexical_env, binding_name)?
      {
        return Err(VmError::InvariantViolation(
          "export default function declaration missing *default* binding",
        ));
      }
      init_scope.heap_mut().env_initialize_binding(
        self.env.lexical_env,
        binding_name,
        Value::Object(func_obj),
      )?;
      return Ok(());
    }

    let Some(name) = &decl.stx.name else {
      return Err(VmError::Unimplemented("anonymous function declaration"));
    };

    let func_obj = self.create_function_object_for_decl(scope, decl, &name.stx.name)?;

    let mut assign_scope = scope.reborrow();
    assign_scope.push_root(Value::Object(func_obj))?;
    let (vm, env) = (&mut self.vm, &mut self.env);
    env.set_var(
      vm,
      &mut *self.host,
      &mut *self.hooks,
      &mut assign_scope,
      &name.stx.name,
      Value::Object(func_obj),
    )?;
    Ok(())
  }

  fn create_function_object_for_decl(
    &mut self,
    scope: &mut Scope<'_>,
    decl: &Node<FuncDecl>,
    name: &str,
  ) -> Result<GcObject, VmError> {
    use crate::function::ThisMode;
    use crate::vm::EcmaFunctionKind;

    let func = &decl.stx.function.stx;
    let is_generator = func.generator;
    let is_async_generator = func.generator && func.async_;
    let is_strict = self.strict
      || match &func.body {
        Some(FuncBody::Block(stmts)) => detect_use_strict_directive(
          self.env.source().text.as_ref(),
          self.env.base_offset() as usize,
          self.env.prefix_len() as usize,
          stmts,
          || self.tick(),
        )?,
        Some(FuncBody::Expression(_)) => false,
        None => return Err(VmError::Unimplemented("function without body")),
      };

    let this_mode = if func.arrow {
      ThisMode::Lexical
    } else if is_strict {
      ThisMode::Strict
    } else {
      ThisMode::Global
    };

    let name_s = scope.alloc_string(name)?;
    let length = self.function_length(func)?;

    let rel_start = decl.loc.start_u32().saturating_sub(self.env.prefix_len());
    let rel_end = decl.loc.end_u32().saturating_sub(self.env.prefix_len());
    let span_start = self.env.base_offset().saturating_add(rel_start);
    let span_end = self.env.base_offset().saturating_add(rel_end);

    let code_id = self.vm.register_ecma_function(
      self.env.source(),
      span_start,
      span_end,
      EcmaFunctionKind::Decl,
    )?;
    let func_obj = scope.alloc_ecma_function(
      code_id,
      // Async and generator functions are not constructable.
      /* is_constructable */
      !func.async_ && !is_generator,
      name_s,
      length,
      this_mode,
      is_strict,
      Some(self.env.lexical_env),
    )?;
    let intr = self
      .vm
      .intrinsics()
      .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;
    scope.heap_mut().object_set_prototype(
      func_obj,
      Some(if is_generator {
        if is_async_generator {
          intr.async_generator_function_prototype()
        } else {
          intr.generator_function_prototype()
        }
      } else if func.async_ {
        intr.async_function_prototype()
      } else {
        intr.function_prototype()
      }),
    )?;
    scope
      .heap_mut()
      .set_function_realm(func_obj, self.env.global_object())?;
    if let Some(realm) = self.vm.current_realm() {
      scope.heap_mut().set_function_job_realm(func_obj, realm)?;
    }
    if let Some(script_or_module) = self.vm.get_active_script_or_module() {
      let token = self.vm.intern_script_or_module(script_or_module)?;
      scope
        .heap_mut()
        .set_function_script_or_module_token(func_obj, Some(token))?;
    }
    if is_generator {
      if is_async_generator {
        crate::function_properties::make_async_generator_function_instance_prototype(
          scope,
          func_obj,
          intr.async_generator_prototype(),
        )?;
      } else {
        crate::function_properties::make_generator_function_instance_prototype(
          scope,
          func_obj,
          intr.generator_prototype(),
        )?;
      }
    }
    Ok(func_obj)
  }

  fn create_class_constructor_object(
    &mut self,
    scope: &mut Scope<'_>,
    name: &str,
    length: u32,
    constructor_body: Option<GcObject>,
    super_value: Value,
    instance_field_count: usize,
  ) -> Result<GcObject, VmError> {
    let intr = self
      .vm
      .intrinsics()
      .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;

    // Root the optional constructor body function and superclass value before allocating any
    // strings/function objects in case those allocations trigger GC.
    let mut init_scope = scope.reborrow();
    if let Some(body) = constructor_body {
      init_scope.push_root(Value::Object(body))?;
    }
    init_scope.push_root(super_value)?;

    let name_s = init_scope.alloc_string(name)?;
    let slots_len = crate::class_fields::CLASS_CTOR_SLOT_INSTANCE_FIELDS_START
      .saturating_add(instance_field_count.saturating_mul(2));
    let mut slots_vec: Vec<Value> = Vec::new();
    slots_vec
      .try_reserve_exact(slots_len)
      .map_err(|_| VmError::OutOfMemory)?;
    slots_vec.push(
      constructor_body
        .map(Value::Object)
        .unwrap_or(Value::Undefined),
    );
    slots_vec.push(super_value);
    slots_vec.resize(slots_len, Value::Undefined);

    let func_obj = init_scope.alloc_native_function_with_slots(
      intr.class_constructor_call(),
      Some(intr.class_constructor_construct()),
      name_s,
      length,
      &slots_vec,
    )?;
    init_scope.push_root(Value::Object(func_obj))?;

    // Per ECMA-262 `ClassDefinitionEvaluation`:
    // - base classes: `F.[[Prototype]] = %Function.prototype%`
    // - derived classes: `F.[[Prototype]] = superCtor` (static inheritance)
    let proto_parent = match super_value {
      Value::Object(super_ctor) => super_ctor,
      Value::Undefined | Value::Null => intr.function_prototype(),
      _ => {
        return Err(VmError::InvariantViolation(
          "class constructor super value is not undefined, null, or object",
        ))
      }
    };
    init_scope
      .heap_mut()
      .object_set_prototype(func_obj, Some(proto_parent))?;
    init_scope
      .heap_mut()
      .set_function_realm(func_obj, self.env.global_object())?;
    if let Some(realm) = self.vm.current_realm() {
      init_scope
        .heap_mut()
        .set_function_job_realm(func_obj, realm)?;
    }
    if let Some(script_or_module) = self.vm.get_active_script_or_module() {
      let token = self.vm.intern_script_or_module(script_or_module)?;
      init_scope
        .heap_mut()
        .set_function_script_or_module_token(func_obj, Some(token))?;
    }
    Ok(func_obj)
  }

  fn instantiate_block_decls_in_stmt_list(
    &mut self,
    scope: &mut Scope<'_>,
    env: GcEnv,
    stmts: &[Node<Stmt>],
  ) -> Result<(), VmError> {
    // Duplicate block-scoped declarations are early errors.
    //
    // Note: switch/catch share this helper even though their scope isn't a syntactic `{}` block.
    let mut seen = HashSet::<String>::new();
    for stmt in stmts {
      // Budget statement-list traversal even when it contains only function declarations (which are
      // instantiated in a later pass). Without this, a block containing many declarations could do
      // large `O(N)` early-error work without any budget checks.
      self.tick()?;
      match &*stmt.stx {
        Stmt::VarDecl(var)
          if matches!(
            var.stx.mode,
            VarDeclMode::Let | VarDeclMode::Const | VarDeclMode::Using | VarDeclMode::AwaitUsing
          ) =>
        {
          for declarator in &var.stx.declarators {
            self.tick()?;
            if matches!(
              var.stx.mode,
              VarDeclMode::Const | VarDeclMode::Using | VarDeclMode::AwaitUsing
            ) && declarator.initializer.is_none()
            {
              let message = match var.stx.mode {
                VarDeclMode::Const => "Missing initializer in const declaration",
                VarDeclMode::Using => "Missing initializer in using declaration",
                VarDeclMode::AwaitUsing => "Missing initializer in await using declaration",
                _ => unreachable!(),
              };
              return Err(syntax_error(
                declarator.pattern.loc,
                message,
              ));
            }
            // Reuse lexical declaration collection logic to detect duplicates across complex patterns.
            let mut tmp = Vec::new();
            self.collect_lexical_decl_names_from_pat(
              &declarator.pattern.stx.pat.stx,
              stmt.loc,
              &mut seen,
              &mut tmp,
            )?;
          }
        }
        Stmt::ClassDecl(decl) => {
          let Some(name) = decl.stx.name.as_ref() else {
            continue;
          };
          let name_str = name.stx.name.as_str();
          if seen.contains(name_str) {
            return Err(syntax_error(
              stmt.loc,
              "Identifier has already been declared",
            ));
          }
          seen.try_reserve(1).map_err(|_| VmError::OutOfMemory)?;
          seen.insert(try_clone_string(name_str)?);
        }
        Stmt::FunctionDecl(decl) if self.strict || Self::is_non_annex_b_hoistable_decl(decl) => {
          let Some(name) = &decl.stx.name else {
            return Err(VmError::Unimplemented("anonymous function declaration"));
          };
          let name_str = name.stx.name.as_str();
          if seen.contains(name_str) {
            return Err(syntax_error(
              stmt.loc,
              "Identifier has already been declared",
            ));
          }
          seen.try_reserve(1).map_err(|_| VmError::OutOfMemory)?;
          seen.insert(try_clone_string(name_str)?);
        }
        _ => {}
      }
    }

    self.instantiate_lexical_decls_in_stmt_list(scope, env, stmts)?;
    self.instantiate_block_scoped_function_decls_in_stmt_list(scope, env, stmts)?;
    Ok(())
  }

  fn instantiate_block_scoped_function_decls_in_stmt_list(
    &mut self,
    scope: &mut Scope<'_>,
    env: GcEnv,
    stmts: &[Node<Stmt>],
  ) -> Result<(), VmError> {
    for stmt in stmts {
      // Tick per statement list entry so large blocks of function declarations cannot be
      // instantiated without consuming fuel (and so we still check termination conditions even if
      // a prior pass used up all remaining fuel).
      self.tick()?;
      let Stmt::FunctionDecl(decl) = &*stmt.stx else {
        continue;
      };
      self.instantiate_block_scoped_function_decl(scope, env, decl)?;
    }
    Ok(())
  }

  fn instantiate_block_scoped_function_decl(
    &mut self,
    scope: &mut Scope<'_>,
    env: GcEnv,
    decl: &Node<FuncDecl>,
  ) -> Result<(), VmError> {
    let Some(name) = &decl.stx.name else {
      return Err(VmError::Unimplemented("anonymous function declaration"));
    };

    let has_binding = scope.heap().env_has_binding(env, &name.stx.name)?;
    if has_binding {
      // In non-strict mode, duplicate block-level *ordinary* function declarations are permitted
      // (Annex B). Later declarations update the existing binding.
      if self.strict || !Self::is_annex_b_eligible_sloppy_function_decl(decl) {
        return Err(syntax_error(decl.loc, "Identifier has already been declared"));
      }

      // If the binding exists but is uninitialized, it must have come from a conflicting lexical
      // declaration (`let`/`const`/`class`), which is an early error.
      match scope
        .heap()
        .env_get_binding_value(env, &name.stx.name, /* strict */ false)
      {
        Ok(_) => {}
        Err(VmError::Throw(Value::Null)) => {
          return Err(syntax_error(decl.loc, "Identifier has already been declared"))
        }
        Err(err) => return Err(err),
      }
    } else {
      scope.env_create_mutable_binding(env, &name.stx.name)?;
    }

    let func_obj = self.create_function_object_for_decl(scope, decl, &name.stx.name)?;

    let mut init_scope = scope.reborrow();
    init_scope.push_root(Value::Object(func_obj))?;
    if has_binding {
      init_scope.heap_mut().env_set_mutable_binding(
        env,
        &name.stx.name,
        Value::Object(func_obj),
        /* strict */ false,
      )?;
    } else {
      init_scope
        .heap_mut()
        .env_initialize_binding(env, &name.stx.name, Value::Object(func_obj))?;
    }
    Ok(())
  }

  fn instantiate_lexical_decls_in_stmt_list(
    &mut self,
    scope: &mut Scope<'_>,
    env: GcEnv,
    stmts: &[Node<Stmt>],
  ) -> Result<(), VmError> {
    for stmt in stmts {
      self.tick()?;
      match &*stmt.stx {
        Stmt::VarDecl(var) => match var.stx.mode {
          VarDeclMode::Let => {
            for declarator in &var.stx.declarators {
              self.tick()?;
              self.instantiate_lexical_names_from_pat(
                scope,
                env,
                &declarator.pattern.stx.pat.stx,
                stmt.loc,
                true,
              )?;
            }
          }
          VarDeclMode::Const | VarDeclMode::Using | VarDeclMode::AwaitUsing => {
            for declarator in &var.stx.declarators {
              self.tick()?;
              self.instantiate_lexical_names_from_pat(
                scope,
                env,
                &declarator.pattern.stx.pat.stx,
                stmt.loc,
                false,
              )?;
            }
          }
          _ => {}
        },
        Stmt::ClassDecl(class) => {
          let Some(name) = class.stx.name.as_ref() else {
            continue;
          };

          if scope.heap().env_has_binding(env, &name.stx.name)? {
            return Err(syntax_error(
              stmt.loc,
              "Identifier has already been declared",
            ));
          }
          scope.env_create_mutable_binding(env, &name.stx.name)?;
        }
        _ => {}
      }
    }
    Ok(())
  }

  fn instantiate_lexical_names_from_pat(
    &mut self,
    scope: &mut Scope<'_>,
    env: GcEnv,
    pat: &Pat,
    loc: parse_js::loc::Loc,
    mutable: bool,
  ) -> Result<(), VmError> {
    match pat {
      Pat::Id(id) => {
        if scope.heap().env_has_binding(env, &id.stx.name)? {
          return Err(syntax_error(loc, "Identifier has already been declared"));
        }
        if mutable {
          scope.env_create_mutable_binding(env, &id.stx.name)?;
        } else {
          scope.env_create_immutable_binding(env, &id.stx.name)?;
        }
        Ok(())
      }
      Pat::Obj(obj) => {
        for prop in &obj.stx.properties {
          self.tick()?;
          self.instantiate_lexical_names_from_pat(
            scope,
            env,
            &prop.stx.target.stx,
            loc,
            mutable,
          )?;
        }
        if let Some(rest) = &obj.stx.rest {
          self.tick()?;
          self.instantiate_lexical_names_from_pat(scope, env, &rest.stx, loc, mutable)?;
        }
        Ok(())
      }
      Pat::Arr(arr) => {
        for elem in &arr.stx.elements {
          self.tick()?;
          if let Some(elem) = elem {
            self.instantiate_lexical_names_from_pat(scope, env, &elem.target.stx, loc, mutable)?;
          }
        }
        if let Some(rest) = &arr.stx.rest {
          self.tick()?;
          self.instantiate_lexical_names_from_pat(scope, env, &rest.stx, loc, mutable)?;
        }
        Ok(())
      }
      Pat::AssignTarget(_) => Err(VmError::Unimplemented(
        "lexical declaration assignment targets",
      )),
    }
  }

  fn instantiate_param_names_from_pat(
    &mut self,
    scope: &mut Scope<'_>,
    env: GcEnv,
    pat: &Pat,
    loc: parse_js::loc::Loc,
  ) -> Result<(), VmError> {
    // Like `instantiate_lexical_names_from_pat`, but tolerant of duplicate names.
    //
    // Sloppy-mode functions with a *simple* parameter list may contain duplicate parameter names,
    // and those duplicates are not early errors. To support that, parameter binding instantiation
    // must only create each binding once.
    match pat {
      Pat::Id(id) => {
        if !scope.heap().env_has_binding(env, &id.stx.name)? {
          scope.env_create_mutable_binding(env, &id.stx.name)?;
        }
        Ok(())
      }
      Pat::Obj(obj) => {
        for prop in &obj.stx.properties {
          self.tick()?;
          self.instantiate_param_names_from_pat(scope, env, &prop.stx.target.stx, loc)?;
        }
        if let Some(rest) = &obj.stx.rest {
          self.tick()?;
          self.instantiate_param_names_from_pat(scope, env, &rest.stx, loc)?;
        }
        Ok(())
      }
      Pat::Arr(arr) => {
        for elem in &arr.stx.elements {
          self.tick()?;
          if let Some(elem) = elem {
            self.instantiate_param_names_from_pat(scope, env, &elem.target.stx, loc)?;
          }
        }
        if let Some(rest) = &arr.stx.rest {
          self.tick()?;
          self.instantiate_param_names_from_pat(scope, env, &rest.stx, loc)?;
        }
        Ok(())
      }
      Pat::AssignTarget(_) => Err(VmError::Unimplemented(
        "lexical declaration assignment targets",
      )),
    }
  }

  fn has_restricted_global_property(
    &mut self,
    scope: &mut Scope<'_>,
    global_object: GcObject,
    name: &str,
  ) -> Result<bool, VmError> {
    // GlobalEnvironmentRecord.HasRestrictedGlobalProperty (ECMA-262).
    //
    // Returns true iff the global object has an own property `name` that is non-configurable.
    let mut key_scope = scope.reborrow();
    key_scope.push_root(Value::Object(global_object))?;
    let key = PropertyKey::from_string(key_scope.alloc_string(name)?);
    let existing =
      key_scope
        .heap()
        .object_get_own_property_with_tick(global_object, &key, || self.tick())?;
    Ok(existing.is_some_and(|d| !d.configurable))
  }

  fn can_declare_global_var(
    &mut self,
    scope: &mut Scope<'_>,
    global_object: GcObject,
    name: &str,
  ) -> Result<bool, VmError> {
    // GlobalEnvironmentRecord.CanDeclareGlobalVar (ECMA-262).
    //
    // Returns true if:
    // - the global object already has an own property for `name`, or
    // - the global object is extensible.
    let mut key_scope = scope.reborrow();
    key_scope.push_root(Value::Object(global_object))?;
    let key = PropertyKey::from_string(key_scope.alloc_string(name)?);
    if key_scope
      .heap()
      .object_get_own_property_with_tick(global_object, &key, || self.tick())?
      .is_some()
    {
      return Ok(true);
    }
    key_scope.heap().object_is_extensible(global_object)
  }

  fn can_declare_global_function(
    &mut self,
    scope: &mut Scope<'_>,
    global_object: GcObject,
    name: &str,
  ) -> Result<bool, VmError> {
    // GlobalEnvironmentRecord.CanDeclareGlobalFunction (ECMA-262).
    //
    // Returns true if:
    // - the global object does not have an own property for `name` and is extensible, or
    // - the existing property is configurable, or
    // - the existing property is a non-configurable data descriptor that is writable + enumerable.
    let mut key_scope = scope.reborrow();
    key_scope.push_root(Value::Object(global_object))?;
    let key = PropertyKey::from_string(key_scope.alloc_string(name)?);
    let existing =
      key_scope
        .heap()
        .object_get_own_property_with_tick(global_object, &key, || self.tick())?;
    let Some(existing) = existing else {
      return key_scope.heap().object_is_extensible(global_object);
    };

    if existing.configurable {
      return Ok(true);
    }

    match existing.kind {
      PropertyKind::Data { writable: true, .. } if existing.enumerable => Ok(true),
      _ => Ok(false),
    }
  }

  fn collect_var_scoped_function_decls_in_stmt_list<'s>(
    &mut self,
    stmts: &'s [Node<Stmt>],
    out: &mut Vec<&'s Node<FuncDecl>>,
  ) -> Result<(), VmError> {
    if self.strict {
      for stmt in stmts {
        self.tick()?;
        let Stmt::FunctionDecl(decl) = &*stmt.stx else {
          continue;
        };
        out.try_reserve(1).map_err(|_| VmError::OutOfMemory)?;
        out.push(decl);
      }
      return Ok(());
    }

    for stmt in stmts {
      self.collect_var_scoped_function_decls_in_stmt(&stmt.stx, out, true)?;
    }
    Ok(())
  }

  fn collect_var_scoped_function_decls_in_stmt<'s>(
    &mut self,
    stmt: &'s Stmt,
    out: &mut Vec<&'s Node<FuncDecl>>,
    in_stmt_list: bool,
  ) -> Result<(), VmError> {
    self.tick()?;
    match stmt {
      Stmt::FunctionDecl(decl) => {
        if in_stmt_list || Self::is_annex_b_eligible_sloppy_function_decl(decl) {
          out.try_reserve(1).map_err(|_| VmError::OutOfMemory)?;
          out.push(decl);
        }
        Ok(())
      }
      Stmt::Block(block) => {
        for stmt in &block.stx.body {
          self.collect_var_scoped_function_decls_in_stmt(&stmt.stx, out, false)?;
        }
        Ok(())
      }
      Stmt::If(stmt) => {
        self.collect_var_scoped_function_decls_in_stmt(&stmt.stx.consequent.stx, out, false)?;
        if let Some(alt) = &stmt.stx.alternate {
          self.collect_var_scoped_function_decls_in_stmt(&alt.stx, out, false)?;
        }
        Ok(())
      }
      Stmt::Try(stmt) => {
        for s in &stmt.stx.wrapped.stx.body {
          self.collect_var_scoped_function_decls_in_stmt(&s.stx, out, false)?;
        }
        if let Some(catch) = &stmt.stx.catch {
          for s in &catch.stx.body {
            self.collect_var_scoped_function_decls_in_stmt(&s.stx, out, false)?;
          }
        }
        if let Some(finally) = &stmt.stx.finally {
          for s in &finally.stx.body {
            self.collect_var_scoped_function_decls_in_stmt(&s.stx, out, false)?;
          }
        }
        Ok(())
      }
      Stmt::With(stmt) => {
        self.collect_var_scoped_function_decls_in_stmt(&stmt.stx.body.stx, out, false)
      }
      Stmt::While(stmt) => {
        self.collect_var_scoped_function_decls_in_stmt(&stmt.stx.body.stx, out, false)
      }
      Stmt::DoWhile(stmt) => {
        self.collect_var_scoped_function_decls_in_stmt(&stmt.stx.body.stx, out, false)
      }
      Stmt::ForTriple(stmt) => {
        for s in &stmt.stx.body.stx.body {
          self.collect_var_scoped_function_decls_in_stmt(&s.stx, out, false)?;
        }
        Ok(())
      }
      Stmt::ForIn(stmt) => {
        for s in &stmt.stx.body.stx.body {
          self.collect_var_scoped_function_decls_in_stmt(&s.stx, out, false)?;
        }
        Ok(())
      }
      Stmt::ForOf(stmt) => {
        for s in &stmt.stx.body.stx.body {
          self.collect_var_scoped_function_decls_in_stmt(&s.stx, out, false)?;
        }
        Ok(())
      }
      Stmt::Label(stmt) => {
        self.collect_var_scoped_function_decls_in_stmt(&stmt.stx.statement.stx, out, false)
      }
      Stmt::Switch(stmt) => {
        const BRANCH_TICK_EVERY: usize = 32;
        for (i, branch) in stmt.stx.branches.iter().enumerate() {
          if i % BRANCH_TICK_EVERY == 0 {
            self.tick()?;
          }
          for s in &branch.stx.body {
            self.collect_var_scoped_function_decls_in_stmt(&s.stx, out, false)?;
          }
        }
        Ok(())
      }
      _ => Ok(()),
    }
  }

  fn collect_var_declared_names_in_stmt_list(
    &mut self,
    stmts: &[Node<Stmt>],
    out: &mut Vec<String>,
  ) -> Result<(), VmError> {
    for stmt in stmts {
      self.collect_var_declared_names_in_stmt(&stmt.stx, out)?;
    }
    Ok(())
  }

  fn collect_var_declared_names_in_stmt(
    &mut self,
    stmt: &Stmt,
    out: &mut Vec<String>,
  ) -> Result<(), VmError> {
    // `VarDeclaredNames` but preserving source order.
    self.tick()?;
    match stmt {
      Stmt::VarDecl(var) => {
        if var.stx.mode != VarDeclMode::Var {
          return Ok(());
        }
        for decl in &var.stx.declarators {
          self.tick()?;
          self.collect_var_declared_names_from_pat_decl(&decl.pattern.stx, out)?;
        }
        Ok(())
      }
      Stmt::Block(block) => self.collect_var_declared_names_in_stmt_list(&block.stx.body, out),
      Stmt::If(stmt) => {
        self.collect_var_declared_names_in_stmt(&stmt.stx.consequent.stx, out)?;
        if let Some(alt) = &stmt.stx.alternate {
          self.collect_var_declared_names_in_stmt(&alt.stx, out)?;
        }
        Ok(())
      }
      Stmt::Try(stmt) => {
        self.collect_var_declared_names_in_stmt_list(&stmt.stx.wrapped.stx.body, out)?;
        if let Some(catch) = &stmt.stx.catch {
          self.collect_var_declared_names_in_stmt_list(&catch.stx.body, out)?;
        }
        if let Some(finally) = &stmt.stx.finally {
          self.collect_var_declared_names_in_stmt_list(&finally.stx.body, out)?;
        }
        Ok(())
      }
      Stmt::With(stmt) => self.collect_var_declared_names_in_stmt(&stmt.stx.body.stx, out),
      Stmt::While(stmt) => self.collect_var_declared_names_in_stmt(&stmt.stx.body.stx, out),
      Stmt::DoWhile(stmt) => self.collect_var_declared_names_in_stmt(&stmt.stx.body.stx, out),
      Stmt::ForTriple(stmt) => {
        if let parse_js::ast::stmt::ForTripleStmtInit::Decl(decl) = &stmt.stx.init {
          if decl.stx.mode == VarDeclMode::Var {
            for d in &decl.stx.declarators {
              self.tick()?;
              self.collect_var_declared_names_from_pat_decl(&d.pattern.stx, out)?;
            }
          }
        }
        self.collect_var_declared_names_in_stmt_list(&stmt.stx.body.stx.body, out)
      }
      Stmt::ForIn(stmt) => {
        if let ForInOfLhs::Decl((mode, pat_decl)) = &stmt.stx.lhs {
          if *mode == VarDeclMode::Var {
            self.collect_var_declared_names_from_pat_decl(&pat_decl.stx, out)?;
          }
        }
        self.collect_var_declared_names_in_stmt_list(&stmt.stx.body.stx.body, out)
      }
      Stmt::ForOf(stmt) => {
        if let ForInOfLhs::Decl((mode, pat_decl)) = &stmt.stx.lhs {
          if *mode == VarDeclMode::Var {
            self.collect_var_declared_names_from_pat_decl(&pat_decl.stx, out)?;
          }
        }
        self.collect_var_declared_names_in_stmt_list(&stmt.stx.body.stx.body, out)
      }
      Stmt::Label(stmt) => self.collect_var_declared_names_in_stmt(&stmt.stx.statement.stx, out),
      Stmt::Switch(stmt) => {
        const BRANCH_TICK_EVERY: usize = 32;
        for (i, branch) in stmt.stx.branches.iter().enumerate() {
          if i % BRANCH_TICK_EVERY == 0 {
            self.tick()?;
          }
          self.collect_var_declared_names_in_stmt_list(&branch.stx.body, out)?;
        }
        Ok(())
      }
      _ => Ok(()),
    }
  }

  fn collect_var_declared_names_from_pat_decl(
    &mut self,
    pat_decl: &PatDecl,
    out: &mut Vec<String>,
  ) -> Result<(), VmError> {
    self.collect_var_declared_names_from_pat(&pat_decl.pat.stx, out)
  }

  fn collect_var_declared_names_from_pat(
    &mut self,
    pat: &Pat,
    out: &mut Vec<String>,
  ) -> Result<(), VmError> {
    match pat {
      Pat::Id(id) => {
        out.try_reserve(1).map_err(|_| VmError::OutOfMemory)?;
        out.push(try_clone_string(id.stx.name.as_str())?);
        Ok(())
      }
      Pat::Obj(obj) => {
        for prop in &obj.stx.properties {
          self.tick()?;
          self.collect_var_declared_names_from_pat(&prop.stx.target.stx, out)?;
        }
        if let Some(rest) = &obj.stx.rest {
          self.tick()?;
          self.collect_var_declared_names_from_pat(&rest.stx, out)?;
        }
        Ok(())
      }
      Pat::Arr(arr) => {
        for elem in &arr.stx.elements {
          self.tick()?;
          if let Some(elem) = elem {
            self.collect_var_declared_names_from_pat(&elem.target.stx, out)?;
          }
        }
        if let Some(rest) = &arr.stx.rest {
          self.tick()?;
          self.collect_var_declared_names_from_pat(&rest.stx, out)?;
        }
        Ok(())
      }
      Pat::AssignTarget(_) => Err(VmError::Unimplemented("var declaration assignment targets")),
    }
  }

  fn collect_var_names(&mut self, stmt: &Stmt, out: &mut HashSet<String>) -> Result<(), VmError> {
    // `VarDeclaredNames` can traverse large statement trees (e.g. nested blocks/ifs with no `var`
    // declarations). Budget it so strict-mode scripts can't bypass fuel/interrupt checks during
    // hoisting by forcing an `O(N)` scan that performs no statement/expression evaluation.
    self.tick()?;
    match stmt {
      Stmt::VarDecl(var) => {
        if var.stx.mode != VarDeclMode::Var {
          return Ok(());
        }
        for decl in &var.stx.declarators {
          self.tick()?;
          self.collect_var_names_from_pat_decl(&decl.pattern.stx, out)?;
        }
      }
      Stmt::Block(block) => {
        for stmt in &block.stx.body {
          self.collect_var_names(&stmt.stx, out)?;
        }
      }
      Stmt::If(stmt) => {
        self.collect_var_names(&stmt.stx.consequent.stx, out)?;
        if let Some(alt) = &stmt.stx.alternate {
          self.collect_var_names(&alt.stx, out)?;
        }
      }
      Stmt::Try(stmt) => {
        for s in &stmt.stx.wrapped.stx.body {
          self.collect_var_names(&s.stx, out)?;
        }
        if let Some(catch) = &stmt.stx.catch {
          for s in &catch.stx.body {
            self.collect_var_names(&s.stx, out)?;
          }
        }
        if let Some(finally) = &stmt.stx.finally {
          for s in &finally.stx.body {
            self.collect_var_names(&s.stx, out)?;
          }
        }
      }
      Stmt::With(stmt) => {
        self.collect_var_names(&stmt.stx.body.stx, out)?;
      }
      Stmt::While(stmt) => {
        self.collect_var_names(&stmt.stx.body.stx, out)?;
      }
      Stmt::DoWhile(stmt) => {
        self.collect_var_names(&stmt.stx.body.stx, out)?;
      }
      Stmt::ForTriple(stmt) => {
        if let parse_js::ast::stmt::ForTripleStmtInit::Decl(decl) = &stmt.stx.init {
          if decl.stx.mode == VarDeclMode::Var {
            for d in &decl.stx.declarators {
              self.tick()?;
              self.collect_var_names_from_pat_decl(&d.pattern.stx, out)?;
            }
          }
        }
        for s in &stmt.stx.body.stx.body {
          self.collect_var_names(&s.stx, out)?;
        }
      }
      Stmt::ForIn(stmt) => {
        if let ForInOfLhs::Decl((mode, pat_decl)) = &stmt.stx.lhs {
          if *mode == VarDeclMode::Var {
            self.collect_var_names_from_pat_decl(&pat_decl.stx, out)?;
          }
        }
        for s in &stmt.stx.body.stx.body {
          self.collect_var_names(&s.stx, out)?;
        }
      }
      Stmt::ForOf(stmt) => {
        if let ForInOfLhs::Decl((mode, pat_decl)) = &stmt.stx.lhs {
          if *mode == VarDeclMode::Var {
            self.collect_var_names_from_pat_decl(&pat_decl.stx, out)?;
          }
        }
        for s in &stmt.stx.body.stx.body {
          self.collect_var_names(&s.stx, out)?;
        }
      }
      Stmt::Label(stmt) => {
        self.collect_var_names(&stmt.stx.statement.stx, out)?;
      }
      Stmt::Switch(stmt) => {
        const BRANCH_TICK_EVERY: usize = 32;
        for (i, branch) in stmt.stx.branches.iter().enumerate() {
          if i % BRANCH_TICK_EVERY == 0 {
            self.tick()?;
          }
          for s in &branch.stx.body {
            self.collect_var_names(&s.stx, out)?;
          }
        }
      }
      _ => {}
    }
    Ok(())
  }

  fn collect_var_names_from_pat_decl(
    &mut self,
    pat_decl: &PatDecl,
    out: &mut HashSet<String>,
  ) -> Result<(), VmError> {
    self.collect_var_names_from_pat(&pat_decl.pat.stx, out)
  }

  fn collect_var_names_from_pat(
    &mut self,
    pat: &Pat,
    out: &mut HashSet<String>,
  ) -> Result<(), VmError> {
    match pat {
      Pat::Id(id) => {
        let name = id.stx.name.as_str();
        if !out.contains(name) {
          out.try_reserve(1).map_err(|_| VmError::OutOfMemory)?;
          out.insert(try_clone_string(name)?);
        }
        Ok(())
      }
      Pat::Obj(obj) => {
        for prop in &obj.stx.properties {
          self.tick()?;
          self.collect_var_names_from_pat(&prop.stx.target.stx, out)?;
        }
        if let Some(rest) = &obj.stx.rest {
          self.tick()?;
          self.collect_var_names_from_pat(&rest.stx, out)?;
        }
        Ok(())
      }
      Pat::Arr(arr) => {
        for elem in &arr.stx.elements {
          self.tick()?;
          if let Some(elem) = elem {
            self.collect_var_names_from_pat(&elem.target.stx, out)?;
          }
        }
        if let Some(rest) = &arr.stx.rest {
          self.tick()?;
          self.collect_var_names_from_pat(&rest.stx, out)?;
        }
        Ok(())
      }
      Pat::AssignTarget(_) => Err(VmError::Unimplemented("var declaration assignment targets")),
    }
  }

  fn eval_stmt_list(
    &mut self,
    scope: &mut Scope<'_>,
    stmts: &[Node<Stmt>],
  ) -> Result<Completion, VmError> {
    // Root the running completion value so it cannot be collected while evaluating subsequent
    // statements (which may allocate and trigger GC).
    let last_root = scope.heap_mut().add_root(Value::Undefined)?;
    let result: Result<Completion, VmError> = (|| {
      let mut last_value: Option<Value> = None;

      for stmt in stmts {
        let completion = self.eval_stmt(scope, stmt)?;
        let completion = completion.update_empty(last_value);

        match completion {
          Completion::Normal(v) => {
            if let Some(v) = v {
              last_value = Some(v);
              scope.heap_mut().set_root(last_root, v);
            }
          }
          abrupt => return Ok(abrupt),
        }
      }

      Ok(Completion::Normal(last_value))
    })();

    // Ensure the persistent root is always removed, even if we return early on a hard-stop error
    // (Termination/OOM) or other internal failure. Otherwise we leak persistent roots and make the
    // heap unsafe to reuse after aborted execution.
    scope.heap_mut().remove_root(last_root);
    result
  }

  fn eval_block_stmt(
    &mut self,
    scope: &mut Scope<'_>,
    block: &BlockStmt,
  ) -> Result<Completion, VmError> {
    if block.body.is_empty() {
      return Ok(Completion::empty());
    }

    // If the block declares no lexical bindings, evaluating the statement list in the existing
    // lexical environment is equivalent to creating a fresh empty environment.
    //
    // This avoids allocating an empty `EnvRecord` for blocks like `{ x++; }` that are executed in
    // tight loops, keeping fuel-based termination responsive for hostile input.
    let needs_lexical_env = block.body.iter().any(|stmt| match &*stmt.stx {
      Stmt::VarDecl(var)
        if matches!(
          var.stx.mode,
          VarDeclMode::Let | VarDeclMode::Const | VarDeclMode::Using | VarDeclMode::AwaitUsing
        ) =>
      {
        true
      }
      Stmt::ClassDecl(_) => true,
      // Block-level function declarations are block-scoped (and must capture the block
      // environment) in both strict mode and non-strict (Annex B) mode.
      Stmt::FunctionDecl(_) => true,
      _ => false,
    });
    if !needs_lexical_env {
      return self.eval_stmt_list(scope, &block.body);
    }

    let outer = self.env.lexical_env;
    let block_env = scope.env_create(Some(outer))?;
    self.env.set_lexical_env(scope.heap_mut(), block_env);

    let result = self
      .instantiate_block_decls_in_stmt_list(scope, block_env, &block.body)
      .and_then(|_| self.eval_stmt_list(scope, &block.body));

    self.env.set_lexical_env(scope.heap_mut(), outer);
    result
  }

  fn eval_function_decl_stmt(
    &mut self,
    scope: &mut Scope<'_>,
    decl: &Node<FuncDecl>,
  ) -> Result<Completion, VmError> {
    // Most function declarations are hoisted/instantiated during statement-list instantiation and
    // have no runtime evaluation effect.
    //
    // Annex B block-level *ordinary* function declarations are special: they are instantiated in
    // the current block's lexical environment (so they capture it), and when the declaration is
    // evaluated it updates the corresponding var-environment binding.
    if self.strict || !Self::is_annex_b_eligible_sloppy_function_decl(decl) {
      return Ok(Completion::empty());
    }

    let Some(name) = &decl.stx.name else {
      // `export default function() {}` has no binding name and is handled during module
      // instantiation instead.
      if decl.stx.export_default {
        return Ok(Completion::empty());
      }
      return Err(VmError::Unimplemented("anonymous function declaration"));
    };

    // Only perform the Annex B var-environment update when a lexical binding for this function
    // exists in the current lexical environment (i.e. we're evaluating a block-scoped function
    // declaration).
    if !scope
      .heap()
      .env_has_binding(self.env.lexical_env, &name.stx.name)?
    {
      return Ok(Completion::empty());
    }

    let f_obj = scope.heap().env_get_binding_value(
      self.env.lexical_env,
      &name.stx.name,
      /* strict */ false,
    )?;

    let mut assign_scope = scope.reborrow();
    assign_scope.push_root(f_obj)?;
    self.env.set_var(
      self.vm,
      &mut *self.host,
      &mut *self.hooks,
      &mut assign_scope,
      &name.stx.name,
      f_obj,
    )?;
    Ok(Completion::empty())
  }

  fn eval_stmt(&mut self, scope: &mut Scope<'_>, stmt: &Node<Stmt>) -> Result<Completion, VmError> {
    self.eval_stmt_labelled(scope, stmt, &[])
  }

  /// Evaluates a statement with an associated label set.
  ///
  /// This models ECMA-262 `LabelledEvaluation` / `LoopEvaluation` label propagation:
  /// nested label statements extend `label_set`, and iteration statements use it to determine which
  /// labelled `continue` completions are consumed by the loop.
  fn eval_stmt_labelled(
    &mut self,
    scope: &mut Scope<'_>,
    stmt: &Node<Stmt>,
    label_set: &[String],
  ) -> Result<Completion, VmError> {
    // One tick per statement.
    self.tick()?;

    let res = match &*stmt.stx {
      Stmt::Empty(_) => Ok(Completion::empty()),
      Stmt::Expr(expr_stmt) => self.eval_expr_stmt(scope, &expr_stmt.stx),
      Stmt::VarDecl(var_decl) => self.eval_var_decl(scope, &var_decl.stx),
      Stmt::ClassDecl(class_decl) => self.eval_class_decl(scope, class_decl),
      Stmt::Debugger(_) => Ok(Completion::empty()),
      Stmt::Block(block) => self.eval_block_stmt(scope, &block.stx),
      Stmt::If(stmt) => self.eval_if(scope, &stmt.stx),
      // Import/export declarations are processed during module linking; their runtime evaluation is
      // defined to produce an empty completion.
      Stmt::Import(_) => Ok(Completion::empty()),
      Stmt::ExportList(_) => Ok(Completion::empty()),
      Stmt::ExportDefaultExpr(stmt) => {
        let is_anonymous_function_or_class = match stmt.stx.expression.stx.as_ref() {
          Expr::Func(func) => func.stx.name.is_none(),
          Expr::Class(class) => class.stx.name.is_none(),
          Expr::ArrowFunc(_) => true,
          _ => false,
        };

        let value = if is_anonymous_function_or_class {
          // `export default <expr>;` performs `SetFunctionName` when exporting an anonymous
          // function/class expression (including arrow functions). Use `eval_expr_named` so anonymous
          // class expressions receive the inferred name **during** class construction (allowing a
          // `static name() {}` class element to override the constructor's initial `"name"` property).
          let mut name_scope = scope.reborrow();
          let default_s = name_scope.alloc_string("default")?;
          name_scope.push_root(Value::String(default_s))?;
          self.eval_expr_named(
            &mut name_scope,
            &stmt.stx.expression,
            PropertyKey::String(default_s),
          )?
        } else {
          self.eval_expr(scope, &stmt.stx.expression)?
        };

        let binding_name = "*default*";
        if !scope
          .heap()
          .env_has_binding(self.env.lexical_env, binding_name)?
        {
          return Err(VmError::InvariantViolation(
            "export default expression missing *default* binding",
          ));
        }
        scope
          .heap_mut()
          .env_initialize_binding(self.env.lexical_env, binding_name, value)?;
        Ok(Completion::empty())
      }
      Stmt::Throw(stmt) => self.eval_throw(scope, stmt),
      Stmt::Try(stmt) => self.eval_try(scope, &stmt.stx),
      Stmt::With(stmt) => self.eval_with(scope, &stmt.stx, label_set),
      Stmt::Return(stmt) => self.eval_return(scope, &stmt.stx),
      Stmt::While(stmt) => self.eval_while(scope, &stmt.stx, label_set),
      Stmt::DoWhile(stmt) => self.eval_do_while(scope, &stmt.stx, label_set),
      Stmt::ForTriple(stmt) => self.eval_for_triple(scope, &stmt.stx, label_set),
      Stmt::ForIn(stmt) => self.eval_for_in(scope, &stmt.stx, label_set),
      Stmt::ForOf(stmt) => self.eval_for_of(scope, &stmt.stx, label_set),
      Stmt::Switch(stmt) => {
        let result = self.eval_switch(scope, &stmt.stx)?;
        Ok(Self::normalise_iteration_break(result))
      }
      Stmt::Label(stmt) => self.eval_label(scope, &stmt.stx, label_set),
      // Function declarations are instantiated during hoisting.
      Stmt::FunctionDecl(decl) => self.eval_function_decl_stmt(scope, decl),
      Stmt::Break(stmt) => Ok(Completion::Break(stmt.stx.label.clone(), None)),
      Stmt::Continue(stmt) => Ok(Completion::Continue(stmt.stx.label.clone(), None)),

      _ => Err(VmError::Unimplemented("statement type")),
    };

    // Treat internal `VmError::Throw*` as a JS throw completion so it is catchable by `try/catch`.
    //
    // This is also the central stack capture point for implicit throws (TDZ errors, TypeErrors,
    // etc) that are surfaced as `Err(VmError::Throw(..))` from lower-level helpers.
    //
    // Note: some callers (e.g. `Vm::call` after `coerce_error_to_throw`) can surface a
    // `VmError::ThrowWithStack` before we reach this point; in that case we still want the top
    // frame to point at the statement location, not at the internal/native frame boundary.
    let source = self.env.source();
    let rel_start = stmt.loc.start_u32().saturating_sub(self.env.prefix_len());
    let abs_offset = self.env.base_offset().saturating_add(rel_start);
    let (line, col) = source.line_col(abs_offset);

    let update_top_frame = |stack: &mut Vec<StackFrame>| {
      if let Some(top) = stack.first_mut() {
        top.source = source.name.clone();
        top.line = line;
        top.col = col;
      } else {
        stack.push(StackFrame {
          function: None,
          source: source.name.clone(),
          line,
          col,
        });
      }
    };

    let thrown_at_stmt = |scope: &mut Scope<'_>, value: Value| {
      let mut stack = self.vm.capture_stack();
      update_top_frame(&mut stack);
      crate::error_object::attach_stack_property_for_throw(scope, value, &stack);
      Thrown { value, stack }
    };

    match res {
      Err(VmError::Throw(value)) => Ok(Completion::Throw(thrown_at_stmt(scope, value))),
      Err(VmError::ThrowWithStack { value, mut stack }) => {
        // If the stack trace was captured while executing a native builtin, the top frame's
        // location will be `<native>:0:0`. Patch that frame to the current statement location so
        // callers see where the exception was triggered in user code.
        //
        // For user-thrown exceptions, the captured stack already contains meaningful source
        // locations and should not be overwritten.
        if stack.first().is_none() || stack.first().is_some_and(|top| top.line == 0) {
          update_top_frame(&mut stack);
        }
        crate::error_object::attach_stack_property_for_throw(scope, value, &stack);
        Ok(Completion::Throw(Thrown { value, stack }))
      }
      Err(VmError::TypeError(message)) => {
        let intr = self
          .vm
          .intrinsics()
          .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;
        let err = new_error(scope, intr.type_error_prototype(), "TypeError", message)?;
        Ok(Completion::Throw(thrown_at_stmt(scope, err)))
      }
      Err(VmError::RangeError(message)) => {
        let intr = self
          .vm
          .intrinsics()
          .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;
        let err = new_error(scope, intr.range_error_prototype(), "RangeError", message)?;
        Ok(Completion::Throw(thrown_at_stmt(scope, err)))
      }
      Err(VmError::PrototypeCycle) => {
        let intr = self
          .vm
          .intrinsics()
          .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;
        let err = new_error(
          scope,
          intr.type_error_prototype(),
          "TypeError",
          "prototype cycle",
        )?;
        Ok(Completion::Throw(thrown_at_stmt(scope, err)))
      }
      Err(VmError::PrototypeChainTooDeep) => {
        let intr = self
          .vm
          .intrinsics()
          .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;
        let err = new_error(
          scope,
          intr.type_error_prototype(),
          "TypeError",
          "prototype chain too deep",
        )?;
        Ok(Completion::Throw(thrown_at_stmt(scope, err)))
      }
      Err(VmError::InvalidPropertyDescriptorPatch) => {
        let intr = self
          .vm
          .intrinsics()
          .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;
        let err = new_error(
          scope,
          intr.type_error_prototype(),
          "TypeError",
          "invalid property descriptor patch: cannot mix data and accessor fields",
        )?;
        Ok(Completion::Throw(thrown_at_stmt(scope, err)))
      }
      Err(VmError::NotCallable) => {
        let intr = self
          .vm
          .intrinsics()
          .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;
        let err = new_error(
          scope,
          intr.type_error_prototype(),
          "TypeError",
          "value is not callable",
        )?;
        Ok(Completion::Throw(thrown_at_stmt(scope, err)))
      }
      Err(VmError::NotConstructable) => {
        let intr = self
          .vm
          .intrinsics()
          .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;
        let err = new_error(
          scope,
          intr.type_error_prototype(),
          "TypeError",
          "value is not a constructor",
        )?;
        Ok(Completion::Throw(thrown_at_stmt(scope, err)))
      }
      other => other,
    }
  }

  fn eval_expr_stmt(
    &mut self,
    scope: &mut Scope<'_>,
    stmt: &ExprStmt,
  ) -> Result<Completion, VmError> {
    let value = self.eval_expr(scope, &stmt.expr)?;
    Ok(Completion::normal(value))
  }

  fn eval_var_decl(
    &mut self,
    scope: &mut Scope<'_>,
    decl: &VarDecl,
  ) -> Result<Completion, VmError> {
    match decl.mode {
      VarDeclMode::Var => {
        // `var` bindings are hoisted to `undefined` at function/script entry.
        for declarator in &decl.declarators {
          let Some(init) = &declarator.initializer else {
            self.tick()?;
            // Destructuring declarations require an initializer (early error in real JS).
            if !matches!(&*declarator.pattern.stx.pat.stx, Pat::Id(_)) {
              return Err(VmError::Unimplemented(
                "destructuring var without initializer",
              ));
            }
            continue;
          };
          let value = self.eval_expr(scope, init)?;
          bind_pattern(
            self.vm,
            &mut *self.host,
            &mut *self.hooks,
            scope,
            self.env,
            &declarator.pattern.stx.pat.stx,
            value,
            BindingKind::Var,
            self.strict,
            self.this,
          )?;
        }
        Ok(Completion::empty())
      }
      VarDeclMode::Let => {
        for declarator in &decl.declarators {
          let value = match &declarator.initializer {
            Some(init) => self.eval_expr(scope, init)?,
            None => {
              self.tick()?;
              // Destructuring declarations require an initializer (early error in real JS).
              if !matches!(&*declarator.pattern.stx.pat.stx, Pat::Id(_)) {
                return Err(VmError::Unimplemented(
                  "destructuring let without initializer",
                ));
              }
              Value::Undefined
            }
          };

          bind_pattern(
            self.vm,
            &mut *self.host,
            &mut *self.hooks,
            scope,
            self.env,
            &declarator.pattern.stx.pat.stx,
            value,
            BindingKind::Let,
            self.strict,
            self.this,
          )?;
        }
        Ok(Completion::empty())
      }
      VarDeclMode::Const => {
        for declarator in &decl.declarators {
          let Some(init) = &declarator.initializer else {
            return Err(syntax_error(
              declarator.pattern.loc,
              "Missing initializer in const declaration",
            ));
          };
          let value = self.eval_expr(scope, init)?;

          bind_pattern(
            self.vm,
            &mut *self.host,
            &mut *self.hooks,
            scope,
            self.env,
            &declarator.pattern.stx.pat.stx,
            value,
            BindingKind::Const,
            self.strict,
            self.this,
          )?;
        }
        Ok(Completion::empty())
      }

      VarDeclMode::Using | VarDeclMode::AwaitUsing => {
        for declarator in &decl.declarators {
          let Some(init) = &declarator.initializer else {
            let message = match decl.mode {
              VarDeclMode::Using => "Missing initializer in using declaration",
              VarDeclMode::AwaitUsing => "Missing initializer in await using declaration",
              _ => unreachable!(),
            };
            return Err(syntax_error(declarator.pattern.loc, message));
          };
          let value = self.eval_expr(scope, init)?;

          bind_pattern(
            self.vm,
            &mut *self.host,
            &mut *self.hooks,
            scope,
            self.env,
            &declarator.pattern.stx.pat.stx,
            value,
            BindingKind::Const,
            self.strict,
            self.this,
          )?;
          check_disposable_resource_value(self.vm, scope, value)?;
        }
        Ok(Completion::empty())
      }
    }
  }

  fn eval_class(
    &mut self,
    scope: &mut Scope<'_>,
    binding: ClassBinding<'_>,
    func_name: &str,
    inferred_name: Option<PropertyKey>,
    extends: Option<&Node<Expr>>,
    members: &[Node<ClassMember>],
    extends_null: bool,
  ) -> Result<GcObject, VmError> {
    // Per ECMA-262, class definitions are always strict mode code, regardless of whether they
    // appear in a sloppy script/function body.
    //
    // This matters for runtime semantics (not just early errors). For example, in sloppy mode,
    // `unbound = 1` creates a global property, but in class bodies it must throw a ReferenceError.
    let saved_strict = self.strict;
    self.strict = true;
    let result = (|| {
      let class_env = self.env.lexical_env;

      // Ensure the requested class binding exists before creating any class element closures that may
      // reference it.
      match binding {
        ClassBinding::None => {}
        ClassBinding::Immutable(name) => {
          if scope.heap().env_has_binding(class_env, name)? {
            return Err(VmError::InvariantViolation(
              "class binding already exists in class environment",
            ));
          }
          scope.env_create_immutable_binding(class_env, name)?;
        }
      }

      // Create the class's private-name environment.
      //
      // `parse-js` represents private names as strings like `"#x"`. To enforce per-class privacy, we
      // allocate a fresh internal symbol for each declared private name and store the mapping on the
      // class's lexical environment record. All class element bodies capture that environment, so
      // private member expressions can resolve the correct symbol even if the class binding is passed
      // around.
      let mut private_names: Vec<String> = Vec::new();
      let mut private_name_set: HashSet<&str> = HashSet::new();
      for member in members {
        if let ClassOrObjKey::Direct(key) = &member.stx.key {
          if key.stx.tt == TT::PrivateMember {
            let name = key.stx.key.as_str();
            if private_name_set.contains(name) {
              continue;
            }
            private_name_set
              .try_reserve(1)
              .map_err(|_| VmError::OutOfMemory)?;
            private_name_set.insert(name);
            private_names
              .try_reserve(1)
              .map_err(|_| VmError::OutOfMemory)?;
            private_names.push(try_clone_string(name)?);
          }
        }
      }
      if !private_names.is_empty() {
        let mut entries: Vec<crate::env::PrivateNameEntry> = Vec::new();
        entries
          .try_reserve_exact(private_names.len())
          .map_err(|_| VmError::OutOfMemory)?;
        // Keep all allocated symbols rooted until the mapping is installed into the class environment
        // record, so intermediate allocations cannot collect them.
        let mut priv_scope = scope.reborrow();
        for name in private_names {
          let desc = priv_scope.alloc_string(&name)?;
          let sym = priv_scope.new_internal_symbol(Some(desc))?;
          priv_scope.push_root(Value::Symbol(sym))?;
          entries.push(crate::env::PrivateNameEntry {
            name: name.into_boxed_str(),
            sym,
          });
        }
        priv_scope
          .heap_mut()
          .env_set_private_names(class_env, entries.into_boxed_slice())?;
      }

      // Evaluate `extends` (class heritage), if present.
      //
      // - `undefined` => no `extends` (base class)
      // - `null` => `extends null`
      // - object => superclass constructor
      let super_value = match extends {
        None => Value::Undefined,
        Some(extends_expr) => {
          let v = self.eval_expr(scope, extends_expr)?;
          match v {
            Value::Undefined => {
              return Err(throw_type_error(
                self.vm,
                scope,
                "Class extends value is not a constructor",
              )?)
            }
            Value::Null => Value::Null,
            Value::Object(_) => {
              if !scope.heap().is_constructor(v)? {
                return Err(throw_type_error(
                  self.vm,
                  scope,
                  "Class extends value is not a constructor",
                )?);
              }
              v
            }
            _ => {
              return Err(throw_type_error(
                self.vm,
                scope,
                "Class extends value is not a constructor",
              )?)
            }
          }
        }
      };

      // Keep the superclass value alive across subsequent allocations/GC until it becomes reachable
      // from the class constructor object (via its native `super` slot).
      //
      // Without this, `class B extends (class A {}) {}` can lose the ephemeral superclass constructor
      // to GC between evaluating `extends` and wiring the class constructor/prototype chains.
      struct RootStackTruncateGuard {
        heap: *mut Heap,
        len: usize,
      }
      impl Drop for RootStackTruncateGuard {
        fn drop(&mut self) {
          // Safety: `heap` remains valid for the duration of `eval_class` and the guard does not
          // outlive the caller's `scope`.
          unsafe {
            (*self.heap).root_stack.truncate(self.len);
          }
        }
      }
      let super_root_len = scope.heap().root_stack.len();
      scope.push_root(super_value)?;
      let heap_ptr = scope.heap_mut() as *mut Heap;
      let _super_root_guard = RootStackTruncateGuard {
        heap: heap_ptr,
        len: super_root_len,
      };
 
      // Count instance elements stored in the class constructor's native slots so the wrapper can
      // preallocate its hidden storage.
      //
      // This includes:
      // - public + private instance fields, and
      // - private instance methods (which are stored per-instance so private access does not consult
      //   the prototype chain).
      let mut instance_field_count: usize = 0;
      let mut private_instance_method_count: usize = 0;
      for member in members {
        if member.stx.static_ {
          continue;
        }
        match &member.stx.val {
          ClassOrObjVal::Prop(_) => {
            instance_field_count = instance_field_count
              .checked_add(1)
              .ok_or(VmError::OutOfMemory)?;
          }
          ClassOrObjVal::Method(_) => {
            let is_private_key = matches!(
              &member.stx.key,
              ClassOrObjKey::Direct(direct) if direct.stx.tt == TT::PrivateMember
            );
            if is_private_key {
              private_instance_method_count = private_instance_method_count
                .checked_add(1)
                .ok_or(VmError::OutOfMemory)?;
            }
          }
          _ => {}
        }
      }
      let instance_slot_pair_count = instance_field_count
        .checked_add(private_instance_method_count)
        .ok_or(VmError::OutOfMemory)?;

    // Find an explicit `constructor(...) { ... }` method, if present.
    let mut ctor_method: Option<(&Node<Func>, u32, parse_js::loc::Loc)> = None;
    for member in members {
      self.tick()?;
      if !member.stx.decorators.is_empty() {
        return Err(VmError::Unimplemented("class member decorators"));
      }
      if member.stx.declare || member.stx.abstract_ {
        return Err(VmError::Unimplemented("class member modifiers"));
      }
      if member.stx.readonly
        || member.stx.accessor
        || member.stx.optional
        || member.stx.override_
        || member.stx.definite_assignment
      {
        return Err(VmError::Unimplemented("class member modifiers"));
      }
      if member.stx.accessibility.is_some() || member.stx.type_annotation.is_some() {
        return Err(VmError::Unimplemented("class member type annotations"));
      }

      if member.stx.static_ {
        continue;
      }
      let ClassOrObjKey::Direct(direct) = &member.stx.key else {
        continue;
      };
      if direct.stx.key != "constructor" {
        continue;
      }

      let ClassOrObjVal::Method(method) = &member.stx.val else {
        continue;
      };

      if ctor_method.is_some() {
        return Err(syntax_error(
          member.loc,
          "A class may only have one constructor",
        ));
      }
      ctor_method = Some((&method.stx.func, member.loc.start_u32(), member.loc));
    }

    let mut ctor_length: u32 = 0;
    let ctor_body_func = if let Some((func_node, member_loc_start, loc)) = ctor_method {
      if func_node.stx.generator {
        return Err(syntax_error(
          loc,
          "Class constructor may not be a generator",
        ));
      }

      ctor_length = self.function_length(&func_node.stx)?;

      let rel_start = member_loc_start.saturating_sub(self.env.prefix_len());
      let rel_end = func_node
        .loc
        .end_u32()
        .saturating_sub(self.env.prefix_len());
      let span_start = self.env.base_offset().saturating_add(rel_start);
      let span_end = self.env.base_offset().saturating_add(rel_end);

      let code = self.vm.register_ecma_function(
        self.env.source(),
        span_start,
        span_end,
        EcmaFunctionKind::ClassMember,
      )?;

      // Class constructor bodies are always strict mode.
      let is_strict = true;
      let this_mode = if func_node.stx.arrow {
        ThisMode::Lexical
      } else {
        ThisMode::Strict
      };
      let closure_env = Some(self.env.lexical_env);

      let mut ctor_scope = scope.reborrow();
      let name_string = ctor_scope.alloc_string("constructor")?;
      let func_obj = ctor_scope.alloc_ecma_function(
        code,
        /* is_constructable */ true,
        name_string,
        ctor_length,
        this_mode,
        is_strict,
        closure_env,
      )?;

      let intr = self
        .vm
        .intrinsics()
        .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;
      ctor_scope
        .heap_mut()
        .object_set_prototype(func_obj, Some(intr.function_prototype()))?;
      ctor_scope
        .heap_mut()
        .set_function_realm(func_obj, self.env.global_object())?;
      if let Some(realm) = self.vm.current_realm() {
        ctor_scope
          .heap_mut()
          .set_function_job_realm(func_obj, realm)?;
      }
      if let Some(script_or_module) = self.vm.get_active_script_or_module() {
        let token = self.vm.intern_script_or_module(script_or_module)?;
        ctor_scope
          .heap_mut()
          .set_function_script_or_module_token(func_obj, Some(token))?;
      }
      Some(func_obj)
    } else {
      None
    };

      let func_obj = self.create_class_constructor_object(
        scope,
        func_name,
        ctor_length,
        ctor_body_func,
        super_value,
        instance_slot_pair_count,
      )?;

      // ECMA-262 `NamedEvaluation` assigns inferred names to anonymous class expressions in specific
      // syntactic positions (e.g. `{ key: class {} }`).
      //
      // This must happen *before* defining class elements: a class can define a `static name() {}`
      // method which should override the constructor's initial `"name"` property. Setting the name
      // after class evaluation would overwrite the method.
      if func_name.is_empty() {
        if let Some(name_key) = inferred_name {
          let mut name_scope = scope.reborrow();
          name_scope.push_root(Value::Object(func_obj))?;
          match name_key {
            PropertyKey::String(s) => {
              name_scope.push_root(Value::String(s))?;
            }
            PropertyKey::Symbol(sym) => {
              name_scope.push_root(Value::Symbol(sym))?;
            }
          }
          crate::function_properties::set_function_name(&mut name_scope, func_obj, name_key, None)?;
        }
      }

      // If the class has an explicit `constructor(...) { ... }` body, annotate that hidden function
      // object so `[[Construct]]` can implement class-field initialization and derived `super()`
      // semantics.
      if let Some(body_func) = ctor_body_func {
        scope.heap_mut().set_function_data(
          body_func,
          FunctionData::ClassConstructorBody {
            class_constructor: func_obj,
          },
        )?;
      }

      // Initialize the requested binding now that the class constructor object exists.
      if let Some(binding_name) = match binding {
        ClassBinding::None => None,
        ClassBinding::Immutable(name) => Some(name),
      } {
        // Root the class constructor object during initialization so if the operation grows the root
        // stack (and triggers GC) we don't collect the class constructor before it becomes reachable
        // from its binding.
        let mut init_scope = scope.reborrow();
        init_scope.push_root(Value::Object(func_obj))?;
        init_scope.heap_mut().env_initialize_binding(
          class_env,
          binding_name,
          Value::Object(func_obj),
        )?;
      }

      // Extract the prototype object created by `make_constructor`.
      let mut class_scope = scope.reborrow();
      class_scope.push_root(Value::Object(func_obj))?;
      let prototype_key_s = class_scope.alloc_string("prototype")?;
      class_scope.push_root(Value::String(prototype_key_s))?;
      let prototype_key = PropertyKey::from_string(prototype_key_s);
      let Some(prototype_desc) = class_scope
        .heap()
        .get_own_property(func_obj, prototype_key)?
      else {
        return Err(VmError::InvariantViolation(
          "class constructor missing prototype property",
        ));
      };
      let PropertyKind::Data { value, .. } = prototype_desc.kind else {
        return Err(VmError::InvariantViolation(
          "class constructor prototype property is not a data property",
        ));
      };
      let Value::Object(prototype_obj) = value else {
        return Err(VmError::InvariantViolation(
          "class constructor prototype property is not an object",
        ));
      };
      class_scope.push_root(Value::Object(prototype_obj))?;

      // Class constructor bodies (the hidden function object invoked via `[[Construct]]`) use the
      // prototype object as their `[[HomeObject]]` so `super.prop` can resolve against
      // `super.prototype`.
      if let Some(body_func) = ctor_body_func {
        class_scope
          .heap_mut()
          .set_function_home_object(body_func, Some(prototype_obj))?;
        let meta_property_context = if matches!(super_value, Value::Undefined) {
          MetaPropertyContext::METHOD
        } else {
          MetaPropertyContext::DERIVED_CONSTRUCTOR
        };
        class_scope
          .heap_mut()
          .set_function_meta_property_context(body_func, meta_property_context)?;
      }

      // `extends null` is special-cased by ECMA-262 `ClassDefinitionEvaluation`:
      // - the class constructor's `[[Prototype]]` is still `%Function.prototype%`
      // - but the prototype object's `[[Prototype]]` is `null`
      if extends_null {
        class_scope
          .heap_mut()
          .object_set_prototype(prototype_obj, None)?;
      }

      // Per ECMAScript, class constructors have a non-writable `prototype` property.
      class_scope.define_property_or_throw(
        func_obj,
        prototype_key,
        PropertyDescriptorPatch {
          writable: Some(false),
          ..Default::default()
        },
      )?;

      // Wire the instance prototype chain for derived classes.
      //
      // - base class: `prototype.[[Prototype]] = %Object.prototype%`
      // - `extends null`: `prototype.[[Prototype]] = null`
      // - derived class: `prototype.[[Prototype]] = super.prototype`
      let intr = self
        .vm
        .intrinsics()
        .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;
      match super_value {
        Value::Undefined => {
          class_scope
            .heap_mut()
            .object_set_prototype(prototype_obj, Some(intr.object_prototype()))?;
        }
        Value::Null => {
          class_scope
            .heap_mut()
            .object_set_prototype(prototype_obj, None)?;
        }
        Value::Object(super_ctor) => {
          let proto_parent = {
            // `Get(superCtor, "prototype")` (Proxy-aware / accessor-aware).
            let mut proto_scope = class_scope.reborrow();
            proto_scope.push_root(Value::Object(super_ctor))?;
            let proto_key_s = proto_scope.alloc_string("prototype")?;
            proto_scope.push_root(Value::String(proto_key_s))?;
            let proto_key = PropertyKey::from_string(proto_key_s);
            let proto_value = proto_scope.ordinary_get_with_host_and_hooks(
              self.vm,
              &mut *self.host,
              &mut *self.hooks,
              super_ctor,
              proto_key,
              Value::Object(super_ctor),
            )?;
            match proto_value {
              Value::Object(o) => Some(o),
              Value::Null => None,
              _ => {
                return Err(throw_type_error(
                  self.vm,
                  &mut proto_scope,
                  "Class extends value does not have a valid prototype property",
                )?)
              }
            }
          };
          class_scope
            .heap_mut()
            .object_set_prototype(prototype_obj, proto_parent)?;
        }
        _ => {
          return Err(VmError::InvariantViolation(
            "class constructor super value is not undefined, null, or object",
          ))
        }
      }

      // Define prototype and static methods.
      //
      // While defining methods, collect class static initialization elements (public static fields,
      // private static fields, and static blocks) so we can evaluate them *after* all methods have
      // been defined (ECMA-262 `ClassDefinitionEvaluation`: the initialization pass happens after the
      // element definition pass).
      enum StaticInitElement<'a> {
        Field {
          key: Value,
          initializer: Value,
        },
        PrivateField {
          sym: GcSymbol,
          init: Option<&'a Node<Expr>>,
        },
        Block(&'a [Node<Stmt>]),
      }
      let mut static_inits: Vec<StaticInitElement<'_>> = Vec::new();
      let mut instance_private_method_idx: usize = 0;
      let mut instance_field_idx: usize = 0;
      let instance_field_slot_start = crate::class_fields::CLASS_CTOR_SLOT_INSTANCE_FIELDS_START
        .saturating_add(private_instance_method_count.saturating_mul(2));
      for member in members {
        self.tick()?;

        if !member.stx.decorators.is_empty() {
          return Err(VmError::Unimplemented("class member decorators"));
        }
        if member.stx.declare || member.stx.abstract_ {
          return Err(VmError::Unimplemented("class member modifiers"));
        }
        if member.stx.readonly
          || member.stx.accessor
          || member.stx.optional
          || member.stx.override_
          || member.stx.definite_assignment
        {
          return Err(VmError::Unimplemented("class member modifiers"));
        }
        if member.stx.accessibility.is_some() || member.stx.type_annotation.is_some() {
          return Err(VmError::Unimplemented("class member type annotations"));
        }

        // Skip the actual `constructor(...) { ... }` method: it's represented by the class constructor
        // object itself (and its hidden body function).
        let is_constructor_method = !member.stx.static_
          && matches!(&member.stx.key, ClassOrObjKey::Direct(direct) if direct.stx.key == "constructor")
          && matches!(&member.stx.val, ClassOrObjVal::Method(_));
        if is_constructor_method {
          continue;
        }

        // Static initialization blocks are not properties on the class/prototype. Record them for
        // later evaluation and continue to the next element.
        if let ClassOrObjVal::StaticBlock(block) = &member.stx.val {
          static_inits
            .try_reserve(1)
            .map_err(|_| VmError::OutOfMemory)?;
          static_inits.push(StaticInitElement::Block(&block.stx.body));
          continue;
        }

        let target_obj = if member.stx.static_ {
          func_obj
        } else {
          prototype_obj
        };

        let member_loc_start = member.loc.start_u32();
        let (key_loc_start, key_is_computed) = match &member.stx.key {
          ClassOrObjKey::Direct(direct) => (direct.loc.start_u32(), false),
          ClassOrObjKey::Computed(expr) => (expr.loc.start_u32(), true),
        };

        let mut member_scope = class_scope.reborrow();
        member_scope.push_root(Value::Object(target_obj))?;

        let is_private_key = matches!(&member.stx.key, ClassOrObjKey::Direct(direct) if direct.stx.tt == TT::PrivateMember);

        let key = match &member.stx.key {
          ClassOrObjKey::Direct(direct) => {
            if direct.stx.tt == TT::PrivateMember {
              let sym = member_scope
                .heap()
                .resolve_private_name_symbol(class_env, &direct.stx.key)?
                .ok_or(VmError::InvariantViolation("unresolved private name"))?;
              PropertyKey::from_symbol(sym)
            } else {
              let key_s = if let Some(units) = literal_string_code_units(&direct.assoc) {
                member_scope.alloc_string_from_code_units(units)?
              } else if direct.stx.tt == TT::LiteralNumber {
                let mut tick = || self.tick();
                let n = crate::ops::parse_ascii_decimal_to_f64_str(&direct.stx.key, &mut tick)?
                  .ok_or(VmError::Unimplemented(
                    "numeric literal property name parse",
                  ))?;
                member_scope.heap_mut().to_string(Value::Number(n))?
              } else {
                member_scope.alloc_string(&direct.stx.key)?
              };
              PropertyKey::from_string(key_s)
            }
          }
          ClassOrObjKey::Computed(expr) => {
            let value = self.eval_expr(&mut member_scope, expr)?;
            member_scope.push_root(value)?;
            self.to_property_key_operator(&mut member_scope, value)?
          }
        };

        match key {
          PropertyKey::String(s) => member_scope.push_root(Value::String(s))?,
          PropertyKey::Symbol(s) => member_scope.push_root(Value::Symbol(s))?,
        };

        match &member.stx.val {
          ClassOrObjVal::Method(method) => {
            let func_node = &method.stx.func;
            let is_async_generator = func_node.stx.generator && func_node.stx.async_;
            let length = self.function_length(&func_node.stx)?;

            let span_start = self.class_member_span_start(
              member_loc_start,
              key_loc_start,
              key_is_computed,
              Some(&func_node.stx),
              None,
            );
            let rel_end = func_node
              .loc
              .end_u32()
              .saturating_sub(self.env.prefix_len());
            let span_end = self.env.base_offset().saturating_add(rel_end);

            let code = self.vm.register_ecma_function(
              self.env.source(),
              span_start,
              span_end,
              EcmaFunctionKind::ClassMember,
            )?;

            // Class methods are always strict mode.
            let is_strict = true;
            let this_mode = if func_node.stx.arrow {
              ThisMode::Lexical
            } else {
              ThisMode::Strict
            };
            let closure_env = Some(self.env.lexical_env);

            let name_string = match key {
              PropertyKey::String(s) => s,
              PropertyKey::Symbol(_) => member_scope.alloc_string("")?,
            };

            let method_func_obj = member_scope.alloc_ecma_function(
              code,
              /* is_constructable */ false,
              name_string,
              length,
              this_mode,
              is_strict,
              closure_env,
            )?;
            member_scope
              .heap_mut()
              .set_function_meta_property_context(method_func_obj, MetaPropertyContext::METHOD)?;

            let intr = self
              .vm
              .intrinsics()
              .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;
            member_scope.heap_mut().object_set_prototype(
              method_func_obj,
              Some(if func_node.stx.generator {
                if is_async_generator {
                  intr.async_generator_function_prototype()
                } else {
                  intr.generator_function_prototype()
                }
              } else if func_node.stx.async_ {
                intr.async_function_prototype()
              } else {
                intr.function_prototype()
              }),
            )?;
            member_scope
              .heap_mut()
              .set_function_realm(method_func_obj, self.env.global_object())?;
            if let Some(realm) = self.vm.current_realm() {
              member_scope
                .heap_mut()
                .set_function_job_realm(method_func_obj, realm)?;
            }
            if let Some(script_or_module) = self.vm.get_active_script_or_module() {
              let token = self.vm.intern_script_or_module(script_or_module)?;
              member_scope
                .heap_mut()
                .set_function_script_or_module_token(method_func_obj, Some(token))?;
            }
            member_scope
              .heap_mut()
              .set_function_home_object(method_func_obj, Some(target_obj))?;
            if func_node.stx.generator {
              if is_async_generator {
                crate::function_properties::make_async_generator_function_instance_prototype(
                  &mut member_scope,
                  method_func_obj,
                  intr.async_generator_prototype(),
                )?;
              } else {
                crate::function_properties::make_generator_function_instance_prototype(
                  &mut member_scope,
                  method_func_obj,
                  intr.generator_prototype(),
                )?;
              }
            }
            member_scope.push_root(Value::Object(method_func_obj))?;

            // Methods use the property key as the function `name` if possible.
            if !matches!(key, PropertyKey::String(_)) {
              crate::function_properties::set_function_name(
                &mut member_scope,
                method_func_obj,
                key,
                None,
              )?;
            }

            // Private instance methods are initialized per-instance (and therefore must not be
            // defined on the shared prototype object). Store them alongside instance field metadata
            // in the class constructor's native slots; `InitializeInstanceElements` will define them
            // as hidden internal-symbol properties.
            if is_private_key && !member.stx.static_ {
              let PropertyKey::Symbol(sym) = key else {
                return Err(VmError::InvariantViolation(
                  "private method key is not a symbol",
                ));
              };
              let slot_base = crate::class_fields::CLASS_CTOR_SLOT_INSTANCE_FIELDS_START
                .saturating_add(instance_private_method_idx.saturating_mul(2));
              member_scope
                .heap_mut()
                .set_function_native_slot(func_obj, slot_base, Value::Symbol(sym))?;
              member_scope.heap_mut().set_function_native_slot(
                func_obj,
                slot_base.saturating_add(1),
                Value::Object(method_func_obj),
              )?;
              instance_private_method_idx = instance_private_method_idx
                .checked_add(1)
                .ok_or(VmError::OutOfMemory)?;
              continue;
            }

            member_scope.define_property_or_throw(
              target_obj,
              key,
              PropertyDescriptorPatch {
                value: Some(Value::Object(method_func_obj)),
                writable: Some(!is_private_key),
                enumerable: Some(false),
                configurable: Some(!is_private_key),
                ..Default::default()
              },
            )?;
          }
          ClassOrObjVal::Getter(getter) => {
            let func_node = &getter.stx.func;
            let length = self.function_length(&func_node.stx)?;

            let span_start = self.class_member_span_start(
              member_loc_start,
              key_loc_start,
              key_is_computed,
              None,
              Some(b"get"),
            );
            let rel_end = func_node
              .loc
              .end_u32()
              .saturating_sub(self.env.prefix_len());
            let span_end = self.env.base_offset().saturating_add(rel_end);

            let code = self.vm.register_ecma_function(
              self.env.source(),
              span_start,
              span_end,
              EcmaFunctionKind::ClassMember,
            )?;

            // Class accessors are always strict mode.
            let is_strict = true;
            let this_mode = if func_node.stx.arrow {
              ThisMode::Lexical
            } else {
              ThisMode::Strict
            };
            let closure_env = Some(self.env.lexical_env);

            let name_string = member_scope.alloc_string("")?;
            let func_obj = member_scope.alloc_ecma_function(
              code,
              /* is_constructable */ false,
              name_string,
              length,
              this_mode,
              is_strict,
              closure_env,
            )?;
            member_scope
              .heap_mut()
              .set_function_meta_property_context(func_obj, MetaPropertyContext::METHOD)?;

            let intr = self
              .vm
              .intrinsics()
              .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;
            member_scope
              .heap_mut()
              .object_set_prototype(func_obj, Some(intr.function_prototype()))?;
            member_scope
              .heap_mut()
              .set_function_realm(func_obj, self.env.global_object())?;
            if let Some(realm) = self.vm.current_realm() {
              member_scope
                .heap_mut()
                .set_function_job_realm(func_obj, realm)?;
            }
            if let Some(script_or_module) = self.vm.get_active_script_or_module() {
              let token = self.vm.intern_script_or_module(script_or_module)?;
              member_scope
                .heap_mut()
                .set_function_script_or_module_token(func_obj, Some(token))?;
            }
            member_scope
              .heap_mut()
              .set_function_home_object(func_obj, Some(target_obj))?;
            member_scope.push_root(Value::Object(func_obj))?;

            crate::function_properties::set_function_name(
              &mut member_scope,
              func_obj,
              key,
              Some("get"),
            )?;

            member_scope.define_property_or_throw(
              target_obj,
              key,
              PropertyDescriptorPatch {
                get: Some(Value::Object(func_obj)),
                enumerable: Some(false),
                // Private accessors may appear as a getter/setter pair, defined as distinct class
                // elements in source order. Using `configurable: false` would reject the second
                // definition via `DefineOwnProperty` invariants, so keep private accessors
                // configurable.
                configurable: Some(true),
                ..Default::default()
              },
            )?;
          }
          ClassOrObjVal::Setter(setter) => {
            let func_node = &setter.stx.func;
            let length = self.function_length(&func_node.stx)?;

            let span_start = self.class_member_span_start(
              member_loc_start,
              key_loc_start,
              key_is_computed,
              None,
              Some(b"set"),
            );
            let rel_end = func_node
              .loc
              .end_u32()
              .saturating_sub(self.env.prefix_len());
            let span_end = self.env.base_offset().saturating_add(rel_end);

            let code = self.vm.register_ecma_function(
              self.env.source(),
              span_start,
              span_end,
              EcmaFunctionKind::ClassMember,
            )?;

            // Class accessors are always strict mode.
            let is_strict = true;
            let this_mode = if func_node.stx.arrow {
              ThisMode::Lexical
            } else {
              ThisMode::Strict
            };
            let closure_env = Some(self.env.lexical_env);

            let name_string = member_scope.alloc_string("")?;
            let func_obj = member_scope.alloc_ecma_function(
              code,
              /* is_constructable */ false,
              name_string,
              length,
              this_mode,
              is_strict,
              closure_env,
            )?;
            member_scope
              .heap_mut()
              .set_function_meta_property_context(func_obj, MetaPropertyContext::METHOD)?;

            let intr = self
              .vm
              .intrinsics()
              .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;
            member_scope
              .heap_mut()
              .object_set_prototype(func_obj, Some(intr.function_prototype()))?;
            member_scope
              .heap_mut()
              .set_function_realm(func_obj, self.env.global_object())?;
            if let Some(realm) = self.vm.current_realm() {
              member_scope
                .heap_mut()
                .set_function_job_realm(func_obj, realm)?;
            }
            if let Some(script_or_module) = self.vm.get_active_script_or_module() {
              let token = self.vm.intern_script_or_module(script_or_module)?;
              member_scope
                .heap_mut()
                .set_function_script_or_module_token(func_obj, Some(token))?;
            }
            member_scope
              .heap_mut()
              .set_function_home_object(func_obj, Some(target_obj))?;
            member_scope.push_root(Value::Object(func_obj))?;

            crate::function_properties::set_function_name(
              &mut member_scope,
              func_obj,
              key,
              Some("set"),
            )?;

            member_scope.define_property_or_throw(
              target_obj,
              key,
              PropertyDescriptorPatch {
                set: Some(Value::Object(func_obj)),
                enumerable: Some(false),
                configurable: Some(true),
                ..Default::default()
              },
            )?;
          }
          ClassOrObjVal::Prop(initializer_expr) => {
            // Class fields (public and private).
            //
            // - instance fields (public and private) are stored as `(key, initializer)` pairs in the
            //   class constructor's native slots, and are initialized per-instance during
            //   `[[Construct]]`.
            // - private instance methods are also stored in these native slots so they can be
            //   installed as hidden own-properties before field initializers run.
            // - static fields are initialized during the post-definition initialization pass (after
            //   all methods have been defined), in source order relative to static blocks.
            //
            // Private static fields are handled separately so we can enforce the correct property
            // attributes (notably non-enumerable and non-configurable).
            //
            // Private instance fields are stored in the constructor slot list like public fields;
            // `initialize_instance_fields_with_host_and_hooks` defines them with spec-correct
            // attributes on each new instance.
            if is_private_key && member.stx.static_ {
              let PropertyKey::Symbol(sym) = key else {
                return Err(VmError::InvariantViolation(
                  "private field key is not a symbol",
                ));
              };
              static_inits
                .try_reserve(1)
                .map_err(|_| VmError::OutOfMemory)?;
              static_inits.push(StaticInitElement::PrivateField {
                sym,
                init: initializer_expr.as_ref(),
              });
              continue;
            }

            let key_value = match key {
              PropertyKey::String(s) => Value::String(s),
              PropertyKey::Symbol(s) => Value::Symbol(s),
            };

            // Create a function object for `= <expr>` initializers so they can be evaluated later with
            // the correct `this` value.
            let init_value = match initializer_expr {
              Some(expr_node) => {
                // Root the initializer expression node span inputs across registration/allocation.
                let mut start_u32 = expr_node.loc.start_u32();
                // `parse-js` expression node spans intentionally exclude parentheses.
                //
                // For class field initializers we later reparse the expression as a standalone
                // snippet (wrapped in a synthetic class method body) so it can execute with the
                // correct lexical `this`/`super`/`new.target` bindings.
                //
                // When the initializer is a *call* whose callee was parenthesized (e.g.
                // `x = (() => super.m())();`), excluding the opening paren produces an invalid
                // snippet like `() => super.m())()` (the closing paren is still included via the
                // call expression span). Expand the snippet start to include the opening paren so
                // lazy parsing succeeds.
                if let Expr::Call(call) = expr_node.stx.as_ref() {
                  if call.stx.callee.assoc.get::<ParenthesizedExpr>().is_some() {
                    let src = self.env.source();
                    let text = src.text.as_ref();
                    let mut i = (start_u32 as usize).min(text.len());
                    // Skip whitespace between the parenthesis and the callee token.
                    while i > 0 && text.as_bytes()[i.saturating_sub(1)].is_ascii_whitespace() {
                      i = i.saturating_sub(1);
                    }
                    if i > 0 && text.as_bytes()[i.saturating_sub(1)] == b'(' {
                      start_u32 = u32::try_from(i.saturating_sub(1)).unwrap_or(start_u32);
                    }
                  }
                }

                let rel_start = start_u32.saturating_sub(self.env.prefix_len());
                let rel_end = expr_node
                  .loc
                  .end_u32()
                  .saturating_sub(self.env.prefix_len());
                let mut span_start = self.env.base_offset().saturating_add(rel_start);
                let span_end = self.env.base_offset().saturating_add(rel_end);

                // `parse-js` stores parentheses via the `ParenthesizedExpr` assoc marker, and (as of
                // v0.24.1) does not include the parentheses themselves in `Loc` spans.
                //
                // For IIFE-style initializers like `(() => expr)()` / `(function(){})()`, this means
                // the call expression span can start *after* the opening `(` while still including
                // the closing `)`, producing an invalid snippet when we later lazily reparse the
                // initializer from its source span.
                //
                // If the call callee is parenthesized, extend the snippet span to include the
                // opening `(` so the sliced source is valid.
                if let Expr::Call(call) = &*expr_node.stx {
                  if call.stx.callee.assoc.get::<ParenthesizedExpr>().is_some() {
                    let source = self.env.source();
                    let bytes = source.text.as_bytes();

                    // We need to include the parentheses that wrap the call's callee expression.
                    //
                    // In `parse-js`, parenthesized expressions are preserved via the
                    // `ParenthesizedExpr` marker, but their parentheses are excluded from `Loc`
                    // spans. That means slicing a call expression span can produce an invalid
                    // snippet like `() => super.x)()` (missing `(` but including `)`).
                    //
                    // To recover a valid snippet, we:
                    // 1. Find the call's argument list opening `(`.
                    // 2. Count how many `)` close the parenthesized callee between:
                    //      callee.loc.end .. args_open
                    // 3. Scan left from the call start to include that many matching `(`.
                    //
                    // Note: we must count based on *callee end*, not just "how many `)` precede the
                    // call arguments", because the callee expression itself may end with `)` (e.g.
                    // `(foo())()`), and only the parentheses after callee end correspond to the
                    // excluded `(`.
                    let skip_trivia_back = |mut idx: usize| -> usize {
                      idx = idx.min(bytes.len());
                      'outer: loop {
                        let mut saw_newline = false;
                        // Skip ASCII whitespace.
                        while idx > 0 {
                          match bytes[idx - 1] {
                            b' ' | b'\t' => idx -= 1,
                            b'\n' | b'\r' => {
                              idx -= 1;
                              saw_newline = true;
                            }
                            _ => break,
                          }
                        }

                        // Skip block comment `/* ... */`.
                        if idx >= 2 && bytes[idx - 2] == b'*' && bytes[idx - 1] == b'/' {
                          idx = idx.saturating_sub(2);
                          while idx >= 2 {
                            if bytes[idx - 2] == b'/' && bytes[idx - 1] == b'*' {
                              idx = idx.saturating_sub(2);
                              continue 'outer;
                            }
                            idx -= 1;
                          }
                          continue 'outer;
                        }

                        // Skip comment-only line comments (`// ... \n`).
                        //
                        // We intentionally only treat `//` as a comment if it is the first
                        // non-whitespace token on the line. This avoids mis-identifying `//` inside
                        // string literals like `"http://..."` while doing this best-effort span
                        // repair.
                        if saw_newline {
                          let mut line_start = idx;
                          while line_start > 0 {
                            let b = bytes[line_start - 1];
                            if b == b'\n' || b == b'\r' {
                              break;
                            }
                            line_start -= 1;
                          }

                          let mut i = line_start;
                          while i < idx {
                            match bytes[i] {
                              b' ' | b'\t' => i += 1,
                              _ => break,
                            }
                          }

                          if i + 1 < idx && bytes[i] == b'/' && bytes[i + 1] == b'/' {
                            idx = line_start;
                            continue 'outer;
                          }
                        }

                        return idx;
                      }
                    };

                    // Find the `(` that opens the call's argument list.
                    let args_open: Option<usize> = if let Some(arg0) = call.stx.arguments.first() {
                      let rel_arg_start = arg0
                        .loc
                        .start_u32()
                        .saturating_sub(self.env.prefix_len());
                      let arg_start = self.env.base_offset().saturating_add(rel_arg_start) as usize;
                      let idx = skip_trivia_back(arg_start);
                      if idx > 0 && bytes.get(idx - 1) == Some(&b'(') {
                        Some(idx - 1)
                      } else {
                        None
                      }
                    } else {
                      // No arguments: find the `(` by scanning back from the closing `)`.
                      let end_idx = skip_trivia_back(span_end as usize);
                      if end_idx == 0 || bytes.get(end_idx - 1) != Some(&b')') {
                        None
                      } else {
                        let close_idx = end_idx - 1;
                        let idx = skip_trivia_back(close_idx);
                        if idx > 0 && bytes.get(idx - 1) == Some(&b'(') {
                          Some(idx - 1)
                        } else {
                          None
                        }
                      }
                    };

                    if let Some(args_open) = args_open {
                      // Find callee end in absolute source coordinates.
                      let rel_callee_end = call
                        .stx
                        .callee
                        .loc
                        .end_u32()
                        .saturating_sub(self.env.prefix_len());
                      let callee_end =
                        self.env.base_offset().saturating_add(rel_callee_end) as usize;
                      let callee_end = callee_end.min(bytes.len());

                      // Count how many `)` appear between callee_end and the call args `(`.
                      let mut close_scan = args_open;
                      let mut close_count: usize = 0;
                      while close_scan > callee_end {
                        close_scan = skip_trivia_back(close_scan);
                        if close_scan <= callee_end {
                          break;
                        }
                        if bytes.get(close_scan - 1) == Some(&b')') {
                          close_count = close_count.saturating_add(1);
                          close_scan -= 1;
                          continue;
                        }
                        break;
                      }

                      // Include the corresponding `(` before the callee start.
                      let mut start_scan = span_start as usize;
                      for _ in 0..close_count {
                        start_scan = skip_trivia_back(start_scan);
                        if start_scan == 0 || bytes.get(start_scan - 1) != Some(&b'(') {
                          break;
                        }
                        start_scan -= 1;
                      }
                      span_start = u32::try_from(start_scan).unwrap_or(span_start);
                    }
                  }
                }

                let member_span_start = self
                  .env
                  .base_offset()
                  .saturating_add(member_loc_start.saturating_sub(self.env.prefix_len()));
                span_start = self.class_field_initializer_span_start_scan(
                  member_span_start,
                  span_start,
                  span_end,
                );

                let code = self.vm.register_ecma_function(
                  self.env.source(),
                  span_start,
                  span_end,
                  EcmaFunctionKind::ClassFieldInitializer,
                )?;

                // Field initializer functions are always strict mode and have `length = 0`.
                let is_strict = true;
                let this_mode = ThisMode::Strict;
                let closure_env = Some(self.env.lexical_env);

                let name_string = member_scope.alloc_string("")?;
                let init_func_obj = member_scope.alloc_ecma_function(
                  code,
                  /* is_constructable */ false,
                  name_string,
                  0,
                  this_mode,
                  is_strict,
                  closure_env,
                )?;
                member_scope
                  .heap_mut()
                  .set_function_meta_property_context(init_func_obj, MetaPropertyContext::METHOD)?;

                let intr = self
                  .vm
                  .intrinsics()
                  .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;
                member_scope
                  .heap_mut()
                  .object_set_prototype(init_func_obj, Some(intr.function_prototype()))?;
                member_scope
                  .heap_mut()
                  .set_function_realm(init_func_obj, self.env.global_object())?;
                if let Some(realm) = self.vm.current_realm() {
                  member_scope
                    .heap_mut()
                    .set_function_job_realm(init_func_obj, realm)?;
                }
                if let Some(script_or_module) = self.vm.get_active_script_or_module() {
                  let token = self.vm.intern_script_or_module(script_or_module)?;
                  member_scope
                    .heap_mut()
                    .set_function_script_or_module_token(init_func_obj, Some(token))?;
                }
                member_scope
                  .heap_mut()
                  .set_function_home_object(init_func_obj, Some(target_obj))?;
                Value::Object(init_func_obj)
              }
              None => Value::Undefined,
            };

            if member.stx.static_ {
              // Static field: defer initialization until after the element definition pass.
              // Drop `member_scope` early so we can push persistent roots onto `class_scope`.
              drop(member_scope);
              class_scope.push_root(key_value)?;
              class_scope.push_root(init_value)?;
              static_inits
                .try_reserve(1)
                .map_err(|_| VmError::OutOfMemory)?;
              static_inits.push(StaticInitElement::Field {
                key: key_value,
                initializer: init_value,
              });
            } else {
              // Instance field: store as `(key, initializer)` in the class constructor's native slots.
              let slot_base = instance_field_slot_start
                .saturating_add(instance_field_idx.saturating_mul(2));
              member_scope
                .heap_mut()
                .set_function_native_slot(func_obj, slot_base, key_value)?;
              member_scope.heap_mut().set_function_native_slot(
                func_obj,
                slot_base.saturating_add(1),
                init_value,
              )?;
              instance_field_idx = instance_field_idx
                .checked_add(1)
                .ok_or(VmError::OutOfMemory)?;
            }
          }
          ClassOrObjVal::IndexSignature(_) => {
            return Err(VmError::Unimplemented("class index signature"));
          }
          // Class static blocks are handled above (collected and evaluated after this loop).
          ClassOrObjVal::StaticBlock(_) => {
            return Err(VmError::InvariantViolation(
              "class static blocks should be collected before key evaluation",
            ));
          }
        }
      }

      // Evaluate class static initialization elements (public static fields, private static fields,
      // and static blocks) in source order.
      for init in static_inits {
        match init {
          StaticInitElement::Block(stmts) => {
            self.eval_class_static_block(&mut class_scope, func_obj, stmts)?;
          }
          StaticInitElement::PrivateField { sym, init } => {
            self.eval_class_static_private_field(&mut class_scope, func_obj, sym, init)?;
          }
          StaticInitElement::Field { key, initializer } => {
            let key = match key {
              Value::String(s) => PropertyKey::from_string(s),
              Value::Symbol(s) => PropertyKey::from_symbol(s),
              Value::Undefined => {
                return Err(VmError::InvariantViolation("static field key is undefined"))
              }
              _ => {
                return Err(VmError::InvariantViolation(
                  "static field key is not a string or symbol",
                ))
              }
            };
            let value = match initializer {
              Value::Object(func) => self.vm.call_with_host_and_hooks(
                &mut *self.host,
                &mut class_scope,
                &mut *self.hooks,
                Value::Object(func),
                Value::Object(func_obj),
                &[],
              )?,
              Value::Undefined => Value::Undefined,
              _ => {
                return Err(VmError::InvariantViolation(
                  "static field initializer is not a function or undefined",
                ))
              }
            };
            class_scope.create_data_property_or_throw(func_obj, key, value)?;
          }
        }
      }

      Ok(func_obj)
    })();
    self.strict = saved_strict;
    result
  }

  fn eval_class_static_block(
    &mut self,
    scope: &mut Scope<'_>,
    receiver: GcObject,
    stmts: &[Node<Stmt>],
  ) -> Result<(), VmError> {
    // Static blocks are evaluated as strict-mode "method" function bodies with `this` bound to the
    // class constructor object and `new.target` set to `undefined`.
    //
    // We implement this by:
    // - creating a fresh var environment whose outer is the current class lexical environment,
    // - creating a function-body lexical environment whose outer is that var environment,
    // - instantiating the statement list, then evaluating it.
    //
    // This matches the internal structure used by `instantiate_function` for ordinary function
    // bodies, but without parameters or an `arguments` object (static blocks have an early error
    // for `ContainsArguments`).
    let mut block_scope = scope.reborrow();
    block_scope.push_root(Value::Object(receiver))?;

    let saved_this = self.this;
    let saved_this_initialized = self.this_initialized;
    let saved_new_target = self.new_target;
    let saved_home_object = self.home_object;
    let saved_lex = self.env.lexical_env;
    let saved_var_env = self.env.var_env();
    let saved_meta_property_context = self.env.meta_property_context();

    self.this = Value::Object(receiver);
    // Static blocks have their own `this` binding which is always initialized, even if the
    // surrounding code is executing inside a derived constructor before `super()` returns.
    self.this_initialized = true;
    self.new_target = Value::Undefined;
    // Static blocks use the class constructor object as their `[[HomeObject]]` so `super.prop`
    // resolves against `Object.getPrototypeOf(classConstructor)` and uses `classConstructor` as the
    // receiver.
    self.home_object = Some(receiver);
    self
      .env
      .set_meta_property_context(MetaPropertyContext::METHOD);

    let var_env = block_scope.env_create(Some(saved_lex))?;
    let body_lex = block_scope.env_create(Some(var_env))?;
    self.env.set_var_env(VarEnv::Env(var_env));
    self.env.set_lexical_env(block_scope.heap_mut(), body_lex);

    let res: Result<Completion, VmError> = (|| {
      self.instantiate_stmt_list(&mut block_scope, stmts)?;
      self.eval_stmt_list(&mut block_scope, stmts)
    })();

    // Restore the surrounding class evaluation context regardless of how the block completes.
    self.env.set_lexical_env(block_scope.heap_mut(), saved_lex);
    self.env.set_var_env(saved_var_env);
    self
      .env
      .set_meta_property_context(saved_meta_property_context);
    self.this = saved_this;
    self.this_initialized = saved_this_initialized;
    self.new_target = saved_new_target;
    self.home_object = saved_home_object;

    match res? {
      Completion::Normal(_) => Ok(()),
      Completion::Throw(thrown) => Err(VmError::ThrowWithStack {
        value: thrown.value,
        stack: thrown.stack,
      }),
      Completion::Return(_) => Err(VmError::InvariantViolation(
        "class static block produced Return completion (early errors should prevent this)",
      )),
      Completion::Break(..) => Err(VmError::InvariantViolation(
        "class static block produced Break completion (early errors should prevent this)",
      )),
      Completion::Continue(..) => Err(VmError::InvariantViolation(
        "class static block produced Continue completion (early errors should prevent this)",
      )),
    }
  }

  fn eval_class_static_private_field(
    &mut self,
    scope: &mut Scope<'_>,
    receiver: GcObject,
    sym: GcSymbol,
    init: Option<&Node<Expr>>,
  ) -> Result<(), VmError> {
    // Static field initializers run with `this` bound to the class constructor object and
    // `new.target` set to `undefined`.
    let mut field_scope = scope.reborrow();
    field_scope.push_roots(&[Value::Object(receiver), Value::Symbol(sym)])?;

    let saved_this = self.this;
    let saved_this_initialized = self.this_initialized;
    let saved_new_target = self.new_target;
    let saved_home_object = self.home_object;
    let saved_meta_property_context = self.env.meta_property_context();
    self.this = Value::Object(receiver);
    // Static field initializers have their own initialized `this` binding (the class constructor),
    // even if evaluated inside a derived constructor before `super()` returns.
    self.this_initialized = true;
    self.new_target = Value::Undefined;
    self.home_object = Some(receiver);
    self
      .env
      .set_meta_property_context(MetaPropertyContext::METHOD);

    let res: Result<(), VmError> = (|| {
      let value = match init {
        Some(expr) => self.eval_expr(&mut field_scope, expr)?,
        None => Value::Undefined,
      };
      field_scope.push_root(value)?;

      // Evaluate the initializer before adding the private field (matching `DefineField` semantics).
      let key = PropertyKey::from_symbol(sym);
      field_scope.define_property_or_throw(
        receiver,
        key,
        PropertyDescriptorPatch {
          value: Some(value),
          writable: Some(true),
          enumerable: Some(false),
          configurable: Some(false),
          ..Default::default()
        },
      )?;
      Ok(())
    })();

    self.this = saved_this;
    self.this_initialized = saved_this_initialized;
    self.new_target = saved_new_target;
    self.home_object = saved_home_object;
    self
      .env
      .set_meta_property_context(saved_meta_property_context);
    res
  }

  fn eval_class_decl(
    &mut self,
    scope: &mut Scope<'_>,
    decl: &Node<ClassDecl>,
  ) -> Result<Completion, VmError> {
    let extends_null = match decl.stx.extends.as_ref() {
      None => false,
      Some(expr) => matches!(&*expr.stx, Expr::LitNull(_)),
    };
    if !decl.stx.decorators.is_empty() {
      return Err(VmError::Unimplemented("class decorators"));
    }
    if decl.stx.type_parameters.is_some() {
      return Err(VmError::Unimplemented("class type parameters"));
    }
    if !decl.stx.implements.is_empty() {
      return Err(VmError::Unimplemented("class implements"));
    }
    if decl.stx.declare || decl.stx.abstract_ {
      return Err(VmError::Unimplemented("class modifiers"));
    }

    let binding_name = match decl.stx.name.as_ref() {
      Some(name) => name.stx.name.as_str(),
      None => "*default*",
    };

    let func_name = match decl.stx.name.as_ref() {
      Some(name) => name.stx.name.as_str(),
      None => "default",
    };

    // Per ECMAScript, class declarations are evaluated within a fresh lexical environment whose
    // outer is the surrounding lexical environment. When the class has a name, that environment
    // contains an immutable binding for the class name so class element functions can reference the
    // class even if the outer binding is later reassigned.
    let outer = self.env.lexical_env;
    let class_env = scope.env_create(Some(outer))?;
    self.env.set_lexical_env(scope.heap_mut(), class_env);

    let result = (|| {
      let inner_binding = match decl.stx.name.as_ref() {
        Some(name) => ClassBinding::Immutable(name.stx.name.as_str()),
        None => ClassBinding::None,
      };
      self.eval_class(
        scope,
        inner_binding,
        func_name,
        None,
        decl.stx.extends.as_ref(),
        &decl.stx.members,
        extends_null,
      )
    })();

    // Restore outer environment regardless of how class evaluation completes.
    self.env.set_lexical_env(scope.heap_mut(), outer);

    let func_obj = result?;

    // Initialize the outer (mutable) class binding in the surrounding environment.
    //
    // Root the class constructor object first: creating the binding may allocate and trigger GC.
    let mut init_scope = scope.reborrow();
    init_scope.push_root(Value::Object(func_obj))?;

    if !init_scope.heap().env_has_binding(outer, binding_name)? {
      // Non-block statement contexts may not have performed lexical hoisting yet.
      init_scope.env_create_mutable_binding(outer, binding_name)?;
    }
    init_scope
      .heap_mut()
      .env_initialize_binding(outer, binding_name, Value::Object(func_obj))?;
    Ok(Completion::empty())
  }

  fn eval_class_expr(
    &mut self,
    scope: &mut Scope<'_>,
    expr: &Node<ClassExpr>,
  ) -> Result<Value, VmError> {
    self.eval_class_expr_inner(scope, expr, None)
  }

  fn eval_class_expr_named(
    &mut self,
    scope: &mut Scope<'_>,
    expr: &Node<ClassExpr>,
    inferred_name: PropertyKey,
  ) -> Result<Value, VmError> {
    self.eval_class_expr_inner(scope, expr, Some(inferred_name))
  }

  fn eval_class_expr_inner(
    &mut self,
    scope: &mut Scope<'_>,
    expr: &Node<ClassExpr>,
    inferred_name: Option<PropertyKey>,
  ) -> Result<Value, VmError> {
    let extends_null = match expr.stx.extends.as_ref() {
      None => false,
      Some(expr) => matches!(&*expr.stx, Expr::LitNull(_)),
    };
    if !expr.stx.decorators.is_empty() {
      return Err(VmError::Unimplemented("class decorators"));
    }
    if expr.stx.type_parameters.is_some() {
      return Err(VmError::Unimplemented("class type parameters"));
    }
    if !expr.stx.implements.is_empty() {
      return Err(VmError::Unimplemented("class implements"));
    }

    // Named class expressions introduce an inner immutable binding for the class name.
    let outer = self.env.lexical_env;
    let result = (|| {
      let Some(name) = expr.stx.name.as_ref() else {
        let func_obj = self.eval_class(
          scope,
          ClassBinding::None,
          "",
          inferred_name,
          expr.stx.extends.as_ref(),
          &expr.stx.members,
          extends_null,
        )?;
        return Ok(Value::Object(func_obj));
      };

      let class_env = scope.env_create(Some(outer))?;
      self.env.set_lexical_env(scope.heap_mut(), class_env);

      let func_obj = self.eval_class(
        scope,
        ClassBinding::Immutable(name.stx.name.as_str()),
        name.stx.name.as_str(),
        None,
        expr.stx.extends.as_ref(),
        &expr.stx.members,
        extends_null,
      )?;
      Ok(Value::Object(func_obj))
    })();

    self.env.set_lexical_env(scope.heap_mut(), outer);
    result
  }

  fn eval_if(&mut self, scope: &mut Scope<'_>, stmt: &IfStmt) -> Result<Completion, VmError> {
    let test = self.eval_expr(scope, &stmt.test)?;
    if to_boolean(scope.heap(), test)? {
      self.eval_stmt(scope, &stmt.consequent)
    } else if let Some(alt) = &stmt.alternate {
      self.eval_stmt(scope, alt)
    } else {
      Ok(Completion::empty())
    }
  }

  fn eval_throw(
    &mut self,
    scope: &mut Scope<'_>,
    stmt: &Node<ThrowStmt>,
  ) -> Result<Completion, VmError> {
    let value = self.eval_expr(scope, &stmt.stx.value)?;

    // Capture a stack trace at the throw site.
    //
    // We capture the VM's current call stack and then update the top frame's `source/line/col` to
    // point at the throw statement (rather than the function entry). This aligns better with
    // browser stack traces where the top frame refers to the actual throw location.
    let source = self.env.source();
    let rel_start = stmt.loc.start_u32().saturating_sub(self.env.prefix_len());
    let abs_offset = self.env.base_offset().saturating_add(rel_start);
    let (line, col) = source.line_col(abs_offset);

    let mut stack = self.vm.capture_stack();
    if let Some(top) = stack.first_mut() {
      top.source = source.name.clone();
      top.line = line;
      top.col = col;
    } else {
      stack.push(StackFrame {
        function: None,
        source: source.name.clone(),
        line,
        col,
      });
    }

    crate::error_object::attach_stack_property_for_throw(scope, value, &stack);
    Ok(Completion::Throw(Thrown { value, stack }))
  }

  fn eval_try(&mut self, scope: &mut Scope<'_>, stmt: &TryStmt) -> Result<Completion, VmError> {
    // Evaluate the `try` statement in a nested scope so stack roots pushed while constructing
    // implicit Error objects (and other temporaries) inside the `try`/`catch`/`finally` do not
    // escape into the surrounding statement list.
    //
    // Without this, repeated throw/catch patterns like:
    // `for (...) { try { ... } catch(e) {} }`
    // can accumulate roots and retain otherwise-unreachable Error objects, eventually exhausting
    // the heap in low-memory configurations (tests run with a small heap limit).
    let mut try_scope = scope.reborrow();

    let mut result = self.eval_block_stmt(&mut try_scope, &stmt.wrapped.stx)?;

    if matches!(result, Completion::Throw(_)) {
      if let Some(catch) = &stmt.catch {
        let (thrown_value, thrown_stack) = match result {
          Completion::Throw(thrown) => (thrown.value, thrown.stack),
          _ => return Err(VmError::Unimplemented("try/catch missing thrown value")),
        };
        crate::error_object::attach_stack_property_for_throw(&mut try_scope, thrown_value, &thrown_stack);
        result = self.eval_catch(&mut try_scope, &catch.stx, thrown_value)?;
      }
    }

    if let Some(finally) = &stmt.finally {
      // Root the pending completion's value (if any) while evaluating `finally`, which may
      // allocate and trigger GC.
      let pending_root = result
        .value()
        .map(|v| try_scope.heap_mut().add_root(v))
        .transpose()?;
      let finally_result = self.eval_block_stmt(&mut try_scope, &finally.stx)?;
      if let Some(root) = pending_root {
        try_scope.heap_mut().remove_root(root);
      }

      if finally_result.is_abrupt() {
        result = finally_result;
      }
    }

    Ok(result.update_empty(Some(Value::Undefined)))
  }

  fn eval_catch(
    &mut self,
    scope: &mut Scope<'_>,
    catch: &CatchBlock,
    thrown: Value,
  ) -> Result<Completion, VmError> {
    let outer = self.env.lexical_env;

    // Root the thrown value across all catch setup, including `env_create`, which may allocate and
    // trigger GC before we instantiate bindings.
    let mut catch_scope = scope.reborrow();
    catch_scope.push_root(thrown)?;

    // ECMA-262 CatchClauseEvaluation:
    // - If the catch parameter is present, it is bound in a fresh environment (paramEnv).
    // - The catch block itself is evaluated in a separate environment (blockEnv) whose outer is
    //   paramEnv. This ensures:
    //   - catch-parameter destructuring defaults observe TDZ for the parameter bindings, and
    //   - closures created in the catch body capture block lexical bindings, not the parameter env.
    let result = (|| {
      if let Some(param) = &catch.parameter {
        // --- Catch parameter binding ---
        let param_env = catch_scope.env_create(Some(outer))?;
        self.env.set_lexical_env(catch_scope.heap_mut(), param_env);

        // Create uninitialized mutable bindings for BoundNames(CatchParameter) before evaluating
        // destructuring defaults.
        self.instantiate_lexical_names_from_pat(
          &mut catch_scope,
          param_env,
          &param.stx.pat.stx,
          param.stx.pat.loc,
          /* mutable */ true,
        )?;

        self.bind_catch_param(&mut catch_scope, &param.stx, thrown, param_env)?;

        // --- Catch block evaluation ---
        let block_env = catch_scope.env_create(Some(param_env))?;
        self.env.set_lexical_env(catch_scope.heap_mut(), block_env);

        self.instantiate_block_decls_in_stmt_list(&mut catch_scope, block_env, &catch.body)?;
        self.eval_stmt_list(&mut catch_scope, &catch.body)
      } else {
        // Optional catch binding (`catch { ... }`): evaluate the catch body as a normal block.
        let needs_lexical_env = catch.body.iter().any(|stmt| match &*stmt.stx {
          Stmt::VarDecl(var)
            if matches!(
              var.stx.mode,
              VarDeclMode::Let
                | VarDeclMode::Const
                | VarDeclMode::Using
                | VarDeclMode::AwaitUsing
            ) =>
          {
            true
          }
          Stmt::ClassDecl(_) => true,
          Stmt::FunctionDecl(_) => true,
          _ => false,
        });
        if !needs_lexical_env {
          return self.eval_stmt_list(&mut catch_scope, &catch.body);
        }

        let block_env = catch_scope.env_create(Some(outer))?;
        self.env.set_lexical_env(catch_scope.heap_mut(), block_env);
        self.instantiate_block_decls_in_stmt_list(&mut catch_scope, block_env, &catch.body)?;
        self.eval_stmt_list(&mut catch_scope, &catch.body)
      }
    })();

    // Always restore the outer lexical environment so later statements run in the correct scope.
    self.env.set_lexical_env(catch_scope.heap_mut(), outer);
    result
  }

  fn bind_catch_param(
    &mut self,
    scope: &mut Scope<'_>,
    param: &PatDecl,
    thrown: Value,
    env: GcEnv,
  ) -> Result<(), VmError> {
    // Bind into the provided catch environment (which should also be the current lexical env).
    let _ = env;
    bind_pattern(
      self.vm,
      &mut *self.host,
      &mut *self.hooks,
      scope,
      self.env,
      &param.pat.stx,
      thrown,
      BindingKind::Let,
      self.strict,
      self.this,
    )
  }

  fn eval_return(
    &mut self,
    scope: &mut Scope<'_>,
    stmt: &ReturnStmt,
  ) -> Result<Completion, VmError> {
    let value = match &stmt.value {
      Some(expr) => self.eval_expr(scope, expr)?,
      None => Value::Undefined,
    };
    Ok(Completion::Return(value))
  }

  /// ECMA-262 `LoopContinues(completion, labelSet)`.
  fn loop_continues(completion: &Completion, label_set: &[String]) -> bool {
    match completion {
      Completion::Normal(_) => true,
      Completion::Continue(None, _) => true,
      Completion::Continue(Some(target), _) => label_set.iter().any(|l| l == target),
      _ => false,
    }
  }

  /// Converts an unlabelled `break` completion from a breakable statement into a normal
  /// completion (ECMA-262 `BreakableStatement` / `LabelledEvaluation` semantics).
  fn normalise_iteration_break(completion: Completion) -> Completion {
    match completion {
      Completion::Break(None, value) => Completion::normal(value.unwrap_or(Value::Undefined)),
      other => other,
    }
  }

  fn eval_while(
    &mut self,
    scope: &mut Scope<'_>,
    stmt: &WhileStmt,
    label_set: &[String],
  ) -> Result<Completion, VmError> {
    let result = self.while_loop_evaluation(scope, stmt, label_set)?;
    Ok(Self::normalise_iteration_break(result))
  }

  /// ECMA-262 `WhileLoopEvaluation`.
  fn while_loop_evaluation(
    &mut self,
    scope: &mut Scope<'_>,
    stmt: &WhileStmt,
    label_set: &[String],
  ) -> Result<Completion, VmError> {
    // Root `V` across the loop so the value can't be collected between iterations.
    let mut scope = scope.reborrow();
    let v_root_idx = scope.heap().root_stack.len();
    scope.push_root(Value::Undefined)?;
    let mut v = Value::Undefined;

    loop {
      let test = self.eval_expr(&mut scope, &stmt.condition)?;
      if !to_boolean(scope.heap(), test)? {
        return Ok(Completion::normal(v));
      }

      let stmt_result = self.eval_stmt(&mut scope, &stmt.body)?;
      if !Self::loop_continues(&stmt_result, label_set) {
        return Ok(stmt_result.update_empty(Some(v)));
      }

      if let Some(value) = stmt_result.value() {
        v = value;
        scope.heap_mut().root_stack[v_root_idx] = value;
      }
    }
  }

  fn eval_do_while(
    &mut self,
    scope: &mut Scope<'_>,
    stmt: &DoWhileStmt,
    label_set: &[String],
  ) -> Result<Completion, VmError> {
    let result = self.do_while_loop_evaluation(scope, stmt, label_set)?;
    Ok(Self::normalise_iteration_break(result))
  }

  /// ECMA-262 `DoWhileLoopEvaluation`.
  fn do_while_loop_evaluation(
    &mut self,
    scope: &mut Scope<'_>,
    stmt: &DoWhileStmt,
    label_set: &[String],
  ) -> Result<Completion, VmError> {
    // Root `V` across the loop so the value can't be collected between iterations.
    let mut scope = scope.reborrow();
    let v_root_idx = scope.heap().root_stack.len();
    scope.push_root(Value::Undefined)?;
    let mut v = Value::Undefined;

    loop {
      let stmt_result = self.eval_stmt(&mut scope, &stmt.body)?;
      if !Self::loop_continues(&stmt_result, label_set) {
        return Ok(stmt_result.update_empty(Some(v)));
      }

      if let Some(value) = stmt_result.value() {
        v = value;
        scope.heap_mut().root_stack[v_root_idx] = value;
      }

      let test = self.eval_expr(&mut scope, &stmt.condition)?;
      if !to_boolean(scope.heap(), test)? {
        return Ok(Completion::normal(v));
      }
    }
  }

  fn eval_with(
    &mut self,
    scope: &mut Scope<'_>,
    stmt: &WithStmt,
    label_set: &[String],
  ) -> Result<Completion, VmError> {
    // Minimal ECMA-262 `WithStatement` evaluation:
    //
    // - Evaluate the object expression, then `ToObject` it.
    // - Create an ObjectEnvironmentRecord with `with_environment = true`.
    // - Evaluate the body with that env record as the current lexical environment.
    let mut with_scope = scope.reborrow();
    let object_value = self.eval_expr(&mut with_scope, &stmt.object)?;
    with_scope.push_root(object_value)?;
    let binding_object =
      with_scope.to_object(self.vm, &mut *self.host, &mut *self.hooks, object_value)?;
    with_scope.push_root(Value::Object(binding_object))?;

    let outer = self.env.lexical_env;
    let with_env = with_scope.alloc_object_env_record(binding_object, Some(outer), true)?;
    self.env.set_lexical_env(with_scope.heap_mut(), with_env);

    let result = self.eval_stmt_labelled(&mut with_scope, &stmt.body, label_set);

    // Always restore the outer lexical environment so later statements run in the correct scope.
    self.env.set_lexical_env(with_scope.heap_mut(), outer);
    result
  }

  fn eval_for_triple(
    &mut self,
    scope: &mut Scope<'_>,
    stmt: &ForTripleStmt,
    label_set: &[String],
  ) -> Result<Completion, VmError> {
    let result = self.for_triple_loop_evaluation(scope, stmt, label_set)?;
    Ok(Self::normalise_iteration_break(result))
  }

  fn create_for_triple_per_iteration_env(
    &mut self,
    scope: &mut Scope<'_>,
    outer: GcEnv,
    last_env: GcEnv,
  ) -> Result<GcEnv, VmError> {
    let crate::env::EnvRecord::Declarative(last) = scope.heap().get_env_record(last_env)? else {
      return Err(VmError::InvariantViolation(
        "for-loop per-iteration environment must be declarative",
      ));
    };

    let bindings = &last.bindings;
    let mut new_bindings: Vec<crate::EnvBinding> = Vec::new();
    new_bindings
      .try_reserve_exact(bindings.len())
      .map_err(|_| VmError::OutOfMemory)?;

    const TICK_EVERY: usize = 32;
    for (i, binding) in bindings.iter().enumerate() {
      if i % TICK_EVERY == 0 {
        self.tick()?;
      }
      new_bindings.push(*binding);
    }

    scope.alloc_env_record(Some(outer), &new_bindings)
  }

  /// ECMA-262 `ForLoopEvaluation` for `for (init; cond; post) { ... }`.
  fn for_triple_loop_evaluation(
    &mut self,
    scope: &mut Scope<'_>,
    stmt: &ForTripleStmt,
    label_set: &[String],
  ) -> Result<Completion, VmError> {
    // Root `V` across the loop so the value can't be collected between iterations.
    let mut scope = scope.reborrow();
    let v_root_idx = scope.heap().root_stack.len();
    scope.push_root(Value::Undefined)?;
    let mut v = Value::Undefined;

    // Lexically-declared `for` loops require per-iteration environments so closures capture the
    // correct binding value (ECMA-262 `CreatePerIterationEnvironment`).
    let lexical_init = match &stmt.init {
      parse_js::ast::stmt::ForTripleStmtInit::Decl(decl)
        if matches!(
          decl.stx.mode,
          VarDeclMode::Let | VarDeclMode::Const | VarDeclMode::Using | VarDeclMode::AwaitUsing
        ) =>
      {
        Some(decl)
      }
      _ => None,
    };

    if let Some(init_decl) = lexical_init {
      let outer_lex = self.env.lexical_env;

      let result = (|| -> Result<Completion, VmError> {
        // Create a loop-scoped declarative environment for the lexical declaration and evaluate the
        // initializer with TDZ semantics.
        let loop_env = scope.env_create(Some(outer_lex))?;
        self.env.set_lexical_env(scope.heap_mut(), loop_env);

        let mutable = init_decl.stx.mode == VarDeclMode::Let;
        for declarator in &init_decl.stx.declarators {
          self.tick()?;
          self.instantiate_lexical_names_from_pat(
            &mut scope,
            loop_env,
            &declarator.pattern.stx.pat.stx,
            init_decl.loc,
            mutable,
          )?;
        }

        let _ = self.eval_var_decl(&mut scope, &init_decl.stx)?;

        // Enter the first per-iteration environment.
        let mut iter_env =
          self.create_for_triple_per_iteration_env(&mut scope, outer_lex, loop_env)?;
        self.env.set_lexical_env(scope.heap_mut(), iter_env);

        // Most `for` loop iterations are naturally budgeted by ticks in:
        // - condition/update expression evaluation (if present), and/or
        // - evaluating at least one statement in the loop body.
        //
        // However, `for (let x = 0;;) {}` can execute no statements/expressions per iteration, so
        // tick explicitly to ensure budgets/interrupts are still observed.
        let needs_explicit_iter_tick =
          stmt.cond.is_none() && stmt.post.is_none() && stmt.body.stx.body.is_empty();

        loop {
          if needs_explicit_iter_tick {
            self.tick()?;
          }

          if let Some(cond) = &stmt.cond {
            let test = self.eval_expr(&mut scope, cond)?;
            if !to_boolean(scope.heap(), test)? {
              return Ok(Completion::normal(v));
            }
          }

          let body_result = self.eval_for_body(&mut scope, &stmt.body.stx)?;
          if !Self::loop_continues(&body_result, label_set) {
            return Ok(body_result.update_empty(Some(v)));
          }

          if let Some(value) = body_result.value() {
            v = value;
            scope.heap_mut().root_stack[v_root_idx] = value;
          }

          // Create the next iteration's environment *before* evaluating the update expression so
          // closures created in the body do not observe the post-update value.
          iter_env = self.create_for_triple_per_iteration_env(&mut scope, outer_lex, iter_env)?;
          self.env.set_lexical_env(scope.heap_mut(), iter_env);

          if let Some(post) = &stmt.post {
            let _ = self.eval_expr(&mut scope, post)?;
          }
        }
      })();

      // Always restore the outer lexical environment so later statements run in the correct scope.
      self.env.set_lexical_env(scope.heap_mut(), outer_lex);
      return result;
    }

    match &stmt.init {
      parse_js::ast::stmt::ForTripleStmtInit::None => {}
      parse_js::ast::stmt::ForTripleStmtInit::Expr(expr) => {
        let _ = self.eval_expr(&mut scope, expr)?;
      }
      parse_js::ast::stmt::ForTripleStmtInit::Decl(decl) => {
        let _ = self.eval_var_decl(&mut scope, &decl.stx)?;
      }
    }

    // Most `for` loop iterations are naturally budgeted by ticks in:
    // - condition/update expression evaluation (if present), and/or
    // - evaluating at least one statement in the loop body.
    //
    // However, `for(;;){}` executes no statements/expressions per iteration. Tick explicitly to
    // ensure budgets/interrupts are still observed.
    let needs_explicit_iter_tick =
      stmt.cond.is_none() && stmt.post.is_none() && stmt.body.stx.body.is_empty();

    loop {
      if needs_explicit_iter_tick {
        self.tick()?;
      }

      if let Some(cond) = &stmt.cond {
        let test = self.eval_expr(&mut scope, cond)?;
        if !to_boolean(scope.heap(), test)? {
          return Ok(Completion::normal(v));
        }
      }

      let stmt_result = self.eval_for_body(&mut scope, &stmt.body.stx)?;
      if !Self::loop_continues(&stmt_result, label_set) {
        return Ok(stmt_result.update_empty(Some(v)));
      }

      if let Some(value) = stmt_result.value() {
        v = value;
        scope.heap_mut().root_stack[v_root_idx] = value;
      }

      if let Some(post) = &stmt.post {
        let _ = self.eval_expr(&mut scope, post)?;
      }
    }
  }

  fn eval_for_in(
    &mut self,
    scope: &mut Scope<'_>,
    stmt: &ForInStmt,
    label_set: &[String],
  ) -> Result<Completion, VmError> {
    let result = self.for_in_loop_evaluation(scope, stmt, label_set)?;
    Ok(Self::normalise_iteration_break(result))
  }

  fn for_in_loop_evaluation(
    &mut self,
    scope: &mut Scope<'_>,
    stmt: &ForInStmt,
    label_set: &[String],
  ) -> Result<Completion, VmError> {
    // ECMA-262 `ForIn/OfHeadEvaluation`:
    // If the loop uses a `ForDeclaration` with lexical bindings (`let` / `const` / `using` /
    // `await using`), create a TDZ lexical environment for the bound names while evaluating the
    // RHS. Closures created during RHS evaluation must capture this TDZ environment (not the loop
    // body envs).
    let rhs_value = self.eval_for_in_of_rhs_with_tdz_env(scope, &stmt.lhs, &stmt.rhs)?;
    // ECMA-262 `ForIn/OfHeadEvaluation` (iterationKind = enumerate):
    // If the RHS evaluates to `null` or `undefined`, iteration is skipped (no throw).
    if matches!(rhs_value, Value::Null | Value::Undefined) {
      return Ok(Completion::normal(Value::Undefined));
    }
    let object = scope.to_object(self.vm, &mut *self.host, &mut *self.hooks, rhs_value)?;

    // Root the base object while enumerating keys and executing the loop body.
    let mut iter_scope = scope.reborrow();
    iter_scope.push_root(Value::Object(object))?;

    let mut enumerator = ForInEnumerator::new(object);

    // Root `V` across the loop so the value can't be collected between iterations.
    let v_root_idx = iter_scope.heap().root_stack.len();
    iter_scope.push_root(Value::Undefined)?;
    let mut v = Value::Undefined;

    // If the loop uses a lexical declaration (`let`/`const`/`using`/`await using`), we emulate
    // per-iteration lexical environments by creating a fresh env record per iteration.
    let outer_lex = self.env.lexical_env;

    loop {
      let next_key =
        enumerator.next_key(self.vm, &mut iter_scope, &mut *self.host, &mut *self.hooks)?;

      let Some(key_s) = next_key else {
        break;
      };

      // Tick once per iteration so `for (k in o) {}` is budgeted even when the body is empty.
      self.tick()?;

      let mut iter_env: Option<GcEnv> = None;
      if let ForInOfLhs::Decl((mode, _)) = &stmt.lhs {
        if matches!(
          *mode,
          VarDeclMode::Let | VarDeclMode::Const | VarDeclMode::Using | VarDeclMode::AwaitUsing
        ) {
          let env = iter_scope.env_create(Some(outer_lex))?;
          self.env.set_lexical_env(iter_scope.heap_mut(), env);
          iter_env = Some(env);
        }
      }

      let value = Value::String(key_s);

      let bind_res: Result<(), VmError> = match &stmt.lhs {
        ForInOfLhs::Decl((mode, pat_decl)) => {
          let kind = match *mode {
            VarDeclMode::Var => BindingKind::Var,
            VarDeclMode::Let => BindingKind::Let,
            VarDeclMode::Const => BindingKind::Const,
            VarDeclMode::Using | VarDeclMode::AwaitUsing => BindingKind::Const,
          };
          bind_pattern(
            self.vm,
            &mut *self.host,
            &mut *self.hooks,
            &mut iter_scope,
            self.env,
            &pat_decl.stx.pat.stx,
            value,
            kind,
            self.strict,
            self.this,
          )
        }
        ForInOfLhs::Assign(pat) => bind_pattern(
          self.vm,
          &mut *self.host,
          &mut *self.hooks,
          &mut iter_scope,
          self.env,
          &pat.stx,
          value,
          BindingKind::Assignment,
          self.strict,
          self.this,
        ),
      };

      if let Err(err) = bind_res {
        if iter_env.is_some() {
          self.env.set_lexical_env(iter_scope.heap_mut(), outer_lex);
        }
        return Err(err);
      }

      let body_completion = match self.eval_for_body(&mut iter_scope, &stmt.body.stx) {
        Ok(c) => c,
        Err(err) => {
          if iter_env.is_some() {
            self.env.set_lexical_env(iter_scope.heap_mut(), outer_lex);
          }
          return Err(err);
        }
      };

      if iter_env.is_some() {
        self.env.set_lexical_env(iter_scope.heap_mut(), outer_lex);
      }

      if !Self::loop_continues(&body_completion, label_set) {
        return Ok(body_completion.update_empty(Some(v)));
      }

      if let Some(value) = body_completion.value() {
        v = value;
        iter_scope.heap_mut().root_stack[v_root_idx] = value;
      }
    }

    Ok(Completion::normal(v))
  }

  fn eval_for_of(
    &mut self,
    scope: &mut Scope<'_>,
    stmt: &ForOfStmt,
    label_set: &[String],
  ) -> Result<Completion, VmError> {
    let result = self.for_of_loop_evaluation(scope, stmt, label_set)?;
    Ok(Self::normalise_iteration_break(result))
  }

  fn for_of_loop_evaluation(
    &mut self,
    scope: &mut Scope<'_>,
    stmt: &ForOfStmt,
    label_set: &[String],
  ) -> Result<Completion, VmError> {
    if stmt.await_ {
      return Err(VmError::InvariantViolation(
        "for-await-of reached in sync statement evaluator",
      ));
    }

    // ECMA-262 `ForIn/OfHeadEvaluation`:
    // If the loop uses a `ForDeclaration` with lexical bindings (`let` / `const` / `using` /
    // `await using`), create a TDZ lexical environment for the bound names while evaluating the
    // RHS. Closures created during RHS evaluation must capture this TDZ environment (not the loop
    // body envs).
    let iterable = self.eval_for_in_of_rhs_with_tdz_env(scope, &stmt.lhs, &stmt.rhs)?;

    // Root the iterable + iterator record while evaluating the loop body, which may allocate and
    // trigger GC.
    let mut iter_scope = scope.reborrow();
    iter_scope.push_root(iterable)?;

    let mut iterator_record = iterator::get_iterator(
      self.vm,
      &mut *self.host,
      &mut *self.hooks,
      &mut iter_scope,
      iterable,
    )?;
    iter_scope.push_roots(&[iterator_record.iterator, iterator_record.next_method])?;

    // Root `V` across the loop so the value can't be collected between iterations.
    let v_root_idx = iter_scope.heap().root_stack.len();
    iter_scope.push_root(Value::Undefined)?;
    let mut v = Value::Undefined;

    // If the loop uses a lexical declaration (`let`/`const`/`using`/`await using`), we emulate
    // per-iteration lexical environments by creating a fresh env record per iteration.
    let outer_lex = self.env.lexical_env;

    loop {
      // Tick once per iteration so `for (x of xs) {}` is budgeted even when the body is empty.
      self.tick()?;

      let next_value = match iterator::iterator_step_value(
        self.vm,
        &mut *self.host,
        &mut *self.hooks,
        &mut iter_scope,
        &mut iterator_record,
      ) {
        Ok(v) => v,
        // Spec: `ForIn/OfBodyEvaluation` does not perform `IteratorClose` on errors produced while
        // stepping the iterator (`next`/`done`/`value`).
        Err(err) => return Err(err),
      };

      let Some(value) = next_value else {
        return Ok(Completion::normal(v));
      };

      let mut iter_env: Option<GcEnv> = None;
      if let ForInOfLhs::Decl((mode, _)) = &stmt.lhs {
        if matches!(
          *mode,
          VarDeclMode::Let | VarDeclMode::Const | VarDeclMode::Using | VarDeclMode::AwaitUsing
        ) {
          let env = iter_scope.env_create(Some(outer_lex))?;
          self.env.set_lexical_env(iter_scope.heap_mut(), env);
          iter_env = Some(env);
        }
      }

      let bind_res: Result<(), VmError> = match &stmt.lhs {
        ForInOfLhs::Decl((mode, pat_decl)) => {
          let kind = match *mode {
            VarDeclMode::Var => BindingKind::Var,
            VarDeclMode::Let => BindingKind::Let,
            VarDeclMode::Const => BindingKind::Const,
            VarDeclMode::Using | VarDeclMode::AwaitUsing => BindingKind::Const,
          };
          bind_pattern(
            self.vm,
            &mut *self.host,
            &mut *self.hooks,
            &mut iter_scope,
            self.env,
            &pat_decl.stx.pat.stx,
            value,
            kind,
            self.strict,
            self.this,
          )
        }
        ForInOfLhs::Assign(pat) => bind_pattern(
          self.vm,
          &mut *self.host,
          &mut *self.hooks,
          &mut iter_scope,
          self.env,
          &pat.stx,
          value,
          BindingKind::Assignment,
          self.strict,
          self.this,
        ),
      };

      if let Err(err) = bind_res {
        if iter_env.is_some() {
          self.env.set_lexical_env(iter_scope.heap_mut(), outer_lex);
        }
        return Err(self.iterator_close_on_error(&mut iter_scope, &iterator_record, err));
      }

      let body_completion = match self.eval_for_body(&mut iter_scope, &stmt.body.stx) {
        Ok(c) => c,
        Err(err) => {
          if iter_env.is_some() {
            self.env.set_lexical_env(iter_scope.heap_mut(), outer_lex);
          }
          return Err(self.iterator_close_on_error(&mut iter_scope, &iterator_record, err));
        }
      };

      if iter_env.is_some() {
        self.env.set_lexical_env(iter_scope.heap_mut(), outer_lex);
      }

      if !Self::loop_continues(&body_completion, label_set) {
        let completion = body_completion.update_empty(Some(v));
        let completion =
          self.iterator_close_on_completion(&mut iter_scope, &iterator_record, completion)?;
        return Ok(completion);
      }

      if let Some(value) = body_completion.value() {
        v = value;
        iter_scope.heap_mut().root_stack[v_root_idx] = value;
      }
    }
  }

  fn eval_for_in_of_rhs_with_tdz_env(
    &mut self,
    scope: &mut Scope<'_>,
    lhs: &ForInOfLhs,
    rhs: &Node<Expr>,
  ) -> Result<Value, VmError> {
    let ForInOfLhs::Decl((mode, pat_decl)) = lhs else {
      return self.eval_expr(scope, rhs);
    };
    if !matches!(
      *mode,
      VarDeclMode::Let | VarDeclMode::Const | VarDeclMode::Using | VarDeclMode::AwaitUsing
    ) {
      return self.eval_expr(scope, rhs);
    }

    let old_env = self.env.lexical_env;
    let tdz_env = scope.env_create(Some(old_env))?;
    Self::create_for_in_of_head_tdz_bindings(scope, tdz_env, &pat_decl.stx.pat)?;

    self.env.set_lexical_env(scope.heap_mut(), tdz_env);
    let rhs_res = self.eval_expr(scope, rhs);
    // Always restore the caller's lexical environment, even on abrupt completion.
    self.env.set_lexical_env(scope.heap_mut(), old_env);
    rhs_res
  }

  fn create_for_in_of_head_tdz_bindings(
    scope: &mut Scope<'_>,
    env: GcEnv,
    pat: &Node<Pat>,
  ) -> Result<(), VmError> {
    match &*pat.stx {
      Pat::Id(id) => scope.env_create_mutable_binding(env, &id.stx.name),
      Pat::Arr(arr) => {
        for elem in &arr.stx.elements {
          let Some(elem) = elem else { continue };
          Self::create_for_in_of_head_tdz_bindings(scope, env, &elem.target)?;
        }
        if let Some(rest) = &arr.stx.rest {
          Self::create_for_in_of_head_tdz_bindings(scope, env, rest)?;
        }
        Ok(())
      }
      Pat::Obj(obj) => {
        for prop in &obj.stx.properties {
          Self::create_for_in_of_head_tdz_bindings(scope, env, &prop.stx.target)?;
        }
        if let Some(rest) = &obj.stx.rest {
          Self::create_for_in_of_head_tdz_bindings(scope, env, rest)?;
        }
        Ok(())
      }
      Pat::AssignTarget(_) => {
        // Assignment targets are not binding patterns; ignore.
        Ok(())
      }
    }
  }

  fn eval_for_body(
    &mut self,
    scope: &mut Scope<'_>,
    body: &ForBody,
  ) -> Result<Completion, VmError> {
    if body.body.is_empty() {
      return Ok(Completion::empty());
    }

    // `ForBody` is a statement-list wrapper used by `parse-js` for loop bodies. When the original
    // source used braces (`for (...) { ... }`), these statements must behave like a block:
    // - lexical declarations are scoped to the body, and
    // - they must not "leak" into the per-iteration environment used for `for (let ...)` loops.
    //
    // If we were to execute the statement list directly in the current lexical environment,
    // `let`/`const` declarations would attempt to re-initialize bindings on subsequent iterations
    // and trip `env_initialize_binding`'s "already initialized" invariant.
    let needs_lexical_env = body.body.iter().any(|stmt| match &*stmt.stx {
      Stmt::VarDecl(var)
        if matches!(
          var.stx.mode,
          VarDeclMode::Let | VarDeclMode::Const | VarDeclMode::Using | VarDeclMode::AwaitUsing
        ) =>
      {
        true
      }
      Stmt::ClassDecl(_) => true,
      Stmt::FunctionDecl(_) => true,
      _ => false,
    });
    if !needs_lexical_env {
      return self.eval_stmt_list(scope, &body.body);
    }

    let outer = self.env.lexical_env;
    let body_env = scope.env_create(Some(outer))?;
    self.env.set_lexical_env(scope.heap_mut(), body_env);

    let result = self
      .instantiate_block_decls_in_stmt_list(scope, body_env, &body.body)
      .and_then(|_| self.eval_stmt_list(scope, &body.body));

    self.env.set_lexical_env(scope.heap_mut(), outer);
    result
  }

  fn eval_label(
    &mut self,
    scope: &mut Scope<'_>,
    stmt: &LabelStmt,
    label_set: &[String],
  ) -> Result<Completion, VmError> {
    let mut new_label_set = label_set.to_vec();
    new_label_set.push(stmt.name.clone());

    let result = self.eval_stmt_labelled(scope, &stmt.statement, &new_label_set)?;

    match result {
      Completion::Break(Some(target), value) if target == stmt.name => {
        // ECMA-262 `LabelledEvaluation`: a labelled `break` is consumed by the matching label,
        // preserving the completion value (which may be ~empty~).
        Ok(Completion::Normal(value))
      }
      other => Ok(other),
    }
  }

  fn eval_switch(
    &mut self,
    scope: &mut Scope<'_>,
    stmt: &SwitchStmt,
  ) -> Result<Completion, VmError> {
    // 13.12.3 Runtime Semantics: Evaluation, SwitchStatement
    let discriminant = self.eval_expr(scope, &stmt.test)?;

    // Root the discriminant across selector evaluation and case-body execution, which may allocate
    // and trigger GC.
    let mut switch_scope = scope.reborrow();
    switch_scope.push_root(discriminant)?;

    // `switch` creates a new lexical environment for the entire case block.
    let outer = self.env.lexical_env;
    let switch_env = switch_scope.env_create(Some(outer))?;
    self
      .env
      .set_lexical_env(switch_scope.heap_mut(), switch_env);

    let result = (|| -> Result<Completion, VmError> {
      const BRANCH_TICK_EVERY: usize = 32;

      // `switch` shares one lexical scope across all case clauses.
      let mut default_idx: Option<usize> = None;
      for (i, branch) in stmt.branches.iter().enumerate() {
        // Budget branch-list traversal: a `switch` statement can contain a very large number of
        // case clauses (bounded by source size), and both block-instantiation and case evaluation
        // may need to walk those lists even when the clause bodies are empty.
        if i % BRANCH_TICK_EVERY == 0 {
          self.tick()?;
        }
        if default_idx.is_none() && branch.stx.case.is_none() {
          default_idx = Some(i);
        }
        self.instantiate_block_decls_in_stmt_list(
          &mut switch_scope,
          switch_env,
          &branch.stx.body,
        )?;
      }

      // ECMA-262 `CaseBlockEvaluation`: `V` starts as `undefined` and is never ~empty~ for normal
      // completion.
      let v_root_idx = switch_scope.heap().root_stack.len();
      switch_scope.push_root(Value::Undefined)?;
      let mut v = Value::Undefined;

      match default_idx {
        None => {
          let mut found = false;
          for (i, branch) in stmt.branches.iter().enumerate() {
            if i % BRANCH_TICK_EVERY == 0 {
              self.tick()?;
            }
            let Some(case_expr) = &branch.stx.case else {
              continue;
            };

            if !found {
              let case_value = self.eval_expr(&mut switch_scope, case_expr)?;
              let mut tick = || self.tick();
              found =
                strict_equal_with_tick(switch_scope.heap(), discriminant, case_value, &mut tick)?;
            }

            if found {
              let r = self.eval_stmt_list(&mut switch_scope, &branch.stx.body)?;
              if let Some(value) = r.value() {
                v = value;
                switch_scope.heap_mut().root_stack[v_root_idx] = value;
              }
              if r.is_abrupt() {
                return Ok(r.update_empty(Some(v)));
              }
            }
          }
          Ok(Completion::normal(v))
        }
        Some(default_idx) => {
          let (a, rest) = stmt.branches.split_at(default_idx);
          let default_branch = &rest[0];
          let b = &rest[1..];

          let mut found = false;
          for (i, branch) in a.iter().enumerate() {
            if i % BRANCH_TICK_EVERY == 0 {
              self.tick()?;
            }
            let Some(case_expr) = &branch.stx.case else {
              continue;
            };

            if !found {
              let case_value = self.eval_expr(&mut switch_scope, case_expr)?;
              let mut tick = || self.tick();
              found =
                strict_equal_with_tick(switch_scope.heap(), discriminant, case_value, &mut tick)?;
            }

            if found {
              let r = self.eval_stmt_list(&mut switch_scope, &branch.stx.body)?;
              if let Some(value) = r.value() {
                v = value;
                switch_scope.heap_mut().root_stack[v_root_idx] = value;
              }
              if r.is_abrupt() {
                return Ok(r.update_empty(Some(v)));
              }
            }
          }

          let mut found_in_b = false;
          if !found {
            for (i, branch) in b.iter().enumerate() {
              if i % BRANCH_TICK_EVERY == 0 {
                self.tick()?;
              }
              let Some(case_expr) = &branch.stx.case else {
                continue;
              };

              if !found_in_b {
                let case_value = self.eval_expr(&mut switch_scope, case_expr)?;
                let mut tick = || self.tick();
                found_in_b =
                  strict_equal_with_tick(switch_scope.heap(), discriminant, case_value, &mut tick)?;
              }

              if found_in_b {
                let r = self.eval_stmt_list(&mut switch_scope, &branch.stx.body)?;
                if let Some(value) = r.value() {
                  v = value;
                  switch_scope.heap_mut().root_stack[v_root_idx] = value;
                }
                if r.is_abrupt() {
                  return Ok(r.update_empty(Some(v)));
                }
              }
            }
          }

          if found_in_b {
            return Ok(Completion::normal(v));
          }

          let default_r = self.eval_stmt_list(&mut switch_scope, &default_branch.stx.body)?;
          if let Some(value) = default_r.value() {
            v = value;
            switch_scope.heap_mut().root_stack[v_root_idx] = value;
          }
          if default_r.is_abrupt() {
            return Ok(default_r.update_empty(Some(v)));
          }

          // NOTE: The following is another complete iteration of the after-default clauses.
          for (i, branch) in b.iter().enumerate() {
            if i % BRANCH_TICK_EVERY == 0 {
              self.tick()?;
            }
            let r = self.eval_stmt_list(&mut switch_scope, &branch.stx.body)?;
            if let Some(value) = r.value() {
              v = value;
              switch_scope.heap_mut().root_stack[v_root_idx] = value;
            }
            if r.is_abrupt() {
              return Ok(r.update_empty(Some(v)));
            }
          }

          Ok(Completion::normal(v))
        }
      }
    })();

    // Restore the outer lexical environment no matter how control leaves the switch.
    self.env.set_lexical_env(switch_scope.heap_mut(), outer);
    result
  }

  fn eval_expr(&mut self, scope: &mut Scope<'_>, expr: &Node<Expr>) -> Result<Value, VmError> {
    Ok(self.eval_expr_chain(scope, expr)?.into_value())
  }

  /// ECMA-262-ish `NamedEvaluation` helper used by object literal property evaluation.
  ///
  /// This implements the observable behaviour of `SetFunctionName` for syntactic anonymous
  /// function/class definitions used as values, using the provided property key as the inferred
  /// name.
  ///
  /// For anonymous *class* expressions, the inferred name must be applied **before** defining class
  /// elements (so a `static name() {}` element can override the constructor's initial `"name"`
  /// property). This requires special handling during class construction.
  fn eval_expr_named(
    &mut self,
    scope: &mut Scope<'_>,
    expr: &Node<Expr>,
    name: PropertyKey,
  ) -> Result<Value, VmError> {
    // This is intentionally syntactic (based on the expression kind), not dynamic (based on the
    // runtime value), so e.g. `{ x: someFunc }` does not rename `someFunc` even if its current
    // `.name` is empty.
    let is_anonymous_function_def = match &*expr.stx {
      Expr::Func(func) => func.stx.name.is_none(),
      Expr::ArrowFunc(_) => true,
      Expr::Class(class) => class.stx.name.is_none(),
      _ => false,
    };

    if !is_anonymous_function_def {
      return self.eval_expr(scope, expr);
    }

    // Root the inferred name key across evaluation and `SetFunctionName` (which can allocate).
    let mut named_scope = scope.reborrow();
    match name {
      PropertyKey::String(s) => named_scope.push_root(Value::String(s))?,
      PropertyKey::Symbol(sym) => named_scope.push_root(Value::Symbol(sym))?,
    };

    // Anonymous class expressions must receive the inferred name during class construction.
    if let Expr::Class(class_expr) = &*expr.stx {
      if class_expr.stx.name.is_none() {
        // `eval_expr` would have charged one tick at expression entry; preserve that budget behaviour
        // when we bypass it for class `NamedEvaluation`.
        self.tick()?;
        return self.eval_class_expr_named(&mut named_scope, class_expr, name);
      }
    }

    let value = self.eval_expr(&mut named_scope, expr)?;
    named_scope.push_root(value)?;

    if let Value::Object(func_obj) = value {
      // `SetFunctionName` only applies to actual Function objects (not callable Proxies).
      let func_name = match named_scope.heap().get_function(func_obj) {
        Ok(f) => Some(f.name),
        Err(VmError::NotCallable) => None,
        Err(err) => return Err(err),
      };
      if let Some(current_name) = func_name {
        // Only infer a name for empty-name functions.
        if named_scope
          .heap()
          .get_string(current_name)?
          .as_code_units()
          .is_empty()
        {
          crate::function_properties::set_function_name(&mut named_scope, func_obj, name, None)?;
        }
      }
    }

    Ok(value)
  }

  fn eval_expr_chain(
    &mut self,
    scope: &mut Scope<'_>,
    expr: &Node<Expr>,
  ) -> Result<OptionalChainEval, VmError> {
    // One tick per expression.
    self.tick()?;

    Ok(match &*expr.stx {
      Expr::LitStr(node) => OptionalChainEval::Value(self.eval_lit_str(scope, node)?),
      Expr::LitNum(node) => OptionalChainEval::Value(self.eval_lit_num(&node.stx)?),
      Expr::LitBigInt(node) => OptionalChainEval::Value(self.eval_lit_bigint(scope, &node.stx)?),
      Expr::LitBool(node) => OptionalChainEval::Value(self.eval_lit_bool(&node.stx)?),
      Expr::LitNull(_) => OptionalChainEval::Value(Value::Null),
      Expr::LitRegex(node) => OptionalChainEval::Value(self.eval_lit_regex(scope, node)?),
      Expr::LitArr(node) => OptionalChainEval::Value(self.eval_lit_arr(scope, &node.stx)?),
      Expr::LitObj(node) => OptionalChainEval::Value(self.eval_lit_obj(scope, &node.stx)?),
      Expr::LitTemplate(node) => {
        OptionalChainEval::Value(self.eval_lit_template(scope, &node.stx)?)
      }
      Expr::TaggedTemplate(node) => {
        OptionalChainEval::Value(self.eval_tagged_template(scope, node)?)
      }
      Expr::This(_) => OptionalChainEval::Value(self.get_this_binding(scope)?),
      Expr::NewTarget(_) => OptionalChainEval::Value(self.new_target),
      Expr::Id(node) => OptionalChainEval::Value(self.eval_id(scope, &node.stx)?),
      Expr::ImportMeta(_) => OptionalChainEval::Value(self.eval_import_meta(scope)?),
      Expr::Call(node) => self.eval_call(scope, &node.stx, node.loc)?,
      Expr::Import(node) => OptionalChainEval::Value(self.eval_import(scope, &node.stx)?),
      Expr::Func(node) => OptionalChainEval::Value(self.eval_func_expr(scope, node)?),
      Expr::ArrowFunc(node) => OptionalChainEval::Value(self.eval_arrow_func_expr(scope, node)?),
      Expr::Class(node) => OptionalChainEval::Value(self.eval_class_expr(scope, node)?),
      Expr::Member(node) => self.eval_member(scope, &node.stx)?,
      Expr::ComputedMember(node) => self.eval_computed_member(scope, &node.stx)?,
      Expr::Unary(node) => OptionalChainEval::Value(self.eval_unary(scope, &node.stx, node.loc)?),
      Expr::UnaryPostfix(node) => {
        OptionalChainEval::Value(self.eval_unary_postfix(scope, &node.stx)?)
      }
      Expr::Binary(node) => OptionalChainEval::Value(self.eval_binary(scope, &node.stx)?),
      Expr::Cond(node) => OptionalChainEval::Value(self.eval_cond(scope, &node.stx)?),

      // Patterns sometimes show up in expression position (e.g. assignment targets). We only
      // support simple identifier patterns for now.
      Expr::IdPat(node) => OptionalChainEval::Value(self.eval_id_pat(scope, &node.stx)?),

      _ => return Err(VmError::Unimplemented("expression type")),
    })
  }

  fn eval_import(&mut self, scope: &mut Scope<'_>, expr: &ImportExpr) -> Result<Value, VmError> {
    // Dynamic `import()` expression.
    //
    // This delegates to the spec-shaped implementation in `module_loading::start_dynamic_import`.
    // Evaluate the specifier expression, then the optional `options` argument.
    //
    // Root the intermediate values while evaluating the second argument and while entering the
    // module loading algorithm, which may allocate and trigger GC.
    let mut import_scope = scope.reborrow();
    let specifier = self.eval_expr(&mut import_scope, &expr.module)?;
    import_scope.push_root(specifier)?;

    let options = match expr.attributes.as_ref() {
      Some(options_expr) => {
        let v = self.eval_expr(&mut import_scope, options_expr)?;
        v
      }
      None => Value::Undefined,
    };
    import_scope.push_root(options)?;

    let modules_ptr = self.vm.module_graph_ptr().ok_or(VmError::Unimplemented(
      "dynamic import requires a module graph",
    ))?;
    // Safety: `Vm::module_graph_ptr` is only set by embeddings that ensure the graph outlives the
    // VM (see `Vm::set_module_graph` docs). `JsRuntime` stores the graph in a `Box`, so the pointer
    // remains stable even if the runtime is moved.
    let modules = unsafe { &mut *modules_ptr };

    crate::start_dynamic_import_with_host_and_hooks(
      self.vm,
      &mut import_scope,
      modules,
      &mut *self.host,
      &mut *self.hooks,
      self.env.global_object(),
      specifier,
      options,
    )
  }

  fn eval_chain_base(
    &mut self,
    scope: &mut Scope<'_>,
    expr: &Node<Expr>,
  ) -> Result<OptionalChainEval, VmError> {
    // Parenthesized expressions break optional-chain propagation:
    // `(a?.b).c` should not short-circuit `.c` when `a` is nullish.
    if expr.assoc.get::<ParenthesizedExpr>().is_some() {
      return Ok(OptionalChainEval::Value(self.eval_expr(scope, expr)?));
    }
    self.eval_expr_chain(scope, expr)
  }

  fn eval_member(
    &mut self,
    scope: &mut Scope<'_>,
    expr: &MemberExpr,
  ) -> Result<OptionalChainEval, VmError> {
    if matches!(&*expr.left.stx, Expr::Super(_)) {
      if expr.optional_chaining {
        // `super?.prop` is a syntax error (early error), so reaching this at runtime indicates a
        // parser/early-error mismatch.
        return Err(VmError::InvariantViolation(
          "optional chaining used with super property access",
        ));
      }
      if expr.right.starts_with('#') {
        return Err(VmError::Unimplemented("super private member access"));
      }

      let mut super_scope = scope.reborrow();
      let actual_this = self.get_this_binding(&mut super_scope)?;
      // Root `this` binding state (may be a DerivedConstructorState cell), the resolved receiver,
      // and `[[HomeObject]]` in a single operation so a GC triggered by root-stack growth cannot
      // collect values that have not yet been pushed.
      let mut roots_buf = [self.this, actual_this, Value::Undefined];
      let roots = if let Some(home) = self.home_object {
        roots_buf[2] = Value::Object(home);
        &roots_buf[..]
      } else {
        &roots_buf[..2]
      };
      super_scope.push_roots(roots)?;
      let key_s = super_scope.alloc_string(&expr.right)?;
      super_scope.push_root(Value::String(key_s))?;
      let key = PropertyKey::from_string(key_s);

      let super_base = self.super_base(&mut super_scope)?;
      let reference = Reference::SuperProperty {
        base: super_base,
        key,
        receiver: actual_this,
      };
      let value = self.get_value_from_reference(&mut super_scope, &reference)?;
      return Ok(OptionalChainEval::Value(value));
    }

    let base = match self.eval_chain_base(scope, &expr.left)? {
      OptionalChainEval::Value(v) => v,
      OptionalChainEval::ShortCircuit => return Ok(OptionalChainEval::ShortCircuit),
    };
    if expr.optional_chaining && is_nullish(base) {
      return Ok(OptionalChainEval::ShortCircuit);
    }

    // `MemberExpression` creates a property reference for any non-nullish base value. The actual
    // `ToObject` coercion happens when the reference is dereferenced (`GetValue` / `PutValue`) so
    // the original base value can be preserved as the call/receiver `this`.
    let mut key_scope = scope.reborrow();
    key_scope.push_root(base)?;
    let reference = if expr.right.starts_with('#') {
      let sym = key_scope
        .heap()
        .resolve_private_name_symbol(self.env.lexical_env, &expr.right)?
        .ok_or(VmError::InvariantViolation("unresolved private name"))?;
      Reference::Private {
        base,
        sym,
        name: &expr.right,
      }
    } else {
      let key_s = key_scope.alloc_string(&expr.right)?;
      Reference::Property {
        base,
        receiver: base,
        key: PropertyKey::from_string(key_s),
      }
    };
    let value = self.get_value_from_reference(&mut key_scope, &reference)?;
    Ok(OptionalChainEval::Value(value))
  }

  fn eval_computed_member(
    &mut self,
    scope: &mut Scope<'_>,
    expr: &ComputedMemberExpr,
  ) -> Result<OptionalChainEval, VmError> {
    if matches!(&*expr.object.stx, Expr::Super(_)) {
      if expr.optional_chaining {
        return Err(VmError::InvariantViolation(
          "optional chaining used with super property access",
        ));
      }
      // `GetThisBinding` must be observed before evaluating the computed key expression, so derived
      // constructors throw before `super()` returns.
      let home_object = self.home_object.ok_or(VmError::InvariantViolation(
        "super property access missing [[HomeObject]]",
      ))?;

      // Root the raw `this` binding (which may be a derived-constructor state cell) and
      // `[[HomeObject]]` across `GetThisBinding`, key evaluation, and `GetSuperBase`.
      let mut key_scope = scope.reborrow();
      let roots = [self.this, Value::Object(home_object)];
      key_scope.push_roots(&roots)?;

      let receiver = self.get_this_binding(&mut key_scope)?;
      key_scope.push_root(receiver)?;

      let member_value = self.eval_expr(&mut key_scope, &expr.member)?;
      key_scope.push_root(member_value)?;

      // Spec: `GetSuperBase` is observed before `ToPropertyKey` when dereferencing a `super[expr]`
      // reference (e.g. `super[key]` should read from the original prototype even if `key.toString`
      // mutates it).
      //
      // Capture the super base first and keep it rooted across `ToPropertyKey` so prototype
      // mutation/GC during key conversion cannot invalidate it.
      let super_base = key_scope.get_prototype_of_with_host_and_hooks(
        self.vm,
        &mut *self.host,
        &mut *self.hooks,
        home_object,
      )?;
      let Some(super_base) = super_base else {
        return Err(throw_type_error(
          self.vm,
          &mut key_scope,
          "Cannot convert undefined or null to object",
        )?);
      };
      key_scope.push_root(Value::Object(super_base))?;

      let key = self.to_property_key_operator(&mut key_scope, member_value)?;
      // Root the key across the final `[[Get]]`, which can invoke accessors/Proxy traps.
      match key {
        PropertyKey::String(s) => key_scope.push_root(Value::String(s))?,
        PropertyKey::Symbol(s) => key_scope.push_root(Value::Symbol(s))?,
      };
      let value = key_scope.get_with_host_and_hooks(
        self.vm,
        &mut *self.host,
        &mut *self.hooks,
        super_base,
        key,
        receiver,
      )?;
      return Ok(OptionalChainEval::Value(value));
    }

    let base = match self.eval_chain_base(scope, &expr.object)? {
      OptionalChainEval::Value(v) => v,
      OptionalChainEval::ShortCircuit => return Ok(OptionalChainEval::ShortCircuit),
    };
    if expr.optional_chaining && is_nullish(base) {
      return Ok(OptionalChainEval::ShortCircuit);
    }

    // `ComputedMemberExpression` performs `ToPropertyKey` on the member expression (which may
    // allocate and invoke user code) before the base is coerced via `ToObject` when the reference
    // is dereferenced.
    let mut key_scope = scope.reborrow();
    key_scope.push_root(base)?;
    let member_value = self.eval_expr(&mut key_scope, &expr.member)?;
    key_scope.push_root(member_value)?;
    let key = self.to_property_key_operator(&mut key_scope, member_value)?;
    let reference = Reference::Property {
      base,
      receiver: base,
      key,
    };
    let value = self.get_value_from_reference(&mut key_scope, &reference)?;
    Ok(OptionalChainEval::Value(value))
  }

  fn eval_super_property_get(
    &mut self,
    scope: &mut Scope<'_>,
    receiver: Value,
    key: PropertyKey,
  ) -> Result<Value, VmError> {
    let home_object = self.home_object.ok_or(VmError::InvariantViolation(
      "super property access missing [[HomeObject]]",
    ))?;

    // Root receiver, `home_object`, and `key` across:
    // - `GetPrototypeOf(home_object)` (Proxy-aware), and
    // - the final `[[Get]]` (which can invoke accessors).
    let mut super_scope = scope.reborrow();
    let key_root = match key {
      PropertyKey::String(s) => Value::String(s),
      PropertyKey::Symbol(s) => Value::Symbol(s),
    };
    super_scope.push_roots(&[receiver, Value::Object(home_object), key_root])?;

    let super_base = super_scope.get_prototype_of_with_host_and_hooks(
      self.vm,
      &mut *self.host,
      &mut *self.hooks,
      home_object,
    )?;
    let Some(super_base) = super_base else {
      // `super` base is `null`: dereferencing throws a TypeError.
      return Err(throw_type_error(
        self.vm,
        &mut super_scope,
        "Cannot convert undefined or null to object",
      )?);
    };

    super_scope.push_root(Value::Object(super_base))?;
    super_scope.get_with_host_and_hooks(
      self.vm,
      &mut *self.host,
      &mut *self.hooks,
      super_base,
      key,
      receiver,
    )
  }

  fn eval_super_property_set(
    &mut self,
    scope: &mut Scope<'_>,
    receiver: Value,
    key: PropertyKey,
    value: Value,
  ) -> Result<(), VmError> {
    let home_object = self.home_object.ok_or(VmError::InvariantViolation(
      "super property access missing [[HomeObject]]",
    ))?;

    // Root receiver, `home_object`, `key`, and `value` across:
    // - `GetPrototypeOf(home_object)` (Proxy-aware), and
    // - the final `[[Set]]` (which can invoke accessors/Proxy traps).
    let mut super_scope = scope.reborrow();
    let key_root = match key {
      PropertyKey::String(s) => Value::String(s),
      PropertyKey::Symbol(s) => Value::Symbol(s),
    };
    super_scope.push_roots(&[receiver, Value::Object(home_object), key_root, value])?;

    let super_base = super_scope.get_prototype_of_with_host_and_hooks(
      self.vm,
      &mut *self.host,
      &mut *self.hooks,
      home_object,
    )?;
    let Some(super_base) = super_base else {
      // `super` base is `null`: dereferencing throws a TypeError.
      return Err(throw_type_error(
        self.vm,
        &mut super_scope,
        "Cannot convert undefined or null to object",
      )?);
    };

    super_scope.push_root(Value::Object(super_base))?;
    let ok = crate::spec_ops::internal_set_with_host_and_hooks(
      self.vm,
      &mut super_scope,
      &mut *self.host,
      &mut *self.hooks,
      super_base,
      key,
      value,
      receiver,
    )?;

    if ok {
      Ok(())
    } else if self.strict {
      Err(throw_type_error(
        self.vm,
        &mut super_scope,
        "Cannot assign to read-only property",
      )?)
    } else {
      // Sloppy-mode assignment to a non-writable/non-extensible target fails silently.
      Ok(())
    }
  }

  fn eval_reference<'b>(
    &mut self,
    scope: &mut Scope<'_>,
    expr: &'b Node<Expr>,
  ) -> Result<Reference<'b>, VmError> {
    match &*expr.stx {
      Expr::Id(id) => Ok(Reference::Binding(&id.stx.name)),
      Expr::IdPat(id) => Ok(Reference::Binding(&id.stx.name)),
      Expr::Member(member) => {
        if member.stx.optional_chaining {
          // Optional chaining is never a valid assignment/update target; this should be rejected by
          // an early error pass before evaluation begins.
          return Err(VmError::InvariantViolation(
            "optional chaining used in reference position",
          ));
        }
        if matches!(&*member.stx.left.stx, Expr::Super(_)) {
          if member.stx.right.starts_with('#') {
            return Err(VmError::Unimplemented("super private member access"));
          }
          let receiver = self.get_this_binding(scope)?;
          let home_object = self.home_object.ok_or(VmError::InvariantViolation(
            "super property access missing [[HomeObject]]",
          ))?;
          let mut super_scope = scope.reborrow();
          // Root `this` binding state (may be a DerivedConstructorState cell), the resolved receiver,
          // and `[[HomeObject]]` across property-key allocation and `GetSuperBase()` (proxy traps can
          // allocate and trigger GC).
          super_scope.push_roots(&[self.this, receiver, Value::Object(home_object)])?;
          let key_s = super_scope.alloc_string(&member.stx.right)?;
          super_scope.push_root(Value::String(key_s))?;
          let key = PropertyKey::from_string(key_s);

          let super_base = self.super_base(&mut super_scope)?;
          return Ok(Reference::SuperProperty {
            base: super_base,
            key,
            receiver,
          });
        }

        let base = self.eval_expr(scope, &member.stx.left)?;
        if is_nullish(base) {
          return Err(throw_type_error(
            self.vm,
            scope,
            "Cannot convert undefined or null to object",
          )?);
        }
        if member.stx.right.starts_with('#') {
          let sym = scope
            .heap()
            .resolve_private_name_symbol(self.env.lexical_env, &member.stx.right)?
            .ok_or(VmError::InvariantViolation("unresolved private name"))?;
          Ok(Reference::Private {
            base,
            sym,
            name: &member.stx.right,
          })
        } else {
          let mut key_scope = scope.reborrow();
          key_scope.push_root(base)?;
          let key_s = key_scope.alloc_string(&member.stx.right)?;
          Ok(Reference::Property {
            base,
            receiver: base,
            key: PropertyKey::from_string(key_s),
          })
        }
      }
      Expr::ComputedMember(member) => {
        if member.stx.optional_chaining {
          return Err(VmError::InvariantViolation(
            "optional chaining used in reference position",
          ));
        }
        if matches!(&*member.stx.object.stx, Expr::Super(_)) {
          // Evaluating a `super[expr]` reference requires an initialized `this` binding. In derived
          // constructors before `super()`, this check happens before evaluating the computed key
          // expression.
          let home_object = self.home_object.ok_or(VmError::InvariantViolation(
            "super property access missing [[HomeObject]]",
          ))?;

          let mut key_scope = scope.reborrow();
          key_scope.push_roots(&[self.this, Value::Object(home_object)])?;

          let receiver = self.get_this_binding(&mut key_scope)?;
          key_scope.push_root(receiver)?;

          let member_value = self.eval_expr(&mut key_scope, &member.stx.member)?;
          key_scope.push_root(member_value)?;

          // Spec: `GetSuperBase` must happen before `ToPropertyKey` for computed super properties.
          //
          // Root the captured super base across `ToPropertyKey` in case key conversion runs user
          // code that mutates the home object's prototype and/or triggers GC.
          let base = self.get_super_base(&mut key_scope)?;
          key_scope.push_root(base)?;

          let key = self.to_property_key_operator(&mut key_scope, member_value)?;
          return Ok(Reference::SuperProperty { base, key, receiver });
        }

        let base = self.eval_expr(scope, &member.stx.object)?;
        let mut key_scope = scope.reborrow();
        key_scope.push_root(base)?;
        let member_value = self.eval_expr(&mut key_scope, &member.stx.member)?;
        key_scope.push_root(member_value)?;
        let key = self.to_property_key_operator(&mut key_scope, member_value)?;
        if is_nullish(base) {
          return Err(throw_type_error(
            self.vm,
            &mut key_scope,
            "Cannot convert undefined or null to object",
          )?);
        }
        Ok(Reference::Property {
          base,
          receiver: base,
          key,
        })
      }
      _ => Err(VmError::Unimplemented("expression is not a reference")),
    }
  }

  fn get_super_base(&mut self, scope: &mut Scope<'_>) -> Result<Value, VmError> {
    let Some(home) = self.home_object else {
      return Err(VmError::InvariantViolation(
        "super property reference requires an active [[HomeObject]]",
      ));
    };
    // `GetPrototypeOf([[HomeObject]])` is Proxy-aware and may allocate/GC. Root `home` so it stays
    // alive for the duration of the lookup.
    scope.push_root(Value::Object(home))?;
    let proto = scope.get_prototype_of_with_host_and_hooks(self.vm, self.host, self.hooks, home)?;
    Ok(match proto {
      Some(p) => Value::Object(p),
      None => Value::Null,
    })
  }

  fn root_reference(
    &self,
    scope: &mut Scope<'_>,
    reference: &Reference<'_>,
  ) -> Result<(), VmError> {
    match *reference {
      Reference::Binding(_) => {}
      Reference::Property {
        base,
        receiver,
        key,
      } => {
        // Root all components together so a GC triggered by root-stack growth cannot collect the
        // not-yet-pushed entry.
        let roots = [
          base,
          receiver,
          match key {
            PropertyKey::String(s) => Value::String(s),
            PropertyKey::Symbol(s) => Value::Symbol(s),
          },
        ];
        scope.push_roots(&roots)?;
      }
      Reference::SuperProperty {
        base,
        key,
        receiver,
      } => {
        let roots = [
          base,
          receiver,
          match key {
            PropertyKey::String(s) => Value::String(s),
            PropertyKey::Symbol(s) => Value::Symbol(s),
          },
        ];
        scope.push_roots(&roots)?;
      }
      Reference::Private { base, sym, .. } => {
        scope.push_roots(&[base, Value::Symbol(sym)])?;
      }
    }
    Ok(())
  }

  fn get_value_from_reference(
    &mut self,
    scope: &mut Scope<'_>,
    reference: &Reference<'_>,
  ) -> Result<Value, VmError> {
    match *reference {
      Reference::Binding(name) => {
        match self.env.get(self.vm, self.host, self.hooks, scope, name)? {
          Some(v) => Ok(v),
          None => {
            let msg =
              crate::fallible_format::try_format_error_message("", name, " is not defined")?;
            Err(throw_reference_error(self.vm, scope, &msg)?)
          }
        }
      }
      Reference::Property { base, receiver, key } => {
        let mut get_scope = scope.reborrow();
        self.root_reference(&mut get_scope, reference)?;
        let object = self.to_object_operator(&mut get_scope, base)?;
        // Root the boxed object so host hooks/accessors can allocate freely.
        get_scope.push_root(Value::Object(object))?;
        get_scope.get_with_host_and_hooks(self.vm, self.host, self.hooks, object, key, receiver)
      }
      Reference::SuperProperty {
        base,
        key,
        receiver,
      } => {
        let mut get_scope = scope.reborrow();
        self.root_reference(&mut get_scope, reference)?;
        let object = self.to_object_operator(&mut get_scope, base)?;
        get_scope.push_root(Value::Object(object))?;
        get_scope.get_with_host_and_hooks(
          self.vm,
          self.host,
          self.hooks,
          object,
          key,
          receiver,
        )
      }
      Reference::Private { base, sym, name } => self.private_get(scope, base, sym, name),
    }
  }

  fn put_value_to_reference(
    &mut self,
    scope: &mut Scope<'_>,
    reference: &Reference<'_>,
    value: Value,
  ) -> Result<(), VmError> {
    match *reference {
      Reference::Binding(name) => self.env.set(
        self.vm,
        self.host,
        self.hooks,
        scope,
        name,
        value,
        self.strict,
      ),
      Reference::Property { base, receiver, key } => {
        let mut set_scope = scope.reborrow();
        self.root_reference(&mut set_scope, reference)?;
        // Root `value` across `ToObject(base)` in case boxing triggers a GC.
        set_scope.push_root(value)?;
        let object = self.to_object_operator(&mut set_scope, base)?;
        set_scope.push_root(Value::Object(object))?;
        let ok = crate::spec_ops::internal_set_with_host_and_hooks(
          self.vm,
          &mut set_scope,
          self.host,
          self.hooks,
          object,
          key,
          value,
          receiver,
        )?;
        if ok {
          Ok(())
        } else if self.strict {
          Err(throw_type_error(
            self.vm,
            &mut set_scope,
            "Cannot assign to read-only property",
          )?)
        } else {
          // Sloppy-mode assignment to a non-writable/non-extensible target fails silently.
          Ok(())
        }
      }
      Reference::SuperProperty {
        base,
        key,
        receiver,
      } => {
        let mut set_scope = scope.reborrow();
        self.root_reference(&mut set_scope, reference)?;
        // Root `value` across `ToObject(base)` in case boxing triggers a GC.
        set_scope.push_root(value)?;
        let object = self.to_object_operator(&mut set_scope, base)?;
        set_scope.push_root(Value::Object(object))?;
        let ok = crate::spec_ops::internal_set_with_host_and_hooks(
          self.vm,
          &mut set_scope,
          self.host,
          self.hooks,
          object,
          key,
          value,
          receiver,
        )?;
        if ok {
          Ok(())
        } else if self.strict {
          Err(throw_type_error(
            self.vm,
            &mut set_scope,
            "Cannot assign to read-only property",
          )?)
        } else {
          Ok(())
        }
      }
      Reference::Private { base, sym, name } => self.private_set(scope, base, sym, name, value),
    }
  }

  fn private_get(
    &mut self,
    scope: &mut Scope<'_>,
    base: Value,
    sym: GcSymbol,
    name: &str,
  ) -> Result<Value, VmError> {
    let Value::Object(obj) = base else {
      return Err(throw_type_error(
        self.vm,
        scope,
        "Cannot read private member from non-object",
      )?);
    };

    let key = PropertyKey::from_symbol(sym);
    let desc = if scope.heap().is_proxy_object(obj) {
      scope.heap().proxy_internal_get_own_property(obj, &key)?
    } else {
      scope.heap().get_own_property(obj, key)?
    };
    let Some(desc) = desc else {
      // Brand check failure.
      let msg =
        crate::fallible_format::try_format_error_message("Cannot read private member ", name, "")?;
      return Err(throw_type_error(self.vm, scope, &msg)?);
    };

    match desc.kind {
      PropertyKind::Data { value, .. } => Ok(value),
      PropertyKind::Accessor { get, .. } => {
        if get == Value::Undefined {
          return Ok(Value::Undefined);
        }
        let mut call_scope = scope.reborrow();
        call_scope.push_roots(&[get, base])?;
        self.call(&mut call_scope, get, base, &[])
      }
    }
  }

  fn private_set(
    &mut self,
    scope: &mut Scope<'_>,
    base: Value,
    sym: GcSymbol,
    name: &str,
    value: Value,
  ) -> Result<(), VmError> {
    let Value::Object(obj) = base else {
      return Err(throw_type_error(
        self.vm,
        scope,
        "Cannot write private member to non-object",
      )?);
    };

    let key = PropertyKey::from_symbol(sym);
    let desc = if scope.heap().is_proxy_object(obj) {
      scope.heap().proxy_internal_get_own_property(obj, &key)?
    } else {
      scope.heap().get_own_property(obj, key)?
    };
    let Some(desc) = desc else {
      let msg =
        crate::fallible_format::try_format_error_message("Cannot write private member ", name, "")?;
      return Err(throw_type_error(self.vm, scope, &msg)?);
    };

    match desc.kind {
      PropertyKind::Data { writable, .. } => {
        if !writable {
          return Err(throw_type_error(
            self.vm,
            scope,
            "Cannot assign to read-only private member",
          )?);
        }
        // Root the RHS value across any internal allocations that might occur while updating the
        // property table.
        let mut set_scope = scope.reborrow();
        set_scope.push_root(value)?;
        if set_scope.heap().is_proxy_object(obj) {
          set_scope
            .heap_mut()
            .proxy_internal_set_existing_data_property_value(obj, &key, value)?;
        } else {
          set_scope
            .heap_mut()
            .object_set_existing_data_property_value(obj, &key, value)?;
        }
        Ok(())
      }
      PropertyKind::Accessor { set, .. } => {
        if set == Value::Undefined {
          return Err(throw_type_error(
            self.vm,
            scope,
            "Cannot set private member (no setter)",
          )?);
        }
        let mut call_scope = scope.reborrow();
        call_scope.push_roots(&[set, base, value])?;
        self.call(&mut call_scope, set, base, &[value]).map(|_| ())
      }
    }
  }

  fn maybe_set_anonymous_function_name_for_assignment(
    &mut self,
    scope: &mut Scope<'_>,
    reference: &Reference<'_>,
    value: Value,
  ) -> Result<(), VmError> {
    let Value::Object(func_obj) = value else {
      return Ok(());
    };

    // `SetFunctionName` only applies to actual Function objects. Callable Proxies are callable, but
    // are not function objects and should not have their `name` mutated.
    let (current_name, is_native_non_constructable) = match scope.heap().get_function(func_obj) {
      Ok(f) => (
        f.name,
        matches!(f.call, crate::function::CallHandler::Native(_)) && f.construct.is_none(),
      ),
      Err(VmError::NotCallable) => return Ok(()),
      Err(err) => return Err(err),
    };
    // Name inference only applies to "anonymous function definitions" (ECMA-262), which excludes
    // anonymous built-in/native functions such as Promise combinator element callbacks.
    //
    // `vm-js` represents user-defined class constructors as native functions (so they can throw
    // when called without `new`), so keep name inference enabled for constructable native
    // functions.
    if is_native_non_constructable {
      return Ok(());
    }
    if !scope
      .heap()
      .get_string(current_name)?
      .as_code_units()
      .is_empty()
    {
      return Ok(());
    }

    let key = match *reference {
      Reference::Binding(name) => {
        // Root the allocated key string: `set_function_name` may allocate and trigger GC while
        // pushing its own roots.
        let name_s = scope.alloc_string(name)?;
        scope.push_root(Value::String(name_s))?;
        PropertyKey::String(name_s)
      }
      Reference::Property { key, .. } => key,
      Reference::SuperProperty { key, .. } => key,
      // Private field assignment does not participate in anonymous function name inference.
      Reference::Private { .. } => return Ok(()),
    };

    crate::function_properties::set_function_name(scope, func_obj, key, None)?;
    Ok(())
  }

  fn eval_func_expr(
    &mut self,
    scope: &mut Scope<'_>,
    expr: &Node<FuncExpr>,
  ) -> Result<Value, VmError> {
    let name = expr.stx.name.as_ref().map(|n| n.stx.name.as_str());
    self.instantiate_function_expr(
      scope,
      expr.loc.start_u32(),
      expr.loc.end_u32(),
      name,
      &expr.stx.func.stx,
    )
  }

  fn eval_arrow_func_expr(
    &mut self,
    scope: &mut Scope<'_>,
    expr: &Node<ArrowFuncExpr>,
  ) -> Result<Value, VmError> {
    self.instantiate_arrow_function_expr(
      scope,
      expr.loc.start_u32(),
      expr.loc.end_u32(),
      &expr.stx.func.stx,
    )
  }

  fn instantiate_function_expr(
    &mut self,
    scope: &mut Scope<'_>,
    loc_start: u32,
    loc_end: u32,
    name: Option<&str>,
    func: &parse_js::ast::func::Func,
  ) -> Result<Value, VmError> {
    use crate::function::ThisMode;
    use crate::vm::EcmaFunctionKind;

    // Use a nested scope so any temporary roots (including environment roots) are popped before
    // returning to the caller.
    let mut scope = scope.reborrow();

    let is_generator = func.generator;
    let is_async_generator = func.generator && func.async_;
    let is_strict = self.strict
      || match &func.body {
        Some(FuncBody::Block(stmts)) => detect_use_strict_directive(
          self.env.source().text.as_ref(),
          self.env.base_offset() as usize,
          self.env.prefix_len() as usize,
          stmts,
          || self.tick(),
        )?,
        Some(FuncBody::Expression(_)) => false,
        None => return Err(VmError::Unimplemented("function without body")),
      };
    let this_mode = if func.arrow {
      ThisMode::Lexical
    } else if is_strict {
      ThisMode::Strict
    } else {
      ThisMode::Global
    };

    // Named function expressions introduce an inner immutable binding for their name so the body
    // can reliably reference itself (for recursion) even when the outer binding is reassigned.
    //
    // Spec: https://tc39.es/ecma262/#sec-runtime-semantics-instantiateordinaryfunctionexpression
    //
    // Note: This is distinct from `SetFunctionName` (function object `name` property), which is
    // handled separately.
    let outer_env = self.env.lexical_env;
    // Root the outer lexical environment while allocating the optional function-name environment and
    // function name string.
    scope.push_env_root(outer_env)?;
    let (closure_env, name_binding_env) = if let Some(name) = name {
      // Create the function name environment and keep it rooted across function allocation.
      let func_env = scope.env_create(Some(outer_env))?;
      scope.push_env_root(func_env)?;
      scope.env_create_immutable_binding(func_env, name)?;
      (Some(func_env), Some((func_env, name)))
    } else {
      (Some(outer_env), None)
    };

    let name_s = match name {
      Some(name) => {
        let s = scope.alloc_string(name)?;
        scope.push_root(Value::String(s))?;
        s
      }
      None => {
        let s = scope.alloc_string("")?;
        scope.push_root(Value::String(s))?;
        s
      }
    };
    let length = self.function_length(func)?;

    let rel_start = loc_start.saturating_sub(self.env.prefix_len());
    let rel_end = loc_end.saturating_sub(self.env.prefix_len());
    let span_start = self.env.base_offset().saturating_add(rel_start);
    let span_end = self.env.base_offset().saturating_add(rel_end);

    let code_id = self.vm.register_ecma_function(
      self.env.source(),
      span_start,
      span_end,
      EcmaFunctionKind::Expr,
    )?;
    let func_obj = scope.alloc_ecma_function(
      code_id,
      // Async and generator functions are not constructable.
      /* is_constructable */
      !func.async_ && !is_generator,
      name_s,
      length,
      this_mode,
      is_strict,
      closure_env,
    )?;

    let meta_property_context = if func.arrow {
      MetaPropertyContext::for_arrow(self.env.meta_property_context())
    } else {
      MetaPropertyContext::FUNCTION
    };
    scope
      .heap_mut()
      .set_function_meta_property_context(func_obj, meta_property_context)?;

    // If this was a named function expression, initialize its name binding now that the function
    // object exists.
    if let Some((env, name)) = name_binding_env {
      scope
        .heap_mut()
        .env_initialize_binding(env, name, Value::Object(func_obj))?;
    }
    let intr = self
      .vm
      .intrinsics()
      .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;
    scope.heap_mut().object_set_prototype(
      func_obj,
      Some(if is_generator {
        if is_async_generator {
          intr.async_generator_function_prototype()
        } else {
          intr.generator_function_prototype()
        }
      } else if func.async_ {
        intr.async_function_prototype()
      } else {
        intr.function_prototype()
      }),
    )?;
    scope
      .heap_mut()
      .set_function_realm(func_obj, self.env.global_object())?;
    if let Some(realm) = self.vm.current_realm() {
      scope.heap_mut().set_function_job_realm(func_obj, realm)?;
    }
    if let Some(script_or_module) = self.vm.get_active_script_or_module() {
      let token = self.vm.intern_script_or_module(script_or_module)?;
      scope
        .heap_mut()
        .set_function_script_or_module_token(func_obj, Some(token))?;
    }
    if is_generator {
      if is_async_generator {
        crate::function_properties::make_async_generator_function_instance_prototype(
          &mut scope,
          func_obj,
          intr.async_generator_prototype(),
        )?;
      } else {
        crate::function_properties::make_generator_function_instance_prototype(
          &mut scope,
          func_obj,
          intr.generator_prototype(),
        )?;
      }
    }
    if func.arrow {
      scope
        .heap_mut()
        .set_function_bound_this(func_obj, self.this)?;
      scope
        .heap_mut()
        .set_function_bound_new_target(func_obj, self.new_target)?;
      scope
        .heap_mut()
        .set_function_home_object(func_obj, self.home_object)?;
    }
    Ok(Value::Object(func_obj))
  }

  fn instantiate_arrow_function_expr(
    &mut self,
    scope: &mut Scope<'_>,
    loc_start: u32,
    loc_end: u32,
    func: &parse_js::ast::func::Func,
  ) -> Result<Value, VmError> {
    use crate::function::ThisMode;
    use crate::vm::EcmaFunctionKind;

    if func.generator {
      // See `create_function_object_for_decl` for rationale.
      let intr = self
        .vm
        .intrinsics()
        .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;
      let message = if func.async_ {
        "async generator functions"
      } else {
        "generator functions"
      };
      let err_obj = crate::error_object::new_syntax_error_object(scope, &intr, message)?;
      return Err(VmError::Throw(err_obj));
    }
    let is_strict = self.strict
      || match &func.body {
        Some(FuncBody::Block(stmts)) => detect_use_strict_directive(
          self.env.source().text.as_ref(),
          self.env.base_offset() as usize,
          self.env.prefix_len() as usize,
          stmts,
          || self.tick(),
        )?,
        Some(FuncBody::Expression(_)) => false,
        None => return Err(VmError::Unimplemented("function without body")),
      };

    let length = self.function_length(func)?;

    let rel_start = loc_start.saturating_sub(self.env.prefix_len());
    let rel_end = loc_end.saturating_sub(self.env.prefix_len());
    let span_start = self.env.base_offset().saturating_add(rel_start);
    let span_end = self.env.base_offset().saturating_add(rel_end);

    let code_id = self.vm.register_ecma_function(
      self.env.source(),
      span_start,
      span_end,
      EcmaFunctionKind::Expr,
    )?;
    let mut alloc_scope = scope.reborrow();
    // Root captured lexical bindings across allocation in case it triggers GC.
    let mut roots_buf = [self.this, self.new_target, Value::Undefined];
    let roots = if let Some(home) = self.home_object {
      roots_buf[2] = Value::Object(home);
      &roots_buf[..]
    } else {
      &roots_buf[..2]
    };
    alloc_scope.push_roots(roots)?;
    let name_s = alloc_scope.alloc_string("")?;
    alloc_scope.push_root(Value::String(name_s))?;

    let func_obj = alloc_scope.alloc_ecma_function(
      code_id,
      false,
      name_s,
      length,
      ThisMode::Lexical,
      is_strict,
      Some(self.env.lexical_env),
    )?;
    let meta_property_context = MetaPropertyContext::for_arrow(self.env.meta_property_context());
    alloc_scope
      .heap_mut()
      .set_function_meta_property_context(func_obj, meta_property_context)?;
    let intr = self
      .vm
      .intrinsics()
      .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;
    alloc_scope
      .heap_mut()
      .object_set_prototype(
        func_obj,
        Some(if func.async_ {
          intr.async_function_prototype()
        } else {
          intr.function_prototype()
        }),
      )?;
    alloc_scope
      .heap_mut()
      .set_function_realm(func_obj, self.env.global_object())?;
    if let Some(realm) = self.vm.current_realm() {
      alloc_scope
        .heap_mut()
        .set_function_job_realm(func_obj, realm)?;
    }
    if let Some(script_or_module) = self.vm.get_active_script_or_module() {
      let token = self.vm.intern_script_or_module(script_or_module)?;
      alloc_scope
        .heap_mut()
        .set_function_script_or_module_token(func_obj, Some(token))?;
    }
    alloc_scope
      .heap_mut()
      .set_function_bound_this(func_obj, self.this)?;
    alloc_scope
      .heap_mut()
      .set_function_bound_new_target(func_obj, self.new_target)?;
    alloc_scope
      .heap_mut()
      .set_function_home_object(func_obj, self.home_object)?;
    Ok(Value::Object(func_obj))
  }

  fn eval_lit_str(
    &mut self,
    scope: &mut Scope<'_>,
    node: &Node<LitStrExpr>,
  ) -> Result<Value, VmError> {
    let s = alloc_string_from_lit_str(scope, node)?;
    Ok(Value::String(s))
  }

  fn eval_lit_regex(
    &mut self,
    scope: &mut Scope<'_>,
    node: &Node<LitRegexExpr>,
  ) -> Result<Value, VmError> {
    let intr = self
      .vm
      .intrinsics()
      .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;

    let literal = node.stx.value.as_str();
    // `parse-js` stores the literal including leading `/` and any flags.
    if !literal.starts_with('/') {
      let err_obj = crate::error_object::new_syntax_error_object(
        scope,
        &intr,
        "Invalid regular expression literal",
      )?;
      return Err(VmError::Throw(err_obj));
    }

    // Stage 1: scan using classic RegExp character-class termination rules to extract flags.
    //
    // This is the legacy `in_class: bool` behaviour, expressed as a depth counter that only ever
    // takes values 0/1. We do this first because:
    // - It preserves behaviour for classic patterns like `/[[]/` where `[` inside a class is a
    //   literal character (not nested), and
    // - It gives us the literal flags suffix so we can detect `v` and optionally do a nested-class
    //   aware scan.
    //
    // Budget scanning for the closing `/` so enormous regexp literals can't monopolize CPU.
    const TICK_EVERY: usize = 1024;
    let mut escaped = false;
    let mut class_depth: usize = 0;
    let mut end_pat: Option<usize> = None;
    let mut steps = 0usize;
    for (i, ch) in literal.char_indices().skip(1) {
      if steps % TICK_EVERY == 0 {
        self.vm.tick()?;
      }
      steps += 1;
      if escaped {
        escaped = false;
        continue;
      }
      match ch {
        '\\' => escaped = true,
        '[' if class_depth == 0 => class_depth = 1,
        ']' if class_depth > 0 => class_depth = 0,
        '/' if class_depth == 0 => {
          end_pat = Some(i);
          break;
        }
        _ => {}
      }
    }
    let Some(mut end_pat) = end_pat else {
      let err_obj = crate::error_object::new_syntax_error_object(
        scope,
        &intr,
        "Unterminated regular expression literal",
      )?;
      return Err(VmError::Throw(err_obj));
    };

    // If the literal flags contain `v`, do a nested character-class aware scan to avoid
    // mis-detecting the closing `/` for modern RegExp set notation (e.g. `/[[0-9]\\/]/v`).
    //
    // If the nested scan fails to find a terminator (e.g. the pattern contains unbalanced `[`/`]`
    // pairs under nesting semantics), fall back to the classic terminator position; the RegExp
    // constructor will report the pattern error.
    let mut has_v_flag = false;
    for (i, b) in literal[end_pat + 1..].bytes().enumerate() {
      // Avoid ticking on the first iteration so short flag strings don't effectively double-charge
      // fuel (the surrounding expression evaluation already ticks).
      if i != 0 && i % TICK_EVERY == 0 {
        self.vm.tick()?;
      }
      if b == b'v' {
        has_v_flag = true;
        break;
      }
    }
    if has_v_flag {
      let mut escaped = false;
      let mut depth: usize = 0;
      let mut nested_end: Option<usize> = None;
      let mut steps = 0usize;
      for (i, ch) in literal.char_indices().skip(1) {
        if steps % TICK_EVERY == 0 {
          self.vm.tick()?;
        }
        steps += 1;
        if escaped {
          escaped = false;
          continue;
        }
        match ch {
          '\\' => escaped = true,
          '[' => depth = depth.saturating_add(1),
          ']' if depth > 0 => depth -= 1,
          '/' if depth == 0 => {
            nested_end = Some(i);
            break;
          }
          _ => {}
        }
      }
      if let Some(i) = nested_end {
        end_pat = i;
      }
    }

    let pattern = &literal[1..end_pat];
    let flags = &literal[end_pat + 1..];

    let pattern_s = scope.alloc_string(pattern)?;
    scope.push_root(Value::String(pattern_s))?;
    let flags_s = scope.alloc_string(flags)?;
    scope.push_root(Value::String(flags_s))?;

    let ctor = Value::Object(intr.regexp_constructor());
    self.vm.construct_with_host_and_hooks(
      &mut *self.host,
      scope,
      &mut *self.hooks,
      ctor,
      &[Value::String(pattern_s), Value::String(flags_s)],
      ctor,
    )
  }

  fn eval_lit_num(&self, expr: &LitNumExpr) -> Result<Value, VmError> {
    Ok(Value::Number(expr.value.0))
  }

  fn eval_lit_bigint(
    &mut self,
    scope: &mut Scope<'_>,
    expr: &LitBigIntExpr,
  ) -> Result<Value, VmError> {
    let b = JsBigInt::parse_ascii_radix_with_tick(&expr.value, 10, &mut || self.tick())?;
    let handle = scope.alloc_bigint(b)?;
    Ok(Value::BigInt(handle))
  }

  fn eval_lit_bool(&self, expr: &LitBoolExpr) -> Result<Value, VmError> {
    Ok(Value::Bool(expr.value))
  }

  fn eval_lit_template(
    &mut self,
    scope: &mut Scope<'_>,
    expr: &LitTemplateExpr,
  ) -> Result<Value, VmError> {
    // Untagged template literals evaluate by concatenating their parts after `ToString`
    // conversion of substitutions.
    let mut units: Vec<u16> = Vec::new();
    for part in &expr.parts {
      match part {
        LitTemplatePart::String(s) => {
          let len = s.encode_utf16().count();
          units.try_reserve(len).map_err(|_| VmError::OutOfMemory)?;
          units.extend(s.encode_utf16());
        }
        LitTemplatePart::Substitution(expr) => {
          let value = self.eval_expr(scope, expr)?;
          scope.push_root(value)?;
          let s = self.to_string_operator(scope, value)?;
          scope.push_root(Value::String(s))?;
          let js = scope.heap().get_string(s)?;
          units
            .try_reserve(js.len_code_units())
            .map_err(|_| VmError::OutOfMemory)?;
          units.extend_from_slice(js.as_code_units());
        }
      }
    }

    let s = scope.alloc_string_from_u16_vec(units)?;
    Ok(Value::String(s))
  }

  fn eval_tagged_template(
    &mut self,
    scope: &mut Scope<'_>,
    expr: &Node<TaggedTemplateExpr>,
  ) -> Result<Value, VmError> {
    let template_parts = template_string_parts(&expr.assoc).ok_or(VmError::InvariantViolation(
      "TaggedTemplateExpr is missing TemplateStringParts association",
    ))?;

    // Compute `callee` and `this` similarly to `CallExpression` evaluation.
    //
    // Parenthesized tag expressions break optional-chain propagation and member-call `this` binding:
    // `(obj?.tag)\`x\`` and `(obj.tag)\`x\`` should not treat the tag as a property reference.
    let callee_is_parenthesized = expr
      .stx
      .function
      .assoc
      .get::<ParenthesizedExpr>()
      .is_some();

    let (callee_value, this_value) = if callee_is_parenthesized {
      let callee_value = self.eval_expr(scope, &expr.stx.function)?;
      (callee_value, Value::Undefined)
    } else {
      match &*expr.stx.function.stx {
        Expr::Member(member) if member.stx.optional_chaining => {
          let base = self.eval_expr(scope, &member.stx.left)?;
          if is_nullish(base) {
            // Optional chaining short-circuit on the base value.
            return Ok(Value::Undefined);
          }

          // Optional chaining member access: evaluate the property reference, preserving the base
          // value for the call `this`.
          let mut key_scope = scope.reborrow();
          key_scope.push_root(base)?;
          let reference = if member.stx.right.starts_with('#') {
            let sym = key_scope
              .heap()
              .resolve_private_name_symbol(self.env.lexical_env, &member.stx.right)?
              .ok_or(VmError::InvariantViolation("unresolved private name"))?;
            Reference::Private {
              base,
              sym,
              name: &member.stx.right,
            }
          } else {
            let key_s = key_scope.alloc_string(&member.stx.right)?;
            Reference::Property {
              base,
              receiver: base,
              key: PropertyKey::from_string(key_s),
            }
          };
          let callee_value = self.get_value_from_reference(&mut key_scope, &reference)?;
          (callee_value, base)
        }
        Expr::ComputedMember(member) if member.stx.optional_chaining => {
          let base = self.eval_expr(scope, &member.stx.object)?;
          if is_nullish(base) {
            return Ok(Value::Undefined);
          }

          // Optional chaining computed member access: `ToPropertyKey` on the member value may
          // allocate and invoke user code. Only if the base is non-nullish do we proceed to
          // dereference the property reference.
          let mut key_scope = scope.reborrow();
          key_scope.push_root(base)?;
          let member_value = self.eval_expr(&mut key_scope, &member.stx.member)?;
          key_scope.push_root(member_value)?;
          let key = self.to_property_key_operator(&mut key_scope, member_value)?;
          let reference = Reference::Property {
            base,
            receiver: base,
            key,
          };
          let callee_value = self.get_value_from_reference(&mut key_scope, &reference)?;
          (callee_value, base)
        }
        Expr::Member(_) | Expr::ComputedMember(_) | Expr::Id(_) | Expr::IdPat(_) => {
          let reference = self.eval_reference(scope, &expr.stx.function)?;
          let this_value = match reference {
            Reference::Property { receiver, .. } => receiver,
            Reference::SuperProperty { receiver, .. } => receiver,
            Reference::Private { base, .. } => base,
            _ => Value::Undefined,
          };

          let mut callee_scope = scope.reborrow();
          self.root_reference(&mut callee_scope, &reference)?;
          let callee_value = self.get_value_from_reference(&mut callee_scope, &reference)?;
          (callee_value, this_value)
        }
        _ => {
          let callee_value = self.eval_expr(scope, &expr.stx.function)?;
          (callee_value, Value::Undefined)
        }
      }
    };

    // Root callee/this/args for the duration of the call.
    let mut call_scope = scope.reborrow();
    call_scope.push_roots(&[callee_value, this_value])?;

    let rel_start = expr.loc.start_u32().saturating_sub(self.env.prefix_len());
    let rel_end = expr.loc.end_u32().saturating_sub(self.env.prefix_len());
    let span_start = self.env.base_offset().saturating_add(rel_start);
    let span_end = self.env.base_offset().saturating_add(rel_end);

    let template_obj = self.vm.get_or_create_template_object(
      &mut call_scope,
      self.env.source(),
      span_start,
      span_end,
      template_parts.raw.as_ref(),
      template_parts.cooked.as_ref(),
    )?;
    call_scope.push_root(Value::Object(template_obj))?;

    let mut args: Vec<Value> = Vec::new();
    // Pre-reserve based on the total part count (an upper bound on the number of substitutions) so
    // we don't need an extra unbudgeted scan over the parts list.
    let subst_count = expr.stx.parts.len();
    args
      .try_reserve_exact(subst_count.saturating_add(1))
      .map_err(|_| VmError::OutOfMemory)?;
    args.push(Value::Object(template_obj));

    // Evaluate substitutions left-to-right.
    for part in &expr.stx.parts {
      let LitTemplatePart::Substitution(sub_expr) = part else {
        continue;
      };
      let value = self.eval_expr(&mut call_scope, sub_expr)?;
      call_scope.push_root(value)?;
      args.push(value);
    }

    self.call(&mut call_scope, callee_value, this_value, &args)
  }

  fn eval_lit_arr(&mut self, scope: &mut Scope<'_>, expr: &LitArrExpr) -> Result<Value, VmError> {
    let mut arr_scope = scope.reborrow();
    let arr = arr_scope.alloc_array(0)?;
    arr_scope.push_root(Value::Object(arr))?;
    let intr = self
      .vm
      .intrinsics()
      .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;
    arr_scope
      .heap_mut()
      .object_set_prototype(arr, Some(intr.array_prototype()))?;

    let mut next_index: u32 = 0;
    for elem in &expr.elements {
      match elem {
        LitArrElem::Empty => {
          // Per-hole tick: `[,,,,]` can have arbitrarily many elements without any nested
          // expression evaluations.
          self.tick()?;
          next_index = next_index.saturating_add(1);
        }
        LitArrElem::Rest(rest_expr) => {
          let mut spread_scope = arr_scope.reborrow();
          let spread_value = self.eval_expr(&mut spread_scope, rest_expr)?;
          spread_scope.push_root(spread_value)?;

          let mut iter = iterator::get_iterator(
            self.vm,
            &mut *self.host,
            &mut *self.hooks,
            &mut spread_scope,
            spread_value,
          )?;
          spread_scope.push_roots_with_extra_roots(&[iter.iterator], &[iter.next_method], &[])?;
          if let Err(err) = spread_scope.push_root(iter.next_method) {
            return Err(self.iterator_close_on_error(&mut spread_scope, &iter, err));
          }

          loop {
            let next_value = match iterator::iterator_step_value(
              self.vm,
              &mut *self.host,
              &mut *self.hooks,
              &mut spread_scope,
              &mut iter,
            ) {
              Ok(v) => v,
              // Spec: array spread does not perform `IteratorClose` on errors produced while
              // stepping the iterator (`next`/`done`/`value`).
              Err(err) => return Err(err),
            };

            let Some(value) = next_value else {
              break;
            };

            let step_res: Result<(), VmError> = (|| {
              // Per-spread-element tick: spreading large iterators should be budgeted even when the
              // iterator's `next()` is native/cheap.
              self.tick()?;

              let idx = next_index;

              let mut elem_scope = spread_scope.reborrow();
              elem_scope.push_root(value)?;
              let key_s = elem_scope.alloc_u32_index_string(idx)?;
              elem_scope.push_root(Value::String(key_s))?;
              let key = PropertyKey::from_string(key_s);
              elem_scope.create_data_property_or_throw(arr, key, value)?;

              next_index = next_index.saturating_add(1);
              Ok(())
            })();
            if let Err(err) = step_res {
              return Err(self.iterator_close_on_error(&mut spread_scope, &iter, err));
            }
          }
        }
        LitArrElem::Single(elem_expr) => {
          let idx = next_index;

          let mut elem_scope = arr_scope.reborrow();
          let value = self.eval_expr(&mut elem_scope, elem_expr)?;
          elem_scope.push_root(value)?;
          let key_s = elem_scope.alloc_u32_index_string(idx)?;
          elem_scope.push_root(Value::String(key_s))?;
          let key = PropertyKey::from_string(key_s);
          elem_scope.create_data_property_or_throw(arr, key, value)?;

          next_index = next_index.saturating_add(1);
        }
      }
    }

    let length_key_s = arr_scope.alloc_string("length")?;
    let length_desc = PropertyDescriptor {
      enumerable: false,
      configurable: false,
      kind: PropertyKind::Data {
        value: Value::Number(next_index as f64),
        writable: true,
      },
    };
    arr_scope.define_property(arr, PropertyKey::from_string(length_key_s), length_desc)?;

    Ok(Value::Object(arr))
  }

  fn eval_lit_obj(&mut self, scope: &mut Scope<'_>, expr: &LitObjExpr) -> Result<Value, VmError> {
    let mut obj_scope = scope.reborrow();
    let obj = obj_scope.alloc_object()?;
    obj_scope.push_root(Value::Object(obj))?;
    let intr = self
      .vm
      .intrinsics()
      .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;
    obj_scope
      .heap_mut()
      .object_set_prototype(obj, Some(intr.object_prototype()))?;

    for member_node in &expr.members {
      // Per-member tick: object literals can do significant work per member even when no nested
      // expressions are evaluated (e.g. shorthand props and methods/getters/setters with direct
      // keys).
      self.tick()?;

      let mut member_scope = obj_scope.reborrow();
      let member_loc_start = member_node.loc.start_u32();
      let member = &member_node.stx.typ;

      match member {
        ObjMemberType::Valued { key, val } => {
          let is_proto_setter = matches!(key, ClassOrObjKey::Direct(direct) if direct.stx.key == "__proto__")
            && matches!(val, ClassOrObjVal::Prop(Some(_)));

          let key_loc_start = match key {
            ClassOrObjKey::Direct(direct) => direct.loc.start_u32(),
            // `ClassOrObjKey::Computed` stores the loc of the *expression inside* the brackets, not
            // the `[` token itself. When we later slice source text for lazy method parsing we need
            // to include the full member prefix (e.g. `[` / `get [` / `set [`), otherwise the
            // reparsed wrapper `({ <snippet> })` becomes invalid (`Symbol.toPrimitive]...`).
            ClassOrObjKey::Computed(_) => member_loc_start,
          };
          let key = match key {
            ClassOrObjKey::Direct(direct) => {
              let key_s = if let Some(units) = literal_string_code_units(&direct.assoc) {
                member_scope.alloc_string_from_code_units(units)?
              } else if direct.stx.tt == TT::LiteralNumber {
                let mut tick = || self.tick();
                let n = crate::ops::parse_ascii_decimal_to_f64_str(&direct.stx.key, &mut tick)?
                  .ok_or(VmError::Unimplemented(
                    "numeric literal property name parse",
                  ))?;
                member_scope.heap_mut().to_string(Value::Number(n))?
              } else {
                member_scope.alloc_string(&direct.stx.key)?
              };
              PropertyKey::from_string(key_s)
            }
            ClassOrObjKey::Computed(expr) => {
              let value = self.eval_expr(&mut member_scope, expr)?;
              member_scope.push_root(value)?;
              self.to_property_key_operator(&mut member_scope, value)?
            }
          };

          match key {
            PropertyKey::String(s) => member_scope.push_root(Value::String(s))?,
            PropertyKey::Symbol(s) => member_scope.push_root(Value::Symbol(s))?,
          };

          match val {
            ClassOrObjVal::Prop(Some(value_expr)) => {
              let value = if is_proto_setter {
                // `__proto__` setters do not define a property and do not participate in
                // `SetFunctionName` inference.
                self.eval_expr(&mut member_scope, value_expr)?
              } else {
                // Spec-ish `NamedEvaluation` / `SetFunctionName` behaviour: for anonymous
                // function/class definitions used as property values, infer `name` from the
                // property key.
                self.eval_expr_named(&mut member_scope, value_expr, key)?
              };
              member_scope.push_root(value)?;
              if is_proto_setter {
                match value {
                  Value::Object(proto) => {
                    member_scope
                      .heap_mut()
                      .object_set_prototype(obj, Some(proto))?;
                  }
                  Value::Null => {
                    member_scope.heap_mut().object_set_prototype(obj, None)?;
                  }
                  _ => {}
                }
              } else {
                member_scope.create_data_property_or_throw(obj, key, value)?;
              }
            }
            ClassOrObjVal::Prop(None) => {
              return Err(VmError::Unimplemented(
                "object literal property without initializer",
              ));
            }
            ClassOrObjVal::Method(method) => {
              let func_node = &method.stx.func;
              let is_async_generator = func_node.stx.generator && func_node.stx.async_;
              let length = self.function_length(&func_node.stx)?;

              let span_start =
                self.object_member_span_start(member_loc_start, key_loc_start, &func_node.stx);
              let rel_end = func_node
                .loc
                .end_u32()
                .saturating_sub(self.env.prefix_len());
              let span_end = self.env.base_offset().saturating_add(rel_end);
              let code = self.vm.register_ecma_function(
                self.env.source(),
                span_start,
                span_end,
                EcmaFunctionKind::ObjectMember,
              )?;

              let is_strict = self.strict
                || match &func_node.stx.body {
                  Some(FuncBody::Block(stmts)) => {
                  detect_use_strict_directive(
                    self.env.source().text.as_ref(),
                    self.env.base_offset() as usize,
                    self.env.prefix_len() as usize,
                    stmts,
                    || self.tick(),
                  )?
                  }
                  Some(FuncBody::Expression(_)) => false,
                  None => return Err(VmError::Unimplemented("method without body")),
                };

              let this_mode = if func_node.stx.arrow {
                ThisMode::Lexical
              } else if is_strict {
                ThisMode::Strict
              } else {
                ThisMode::Global
              };

              let closure_env = Some(self.env.lexical_env);

              let name_string = match key {
                PropertyKey::String(s) => s,
                PropertyKey::Symbol(_) => member_scope.alloc_string("")?,
              };

              let func_obj = member_scope.alloc_ecma_function(
                code,
                /* is_constructable */ false,
                name_string,
                length,
                this_mode,
                is_strict,
                closure_env,
              )?;
              member_scope
                .heap_mut()
                .set_function_meta_property_context(func_obj, MetaPropertyContext::METHOD)?;
              let intr = self
                .vm
                .intrinsics()
                .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;
              member_scope.heap_mut().object_set_prototype(
                func_obj,
                Some(if func_node.stx.generator {
                  if is_async_generator {
                    intr.async_generator_function_prototype()
                  } else {
                    intr.generator_function_prototype()
                  }
                } else if func_node.stx.async_ {
                  intr.async_function_prototype()
                } else {
                  intr.function_prototype()
                }),
              )?;
              member_scope
                .heap_mut()
                .set_function_realm(func_obj, self.env.global_object())?;
              if let Some(realm) = self.vm.current_realm() {
                member_scope
                  .heap_mut()
                  .set_function_job_realm(func_obj, realm)?;
              }
              if let Some(script_or_module) = self.vm.get_active_script_or_module() {
                let token = self.vm.intern_script_or_module(script_or_module)?;
                member_scope
                  .heap_mut()
                  .set_function_script_or_module_token(func_obj, Some(token))?;
              }
              // Object literal methods/getters/setters use the object itself as `[[HomeObject]]`
              // (needed for `super.prop` and for arrow functions created inside the method body).
              member_scope
                .heap_mut()
                .set_function_home_object(func_obj, Some(obj))?;
              if func_node.stx.generator {
                if is_async_generator {
                  crate::function_properties::make_async_generator_function_instance_prototype(
                    &mut member_scope,
                    func_obj,
                    intr.async_generator_prototype(),
                  )?;
                } else {
                  crate::function_properties::make_generator_function_instance_prototype(
                    &mut member_scope,
                    func_obj,
                    intr.generator_prototype(),
                  )?;
                }
              }
              if func_node.stx.arrow {
                member_scope
                  .heap_mut()
                  .set_function_bound_this(func_obj, self.this)?;
                member_scope
                  .heap_mut()
                  .set_function_bound_new_target(func_obj, self.new_target)?;
                member_scope
                  .heap_mut()
                  .set_function_home_object(func_obj, self.home_object)?;
              } else {
                // Object literal methods use the object itself as their `[[HomeObject]]`.
                member_scope
                  .heap_mut()
                  .set_function_home_object(func_obj, Some(obj))?;
              }
              member_scope.push_root(Value::Object(func_obj))?;

              // Methods use the property key as the function `name` if possible.
              if !matches!(key, PropertyKey::String(_)) {
                crate::function_properties::set_function_name(
                  &mut member_scope,
                  func_obj,
                  key,
                  None,
                )?;
              }

              member_scope.create_data_property_or_throw(obj, key, Value::Object(func_obj))?;
            }
            ClassOrObjVal::Getter(getter) => {
              let func_node = &getter.stx.func;
              let length = self.function_length(&func_node.stx)?;

              let rel_start = member_loc_start.saturating_sub(self.env.prefix_len());
              let rel_end = func_node
                .loc
                .end_u32()
                .saturating_sub(self.env.prefix_len());
              let span_start = self.env.base_offset().saturating_add(rel_start);
              let span_end = self.env.base_offset().saturating_add(rel_end);
              let code = self.vm.register_ecma_function(
                self.env.source(),
                span_start,
                span_end,
                EcmaFunctionKind::ObjectMember,
              )?;

              let is_strict = self.strict
                || match &func_node.stx.body {
                  Some(FuncBody::Block(stmts)) => {
                  detect_use_strict_directive(
                    self.env.source().text.as_ref(),
                    self.env.base_offset() as usize,
                    self.env.prefix_len() as usize,
                    stmts,
                    || self.tick(),
                  )?
                  }
                  Some(FuncBody::Expression(_)) => false,
                  None => return Err(VmError::Unimplemented("getter without body")),
                };

              let this_mode = if func_node.stx.arrow {
                ThisMode::Lexical
              } else if is_strict {
                ThisMode::Strict
              } else {
                ThisMode::Global
              };

              let closure_env = Some(self.env.lexical_env);

              let name_string = member_scope.alloc_string("")?;
              let func_obj = member_scope.alloc_ecma_function(
                code,
                /* is_constructable */ false,
                name_string,
                length,
                this_mode,
                is_strict,
                closure_env,
              )?;
              member_scope
                .heap_mut()
                .set_function_meta_property_context(func_obj, MetaPropertyContext::METHOD)?;
              let intr = self
                .vm
                .intrinsics()
                .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;
              member_scope
                .heap_mut()
                .object_set_prototype(func_obj, Some(intr.function_prototype()))?;
              member_scope
                .heap_mut()
                .set_function_realm(func_obj, self.env.global_object())?;
              if let Some(realm) = self.vm.current_realm() {
                member_scope
                  .heap_mut()
                  .set_function_job_realm(func_obj, realm)?;
              }
              if let Some(script_or_module) = self.vm.get_active_script_or_module() {
                let token = self.vm.intern_script_or_module(script_or_module)?;
                member_scope
                  .heap_mut()
                  .set_function_script_or_module_token(func_obj, Some(token))?;
              }
              member_scope
                .heap_mut()
                .set_function_home_object(func_obj, Some(obj))?;
              if func_node.stx.arrow {
                member_scope
                  .heap_mut()
                  .set_function_bound_this(func_obj, self.this)?;
                member_scope
                  .heap_mut()
                  .set_function_bound_new_target(func_obj, self.new_target)?;
                member_scope
                  .heap_mut()
                  .set_function_home_object(func_obj, self.home_object)?;
              } else {
                // Object literal accessors use the object itself as their `[[HomeObject]]`.
                member_scope
                  .heap_mut()
                  .set_function_home_object(func_obj, Some(obj))?;
              }
              member_scope.push_root(Value::Object(func_obj))?;
              crate::function_properties::set_function_name(
                &mut member_scope,
                func_obj,
                key,
                Some("get"),
              )?;

              let ok = member_scope.define_own_property(
                obj,
                key,
                PropertyDescriptorPatch {
                  get: Some(Value::Object(func_obj)),
                  enumerable: Some(true),
                  configurable: Some(true),
                  ..Default::default()
                },
              )?;
              if !ok {
                return Err(VmError::Unimplemented("DefineOwnProperty returned false"));
              }
            }
            ClassOrObjVal::Setter(setter) => {
              let func_node = &setter.stx.func;
              let length = self.function_length(&func_node.stx)?;

              let rel_start = member_loc_start.saturating_sub(self.env.prefix_len());
              let rel_end = func_node
                .loc
                .end_u32()
                .saturating_sub(self.env.prefix_len());
              let span_start = self.env.base_offset().saturating_add(rel_start);
              let span_end = self.env.base_offset().saturating_add(rel_end);
              let code = self.vm.register_ecma_function(
                self.env.source(),
                span_start,
                span_end,
                EcmaFunctionKind::ObjectMember,
              )?;

              let is_strict = self.strict
                || match &func_node.stx.body {
                  Some(FuncBody::Block(stmts)) => {
                  detect_use_strict_directive(
                    self.env.source().text.as_ref(),
                    self.env.base_offset() as usize,
                    self.env.prefix_len() as usize,
                    stmts,
                    || self.tick(),
                  )?
                  }
                  Some(FuncBody::Expression(_)) => false,
                  None => return Err(VmError::Unimplemented("setter without body")),
                };

              let this_mode = if func_node.stx.arrow {
                ThisMode::Lexical
              } else if is_strict {
                ThisMode::Strict
              } else {
                ThisMode::Global
              };

              let closure_env = Some(self.env.lexical_env);

              let name_string = member_scope.alloc_string("")?;
              let func_obj = member_scope.alloc_ecma_function(
                code,
                /* is_constructable */ false,
                name_string,
                length,
                this_mode,
                is_strict,
                closure_env,
              )?;
              member_scope
                .heap_mut()
                .set_function_meta_property_context(func_obj, MetaPropertyContext::METHOD)?;
              let intr = self
                .vm
                .intrinsics()
                .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;
              member_scope
                .heap_mut()
                .object_set_prototype(func_obj, Some(intr.function_prototype()))?;
              member_scope
                .heap_mut()
                .set_function_realm(func_obj, self.env.global_object())?;
              if let Some(realm) = self.vm.current_realm() {
                member_scope
                  .heap_mut()
                  .set_function_job_realm(func_obj, realm)?;
              }
              if let Some(script_or_module) = self.vm.get_active_script_or_module() {
                let token = self.vm.intern_script_or_module(script_or_module)?;
                member_scope
                  .heap_mut()
                  .set_function_script_or_module_token(func_obj, Some(token))?;
              }
              member_scope
                .heap_mut()
                .set_function_home_object(func_obj, Some(obj))?;
              if func_node.stx.arrow {
                member_scope
                  .heap_mut()
                  .set_function_bound_this(func_obj, self.this)?;
                member_scope
                  .heap_mut()
                  .set_function_bound_new_target(func_obj, self.new_target)?;
                member_scope
                  .heap_mut()
                  .set_function_home_object(func_obj, self.home_object)?;
              } else {
                // Object literal accessors use the object itself as their `[[HomeObject]]`.
                member_scope
                  .heap_mut()
                  .set_function_home_object(func_obj, Some(obj))?;
              }
              member_scope.push_root(Value::Object(func_obj))?;
              crate::function_properties::set_function_name(
                &mut member_scope,
                func_obj,
                key,
                Some("set"),
              )?;

              let ok = member_scope.define_own_property(
                obj,
                key,
                PropertyDescriptorPatch {
                  set: Some(Value::Object(func_obj)),
                  enumerable: Some(true),
                  configurable: Some(true),
                  ..Default::default()
                },
              )?;
              if !ok {
                return Err(VmError::Unimplemented("DefineOwnProperty returned false"));
              }
            }
            ClassOrObjVal::IndexSignature(_) => {
              return Err(VmError::Unimplemented("object literal index signature"));
            }
            ClassOrObjVal::StaticBlock(_) => {
              return Err(VmError::Unimplemented("object literal static block"));
            }
          }
        }
        ObjMemberType::Shorthand { id } => {
          let key_s = member_scope.alloc_string(&id.stx.name)?;
          member_scope.push_root(Value::String(key_s))?;
          let key = PropertyKey::from_string(key_s);
          let value = self.eval_id(&mut member_scope, &id.stx)?;
          member_scope.push_root(value)?;
          member_scope.create_data_property_or_throw(obj, key, value)?;
        }
        ObjMemberType::Rest { val } => {
          let src_value = self.eval_expr(&mut member_scope, val)?;
          member_scope.push_root(src_value)?;

          crate::spec_ops::copy_data_properties_with_host_and_hooks(
            self.vm,
            &mut member_scope,
            &mut *self.host,
            &mut *self.hooks,
            obj,
            src_value,
            &[],
          )?;
        }
      }
    }

    Ok(Value::Object(obj))
  }

  fn eval_import_meta(&mut self, scope: &mut Scope<'_>) -> Result<Value, VmError> {
    let Some(ScriptOrModule::Module(module)) = self.vm.get_active_script_or_module() else {
      return Err(VmError::Unimplemented("import.meta outside of modules"));
    };
    let obj = self
      .vm
      .get_or_create_import_meta_object(scope, self.hooks, module)?;
    Ok(Value::Object(obj))
  }

  fn eval_id(&mut self, scope: &mut Scope<'_>, expr: &IdExpr) -> Result<Value, VmError> {
    match self.env.get(
      self.vm,
      &mut *self.host,
      &mut *self.hooks,
      scope,
      &expr.name,
    )? {
      Some(v) => Ok(v),
      None => {
        let msg =
          crate::fallible_format::try_format_error_message("", &expr.name, " is not defined")?;
        Err(throw_reference_error(self.vm, scope, &msg)?)
      }
    }
  }

  fn eval_id_pat(&mut self, scope: &mut Scope<'_>, expr: &IdPat) -> Result<Value, VmError> {
    match self.env.get(
      self.vm,
      &mut *self.host,
      &mut *self.hooks,
      scope,
      &expr.name,
    )? {
      Some(v) => Ok(v),
      None => {
        let msg =
          crate::fallible_format::try_format_error_message("", &expr.name, " is not defined")?;
        Err(throw_reference_error(self.vm, scope, &msg)?)
      }
    }
  }

  fn eval_unary(
    &mut self,
    scope: &mut Scope<'_>,
    expr: &UnaryExpr,
    loc: parse_js::loc::Loc,
  ) -> Result<Value, VmError> {
    match expr.operator {
      OperatorName::PrefixIncrement => self.eval_update_expression(scope, &expr.argument, 1, true),
      OperatorName::PrefixDecrement => self.eval_update_expression(scope, &expr.argument, -1, true),
      OperatorName::PostfixIncrement => {
        self.eval_update_expression(scope, &expr.argument, 1, false)
      }
      OperatorName::PostfixDecrement => {
        self.eval_update_expression(scope, &expr.argument, -1, false)
      }
      OperatorName::Delete => match &*expr.argument.stx {
        Expr::Member(member) if matches!(&*member.stx.left.stx, Expr::Super(_)) => {
          // `delete` of a Super Reference must throw a ReferenceError. However, evaluating a super
          // property reference requires an initialized `this` binding; in derived constructors
          // before `super()` that evaluation throws first (and must not be masked by the delete
          // semantics).
          //
          // Spec: https://tc39.es/ecma262/#sec-delete-operator-runtime-semantics-evaluation
          let _ = self.get_this_binding(scope)?;
          Err(
            // ECMA-262 `Evaluation` for the `delete` operator explicitly rejects Super References.
            //
            // This must be a runtime error (not a syntax error), and it applies to both instance and
            // static `super` property references.
            throw_reference_error(self.vm, scope, "Cannot delete a super property")?,
          )
        }
        Expr::ComputedMember(member) if matches!(&*member.stx.object.stx, Expr::Super(_)) => {
          // Evaluating a super property reference requires an initialized `this` binding. In
          // derived constructors before `super()`, this check happens before evaluating the
          // computed key expression.
          let _ = self.get_this_binding(scope)?;

          // Ensure the computed key expression is evaluated (including `ToPropertyKey`
          // coercion) before throwing, per `super[expr]` evaluation semantics.
          let mut del_scope = scope.reborrow();
          let member_value = self.eval_expr(&mut del_scope, &member.stx.member)?;
          del_scope.push_root(member_value)?;
          let _ = self.to_property_key_operator(&mut del_scope, member_value)?;
          Err(throw_reference_error(
            self.vm,
            &mut del_scope,
            "Cannot delete a super property",
          )?)
        }
        Expr::Id(id) => {
          if self.strict {
            return Err(syntax_error(
              expr.argument.loc,
              "Delete of an unqualified identifier in strict mode.",
            ));
          }

          // Sloppy-mode: deleting an unqualified identifier returns `true` if the reference is
          // unresolvable, otherwise it deletes the binding. Declarative env-record bindings are
          // not deletable, but `with`-introduced ObjectEnvironmentRecord bindings are deletable (as
          // they are backed by object properties).
          if let Some(env) = self.env.resolve_lexical_binding(
            self.vm,
            &mut *self.host,
            &mut *self.hooks,
            scope,
            &id.stx.name,
          )? {
            match scope.heap().get_env_record(env)? {
              crate::env::EnvRecord::Declarative(_) => return Ok(Value::Bool(false)),
              crate::env::EnvRecord::Object(obj) => {
                let binding_object = obj.binding_object;
                let mut key_scope = scope.reborrow();
                key_scope.push_root(Value::Object(binding_object))?;
                let key_s = key_scope.alloc_string(&id.stx.name)?;
                key_scope.push_root(Value::String(key_s))?;
                let key = PropertyKey::from_string(key_s);
                return Ok(Value::Bool(
                  crate::spec_ops::internal_delete_with_host_and_hooks(
                    self.vm,
                    &mut key_scope,
                    &mut *self.host,
                    &mut *self.hooks,
                    binding_object,
                    key,
                  )?,
                ));
              }
            }
          }

          let global_object = self.env.global_object;
          let mut key_scope = scope.reborrow();
          key_scope.push_root(Value::Object(global_object))?;
          let key_s = key_scope.alloc_string(&id.stx.name)?;
          key_scope.push_root(Value::String(key_s))?;
          let key = PropertyKey::from_string(key_s);

          if !crate::spec_ops::internal_has_property_with_host_and_hooks(
            self.vm,
            &mut key_scope,
            &mut *self.host,
            &mut *self.hooks,
            global_object,
            key,
          )? {
            return Ok(Value::Bool(true));
          }

          Ok(Value::Bool(
            crate::spec_ops::internal_delete_with_host_and_hooks(
              self.vm,
              &mut key_scope,
              &mut *self.host,
              &mut *self.hooks,
              global_object,
              key,
            )?,
          ))
        }
        Expr::IdPat(id) => {
          if self.strict {
            return Err(syntax_error(
              expr.argument.loc,
              "Delete of an unqualified identifier in strict mode.",
            ));
          }

          if let Some(env) = self.env.resolve_lexical_binding(
            self.vm,
            &mut *self.host,
            &mut *self.hooks,
            scope,
            &id.stx.name,
          )? {
            match scope.heap().get_env_record(env)? {
              crate::env::EnvRecord::Declarative(_) => return Ok(Value::Bool(false)),
              crate::env::EnvRecord::Object(obj) => {
                let binding_object = obj.binding_object;
                let mut key_scope = scope.reborrow();
                key_scope.push_root(Value::Object(binding_object))?;
                let key_s = key_scope.alloc_string(&id.stx.name)?;
                key_scope.push_root(Value::String(key_s))?;
                let key = PropertyKey::from_string(key_s);
                return Ok(Value::Bool(
                  crate::spec_ops::internal_delete_with_host_and_hooks(
                    self.vm,
                    &mut key_scope,
                    &mut *self.host,
                    &mut *self.hooks,
                    binding_object,
                    key,
                  )?,
                ));
              }
            }
          }

          let global_object = self.env.global_object;
          let mut key_scope = scope.reborrow();
          key_scope.push_root(Value::Object(global_object))?;
          let key_s = key_scope.alloc_string(&id.stx.name)?;
          key_scope.push_root(Value::String(key_s))?;
          let key = PropertyKey::from_string(key_s);

          if !crate::spec_ops::internal_has_property_with_host_and_hooks(
            self.vm,
            &mut key_scope,
            &mut *self.host,
            &mut *self.hooks,
            global_object,
            key,
          )? {
            return Ok(Value::Bool(true));
          }

          Ok(Value::Bool(
            crate::spec_ops::internal_delete_with_host_and_hooks(
              self.vm,
              &mut key_scope,
              &mut *self.host,
              &mut *self.hooks,
              global_object,
              key,
            )?,
          ))
        }
        Expr::Member(member) if member.stx.optional_chaining => {
          // `delete obj?.prop` short-circuits to `true` when the base is nullish.
          let base = self.eval_expr(scope, &member.stx.left)?;
          if is_nullish(base) {
            return Ok(Value::Bool(true));
          }

          let mut del_scope = scope.reborrow();
          del_scope.push_root(base)?;
          let key_s = del_scope.alloc_string(&member.stx.right)?;
          del_scope.push_root(Value::String(key_s))?;
          let key = PropertyKey::from_string(key_s);

          let object = self.to_object_operator(&mut del_scope, base)?;
          del_scope.push_root(Value::Object(object))?;
          let ok = crate::spec_ops::internal_delete_with_host_and_hooks(
            self.vm,
            &mut del_scope,
            &mut *self.host,
            &mut *self.hooks,
            object,
            key,
          )?;
          if self.strict && !ok {
            return Err(throw_type_error(
              self.vm,
              &mut del_scope,
              "Cannot delete property",
            )?);
          }
          Ok(Value::Bool(ok))
        }
        Expr::ComputedMember(member) if member.stx.optional_chaining => {
          // `delete obj?.[expr]` short-circuits to `true` when the base is nullish and does not
          // evaluate the member expression.
          let base = self.eval_expr(scope, &member.stx.object)?;
          if is_nullish(base) {
            return Ok(Value::Bool(true));
          }

          let mut del_scope = scope.reborrow();
          del_scope.push_root(base)?;
          let member_value = self.eval_expr(&mut del_scope, &member.stx.member)?;
          del_scope.push_root(member_value)?;
          let key = self.to_property_key_operator(&mut del_scope, member_value)?;
          let key_root = match key {
            PropertyKey::String(s) => Value::String(s),
            PropertyKey::Symbol(s) => Value::Symbol(s),
          };
          del_scope.push_root(key_root)?;

          let object = self.to_object_operator(&mut del_scope, base)?;
          del_scope.push_root(Value::Object(object))?;
          let ok = crate::spec_ops::internal_delete_with_host_and_hooks(
            self.vm,
            &mut del_scope,
            &mut *self.host,
            &mut *self.hooks,
            object,
            key,
          )?;
          if self.strict && !ok {
            return Err(throw_type_error(
              self.vm,
              &mut del_scope,
              "Cannot delete property",
            )?);
          }
          Ok(Value::Bool(ok))
        }
        Expr::Member(member) => {
          // `delete a?.b.c` is a delete of an optional chain continuation: if the chain short
          // circuits, the operand is not a reference and `delete` returns true.
          let base = match self.eval_chain_base(scope, &member.stx.left)? {
            OptionalChainEval::Value(v) => v,
            OptionalChainEval::ShortCircuit => return Ok(Value::Bool(true)),
          };
          let mut del_scope = scope.reborrow();
          del_scope.push_root(base)?;
          let key_s = del_scope.alloc_string(&member.stx.right)?;
          del_scope.push_root(Value::String(key_s))?;
          let key = PropertyKey::from_string(key_s);

          let object = self.to_object_operator(&mut del_scope, base)?;
          del_scope.push_root(Value::Object(object))?;
          let ok = crate::spec_ops::internal_delete_with_host_and_hooks(
            self.vm,
            &mut del_scope,
            &mut *self.host,
            &mut *self.hooks,
            object,
            key,
          )?;
          if self.strict && !ok {
            return Err(throw_type_error(
              self.vm,
              &mut del_scope,
              "Cannot delete property",
            )?);
          }
          Ok(Value::Bool(ok))
        }
        Expr::ComputedMember(member) => {
          let base = match self.eval_chain_base(scope, &member.stx.object)? {
            OptionalChainEval::Value(v) => v,
            OptionalChainEval::ShortCircuit => return Ok(Value::Bool(true)),
          };

          let mut del_scope = scope.reborrow();
          del_scope.push_root(base)?;
          let member_value = self.eval_expr(&mut del_scope, &member.stx.member)?;
          del_scope.push_root(member_value)?;
          let key = self.to_property_key_operator(&mut del_scope, member_value)?;
          let key_root = match key {
            PropertyKey::String(s) => Value::String(s),
            PropertyKey::Symbol(s) => Value::Symbol(s),
          };
          del_scope.push_root(key_root)?;

          let object = self.to_object_operator(&mut del_scope, base)?;
          del_scope.push_root(Value::Object(object))?;
          let ok = crate::spec_ops::internal_delete_with_host_and_hooks(
            self.vm,
            &mut del_scope,
            &mut *self.host,
            &mut *self.hooks,
            object,
            key,
          )?;
          if self.strict && !ok {
            return Err(throw_type_error(
              self.vm,
              &mut del_scope,
              "Cannot delete property",
            )?);
          }
          Ok(Value::Bool(ok))
        }
        // `delete` of non-reference expressions always returns true (after evaluating the operand).
        _ => {
          let _ = self.eval_expr(scope, &expr.argument)?;
          Ok(Value::Bool(true))
        }
      },
      OperatorName::LogicalNot => {
        let argument = self.eval_expr(scope, &expr.argument)?;
        Ok(Value::Bool(!to_boolean(scope.heap(), argument)?))
      }
      OperatorName::UnaryPlus => {
        let argument = self.eval_expr(scope, &expr.argument)?;
        let n = self.to_number_operator(scope, argument)?;
        Ok(Value::Number(n))
      }
      OperatorName::UnaryNegation => {
        let argument = self.eval_expr(scope, &expr.argument)?;
        let mut neg_scope = scope.reborrow();
        neg_scope.push_root(argument)?;
        let num = self.to_numeric(&mut neg_scope, argument)?;
        Ok(match num {
          NumericValue::Number(n) => Value::Number(-n),
          NumericValue::BigInt(b) => {
            neg_scope.push_root(Value::BigInt(b))?;
            let bi = neg_scope.heap().get_bigint(b)?;
            let out = bi.neg()?;
            let out = neg_scope.alloc_bigint(out)?;
            Value::BigInt(out)
          }
        })
      }
      OperatorName::BitwiseNot => {
        let argument = self.eval_expr(scope, &expr.argument)?;
        let mut not_scope = scope.reborrow();
        not_scope.push_root(argument)?;
        let num = self.to_numeric(&mut not_scope, argument)?;
        Ok(match num {
          NumericValue::Number(n) => Value::Number((!to_int32(n)) as f64),
          NumericValue::BigInt(b) => {
            not_scope.push_root(Value::BigInt(b))?;
            let bi = not_scope.heap().get_bigint(b)?;
            let out = bi.bitwise_not()?;
            let out = not_scope.alloc_bigint(out)?;
            Value::BigInt(out)
          }
        })
      }
      OperatorName::Typeof => {
        let argument = match &*expr.argument.stx {
          Expr::Id(id) => {
            // Preserve the `typeof` special-case: unresolvable identifiers yield `"undefined"`
            // instead of throwing a ReferenceError.
            self.tick()?;
            self
              .env
              .get(
                self.vm,
                &mut *self.host,
                &mut *self.hooks,
                scope,
                &id.stx.name,
              )?
              .unwrap_or(Value::Undefined)
          }
          Expr::IdPat(id) => {
            self.tick()?;
            self
              .env
              .get(
                self.vm,
                &mut *self.host,
                &mut *self.hooks,
                scope,
                &id.stx.name,
              )?
              .unwrap_or(Value::Undefined)
          }
          _ => self.eval_expr(scope, &expr.argument)?,
        };
        let t = typeof_name(scope.heap(), argument)?;
        let s = scope.alloc_string(t)?;
        Ok(Value::String(s))
      }
      OperatorName::Void => {
        let _ = self.eval_expr(scope, &expr.argument)?;
        Ok(Value::Undefined)
      }
      OperatorName::New => {
        // `parse-js` represents `new f()` as a `UnaryExpr` whose argument is a `CallExpr`.
        //
        // Important: `new (f())` must *not* use `f` as the constructor. It must first evaluate the
        // parenthesized call expression and then construct the *result* with no arguments.
        //
        // `parse-js` stores parentheses via the `ParenthesizedExpr` assoc marker, so treat
        // parenthesized call expressions as the `new (expr)` form (no argument list for `new`).
        let is_parenthesized = expr.argument.assoc.get::<ParenthesizedExpr>().is_some();
        let (callee_expr, call_args) = match &*expr.argument.stx {
          Expr::Call(call) if !is_parenthesized => (&call.stx.callee, Some(&call.stx.arguments)),
          _ => (&expr.argument, None),
        };

        let mut new_scope = scope.reborrow();
        let callee = self.eval_expr(&mut new_scope, callee_expr)?;
        new_scope.push_root(callee)?;

        let mut args: Vec<Value> = Vec::new();
        if let Some(call_args) = call_args {
          args
            .try_reserve_exact(call_args.len())
            .map_err(|_| VmError::OutOfMemory)?;
          for arg in call_args {
            if arg.stx.spread {
              let spread_value = self.eval_expr(&mut new_scope, &arg.stx.value)?;
              new_scope.push_root(spread_value)?;

              let mut iter = iterator::get_iterator(
                self.vm,
                &mut *self.host,
                &mut *self.hooks,
                &mut new_scope,
                spread_value,
              )?;
              new_scope.push_roots_with_extra_roots(&[iter.iterator], &[iter.next_method], &[])?;
              if let Err(err) = new_scope.push_root(iter.next_method) {
                // `ArgumentListEvaluation` uses `IteratorStepValue` and does not perform
                // `IteratorClose` on abrupt completions (including when `next` throws).
                return Err(err);
              }

              loop {
                let next_value = match iterator::iterator_step_value(
                  self.vm,
                  &mut *self.host,
                  &mut *self.hooks,
                  &mut new_scope,
                  &mut iter,
                ) {
                  Ok(v) => v,
                  // Spec: spread argument evaluation does not perform `IteratorClose` on errors
                  // produced while stepping the iterator (`next`/`done`/`value`).
                  Err(err) => return Err(err),
                };

                let Some(value) = next_value else {
                  break;
                };

                let step_res: Result<(), VmError> = (|| {
                  self.tick()?;
                  new_scope.push_root(value)?;
                  args.try_reserve(1).map_err(|_| VmError::OutOfMemory)?;
                  args.push(value);
                  Ok(())
                })();
                if let Err(err) = step_res {
                  return Err(err);
                }
              }
            } else {
              let value = self.eval_expr(&mut new_scope, &arg.stx.value)?;
              new_scope.push_root(value)?;
              args.try_reserve(1).map_err(|_| VmError::OutOfMemory)?;
              args.push(value);
            }
          }
        }

        // For `new`, the `newTarget` is the same as the constructor.
        let source = self.env.source();
        let rel_start = loc.start_u32().saturating_sub(self.env.prefix_len());
        let abs_offset = self.env.base_offset().saturating_add(rel_start);

        match self.vm.construct_with_host_and_hooks_at_location(
          &mut *self.host,
          &mut new_scope,
          &mut *self.hooks,
          callee,
          &args,
          callee,
          source.as_ref(),
          abs_offset,
        ) {
          Ok(v) => Ok(v),
          Err(VmError::NotConstructable) => Err(throw_type_error(
            self.vm,
            &mut new_scope,
            "Value is not a constructor",
          )?),
          Err(err) => Err(err),
        }
      }
      _ => Err(VmError::Unimplemented("unary operator")),
    }
  }

  fn eval_unary_postfix(
    &mut self,
    scope: &mut Scope<'_>,
    expr: &UnaryPostfixExpr,
  ) -> Result<Value, VmError> {
    match expr.operator {
      OperatorName::PostfixIncrement => {
        self.eval_update_expression(scope, &expr.argument, 1, false)
      }
      OperatorName::PostfixDecrement => {
        self.eval_update_expression(scope, &expr.argument, -1, false)
      }
      _ => Err(VmError::Unimplemented("postfix unary operator")),
    }
  }

  fn eval_update_expression(
    &mut self,
    scope: &mut Scope<'_>,
    argument: &Node<Expr>,
    delta: i8,
    prefix: bool,
  ) -> Result<Value, VmError> {
    let reference = self.eval_reference(scope, argument)?;
    let mut update_scope = scope.reborrow();
    self.root_reference(&mut update_scope, &reference)?;

    let old_value = self.get_value_from_reference(&mut update_scope, &reference)?;
    update_scope.push_root(old_value)?;

    let old_numeric = self.to_numeric(&mut update_scope, old_value)?;
    let delta_bigint = JsBigInt::from_i128(delta as i128)?;

    let (old_out, new_value) = match old_numeric {
      NumericValue::Number(n) => {
        let new_n = n + f64::from(delta);
        (Value::Number(n), Value::Number(new_n))
      }
      NumericValue::BigInt(b) => {
        update_scope.push_root(Value::BigInt(b))?;
        let bi = update_scope.heap().get_bigint(b)?;
        let out = bi.add(&delta_bigint)?;
        let out = update_scope.alloc_bigint(out)?;
        (Value::BigInt(b), Value::BigInt(out))
      }
    };

    update_scope.push_root(new_value)?;
    self.put_value_to_reference(&mut update_scope, &reference, new_value)?;
    if prefix {
      Ok(new_value)
    } else {
      Ok(old_out)
    }
  }

  fn eval_call(
    &mut self,
    scope: &mut Scope<'_>,
    expr: &CallExpr,
    loc: parse_js::loc::Loc,
  ) -> Result<OptionalChainEval, VmError> {
    // Track whether this call is *syntactically* a direct eval candidate (`eval(...)`).
    //
    // A call is only a direct eval if:
    // - it is syntactically `eval(...)`, and
    // - `eval` resolves to the original `%eval%` intrinsic function object.
    //
    // Otherwise this is an indirect eval (or just an ordinary call if `eval` was shadowed).
    let callee_is_parenthesized = expr.callee.assoc.get::<ParenthesizedExpr>().is_some();
    let direct_eval_syntax = !expr.optional_chaining
      && !callee_is_parenthesized
      && match &*expr.callee.stx {
        Expr::Id(id) => id.stx.name == "eval",
        Expr::IdPat(id) => id.stx.name == "eval",
        _ => false,
      };

    // `super(...args)` in derived class constructors.
    if matches!(&*expr.callee.stx, Expr::Super(_)) {
      if expr.optional_chaining {
        return Err(VmError::Unimplemented("optional chaining super call"));
      }

      // Derived constructor `super()` semantics must be visible to nested arrow functions and eval
      // code. Those contexts capture the enclosing constructor's `this` as a shared heap object.
      if let Value::Object(state_obj) = self.this {
        if scope.heap().is_derived_constructor_state(state_obj) {
          let class_ctor = {
            let state = scope.heap().get_derived_constructor_state(state_obj)?;
            state.class_constructor
          };

          // Resolve the superclass constructor from the class constructor's hidden `extends` slot.
          let super_value = crate::class_fields::class_constructor_super_value(scope, class_ctor)?;
          let super_ctor = match super_value {
            Value::Object(o) => o,
            Value::Null => {
              return Err(throw_type_error(
                self.vm,
                scope,
                "Class extends value is not a constructor",
              )?)
            }
            Value::Undefined => {
              return Err(VmError::InvariantViolation(
                "derived constructor attempted super() call with undefined superclass",
              ))
            }
            _ => {
              return Err(VmError::InvariantViolation(
                "class constructor super slot is not undefined, null, or object",
              ))
            }
          };

          // Root callee/new_target and the derived-constructor state for the duration of argument
          // evaluation + construction.
          let mut call_scope = scope.reborrow();
          call_scope.push_roots(&[
            Value::Object(super_ctor),
            self.new_target,
            Value::Object(state_obj),
            Value::Object(class_ctor),
          ])?;

          // Evaluate argument list (including spread) in source order.
          let mut args: Vec<Value> = Vec::new();
          args
            .try_reserve_exact(expr.arguments.len())
            .map_err(|_| VmError::OutOfMemory)?;
          for arg in &expr.arguments {
            if arg.stx.spread {
              let spread_value = self.eval_expr(&mut call_scope, &arg.stx.value)?;
              call_scope.push_root(spread_value)?;

              let mut iter = iterator::get_iterator(
                self.vm,
                &mut *self.host,
                &mut *self.hooks,
                &mut call_scope,
                spread_value,
              )?;
              call_scope.push_roots_with_extra_roots(&[iter.iterator], &[iter.next_method], &[])?;
              if let Err(err) = call_scope.push_root(iter.next_method) {
                // `ArgumentListEvaluation` uses `IteratorStepValue` and does not perform
                // `IteratorClose` on abrupt completions (including when `next` throws).
                return Err(err);
              }

              loop {
                let next_value = match iterator::iterator_step_value(
                  self.vm,
                  &mut *self.host,
                  &mut *self.hooks,
                  &mut call_scope,
                  &mut iter,
                ) {
                  Ok(v) => v,
                  // Spec: spread argument evaluation does not perform `IteratorClose` on errors
                  // produced while stepping the iterator (`next`/`done`/`value`).
                  Err(err) => return Err(err),
                };

                let Some(value) = next_value else {
                  break;
                };

                let step_res: Result<(), VmError> = (|| {
                  self.tick()?;
                  call_scope.push_root(value)?;
                  args.try_reserve(1).map_err(|_| VmError::OutOfMemory)?;
                  args.push(value);
                  Ok(())
                })();
                if let Err(err) = step_res {
                  return Err(err);
                }
              }
            } else {
              let value = self.eval_expr(&mut call_scope, &arg.stx.value)?;
              call_scope.push_root(value)?;
              args.try_reserve(1).map_err(|_| VmError::OutOfMemory)?;
              args.push(value);
            }
          }

          // Construct the superclass instance: `Construct(super, args, newTarget)`.
          let source = self.env.source();
          let rel_start = loc.start_u32().saturating_sub(self.env.prefix_len());
          let abs_offset = self.env.base_offset().saturating_add(rel_start);
          let this_value = self.vm.construct_with_host_and_hooks_at_location(
            &mut *self.host,
            &mut call_scope,
            &mut *self.hooks,
            Value::Object(super_ctor),
            &args,
            self.new_target,
            source.as_ref(),
            abs_offset,
          )?;

          let Value::Object(this_obj) = this_value else {
            return Err(VmError::InvariantViolation(
              "super constructor returned non-object from Construct",
            ));
          };

          // `super()` in derived constructors always evaluates arguments and performs `Construct`
          // first. The ReferenceError for calling `super()` more than once comes from trying to bind
          // `this` again (after the base constructor has already run).
          let already_initialized = {
            let state = call_scope.heap().get_derived_constructor_state(state_obj)?;
            state.this_value.is_some()
          };
          if already_initialized {
            return Err(throw_reference_error(
              self.vm,
              &mut call_scope,
              "super() can only be called once in a derived constructor",
            )?);
          }

          // Initialize the enclosing derived constructor's `this` binding exactly once.
          call_scope
            .heap_mut()
            .get_derived_constructor_state_mut(state_obj)?
            .this_value = Some(this_obj);

          // Initialize derived instance fields immediately after `super()` returns.
          crate::class_fields::initialize_instance_fields_with_host_and_hooks(
            self.vm,
            &mut call_scope,
            &mut *self.host,
            &mut *self.hooks,
            this_obj,
            class_ctor,
          )?;

          return Ok(OptionalChainEval::Value(this_value));
        }
      }

      let Some(class_ctor) = self.class_constructor else {
        return Err(VmError::Unimplemented(
          "super call outside of class constructor",
        ));
      };
      if !self.derived_constructor {
        return Err(throw_reference_error(
          self.vm,
          scope,
          "super() is not allowed in base class constructors",
        )?);
      }

      // Resolve the superclass constructor from the class constructor's hidden `extends` slot.
      let super_value = crate::class_fields::class_constructor_super_value(scope, class_ctor)?;
      let super_ctor = match super_value {
        Value::Object(o) => o,
        Value::Null => {
          return Err(throw_type_error(
            self.vm,
            scope,
            "Class extends value is not a constructor",
          )?)
        }
        Value::Undefined => {
          return Err(VmError::InvariantViolation(
            "derived constructor attempted super() call with undefined superclass",
          ))
        }
        _ => {
          return Err(VmError::InvariantViolation(
            "class constructor super slot is not undefined, null, or object",
          ))
        }
      };

      // Root callee/new_target for the duration of argument evaluation + construction.
      let mut call_scope = scope.reborrow();
      call_scope.push_roots(&[Value::Object(super_ctor), self.new_target])?;

      // Evaluate argument list (including spread) in source order.
      let mut args: Vec<Value> = Vec::new();
      args
        .try_reserve_exact(expr.arguments.len())
        .map_err(|_| VmError::OutOfMemory)?;
      for arg in &expr.arguments {
        if arg.stx.spread {
          let spread_value = self.eval_expr(&mut call_scope, &arg.stx.value)?;
          call_scope.push_root(spread_value)?;

          let mut iter = iterator::get_iterator(
            self.vm,
            &mut *self.host,
            &mut *self.hooks,
            &mut call_scope,
            spread_value,
          )?;
          call_scope.push_roots_with_extra_roots(&[iter.iterator], &[iter.next_method], &[])?;
          if let Err(err) = call_scope.push_root(iter.next_method) {
            // `ArgumentListEvaluation` uses `IteratorStepValue` and does not perform `IteratorClose`
            // on abrupt completions (including when `next` throws).
            return Err(err);
          }

          loop {
            let next_value = match iterator::iterator_step_value(
              self.vm,
              &mut *self.host,
              &mut *self.hooks,
              &mut call_scope,
              &mut iter,
            ) {
              Ok(v) => v,
              // Spec: spread argument evaluation does not perform `IteratorClose` on errors produced
              // while stepping the iterator (`next`/`done`/`value`).
              Err(err) => return Err(err),
            };

            let Some(value) = next_value else {
              break;
            };

            let step_res: Result<(), VmError> = (|| {
              self.tick()?;
              call_scope.push_root(value)?;
              args.try_reserve(1).map_err(|_| VmError::OutOfMemory)?;
              args.push(value);
              Ok(())
            })();
            if let Err(err) = step_res {
              return Err(err);
            }
          }
        } else {
          let value = self.eval_expr(&mut call_scope, &arg.stx.value)?;
          call_scope.push_root(value)?;
          args.try_reserve(1).map_err(|_| VmError::OutOfMemory)?;
          args.push(value);
        }
      }

      // Construct the superclass instance: `Construct(super, args, newTarget)`.
      let source = self.env.source();
      let rel_start = loc.start_u32().saturating_sub(self.env.prefix_len());
      let abs_offset = self.env.base_offset().saturating_add(rel_start);
      let this_value = self.vm.construct_with_host_and_hooks_at_location(
        &mut *self.host,
        &mut call_scope,
        &mut *self.hooks,
        Value::Object(super_ctor),
        &args,
        self.new_target,
        source.as_ref(),
        abs_offset,
      )?;

      let Value::Object(this_obj) = this_value else {
        return Err(VmError::InvariantViolation(
          "super constructor returned non-object from Construct",
        ));
      };

      // `super()` in derived constructors always evaluates arguments and performs `Construct` first.
      // The ReferenceError for calling `super()` more than once comes from trying to bind `this`
      // again (after the base constructor has already run).
      if self.this_initialized {
        return Err(throw_reference_error(
          self.vm,
          &mut call_scope,
          "super() can only be called once in a derived constructor",
        )?);
      }

      // Bind `this` and keep it rooted for the remainder of constructor evaluation.
      let this_root_idx = self.this_root_idx.ok_or(VmError::InvariantViolation(
        "derived constructor missing this root slot",
      ))?;
      self.this = this_value;
      self.this_initialized = true;
      call_scope.heap_mut().root_stack[this_root_idx] = this_value;

      // Initialize derived instance fields immediately after `super()` returns.
      crate::class_fields::initialize_instance_fields_with_host_and_hooks(
        self.vm,
        &mut call_scope,
        &mut *self.host,
        &mut *self.hooks,
        this_obj,
        class_ctor,
      )?;

      return Ok(OptionalChainEval::Value(this_value));
    }

    // Evaluate the callee and compute the `this` value for the call.
    let (callee_value, this_value) = match &*expr.callee.stx {
      // `super.m()` calls (instance/static).
      Expr::Member(member) if matches!(&*member.stx.left.stx, Expr::Super(_)) => {
        if member.stx.optional_chaining {
          return Err(VmError::InvariantViolation(
            "optional chaining used with super property access",
          ));
        }
        if member.stx.right.starts_with('#') {
          return Err(VmError::Unimplemented("super private member access"));
        }
        // Evaluate the property reference (including `this` binding errors) before arguments.
        let mut super_scope = scope.reborrow();
        let actual_this = self.get_this_binding(&mut super_scope)?;
        // Root `this` binding state (may be a DerivedConstructorState cell), the resolved receiver,
        // and `[[HomeObject]]` in a single operation so a GC triggered by root-stack growth cannot
        // collect values that have not yet been pushed.
        let mut roots_buf = [self.this, actual_this, Value::Undefined];
        let roots = if let Some(home) = self.home_object {
          roots_buf[2] = Value::Object(home);
          &roots_buf[..]
        } else {
          &roots_buf[..2]
        };
        super_scope.push_roots(roots)?;
        let key_s = super_scope.alloc_string(&member.stx.right)?;
        super_scope.push_root(Value::String(key_s))?;
        let key = PropertyKey::from_string(key_s);

        let super_base = self.super_base(&mut super_scope)?;
        let reference = Reference::SuperProperty {
          base: super_base,
          key,
          receiver: actual_this,
        };
        let callee_value = self.get_value_from_reference(&mut super_scope, &reference)?;
        (callee_value, actual_this)
      }
      // `super[expr](...args)` calls (instance/static).
      Expr::ComputedMember(member) if matches!(&*member.stx.object.stx, Expr::Super(_)) => {
        if member.stx.optional_chaining {
          return Err(VmError::InvariantViolation(
            "optional chaining used with super property access",
          ));
        }
        // `GetThisBinding` must be observed before evaluating the computed key expression.
        let home_object = self.home_object.ok_or(VmError::InvariantViolation(
          "super property access missing [[HomeObject]]",
        ))?;

        let mut key_scope = scope.reborrow();
        let roots = [self.this, Value::Object(home_object)];
        key_scope.push_roots(&roots)?;

        let receiver = self.get_this_binding(&mut key_scope)?;
        key_scope.push_root(receiver)?;

        // Root receiver + home object across evaluation of the computed key, `GetSuperBase`,
        // `ToPropertyKey`, and the final `[[Get]]`.
        let member_value = self.eval_expr(&mut key_scope, &member.stx.member)?;
        key_scope.push_root(member_value)?;

        // Spec: `GetSuperBase` must happen before `ToPropertyKey` for computed super properties.
        let super_base = key_scope.get_prototype_of_with_host_and_hooks(
          self.vm,
          &mut *self.host,
          &mut *self.hooks,
          home_object,
        )?;
        let Some(super_base) = super_base else {
          return Err(throw_type_error(
            self.vm,
            &mut key_scope,
            "Cannot convert undefined or null to object",
          )?);
        };
        key_scope.push_root(Value::Object(super_base))?;

        let key = self.to_property_key_operator(&mut key_scope, member_value)?;
        // Root the computed key across the `[[Get]]`, which can invoke accessors/Proxy traps.
        match key {
          PropertyKey::String(s) => key_scope.push_root(Value::String(s))?,
          PropertyKey::Symbol(s) => key_scope.push_root(Value::Symbol(s))?,
        };

        let callee_value = key_scope.get_with_host_and_hooks(
          self.vm,
          &mut *self.host,
          &mut *self.hooks,
          super_base,
          key,
          receiver,
        )?;
        (callee_value, receiver)
      }
      // Optional member call (e.g. `obj?.method()`): only applies when the optional-chain member
      // expression is directly in the call callee position (i.e. not parenthesized).
      Expr::Member(member) if member.stx.optional_chaining && !callee_is_parenthesized => {
        let base = match self.eval_chain_base(scope, &member.stx.left)? {
          OptionalChainEval::Value(v) => v,
          OptionalChainEval::ShortCircuit => return Ok(OptionalChainEval::ShortCircuit),
        };
        if is_nullish(base) {
          // Optional chaining short-circuit on the base value.
          return Ok(OptionalChainEval::ShortCircuit);
        }

        // Optional chaining member call: preserve the base value for the call `this` binding.
        let mut key_scope = scope.reborrow();
        key_scope.push_root(base)?;
        let reference = if member.stx.right.starts_with('#') {
          let sym = key_scope
            .heap()
            .resolve_private_name_symbol(self.env.lexical_env, &member.stx.right)?
            .ok_or(VmError::InvariantViolation("unresolved private name"))?;
          Reference::Private {
            base,
            sym,
            name: &member.stx.right,
          }
        } else {
          let key_s = key_scope.alloc_string(&member.stx.right)?;
          Reference::Property {
            base,
            receiver: base,
            key: PropertyKey::from_string(key_s),
          }
        };
        let callee_value = self.get_value_from_reference(&mut key_scope, &reference)?;
        (callee_value, base)
      }
      // Optional computed-member call (e.g. `obj?.[expr]()`): only applies when the optional-chain
      // computed member expression is directly in the call callee position (i.e. not parenthesized).
      Expr::ComputedMember(member) if member.stx.optional_chaining && !callee_is_parenthesized => {
        // `super?.[expr](...)` is an early error, but super computed-member calls can still appear
        // in this position when the callee is not optional-chained. For derived constructors
        // before `super()`, evaluating a super property reference must throw before evaluating the
        // computed key expression.
        if matches!(&*member.stx.object.stx, Expr::Super(_)) {
          // `GetThisBinding` must run before evaluating the key expression.
          let _ = self.get_this_binding(scope)?;
        }

        let base = match self.eval_chain_base(scope, &member.stx.object)? {
          OptionalChainEval::Value(v) => v,
          OptionalChainEval::ShortCircuit => return Ok(OptionalChainEval::ShortCircuit),
        };
        if is_nullish(base) {
          return Ok(OptionalChainEval::ShortCircuit);
        }

        // `ToPropertyKey` may allocate and invoke user code. Only if the base is non-nullish do we
        // evaluate the key and dereference the property reference.
        let mut key_scope = scope.reborrow();
        key_scope.push_root(base)?;
        let member_value = self.eval_expr(&mut key_scope, &member.stx.member)?;
        key_scope.push_root(member_value)?;
        let key = self.to_property_key_operator(&mut key_scope, member_value)?;
        let reference = Reference::Property {
          base,
          receiver: base,
          key,
        };
        let callee_value = self.get_value_from_reference(&mut key_scope, &reference)?;
        (callee_value, base)
      }
      // Ordinary member call (e.g. `obj.method()`), but with optional-chain propagation when the
      // member base expression is an unparenthesized optional chain (e.g. `a?.b.c()`).
      Expr::Member(member) if !member.stx.optional_chaining => {
        if matches!(&*member.stx.left.stx, Expr::Super(_)) {
          if member.stx.right.starts_with('#') {
            return Err(VmError::InvariantViolation(
              "super private member access is not valid (early errors should prevent this)",
            ));
          }
          let receiver = self.get_this_binding(scope)?;

          let mut key_scope = scope.reborrow();
          // Root receiver + key across `GetSuperBase()` and any proxy traps.
          key_scope.push_roots(&[self.this, receiver])?;
          let key_s = key_scope.alloc_string(&member.stx.right)?;
          key_scope.push_root(Value::String(key_s))?;
          let key = PropertyKey::from_string(key_s);

          let base = self.get_super_base(&mut key_scope)?;
          let reference = Reference::SuperProperty { base, key, receiver };
          let callee_value = self.get_value_from_reference(&mut key_scope, &reference)?;
          (callee_value, receiver)
        } else {
        match self.eval_chain_base(scope, &member.stx.left)? {
          OptionalChainEval::Value(base) => {
            if is_nullish(base) {
              return Err(throw_type_error(
                self.vm,
                scope,
                "Cannot convert undefined or null to object",
              )?);
            }

            let mut key_scope = scope.reborrow();
            key_scope.push_root(base)?;
            let reference = if member.stx.right.starts_with('#') {
              let sym = key_scope
                .heap()
                .resolve_private_name_symbol(self.env.lexical_env, &member.stx.right)?
                .ok_or(VmError::InvariantViolation("unresolved private name"))?;
              Reference::Private {
                base,
                sym,
                name: &member.stx.right,
              }
            } else {
              let key_s = key_scope.alloc_string(&member.stx.right)?;
              Reference::Property {
                base,
                receiver: base,
                key: PropertyKey::from_string(key_s),
              }
            };
            let callee_value = self.get_value_from_reference(&mut key_scope, &reference)?;
            (callee_value, base)
          }
          OptionalChainEval::ShortCircuit => {
            if callee_is_parenthesized {
              // `(a?.b.c)()` is not part of the optional chain: the callee evaluates to `undefined`,
              // and the call will throw (after evaluating arguments) like any other `undefined()`.
              (Value::Undefined, Value::Undefined)
            } else {
              return Ok(OptionalChainEval::ShortCircuit);
            }
          }
        }
        }
      }
      // Ordinary computed-member call (e.g. `obj[expr]()`), but with optional-chain propagation.
      Expr::ComputedMember(member) if !member.stx.optional_chaining => {
        if matches!(&*member.stx.object.stx, Expr::Super(_)) {
          // Computed super call `super[expr]()`:
          // - resolve the `this` binding first (throwing in derived constructors before `super()`),
          // - then evaluate the computed key and call with `this = receiver`.
          let mut key_scope = scope.reborrow();
          let receiver = self.get_this_binding(&mut key_scope)?;
          // Root `this` binding state (may be a DerivedConstructorState cell), the resolved receiver,
          // and `[[HomeObject]]` in a single operation so a GC triggered by root-stack growth cannot
          // collect values that have not yet been pushed.
          let mut roots_buf = [self.this, receiver, Value::Undefined];
          let roots = if let Some(home) = self.home_object {
            roots_buf[2] = Value::Object(home);
            &roots_buf[..]
          } else {
            &roots_buf[..2]
          };
          key_scope.push_roots(roots)?;
          let member_value = self.eval_expr(&mut key_scope, &member.stx.member)?;
          key_scope.push_root(member_value)?;
          let key = self.to_property_key_operator(&mut key_scope, member_value)?;
          match key {
            PropertyKey::String(s) => {
              key_scope.push_root(Value::String(s))?;
            }
            PropertyKey::Symbol(s) => {
              key_scope.push_root(Value::Symbol(s))?;
            }
          }

          let base = self.get_super_base(&mut key_scope)?;
          let reference = Reference::SuperProperty { base, key, receiver };
          let callee_value = self.get_value_from_reference(&mut key_scope, &reference)?;
          (callee_value, receiver)
        } else {
        match self.eval_chain_base(scope, &member.stx.object)? {
          OptionalChainEval::Value(base) => {
            // In non-optional computed member access, the key expression is evaluated even if the
            // base is nullish (the TypeError is thrown only when the reference is dereferenced).
            let mut key_scope = scope.reborrow();
            key_scope.push_root(base)?;
            let member_value = self.eval_expr(&mut key_scope, &member.stx.member)?;
            key_scope.push_root(member_value)?;
            let key = self.to_property_key_operator(&mut key_scope, member_value)?;
            if is_nullish(base) {
              return Err(throw_type_error(
                self.vm,
                &mut key_scope,
                "Cannot convert undefined or null to object",
              )?);
            }
            let reference = Reference::Property {
              base,
              receiver: base,
              key,
            };
            let callee_value = self.get_value_from_reference(&mut key_scope, &reference)?;
            (callee_value, base)
          }
          OptionalChainEval::ShortCircuit => {
            if callee_is_parenthesized {
              (Value::Undefined, Value::Undefined)
            } else {
              return Ok(OptionalChainEval::ShortCircuit);
            }
          }
        }
        }
      }
      Expr::Id(_) | Expr::IdPat(_) => {
        let reference = self.eval_reference(scope, &expr.callee)?;
        let mut callee_scope = scope.reborrow();
        self.root_reference(&mut callee_scope, &reference)?;
        let callee_value = self.get_value_from_reference(&mut callee_scope, &reference)?;
        (callee_value, Value::Undefined)
      }
      // Any other callee expression, including optional member access that is not in direct call
      // position (e.g. `(obj?.method)()`).
      _ => {
        let callee_value = self.eval_expr(scope, &expr.callee)?;
        (callee_value, Value::Undefined)
      }
    };

    // Optional call: if the callee is nullish, return `undefined` without evaluating args.
    if expr.optional_chaining && is_nullish(callee_value) {
      return Ok(OptionalChainEval::ShortCircuit);
    }

    // Root callee/this/args for the duration of the call.
    let mut call_scope = scope.reborrow();
    call_scope.push_roots(&[callee_value, this_value])?;

    let mut args: Vec<Value> = Vec::new();
    args
      .try_reserve_exact(expr.arguments.len())
      .map_err(|_| VmError::OutOfMemory)?;
    for arg in &expr.arguments {
      if arg.stx.spread {
        let spread_value = self.eval_expr(&mut call_scope, &arg.stx.value)?;
        call_scope.push_root(spread_value)?;

        let mut iter = iterator::get_iterator(
          self.vm,
          &mut *self.host,
          &mut *self.hooks,
          &mut call_scope,
          spread_value,
        )?;
        call_scope.push_roots_with_extra_roots(&[iter.iterator], &[iter.next_method], &[])?;
        if let Err(err) = call_scope.push_root(iter.next_method) {
          // `ArgumentListEvaluation` uses `IteratorStepValue` and does not perform `IteratorClose`
          // on abrupt completions (including when `next` throws).
          return Err(err);
        }

        loop {
          let next_value = match iterator::iterator_step_value(
            self.vm,
            &mut *self.host,
            &mut *self.hooks,
            &mut call_scope,
            &mut iter,
          ) {
            Ok(v) => v,
            // Spec: spread argument evaluation does not perform `IteratorClose` on errors produced
            // while stepping the iterator (`next`/`done`/`value`).
            Err(err) => return Err(err),
          };

          let Some(value) = next_value else {
            break;
          };

          let step_res: Result<(), VmError> = (|| {
            self.tick()?;
            call_scope.push_root(value)?;
            args.try_reserve(1).map_err(|_| VmError::OutOfMemory)?;
            args.push(value);
            Ok(())
          })();
          if let Err(err) = step_res {
            return Err(err);
          }
        }
      } else {
        let value = self.eval_expr(&mut call_scope, &arg.stx.value)?;
        call_scope.push_root(value)?;
        args.try_reserve(1).map_err(|_| VmError::OutOfMemory)?;
        args.push(value);
      }
    }
    if direct_eval_syntax {
      let intr = self
        .vm
        .intrinsics()
        .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;
      if callee_value == Value::Object(intr.eval()) {
        // Direct eval: execute in the caller's lexical environment (with strictness propagation).
        let arg0 = args.get(0).copied().unwrap_or(Value::Undefined);
        return match arg0 {
          Value::String(s) => Ok(OptionalChainEval::Value(
            self.eval_direct_eval_string(&mut call_scope, s)?,
          )),
          other => Ok(OptionalChainEval::Value(other)),
        };
      }
    }

    let source = self.env.source();
    let rel_start = loc.start_u32().saturating_sub(self.env.prefix_len());
    let abs_offset = self.env.base_offset().saturating_add(rel_start);

    let value = self.vm.call_with_host_and_hooks_at_location(
      &mut *self.host,
      &mut call_scope,
      &mut *self.hooks,
      callee_value,
      this_value,
      &args,
      source.as_ref(),
      abs_offset,
    )?;
    Ok(OptionalChainEval::Value(value))
  }

  fn eval_direct_eval_string(
    &mut self,
    scope: &mut Scope<'_>,
    source_string: GcString,
  ) -> Result<Value, VmError> {
    perform_direct_eval_with_host_and_hooks(
      self.vm,
      scope,
      &mut *self.host,
      &mut *self.hooks,
      self.env,
      self.strict,
      self.this,
      self.new_target,
      self.home_object,
      source_string,
    )
  }

  fn eval_cond(&mut self, scope: &mut Scope<'_>, expr: &CondExpr) -> Result<Value, VmError> {
    let test = self.eval_expr(scope, &expr.test)?;
    if to_boolean(scope.heap(), test)? {
      self.eval_expr(scope, &expr.consequent)
    } else {
      self.eval_expr(scope, &expr.alternate)
    }
  }

  fn eval_binary(&mut self, scope: &mut Scope<'_>, expr: &BinaryExpr) -> Result<Value, VmError> {
    match expr.operator {
      OperatorName::Assignment => {
        // Destructuring assignment patterns appear in expression position as `Expr::ObjPat` /
        // `Expr::ArrPat` nodes. These are not valid "references" and must be handled by pattern
        // binding.
        match &*expr.left.stx {
          Expr::ObjPat(_) | Expr::ArrPat(_) => {
            let value = self.eval_expr(scope, &expr.right)?;
            bind_assignment_target(
              self.vm,
              &mut *self.host,
              &mut *self.hooks,
              scope,
              self.env,
              &expr.left,
              value,
              self.strict,
              self.this,
            )?;
            Ok(value)
          }
          _ => {
            let reference = self.eval_reference(scope, &expr.left)?;
            let mut rhs_scope = scope.reborrow();
            self.root_reference(&mut rhs_scope, &reference)?;
            let value = self.eval_expr(&mut rhs_scope, &expr.right)?;
            rhs_scope.push_root(value)?;
            self.maybe_set_anonymous_function_name_for_assignment(
              &mut rhs_scope,
              &reference,
              value,
            )?;
            self.put_value_to_reference(&mut rhs_scope, &reference, value)?;
            Ok(value)
          }
        }
      }
      OperatorName::AssignmentAddition => match &*expr.left.stx {
        Expr::ObjPat(_) | Expr::ArrPat(_) => Err(VmError::Unimplemented(
          "assignment addition to destructuring patterns",
        )),
        _ => {
          let reference = self.eval_reference(scope, &expr.left)?;
          let mut op_scope = scope.reborrow();
          self.root_reference(&mut op_scope, &reference)?;

          let left = self.get_value_from_reference(&mut op_scope, &reference)?;
          // Root `left` across evaluation of the RHS in case it allocates and triggers GC.
          op_scope.push_root(left)?;
          let right = self.eval_expr(&mut op_scope, &expr.right)?;

          let value = self.addition_operator(&mut op_scope, left, right)?;
          op_scope.push_root(value)?;
          self.put_value_to_reference(&mut op_scope, &reference, value)?;
          Ok(value)
        }
      },
      OperatorName::AssignmentExponentiation => match &*expr.left.stx {
        Expr::ObjPat(_) | Expr::ArrPat(_) => Err(VmError::Unimplemented(
          "assignment exponentiation to destructuring patterns",
        )),
        _ => {
          let reference = self.eval_reference(scope, &expr.left)?;
          let mut op_scope = scope.reborrow();
          self.root_reference(&mut op_scope, &reference)?;

          let left = self.get_value_from_reference(&mut op_scope, &reference)?;
          // Root `left` across evaluation of the RHS in case it allocates and triggers GC.
          op_scope.push_root(left)?;
          let right = self.eval_expr(&mut op_scope, &expr.right)?;

          let value = self.exponentiation_operator(&mut op_scope, left, right)?;
          op_scope.push_root(value)?;
          self.put_value_to_reference(&mut op_scope, &reference, value)?;
          Ok(value)
        }
      },
      OperatorName::AssignmentSubtraction
      | OperatorName::AssignmentMultiplication
      | OperatorName::AssignmentDivision
      | OperatorName::AssignmentRemainder => match &*expr.left.stx {
        Expr::ObjPat(_) | Expr::ArrPat(_) => Err(VmError::Unimplemented(
          "arithmetic compound assignment to destructuring patterns",
        )),
        _ => {
          // Compound assignment evaluation order per ECMA-262:
          // 1. Evaluate LHS reference once.
          // 2. GetValue(lref) BEFORE evaluating RHS.
          // 3. Evaluate RHS.
          // 4. Apply operator to lval and rval.
          // 5. PutValue(lref, result).
          let reference = self.eval_reference(scope, &expr.left)?;
          let mut op_scope = scope.reborrow();
          self.root_reference(&mut op_scope, &reference)?;

          let left = self.get_value_from_reference(&mut op_scope, &reference)?;
          // Root `left` across evaluation of the RHS in case it allocates and triggers GC.
          op_scope.push_root(left)?;
          let right = self.eval_expr(&mut op_scope, &expr.right)?;
          // Root `right` across `ToNumeric` and BigInt arithmetic.
          op_scope.push_root(right)?;

          let left_num = self.to_numeric(&mut op_scope, left)?;
          let right_num = self.to_numeric(&mut op_scope, right)?;
          let value = match (left_num, right_num) {
            (NumericValue::Number(a), NumericValue::Number(b)) => {
              let value = match expr.operator {
                OperatorName::AssignmentSubtraction => Value::Number(a - b),
                OperatorName::AssignmentMultiplication => Value::Number(a * b),
                OperatorName::AssignmentDivision => Value::Number(a / b),
                OperatorName::AssignmentRemainder => Value::Number(a % b),
                _ => {
                  return Err(VmError::InvariantViolation(
                    "unexpected operator in arithmetic compound assignment",
                  ));
                }
              };
              Ok(value)
            }
            (NumericValue::BigInt(a), NumericValue::BigInt(b)) => {
              let out = {
                let a = op_scope.heap().get_bigint(a)?;
                let b = op_scope.heap().get_bigint(b)?;

                if b.is_zero()
                  && matches!(
                    expr.operator,
                    OperatorName::AssignmentDivision | OperatorName::AssignmentRemainder
                  )
                {
                  return Err(throw_range_error(self.vm, &mut op_scope, "Division by zero")?);
                }

                match expr.operator {
                  OperatorName::AssignmentSubtraction => a.sub(b)?,
                  OperatorName::AssignmentMultiplication => {
                    a.mul_with_tick(b, &mut || self.tick())?
                  }
                  OperatorName::AssignmentDivision => {
                    let (q, _) = a.div_mod_with_tick(b, &mut || self.tick())?;
                    q
                  }
                  OperatorName::AssignmentRemainder => {
                    let (_, r) = a.div_mod_with_tick(b, &mut || self.tick())?;
                    r
                  }
                  _ => {
                    return Err(VmError::InvariantViolation(
                      "unexpected operator in arithmetic BigInt compound assignment",
                    ));
                  }
                }
              };
              let out = op_scope.alloc_bigint(out)?;
              Ok(Value::BigInt(out))
            }
            _ => Err(throw_type_error(
              self.vm,
              &mut op_scope,
              "Cannot mix BigInt and other types",
            )?),
          }?;

          op_scope.push_root(value)?;
          self.put_value_to_reference(&mut op_scope, &reference, value)?;
          Ok(value)
        }
      },
      OperatorName::AssignmentBitwiseAnd
      | OperatorName::AssignmentBitwiseOr
      | OperatorName::AssignmentBitwiseXor => match &*expr.left.stx {
        Expr::ObjPat(_) | Expr::ArrPat(_) => Err(VmError::Unimplemented(
          "assignment bitwise op to destructuring patterns",
        )),
        _ => {
          let reference = self.eval_reference(scope, &expr.left)?;
          let mut op_scope = scope.reborrow();
          self.root_reference(&mut op_scope, &reference)?;

          let left = self.get_value_from_reference(&mut op_scope, &reference)?;
          // Root `left` across evaluation of the RHS in case it allocates and triggers GC.
          op_scope.push_root(left)?;
          let right = self.eval_expr(&mut op_scope, &expr.right)?;
          // Root `right` across `ToNumeric` and BigInt operations.
          op_scope.push_root(right)?;

          let left_num = self.to_numeric(&mut op_scope, left)?;
          let right_num = self.to_numeric(&mut op_scope, right)?;
          let value = match (left_num, right_num) {
            (NumericValue::Number(a), NumericValue::Number(b)) => {
              let a = to_int32(a);
              let b = to_int32(b);
              let out = match expr.operator {
                OperatorName::AssignmentBitwiseAnd => a & b,
                OperatorName::AssignmentBitwiseOr => a | b,
                OperatorName::AssignmentBitwiseXor => a ^ b,
                _ => {
                  return Err(VmError::InvariantViolation(
                    "unexpected operator in bitwise compound assignment",
                  ));
                }
              };
              Ok(Value::Number(out as f64))
            }
            (NumericValue::BigInt(a), NumericValue::BigInt(b)) => {
              let out = {
                let a = op_scope.heap().get_bigint(a)?;
                let b = op_scope.heap().get_bigint(b)?;
                match expr.operator {
                  OperatorName::AssignmentBitwiseAnd => a.bitwise_and(b)?,
                  OperatorName::AssignmentBitwiseOr => a.bitwise_or(b)?,
                  OperatorName::AssignmentBitwiseXor => a.bitwise_xor(b)?,
                  _ => {
                    return Err(VmError::InvariantViolation(
                      "unexpected operator in bitwise BigInt compound assignment",
                    ));
                  }
                }
              };
              let out = op_scope.alloc_bigint(out)?;
              Ok(Value::BigInt(out))
            }
            _ => Err(throw_type_error(
              self.vm,
              &mut op_scope,
              "Cannot mix BigInt and other types",
            )?),
          }?;

          op_scope.push_root(value)?;
          self.put_value_to_reference(&mut op_scope, &reference, value)?;
          Ok(value)
        }
      },
      OperatorName::AssignmentBitwiseLeftShift
      | OperatorName::AssignmentBitwiseRightShift
      | OperatorName::AssignmentBitwiseUnsignedRightShift => match &*expr.left.stx {
        Expr::ObjPat(_) | Expr::ArrPat(_) => Err(VmError::Unimplemented(
          "assignment bitwise shift to destructuring patterns",
        )),
        _ => {
          let reference = self.eval_reference(scope, &expr.left)?;
          let mut op_scope = scope.reborrow();
          self.root_reference(&mut op_scope, &reference)?;

          let left = self.get_value_from_reference(&mut op_scope, &reference)?;
          // Root `left` across evaluation of the RHS in case it allocates and triggers GC.
          op_scope.push_root(left)?;
          let right = self.eval_expr(&mut op_scope, &expr.right)?;
          // Root `right` across `ToNumeric` and BigInt arithmetic.
          op_scope.push_root(right)?;

          let left_num = self.to_numeric(&mut op_scope, left)?;
          let right_num = self.to_numeric(&mut op_scope, right)?;
          let value = match (left_num, right_num) {
            (NumericValue::Number(a), NumericValue::Number(b)) => {
              let shift = (to_uint32(b) & 0x1f) as u32;
              let value = match expr.operator {
                OperatorName::AssignmentBitwiseLeftShift => {
                  let a = to_int32(a);
                  Value::Number(a.wrapping_shl(shift) as f64)
                }
                OperatorName::AssignmentBitwiseRightShift => {
                  let a = to_int32(a);
                  Value::Number(a.wrapping_shr(shift) as f64)
                }
                OperatorName::AssignmentBitwiseUnsignedRightShift => {
                  let a = to_uint32(a);
                  Value::Number((a >> shift) as f64)
                }
                _ => {
                  return Err(VmError::InvariantViolation(
                    "unexpected operator in bitwise shift compound assignment",
                  ));
                }
              };
              Ok(value)
            }
            (NumericValue::BigInt(a), NumericValue::BigInt(b)) => {
              if matches!(expr.operator, OperatorName::AssignmentBitwiseUnsignedRightShift) {
                Err(throw_type_error(
                  self.vm,
                  &mut op_scope,
                  "BigInt does not support unsigned right shift",
                )?)
              } else {
                let out = {
                  let a = op_scope.heap().get_bigint(a)?;
                  let b = op_scope.heap().get_bigint(b)?;

                  let (shift_negative, shift): (bool, u64) = match b.try_to_i128() {
                    Some(shift_i) => {
                      let shift_mag: u128 = if shift_i == i128::MIN {
                        1u128 << 127
                      } else if shift_i < 0 {
                        (-shift_i) as u128
                      } else {
                        shift_i as u128
                      };
                      let shift = u64::try_from(shift_mag).unwrap_or(u64::MAX);
                      (shift_i < 0, shift)
                    }
                    None => (b.is_negative(), u64::MAX),
                  };

                  match expr.operator {
                    OperatorName::AssignmentBitwiseLeftShift => {
                      if shift_negative {
                        a.shr(shift)?
                      } else {
                        a.shl(shift)?
                      }
                    }
                    OperatorName::AssignmentBitwiseRightShift => {
                      if shift_negative {
                        a.shl(shift)?
                      } else {
                        a.shr(shift)?
                      }
                    }
                    OperatorName::AssignmentBitwiseUnsignedRightShift => {
                      return Err(VmError::InvariantViolation(
                        "unexpected unsigned right shift in BigInt compound assignment",
                      ));
                    }
                    _ => {
                      return Err(VmError::InvariantViolation(
                        "unexpected operator in BigInt shift compound assignment",
                      ));
                    }
                  }
                };
                let out = op_scope.alloc_bigint(out)?;
                Ok(Value::BigInt(out))
              }
            }
            _ => Err(throw_type_error(
              self.vm,
              &mut op_scope,
              "Cannot mix BigInt and other types",
            )?),
          }?;

          op_scope.push_root(value)?;
          self.put_value_to_reference(&mut op_scope, &reference, value)?;
          Ok(value)
        }
      },
      OperatorName::AssignmentLogicalAnd
      | OperatorName::AssignmentLogicalOr
      | OperatorName::AssignmentNullishCoalescing => match &*expr.left.stx {
        Expr::ObjPat(_) | Expr::ArrPat(_) => Err(VmError::Unimplemented(
          "logical assignment to destructuring patterns",
        )),
        _ => {
          let reference = self.eval_reference(scope, &expr.left)?;
          let mut op_scope = scope.reborrow();
          self.root_reference(&mut op_scope, &reference)?;

          let left = self.get_value_from_reference(&mut op_scope, &reference)?;

          let should_assign = match expr.operator {
            OperatorName::AssignmentLogicalAnd => to_boolean(op_scope.heap(), left)?,
            OperatorName::AssignmentLogicalOr => !to_boolean(op_scope.heap(), left)?,
            OperatorName::AssignmentNullishCoalescing => is_nullish(left),
            _ => {
              return Err(VmError::InvariantViolation(
                "unexpected operator in logical assignment expression",
              ));
            }
          };
          if !should_assign {
            return Ok(left);
          }

          // Root `left` across evaluation of the RHS in case it allocates and triggers GC.
          op_scope.push_root(left)?;
          let right = self.eval_expr(&mut op_scope, &expr.right)?;

          // Root `right` across anonymous function name inference + `PutValue`.
          op_scope.push_root(right)?;
          self.maybe_set_anonymous_function_name_for_assignment(&mut op_scope, &reference, right)?;
          self.put_value_to_reference(&mut op_scope, &reference, right)?;
          Ok(right)
        }
      },
      OperatorName::LogicalAnd => {
        let left = self.eval_expr(scope, &expr.left)?;
        if !to_boolean(scope.heap(), left)? {
          return Ok(left);
        }
        self.eval_expr(scope, &expr.right)
      }
      OperatorName::LogicalOr => {
        let left = self.eval_expr(scope, &expr.left)?;
        if to_boolean(scope.heap(), left)? {
          return Ok(left);
        }
        self.eval_expr(scope, &expr.right)
      }
      OperatorName::NullishCoalescing => {
        let left = self.eval_expr(scope, &expr.left)?;
        if is_nullish(left) {
          self.eval_expr(scope, &expr.right)
        } else {
          Ok(left)
        }
      }
      OperatorName::StrictEquality => {
        let left = self.eval_expr(scope, &expr.left)?;
        // Root `left` across evaluation of `right` in case the RHS allocates and triggers GC.
        let mut rhs_scope = scope.reborrow();
        rhs_scope.push_root(left)?;
        let right = self.eval_expr(&mut rhs_scope, &expr.right)?;
        let mut tick = || self.tick();
        Ok(Value::Bool(strict_equal_with_tick(
          rhs_scope.heap(),
          left,
          right,
          &mut tick,
        )?))
      }
      OperatorName::StrictInequality => {
        let left = self.eval_expr(scope, &expr.left)?;
        // Root `left` across evaluation of `right` in case the RHS allocates and triggers GC.
        let mut rhs_scope = scope.reborrow();
        rhs_scope.push_root(left)?;
        let right = self.eval_expr(&mut rhs_scope, &expr.right)?;
        let mut tick = || self.tick();
        Ok(Value::Bool(!strict_equal_with_tick(
          rhs_scope.heap(),
          left,
          right,
          &mut tick,
        )?))
      }
      OperatorName::Equality => {
        let left = self.eval_expr(scope, &expr.left)?;
        // Root `left` across evaluation of `right` in case the RHS allocates and triggers GC.
        let mut rhs_scope = scope.reborrow();
        rhs_scope.push_root(left)?;
        let right = self.eval_expr(&mut rhs_scope, &expr.right)?;
        Ok(Value::Bool(self.abstract_equality_comparison(
          &mut rhs_scope,
          left,
          right,
        )?))
      }
      OperatorName::Inequality => {
        let left = self.eval_expr(scope, &expr.left)?;
        // Root `left` across evaluation of `right` in case the RHS allocates and triggers GC.
        let mut rhs_scope = scope.reborrow();
        rhs_scope.push_root(left)?;
        let right = self.eval_expr(&mut rhs_scope, &expr.right)?;
        Ok(Value::Bool(!self.abstract_equality_comparison(
          &mut rhs_scope,
          left,
          right,
        )?))
      }
      OperatorName::In => {
        // `#x in obj` is a private brand check, not a normal property-name `in` operation.
        //
        // The LHS is syntactically a private identifier, not an expression to be evaluated as an
        // identifier reference.
        let private_name = match &*expr.left.stx {
          Expr::Id(id) if id.stx.name.starts_with('#') => Some(id.stx.name.as_str()),
          Expr::IdPat(id) if id.stx.name.starts_with('#') => Some(id.stx.name.as_str()),
          _ => None,
        };

        if let Some(private_name) = private_name {
          let right = self.eval_expr(scope, &expr.right)?;
          let Value::Object(obj) = right else {
            return Err(throw_type_error(
              self.vm,
              scope,
              "Right-hand side of 'in' should be an object",
            )?);
          };

          // Root the RHS object across private-name resolution and own-property lookup, which may
          // allocate/tick.
          let mut rhs_scope = scope.reborrow();
          rhs_scope.push_root(Value::Object(obj))?;

          let sym = rhs_scope
            .heap()
            .resolve_private_name_symbol(self.env.lexical_env, private_name)?
            .ok_or(VmError::InvariantViolation("unresolved private name"))?;

          rhs_scope.push_root(Value::Symbol(sym))?;
          let key = PropertyKey::from_symbol(sym);
          // Private brand checks:
          // - do not consult the prototype chain, and
          // - do not dispatch to Proxy traps (they are not observable).
          //
          // A Proxy can still pass the check if it is itself "branded" (e.g. returned from a class
          // constructor and then initialized with private elements).
          let has = if rhs_scope.heap().is_proxy_object(obj) {
            rhs_scope
              .heap()
              .proxy_internal_get_own_property(obj, &key)?
              .is_some()
          } else {
            rhs_scope.heap().get_own_property(obj, key)?.is_some()
          };
          return Ok(Value::Bool(has));
        }

        let left = self.eval_expr(scope, &expr.left)?;
        // Root `left` across evaluation of `right` in case the RHS allocates and triggers GC.
        let mut rhs_scope = scope.reborrow();
        rhs_scope.push_root(left)?;
        let right = self.eval_expr(&mut rhs_scope, &expr.right)?;
        let Value::Object(obj) = right else {
          return Err(throw_type_error(
            self.vm,
            &mut rhs_scope,
            "Right-hand side of 'in' should be an object",
          )?);
        };

        // Root the RHS object across `ToPropertyKey`, which may allocate and trigger GC.
        rhs_scope.push_root(Value::Object(obj))?;
        let key = self.to_property_key_operator(&mut rhs_scope, left)?;
        Ok(Value::Bool(
          crate::spec_ops::internal_has_property_with_host_and_hooks(
            self.vm,
            &mut rhs_scope,
            &mut *self.host,
            &mut *self.hooks,
            obj,
            key,
          )?,
        ))
      }
      OperatorName::Instanceof => {
        let left = self.eval_expr(scope, &expr.left)?;
        // Root `left` across evaluation of `right` in case the RHS allocates and triggers GC.
        let mut rhs_scope = scope.reborrow();
        rhs_scope.push_root(left)?;
        let right = self.eval_expr(&mut rhs_scope, &expr.right)?;
        rhs_scope.push_root(right)?;
        Ok(Value::Bool(self.instanceof_operator(
          &mut rhs_scope,
          left,
          right,
        )?))
      }
      OperatorName::Addition => {
        let left = self.eval_expr(scope, &expr.left)?;
        // Root `left` across evaluation of `right` in case the RHS allocates and triggers GC.
        let mut rhs_scope = scope.reborrow();
        rhs_scope.push_root(left)?;
        let right = self.eval_expr(&mut rhs_scope, &expr.right)?;
        self.addition_operator(&mut rhs_scope, left, right)
      }
      OperatorName::Exponentiation => {
        let left = self.eval_expr(scope, &expr.left)?;
        // Root `left` across evaluation of `right` in case the RHS allocates and triggers GC.
        let mut rhs_scope = scope.reborrow();
        rhs_scope.push_root(left)?;
        let right = self.eval_expr(&mut rhs_scope, &expr.right)?;
        self.exponentiation_operator(&mut rhs_scope, left, right)
      }
      OperatorName::Multiplication => {
        let left = self.eval_expr(scope, &expr.left)?;
        // Root `left` across evaluation of `right` in case the RHS allocates and triggers GC.
        let mut rhs_scope = scope.reborrow();
        rhs_scope.push_root(left)?;
        let right = self.eval_expr(&mut rhs_scope, &expr.right)?;
        rhs_scope.push_root(right)?;

        let left_num = self.to_numeric(&mut rhs_scope, left)?;
        let right_num = self.to_numeric(&mut rhs_scope, right)?;
        match (left_num, right_num) {
          (NumericValue::Number(a), NumericValue::Number(b)) => Ok(Value::Number(a * b)),
          (NumericValue::BigInt(a), NumericValue::BigInt(b)) => {
            let out = {
              let a = rhs_scope.heap().get_bigint(a)?;
              let b = rhs_scope.heap().get_bigint(b)?;
              a.mul_with_tick(b, &mut || self.tick())?
            };
            let out = rhs_scope.alloc_bigint(out)?;
            Ok(Value::BigInt(out))
          }
          _ => Err(throw_type_error(
            self.vm,
            &mut rhs_scope,
            "Cannot mix BigInt and other types",
          )?),
        }
      }
      OperatorName::BitwiseAnd | OperatorName::BitwiseOr | OperatorName::BitwiseXor => {
        let left = self.eval_expr(scope, &expr.left)?;
        // Root `left` across evaluation of `right` in case the RHS allocates and triggers GC.
        let mut rhs_scope = scope.reborrow();
        rhs_scope.push_root(left)?;
        let right = self.eval_expr(&mut rhs_scope, &expr.right)?;
        rhs_scope.push_root(right)?;

        let left_num = self.to_numeric(&mut rhs_scope, left)?;
        let right_num = self.to_numeric(&mut rhs_scope, right)?;
        match (left_num, right_num) {
          (NumericValue::Number(a), NumericValue::Number(b)) => {
            let a = to_int32(a);
            let b = to_int32(b);
            let out = match expr.operator {
              OperatorName::BitwiseAnd => a & b,
              OperatorName::BitwiseOr => a | b,
              OperatorName::BitwiseXor => a ^ b,
              _ => {
                return Err(VmError::InvariantViolation(
                  "unexpected operator in bitwise int32 binary op",
                ));
              }
            };
            Ok(Value::Number(out as f64))
          }
          (NumericValue::BigInt(a), NumericValue::BigInt(b)) => {
            let out = {
              let a = rhs_scope.heap().get_bigint(a)?;
              let b = rhs_scope.heap().get_bigint(b)?;
              match expr.operator {
                OperatorName::BitwiseAnd => a.bitwise_and(b)?,
                OperatorName::BitwiseOr => a.bitwise_or(b)?,
                OperatorName::BitwiseXor => a.bitwise_xor(b)?,
                _ => unreachable!(),
              }
            };
            let out = rhs_scope.alloc_bigint(out)?;
            Ok(Value::BigInt(out))
          }
          _ => Err(throw_type_error(
            self.vm,
            &mut rhs_scope,
            "Cannot mix BigInt and other types",
          )?),
        }
      }
      OperatorName::BitwiseLeftShift
      | OperatorName::BitwiseRightShift
      | OperatorName::BitwiseUnsignedRightShift => {
        let left = self.eval_expr(scope, &expr.left)?;
        // Root `left` across evaluation of `right` in case the RHS allocates and triggers GC.
        let mut rhs_scope = scope.reborrow();
        rhs_scope.push_root(left)?;
        let right = self.eval_expr(&mut rhs_scope, &expr.right)?;
        rhs_scope.push_root(right)?;

        let left_num = self.to_numeric(&mut rhs_scope, left)?;
        let right_num = self.to_numeric(&mut rhs_scope, right)?;
        match (left_num, right_num) {
          (NumericValue::Number(a), NumericValue::Number(b)) => {
            let shift = (to_uint32(b) & 0x1f) as u32;
            match expr.operator {
              OperatorName::BitwiseLeftShift => {
                let a = to_int32(a);
                Ok(Value::Number(a.wrapping_shl(shift) as f64))
              }
              OperatorName::BitwiseRightShift => {
                let a = to_int32(a);
                Ok(Value::Number(a.wrapping_shr(shift) as f64))
              }
              OperatorName::BitwiseUnsignedRightShift => {
                let a = to_uint32(a);
                Ok(Value::Number((a >> shift) as f64))
              }
              _ => {
                return Err(VmError::InvariantViolation(
                  "unexpected operator in bitwise shift binary op",
                ));
              }
            }
          }
          (NumericValue::BigInt(a), NumericValue::BigInt(b)) => {
            if matches!(expr.operator, OperatorName::BitwiseUnsignedRightShift) {
              return Err(throw_type_error(
                self.vm,
                &mut rhs_scope,
                "BigInt does not support unsigned right shift",
              )?);
            }

            let out = {
              let a = rhs_scope.heap().get_bigint(a)?;
              let b = rhs_scope.heap().get_bigint(b)?;

              let (shift_negative, shift): (bool, u64) = match b.try_to_i128() {
                Some(shift_i) => {
                  let shift_mag: u128 = if shift_i == i128::MIN {
                    1u128 << 127
                  } else if shift_i < 0 {
                    (-shift_i) as u128
                  } else {
                    shift_i as u128
                  };
                  let shift = u64::try_from(shift_mag).unwrap_or(u64::MAX);
                  (shift_i < 0, shift)
                }
                None => (b.is_negative(), u64::MAX),
              };

              match expr.operator {
                OperatorName::BitwiseLeftShift => {
                  if shift_negative {
                    a.shr(shift)?
                  } else {
                    a.shl(shift)?
                  }
                }
                OperatorName::BitwiseRightShift => {
                  if shift_negative {
                    a.shl(shift)?
                  } else {
                    a.shr(shift)?
                  }
                }
                OperatorName::BitwiseUnsignedRightShift => unreachable!(),
                _ => unreachable!(),
              }
            };
            let out = rhs_scope.alloc_bigint(out)?;
            Ok(Value::BigInt(out))
          }
          _ => Err(throw_type_error(
            self.vm,
            &mut rhs_scope,
            "Cannot mix BigInt and other types",
          )?),
        }
      }
      OperatorName::Subtraction | OperatorName::Division | OperatorName::Remainder => {
        let left = self.eval_expr(scope, &expr.left)?;
        // Root `left` across evaluation of `right` in case the RHS allocates and triggers GC.
        let mut rhs_scope = scope.reborrow();
        rhs_scope.push_root(left)?;
        let right = self.eval_expr(&mut rhs_scope, &expr.right)?;
        rhs_scope.push_root(right)?;

        let left_num = self.to_numeric(&mut rhs_scope, left)?;
        let right_num = self.to_numeric(&mut rhs_scope, right)?;

        match (left_num, right_num) {
          (NumericValue::Number(a), NumericValue::Number(b)) => Ok(match expr.operator {
            OperatorName::Subtraction => Value::Number(a - b),
            OperatorName::Division => Value::Number(a / b),
            OperatorName::Remainder => Value::Number(a % b),
            _ => unreachable!(),
          }),
          (NumericValue::BigInt(a), NumericValue::BigInt(b)) => {
            let out = {
              let a = rhs_scope.heap().get_bigint(a)?;
              let b = rhs_scope.heap().get_bigint(b)?;
              if b.is_zero()
                && matches!(
                  expr.operator,
                  OperatorName::Division | OperatorName::Remainder
                )
              {
                return Err(throw_range_error(
                  self.vm,
                  &mut rhs_scope,
                  "Division by zero",
                )?);
              }

              match expr.operator {
                OperatorName::Subtraction => a.sub(b)?,
                OperatorName::Division => {
                  let (q, _) = a.div_mod_with_tick(b, &mut || self.tick())?;
                  q
                }
                OperatorName::Remainder => {
                  let (_, r) = a.div_mod_with_tick(b, &mut || self.tick())?;
                  r
                }
                _ => unreachable!(),
              }
            };
            let out = rhs_scope.alloc_bigint(out)?;
            Ok(Value::BigInt(out))
          }
          _ => Err(throw_type_error(
            self.vm,
            &mut rhs_scope,
            "Cannot mix BigInt and other types",
          )?),
        }
      }
      OperatorName::LessThan
      | OperatorName::LessThanOrEqual
      | OperatorName::GreaterThan
      | OperatorName::GreaterThanOrEqual => {
        let left = self.eval_expr(scope, &expr.left)?;
        // Root `left` across evaluation of `right` in case the RHS allocates and triggers GC.
        let mut rhs_scope = scope.reborrow();
        rhs_scope.push_root(left)?;
        let right = self.eval_expr(&mut rhs_scope, &expr.right)?;
        let result =
          self.relational_comparison_operator(&mut rhs_scope, expr.operator, left, right)?;
        Ok(Value::Bool(result))
      }
      OperatorName::Comma => {
        let _ = self.eval_expr(scope, &expr.left)?;
        self.eval_expr(scope, &expr.right)
      }
      _ => Err(VmError::Unimplemented("binary operator")),
    }
  }

  fn instanceof_operator(
    &mut self,
    scope: &mut Scope<'_>,
    object: Value,
    mut constructor: Value,
  ) -> Result<bool, VmError> {
    // Root inputs for the duration of the operation: `instanceof` can allocate when performing
    // `GetMethod`/`Get`/`Call`.
    let mut scope = scope.reborrow();
    scope.push_roots(&[object, constructor])?;

    // InstanceofOperator(O, C) (ECMA-262).
    //
    // Spec: https://tc39.es/ecma262/#sec-instanceofoperator
    let has_instance_sym = self
      .vm
      .intrinsics()
      .ok_or(VmError::Unimplemented("intrinsics not initialized"))?
      .well_known_symbols()
      .has_instance;
    let has_instance_key = PropertyKey::from_symbol(has_instance_sym);

    // Bound functions (`C.[[BoundTargetFunction]]`) delegate to `InstanceofOperator(O, BC)` as part
    // of `OrdinaryHasInstance`. Implement that delegation here (iteratively) so `instanceof` never
    // recurses through a deep `.bind()` chain and so the bound target's `@@hasInstance` is consulted
    // per spec.
    let mut bound_steps = 0usize;

    loop {
      // Root inputs for the duration of this iteration: `instanceof` can allocate when performing
      // `GetMethod`/`Get`/`Call`.
      let mut iter_scope = scope.reborrow();
      // Root the *current* constructor value (which can change when delegating bound functions).
      iter_scope.push_root(constructor)?;

      // 1. If Type(C) is not Object, throw a TypeError exception.
      let Value::Object(constructor_obj) = constructor else {
        return Err(throw_type_error(
          self.vm,
          &mut iter_scope,
          "Right-hand side of 'instanceof' is not an object",
        )?);
      };

      // 2. GetMethod(C, @@hasInstance).
      let method = match crate::spec_ops::get_method_with_host_and_hooks(
        self.vm,
        &mut iter_scope,
        &mut *self.host,
        &mut *self.hooks,
        Value::Object(constructor_obj),
        has_instance_key,
      ) {
        Ok(m) => m,
        Err(VmError::TypeError(msg)) => {
          return Err(throw_type_error(self.vm, &mut iter_scope, msg)?)
        }
        Err(err) => return Err(err),
      };

      if let Some(method) = method {
        // Root `method` across the call. When `C` is a Proxy, `GetMethod(C, @@hasInstance)` can
        // return a function that is not reachable from any rooted object (it can be synthesized by
        // the Proxy's `get` trap), and we must keep it alive until the call begins.
        iter_scope.push_root(method)?;
        let result = self.call(
          &mut iter_scope,
          method,
          Value::Object(constructor_obj),
          &[object],
        )?;
        return Ok(to_boolean(iter_scope.heap(), result)?);
      }

      // 3. If IsCallable(C) is false, throw a TypeError exception.
      if !iter_scope.heap().is_callable(constructor)? {
        return Err(throw_type_error(
          self.vm,
          &mut iter_scope,
          "Right-hand side of 'instanceof' is not callable",
        )?);
      }

      // `OrdinaryHasInstance` step 2 (bound function delegation):
      //
      // If `C` has `[[BoundTargetFunction]]`, delegate to `InstanceofOperator(O, BC)` which will
      // consult `BC[@@hasInstance]` (including Proxy `get` traps).
      if let Ok(func) = iter_scope.heap().get_function(constructor_obj) {
        if let Some(bound_target) = func.bound_target {
          // Budget extremely deep bound chains and prevent hangs if an invariant is violated.
          const TICK_EVERY: usize = 32;
          if bound_steps != 0 && bound_steps % TICK_EVERY == 0 {
            self.tick()?;
          }
          if bound_steps >= crate::MAX_PROTOTYPE_CHAIN {
            return Err(VmError::PrototypeChainTooDeep);
          }
          bound_steps += 1;
          constructor = Value::Object(bound_target);
          continue;
        }
      }

      return self.ordinary_has_instance(&mut iter_scope, constructor_obj, object);
    }
  }

  fn ordinary_has_instance(
    &mut self,
    scope: &mut Scope<'_>,
    constructor: GcObject,
    object: Value,
  ) -> Result<bool, VmError> {
    // If the LHS is not an object, `instanceof` is `false` without further observable actions.
    let Value::Object(object) = object else {
      return Ok(false);
    };

    // P = Get(C, "prototype").
    let prototype_s = scope.alloc_string("prototype")?;
    scope.push_root(Value::String(prototype_s))?;
    let prototype = match scope.get_with_host_and_hooks(
      self.vm,
      &mut *self.host,
      &mut *self.hooks,
      constructor,
      PropertyKey::from_string(prototype_s),
      Value::Object(constructor),
    ) {
      Ok(v) => v,
      Err(VmError::TypeError(msg)) => return Err(throw_type_error(self.vm, scope, msg)?),
      Err(err) => return Err(err),
    };

    let Value::Object(prototype) = prototype else {
      return Err(throw_type_error(
        self.vm,
        scope,
        "Function has non-object prototype in instanceof check",
      )?);
    };

    // Root `prototype` for the duration of the algorithm. For Proxy constructors, `Get(C,
    // "prototype")` can return an object that is not reachable from the constructor/target, and we
    // must keep it alive across the prototype-chain walk.
    scope.push_root(Value::Object(prototype))?;

    // Walk `object`'s prototype chain until we find `prototype` or reach the end.
    let mut current = scope.get_prototype_of_with_host_and_hooks(
      self.vm,
      &mut *self.host,
      &mut *self.hooks,
      object,
    )?;
    let mut steps = 0usize;
    let mut visited: HashSet<GcObject> = HashSet::new();
    while let Some(obj) = current {
      // Budget the prototype traversal: hostile inputs can synthesize extremely deep chains (up to
      // the engine hard limit) inside a single `instanceof` expression. Observe fuel/deadline /
      // interrupt budgets periodically while walking.
      //
      // Note: avoid ticking on the first iteration so shallow `instanceof` checks don't
      // effectively double-charge fuel (the surrounding expression evaluation already ticks).
      const TICK_EVERY: usize = 32;
      if steps != 0 && steps % TICK_EVERY == 0 {
        self.tick()?;
      }

      if steps >= crate::MAX_PROTOTYPE_CHAIN {
        return Err(VmError::PrototypeChainTooDeep);
      }
      steps += 1;

      if visited.try_reserve(1).is_err() {
        return Err(VmError::OutOfMemory);
      }
      if !visited.insert(obj) {
        return Err(VmError::PrototypeCycle);
      }

      // Root this prototype step. A Proxy `getPrototypeOf` trap can return an arbitrary object that
      // is not necessarily reachable from the original LHS, and the VM must keep it alive until
      // the algorithm completes.
      scope.push_root(Value::Object(obj))?;

      if obj == prototype {
        return Ok(true);
      }
      current = scope.get_prototype_of_with_host_and_hooks(
        self.vm,
        &mut *self.host,
        &mut *self.hooks,
        obj,
      )?;
    }

    Ok(false)
  }

  fn to_primitive(
    &mut self,
    scope: &mut Scope<'_>,
    value: Value,
    hint: ToPrimitiveHint,
  ) -> Result<Value, VmError> {
    let mut scope = scope.reborrow();
    scope.push_root(value)?;
    match scope.to_primitive(self.vm, &mut *self.host, &mut *self.hooks, value, hint) {
      Ok(v) => Ok(v),
      Err(VmError::TypeError(msg)) => Err(throw_type_error(self.vm, &mut scope, msg)?),
      Err(err) => Err(err),
    }
  }

  fn to_number_operator(&mut self, scope: &mut Scope<'_>, value: Value) -> Result<f64, VmError> {
    let mut num_scope = scope.reborrow();
    num_scope.push_root(value)?;
    match num_scope.to_number(self.vm, &mut *self.host, &mut *self.hooks, value) {
      Ok(n) => Ok(n),
      Err(VmError::TypeError(msg)) => Err(throw_type_error(self.vm, &mut num_scope, msg)?),
      Err(err) => Err(err),
    }
  }

  fn to_string_operator(
    &mut self,
    scope: &mut Scope<'_>,
    value: Value,
  ) -> Result<GcString, VmError> {
    let mut string_scope = scope.reborrow();
    string_scope.push_root(value)?;
    match string_scope.to_string(self.vm, &mut *self.host, &mut *self.hooks, value) {
      Ok(s) => Ok(s),
      Err(VmError::TypeError(msg)) => Err(throw_type_error(self.vm, &mut string_scope, msg)?),
      Err(err) => Err(err),
    }
  }

  fn to_object_operator(
    &mut self,
    scope: &mut Scope<'_>,
    value: Value,
  ) -> Result<GcObject, VmError> {
    let mut scope = scope.reborrow();
    scope.push_root(value)?;
    match scope.to_object(self.vm, &mut *self.host, &mut *self.hooks, value) {
      Ok(obj) => Ok(obj),
      Err(VmError::TypeError(msg)) => Err(throw_type_error(self.vm, &mut scope, msg)?),
      Err(err) => Err(err),
    }
  }

  fn to_property_key_operator(
    &mut self,
    scope: &mut Scope<'_>,
    value: Value,
  ) -> Result<PropertyKey, VmError> {
    let mut key_scope = scope.reborrow();
    key_scope.push_root(value)?;
    match key_scope.to_property_key(self.vm, &mut *self.host, &mut *self.hooks, value) {
      Ok(key) => Ok(key),
      Err(VmError::TypeError(msg)) => Err(throw_type_error(self.vm, &mut key_scope, msg)?),
      Err(err) => Err(err),
    }
  }

  /// ECMA-262 Abstract Equality Comparison (`==`).
  fn abstract_equality_comparison(
    &mut self,
    scope: &mut Scope<'_>,
    a: Value,
    b: Value,
  ) -> Result<bool, VmError> {
    use Value::*;

    // Root inputs for the duration of the comparison: `ToPrimitive` can invoke user code and
    // allocate.
    let mut scope = scope.reborrow();
    scope.push_roots(&[a, b])?;

    let mut x = a;
    let mut y = b;
    loop {
      match (x, y) {
        // 1. Same type => strict equality.
        (Undefined, Undefined) => return Ok(true),
        (Null, Null) => return Ok(true),
        (Bool(ax), Bool(by)) => return Ok(ax == by),
        (Number(ax), Number(by)) => return Ok(ax == by),
        (BigInt(ax), BigInt(by)) => {
          let ax = scope.heap().get_bigint(ax)?;
          let by = scope.heap().get_bigint(by)?;
          return Ok(ax == by);
        }
        (String(ax), String(by)) => {
          let a = scope.heap().get_string(ax)?.as_code_units();
          let b = scope.heap().get_string(by)?.as_code_units();
          return Ok(crate::tick::code_units_eq_with_ticks(a, b, || self.tick())?);
        }
        (Symbol(ax), Symbol(by)) => return Ok(ax == by),
        (Object(ax), Object(by)) => return Ok(ax == by),

        // 2. `null == undefined`.
        (Undefined, Null) | (Null, Undefined) => return Ok(true),

        // 3/4. Number/String.
        (Number(_), String(_)) => {
          let n = scope.heap_mut().to_number_with_tick(y, || self.tick())?;
          y = Number(n);
        }
        (String(_), Number(_)) => {
          let n = scope.heap_mut().to_number_with_tick(x, || self.tick())?;
          x = Number(n);
        }

        // 5/6. BigInt/String.
        (BigInt(ax), String(bs)) => {
          let mut tick = || self.tick();
          let Some(bi) = string_to_bigint(scope.heap(), bs, &mut tick)? else {
            return Ok(false);
          };
          return Ok(scope.heap().get_bigint(ax)? == &bi);
        }
        (String(as_), BigInt(by)) => {
          let mut tick = || self.tick();
          let Some(bi) = string_to_bigint(scope.heap(), as_, &mut tick)? else {
            return Ok(false);
          };
          return Ok(scope.heap().get_bigint(by)? == &bi);
        }

        // 7/8. Boolean => ToNumber.
        (Bool(ax), _) => {
          x = Number(if ax { 1.0 } else { 0.0 });
        }
        (_, Bool(by)) => {
          y = Number(if by { 1.0 } else { 0.0 });
        }

        // 9/10. Object => ToPrimitive (default hint).
        (Object(_), String(_) | Number(_) | BigInt(_) | Symbol(_)) => {
          x = self.to_primitive(&mut scope, x, ToPrimitiveHint::Default)?;
          scope.push_root(x)?;
        }
        (String(_) | Number(_) | BigInt(_) | Symbol(_), Object(_)) => {
          y = self.to_primitive(&mut scope, y, ToPrimitiveHint::Default)?;
          scope.push_root(y)?;
        }

        // 11/12. BigInt/Number.
        (BigInt(ax), Number(by)) => {
          return Ok(matches!(
            bigint_compare_number(scope.heap(), ax, by)?,
            Some(Ordering::Equal)
          ))
        }
        (Number(ax), BigInt(by)) => {
          return Ok(matches!(
            bigint_compare_number(scope.heap(), by, ax)?,
            Some(Ordering::Equal)
          ))
        }

        // Everything else is false.
        _ => return Ok(false),
      }
    }
  }

  /// ECMA-262 Abstract Relational Comparison.
  ///
  /// Returns `Ok(None)` for the spec's `undefined` result (e.g. when comparing NaN).
  fn abstract_relational_comparison(
    &mut self,
    scope: &mut Scope<'_>,
    x: Value,
    y: Value,
    left_first: bool,
  ) -> Result<Option<bool>, VmError> {
    // Root inputs for the duration of the comparison: `ToPrimitive`/`ToNumeric` can allocate.
    let mut scope = scope.reborrow();
    scope.push_roots(&[x, y])?;

    // 1. ToPrimitive, hint Number (order depends on `left_first`).
    let (px, py) = if left_first {
      let px = self.to_primitive(&mut scope, x, ToPrimitiveHint::Number)?;
      scope.push_root(px)?;
      let py = self.to_primitive(&mut scope, y, ToPrimitiveHint::Number)?;
      scope.push_root(py)?;
      (px, py)
    } else {
      let py = self.to_primitive(&mut scope, y, ToPrimitiveHint::Number)?;
      scope.push_root(py)?;
      let px = self.to_primitive(&mut scope, x, ToPrimitiveHint::Number)?;
      scope.push_root(px)?;
      (px, py)
    };

    // 2. String/string => lexicographic code-unit comparison.
    if let (Value::String(sx), Value::String(sy)) = (px, py) {
      let a = scope.heap().get_string(sx)?.as_code_units();
      let b = scope.heap().get_string(sy)?.as_code_units();
      let ord = crate::tick::code_units_cmp_with_ticks(a, b, || self.tick())?;
      return Ok(Some(ord == Ordering::Less));
    }

    // 2.b. BigInt/string => parse the string as a BigInt (StringToBigInt).
    //
    // This matches test262 semantics like:
    // - `'9007199254740993' > 9007199254740992n` (string must not round via Number)
    // - `'0.' < 1n` (invalid BigInt parse => undefined => false)
    match (px, py) {
      (Value::BigInt(a), Value::String(bs)) => {
        let mut tick = || self.tick();
        let Some(bi) = string_to_bigint(scope.heap(), bs, &mut tick)? else {
          return Ok(None);
        };
        return Ok(Some(scope.heap().get_bigint(a)? < &bi));
      }
      (Value::String(as_), Value::BigInt(b)) => {
        let mut tick = || self.tick();
        let Some(ai) = string_to_bigint(scope.heap(), as_, &mut tick)? else {
          return Ok(None);
        };
        return Ok(Some(&ai < scope.heap().get_bigint(b)?));
      }
      _ => {}
    }

    // 3. Otherwise => ToNumeric then numeric comparison.
    let nx = self.to_numeric(&mut scope, px)?;
    let ny = self.to_numeric(&mut scope, py)?;
    Ok(match (nx, ny) {
      (NumericValue::Number(a), NumericValue::Number(b)) => {
        if a.is_nan() || b.is_nan() {
          None
        } else {
          Some(a < b)
        }
      }
      (NumericValue::BigInt(a), NumericValue::BigInt(b)) => {
        let a = scope.heap().get_bigint(a)?;
        let b = scope.heap().get_bigint(b)?;
        Some(a < b)
      }
      (NumericValue::BigInt(a), NumericValue::Number(b)) => {
        bigint_compare_number(scope.heap(), a, b)?.map(|ord| ord == Ordering::Less)
      }
      (NumericValue::Number(a), NumericValue::BigInt(b)) => {
        bigint_compare_number(scope.heap(), b, a)?.map(|ord| ord == Ordering::Greater)
      }
    })
  }

  fn relational_comparison_operator(
    &mut self,
    scope: &mut Scope<'_>,
    operator: OperatorName,
    left: Value,
    right: Value,
  ) -> Result<bool, VmError> {
    use OperatorName::*;

    Ok(match operator {
      LessThan => self
        .abstract_relational_comparison(scope, left, right, /* left_first */ true)?
        .unwrap_or(false),
      GreaterThan => self
        .abstract_relational_comparison(scope, right, left, /* left_first */ false)?
        .unwrap_or(false),
      LessThanOrEqual => match self.abstract_relational_comparison(scope, right, left, false)? {
        None => false,
        Some(r) => !r,
      },
      GreaterThanOrEqual => match self.abstract_relational_comparison(scope, left, right, true)? {
        None => false,
        Some(r) => !r,
      },
      _ => {
        return Err(VmError::InvariantViolation(
          "internal error: unexpected operator in relational comparison",
        ));
      }
    })
  }

  fn addition_operator(
    &mut self,
    scope: &mut Scope<'_>,
    left: Value,
    right: Value,
  ) -> Result<Value, VmError> {
    // Root inputs and intermediates for the duration of the operation: `+` may allocate
    // (string concatenation, ToString) and thus trigger GC.
    let mut add_scope = scope.reborrow();
    add_scope.push_roots(&[left, right])?;

    // ECMA-262 AdditionOperator (+): ToPrimitive (default), then string concat if either side is a
    // string; otherwise numeric addition.
    let left_prim = self.to_primitive(&mut add_scope, left, ToPrimitiveHint::Default)?;
    add_scope.push_root(left_prim)?;
    let right_prim = self.to_primitive(&mut add_scope, right, ToPrimitiveHint::Default)?;
    add_scope.push_root(right_prim)?;

    if matches!(left_prim, Value::String(_)) || matches!(right_prim, Value::String(_)) {
      let left_s = self.to_string_operator(&mut add_scope, left_prim)?;
      add_scope.push_root(Value::String(left_s))?;
      let right_s = self.to_string_operator(&mut add_scope, right_prim)?;
      add_scope.push_root(Value::String(right_s))?;

      let left_units = add_scope.heap().get_string(left_s)?.as_code_units();
      let right_units = add_scope.heap().get_string(right_s)?.as_code_units();

      let total_len = left_units
        .len()
        .checked_add(right_units.len())
        .ok_or(VmError::OutOfMemory)?;
      let mut units: Vec<u16> = Vec::new();
      units
        .try_reserve_exact(total_len)
        .map_err(|_| VmError::OutOfMemory)?;
      vec_try_extend_from_slice_with_ticks(&mut units, left_units, || self.tick())?;
      vec_try_extend_from_slice_with_ticks(&mut units, right_units, || self.tick())?;

      let s = add_scope.alloc_string_from_u16_vec(units)?;
      Ok(Value::String(s))
    } else {
      let left_num = self.to_numeric(&mut add_scope, left_prim)?;
      let right_num = self.to_numeric(&mut add_scope, right_prim)?;
      Ok(match (left_num, right_num) {
        (NumericValue::Number(a), NumericValue::Number(b)) => Value::Number(a + b),
        (NumericValue::BigInt(a), NumericValue::BigInt(b)) => {
          let out = {
            let a = add_scope.heap().get_bigint(a)?;
            let b = add_scope.heap().get_bigint(b)?;
            a.add(b)?
          };
          let out = add_scope.alloc_bigint(out)?;
          Value::BigInt(out)
        }
        _ => {
          return Err(throw_type_error(
            self.vm,
            &mut add_scope,
            "Cannot mix BigInt and other types",
          )?)
        }
      })
    }
  }

  fn exponentiation_operator(
    &mut self,
    scope: &mut Scope<'_>,
    left: Value,
    right: Value,
  ) -> Result<Value, VmError> {
    // Root both operands for the duration of the operation: `ToNumeric` can allocate (via
    // `ToPrimitive`) and trigger GC.
    let mut op_scope = scope.reborrow();
    op_scope.push_roots(&[left, right])?;

    let left_num = self.to_numeric(&mut op_scope, left)?;
    let right_num = self.to_numeric(&mut op_scope, right)?;
    match (left_num, right_num) {
      (NumericValue::Number(a), NumericValue::Number(b)) => {
        Ok(Value::Number(crate::ops::number_exponentiate(a, b)))
      }
      (NumericValue::BigInt(a), NumericValue::BigInt(b)) => {
        let out = {
          let base = op_scope.heap().get_bigint(a)?;
          let exp = op_scope.heap().get_bigint(b)?;
          if exp.is_negative() {
            return Err(throw_range_error(
              self.vm,
              &mut op_scope,
              "BigInt exponent must be >= 0",
            )?);
          }
          let mut tick = || self.tick();
          base.pow_with_tick(exp, &mut tick)?
        };
        let out = op_scope.alloc_bigint(out)?;
        Ok(Value::BigInt(out))
      }
      _ => Err(throw_type_error(
        self.vm,
        &mut op_scope,
        "Cannot mix BigInt and other types",
      )?),
    }
  }

  fn to_numeric(&mut self, scope: &mut Scope<'_>, value: Value) -> Result<NumericValue, VmError> {
    // ECMA-262 `ToNumeric`: ToPrimitive (hint Number), then return BigInt directly or convert to
    // Number.
    let prim = self.to_primitive(scope, value, ToPrimitiveHint::Number)?;
    // If `prim` is a heap-managed primitive (BigInt), root it for the remainder of this scope so
    // subsequent allocations (BigInt arithmetic, string conversions, etc) cannot collect it.
    if let Value::BigInt(b) = prim {
      scope.push_root(Value::BigInt(b))?;
    }
    match prim {
      Value::BigInt(b) => Ok(NumericValue::BigInt(b)),
      other => match scope.heap_mut().to_number_with_tick(other, || self.tick()) {
        Ok(n) => Ok(NumericValue::Number(n)),
        Err(VmError::TypeError(msg)) => Err(throw_type_error(self.vm, scope, msg)?),
        Err(err) => Err(err),
      },
    }
  }
}

pub(crate) fn string_to_bigint(
  heap: &Heap,
  s: GcString,
  tick: &mut impl FnMut() -> Result<(), VmError>,
) -> Result<Option<JsBigInt>, VmError> {
  let units = heap.get_string(s)?.as_code_units();
  JsBigInt::parse_utf16_string_with_tick(units, tick)
}

fn bigint_compare_number(heap: &Heap, bi: GcBigInt, n: f64) -> Result<Option<Ordering>, VmError> {
  if n.is_nan() {
    return Ok(None);
  }
  if n == f64::INFINITY {
    return Ok(Some(Ordering::Less));
  }
  if n == f64::NEG_INFINITY {
    return Ok(Some(Ordering::Greater));
  }

  let bi = heap.get_bigint(bi)?;

  // Treat +0 and -0 as equal.
  if n == 0.0 {
    if bi.is_zero() {
      return Ok(Some(Ordering::Equal));
    }
    return Ok(Some(if bi.is_negative() {
      Ordering::Less
    } else {
      Ordering::Greater
    }));
  }

  // Integral number: compare directly.
  if n.fract() == 0.0 {
    let Some(n_big) = JsBigInt::from_f64_exact(n)? else {
      // `n` is finite and integral, so this should be unreachable.
      return Ok(None);
    };
    return Ok(Some(bi.cmp(&n_big)));
  }

  // Non-integral number: since `bi` is integral, compare against floor/ceil.
  if n > 0.0 {
    let floor = n.floor();
    let Some(floor_big) = JsBigInt::from_f64_exact(floor)? else {
      return Ok(None);
    };
    let ord = bi.cmp(&floor_big);
    return Ok(Some(if ord == Ordering::Greater {
      Ordering::Greater
    } else {
      // `bi == floor(n)` is still < n.
      Ordering::Less
    }));
  }

  // n < 0.0
  let ceil = n.ceil();
  let Some(ceil_big) = JsBigInt::from_f64_exact(ceil)? else {
    return Ok(None);
  };
  let ord = bi.cmp(&ceil_big);
  Ok(Some(if ord == Ordering::Less {
    Ordering::Less
  } else {
    // `bi == ceil(n)` is still > n.
    Ordering::Greater
  }))
}

fn alloc_string_from_lit_str(
  scope: &mut Scope<'_>,
  node: &Node<LitStrExpr>,
) -> Result<GcString, VmError> {
  if let Some(units) = literal_string_code_units(&node.assoc) {
    scope.alloc_string_from_code_units(units)
  } else {
    scope.alloc_string_from_utf8(&node.stx.value)
  }
}

/// Persistent continuation frames for async function execution.
///
/// This is an explicit reification of the evaluator call stack needed to resume execution after an
/// `await` suspension point.
#[derive(Debug)]
#[allow(private_interfaces)]
pub(crate) enum AsyncFrame {
  /// Root frame for block-bodied async functions (`async function f(){...}`).
  RootBlockBody,
  /// Root frame for expression-bodied async arrow functions (`async () => expr`).
  RootExprBody { expr: *const Node<Expr> },
  /// Root frame for async module evaluation (`run_module_async` / top-level await).
  RootModuleBody,
  /// Root frame for async classic script evaluation (top-level await / `for await...of` in scripts).
  RootScriptBody,
  /// Root frame for compiled (HIR) async execution.
  HirAsync { state: crate::hir_exec::HirAsyncState },
  /// Converts the internal optional-chaining sentinel value to `undefined`.
  ///
  /// This frame is injected by `async_eval_expr` so the async evaluator can propagate optional-chain
  /// short-circuits through non-optional chain segments, while ensuring the sentinel never becomes
  /// observable from user code when an expression completes.
  ConvertOptionalChainShortCircuit,

  /// Resume statement-list evaluation after a suspended statement completes.
  StmtList {
    stmts: *const Vec<Node<Stmt>>,
    next_index: usize,
    last_value_root: RootId,
    last_value_is_set: bool,
  },
  /// Best-effort stack trace capture for throw completions leaving an async statement evaluation.
  ///
  /// This mirrors `Evaluator::eval_stmt_labelled`'s implicit-throw handling for statements that
  /// contain `await` / `yield` and therefore suspend and resume via the async frame stack.
  FinalizeThrowAtStmt { stmt: *const Node<Stmt> },

  /// Restore the outer lexical environment after finishing a block/catch/finally body.
  RestoreLexEnv { outer: GcEnv },
  /// Restore the evaluator's strict-mode flag after a temporary override.
  ///
  /// This is used for constructs that are always evaluated as strict-mode code regardless of the
  /// surrounding context, but which can suspend and resume (e.g. class definition evaluation when
  /// a computed member key contains `await`).
  RestoreStrict { saved_strict: bool },

  /// Finish an expression statement after its expression is evaluated.
  ExprStmt,
  /// Finish a return statement after its value expression is evaluated.
  Return,
  /// Finish an `export default <expr>` statement after the default expression is evaluated.
  ExportDefaultExpr,
  /// Finish a throw statement after its thrown value expression is evaluated.
  Throw { stmt: *const Node<ThrowStmt> },
  /// Finish a class declaration after evaluating the class definition.
  ClassDecl {
    decl: *const Node<ClassDecl>,
    outer: GcEnv,
  },

  /// Continue a `var`/`let`/`const` declaration after a declarator initializer completes.
  VarDecl {
    decl: *const VarDecl,
    next_declarator_index: usize,
  },
  /// Continue a `var`/`let`/`const` declaration after binding a declarator value suspends.
  VarDeclAfterBinding {
    decl: *const VarDecl,
    next_declarator_index: usize,
  },

  /// Continue an object destructuring pattern after suspending while evaluating a computed key.
  BindObjAfterKey {
    pat: *const ObjPat,
    prop_index: usize,
    value_root: RootId,
    excluded: Vec<RootedPropertyKey>,
    kind: BindingKind,
  },
  /// Continue an object destructuring pattern after suspending while evaluating a default value.
  BindObjAfterDefault {
    pat: *const ObjPat,
    prop_index: usize,
    value_root: RootId,
    excluded: Vec<RootedPropertyKey>,
    kind: BindingKind,
  },
  /// Continue an object destructuring pattern after a nested binding suspends.
  BindObjContinue {
    pat: *const ObjPat,
    next_prop_index: usize,
    value_root: RootId,
    excluded: Vec<RootedPropertyKey>,
    kind: BindingKind,
  },

  /// Continue an array destructuring pattern after suspending while evaluating a default value.
  BindArrAfterDefault {
    pat: *const ArrPat,
    elem_index: usize,
    array_index: u32,
    len: u32,
    value_root: RootId,
    kind: BindingKind,
  },
  /// Continue an array destructuring pattern after a nested binding suspends.
  BindArrContinue {
    pat: *const ArrPat,
    elem_index: usize,
    array_index: u32,
    len: u32,
    value_root: RootId,
    kind: BindingKind,
  },

  /// Continue an `if` statement after evaluating the test expression.
  IfAfterTest {
    consequent: *const Node<Stmt>,
    alternate: Option<*const Node<Stmt>>,
  },

  /// Continue a `with` statement after evaluating its object expression.
  WithAfterObject {
    stmt: *const WithStmt,
    label_set: Vec<String>,
    outer: GcEnv,
  },

  /// Continue a `while` loop after evaluating the test expression.
  WhileAfterTest {
    stmt: *const WhileStmt,
    label_set: Vec<String>,
    v_root: RootId,
  },
  /// Continue a `while` loop after evaluating the body statement.
  WhileAfterBody {
    stmt: *const WhileStmt,
    label_set: Vec<String>,
    v_root: RootId,
  },

  /// Continue a `do..while` loop after evaluating the body statement.
  DoWhileAfterBody {
    stmt: *const DoWhileStmt,
    label_set: Vec<String>,
    v_root: RootId,
  },
  /// Continue a `do..while` loop after evaluating the test expression.
  DoWhileAfterTest {
    stmt: *const DoWhileStmt,
    label_set: Vec<String>,
    v_root: RootId,
  },

  /// Continue a `for (init; cond; post) { ... }` loop after evaluating the initializer.
  ForTripleAfterInit {
    stmt: *const ForTripleStmt,
    label_set: Vec<String>,
    v_root: RootId,
    needs_explicit_iter_tick: bool,
  },
  /// Continue a `for (init; cond; post) { ... }` loop after evaluating the test expression.
  ForTripleAfterTest {
    stmt: *const ForTripleStmt,
    label_set: Vec<String>,
    v_root: RootId,
    needs_explicit_iter_tick: bool,
  },
  /// Continue a `for (init; cond; post) { ... }` loop after evaluating the body.
  ForTripleAfterBody {
    stmt: *const ForTripleStmt,
    label_set: Vec<String>,
    v_root: RootId,
    needs_explicit_iter_tick: bool,
  },
  /// Continue a `for (init; cond; post) { ... }` loop after evaluating the post expression.
  ForTripleAfterPost {
    stmt: *const ForTripleStmt,
    label_set: Vec<String>,
    v_root: RootId,
    needs_explicit_iter_tick: bool,
  },

  /// Continue a `for..in` loop after evaluating the RHS expression.
  ForInAfterRhs {
    stmt: *const ForInStmt,
    label_set: Vec<String>,
  },
  /// Continue a `for..in` loop after binding the current iteration value.
  ForInAfterBind {
    stmt: *const ForInStmt,
    label_set: Vec<String>,
    object_root: RootId,
    key_roots: Vec<RootId>,
    next_key_index: usize,
    v_root: RootId,
    outer_lex: GcEnv,
    iter_env_created: bool,
  },
  /// Continue a `for..in` loop after evaluating the body statement list for one iteration.
  ForInAfterBody {
    stmt: *const ForInStmt,
    label_set: Vec<String>,
    object_root: RootId,
    key_roots: Vec<RootId>,
    next_key_index: usize,
    v_root: RootId,
    outer_lex: GcEnv,
  },

  /// Continue a `for..of` loop after evaluating the RHS iterable expression.
  ForOfAfterRhs {
    stmt: *const ForOfStmt,
    label_set: Vec<String>,
  },
  /// Continue a `for..of` loop after binding the current iteration value.
  ForOfAfterBind {
    stmt: *const ForOfStmt,
    label_set: Vec<String>,
    iterator_record: iterator::IteratorRecord,
    iterator_root: RootId,
    next_method_root: RootId,
    v_root: RootId,
    outer_lex: GcEnv,
    iter_env_created: bool,
  },
  /// Continue a `for..of` loop after evaluating the body statement list for one iteration.
  ForOfAfterBody {
    stmt: *const ForOfStmt,
    label_set: Vec<String>,
    iterator_record: iterator::IteratorRecord,
    iterator_root: RootId,
    next_method_root: RootId,
    v_root: RootId,
    outer_lex: GcEnv,
  },

  /// Continue a `for await..of` loop after evaluating the RHS expression.
  ForAwaitOfAfterRhs {
    stmt: *const ForOfStmt,
    label_set: Vec<String>,
    v_root: RootId,
    outer_lex: GcEnv,
  },
  /// Continue a `for await..of` loop after awaiting `iterator.next()`.
  ForAwaitOfAfterNext {
    stmt: *const ForOfStmt,
    label_set: Vec<String>,
    v_root: RootId,
    outer_lex: GcEnv,
    iterator_record: iterator::AsyncIteratorRecord,
    iterator_root: RootId,
    next_method_root: RootId,
  },
  /// Continue a `for await..of` loop after binding the current iteration value.
  ForAwaitOfAfterBind {
    stmt: *const ForOfStmt,
    label_set: Vec<String>,
    v_root: RootId,
    outer_lex: GcEnv,
    iterator_record: iterator::AsyncIteratorRecord,
    iterator_root: RootId,
    next_method_root: RootId,
    iter_env_created: bool,
  },
  /// Continue a `for await..of` loop after evaluating the loop body.
  ForAwaitOfAfterBody {
    stmt: *const ForOfStmt,
    label_set: Vec<String>,
    v_root: RootId,
    outer_lex: GcEnv,
    iterator_record: iterator::AsyncIteratorRecord,
    iterator_root: RootId,
    next_method_root: RootId,
  },
  /// Continue after awaiting `AsyncIteratorClose` for `for await..of`.
  ForAwaitOfAfterClose {
    pending: RootedCompletion,
    iterator_root: RootId,
    next_method_root: RootId,
  },

  /// Continue a `switch` statement after evaluating the discriminant expression.
  SwitchAfterDiscriminant { stmt: *const SwitchStmt },
  /// Continue a `switch` statement after evaluating a case selector expression.
  SwitchAfterCaseExpr {
    stmt: *const SwitchStmt,
    discriminant_root: RootId,
    v_root: RootId,
    default_index: Option<usize>,
    branch_index: usize,
  },
  /// Continue a `switch` statement after evaluating a case body statement list.
  SwitchAfterBody {
    stmt: *const SwitchStmt,
    discriminant_root: RootId,
    v_root: RootId,
    next_branch_index: usize,
  },

  /// Continue a labelled statement after evaluating its wrapped statement.
  LabelAfterStmt { label: String },

  /// Continue a `try` statement after evaluating the wrapped block.
  TryAfterWrapped { stmt: *const TryStmt },
  /// Continue a `try` statement after evaluating the catch block.
  TryAfterCatch { stmt: *const TryStmt },
  /// Continue a `try` statement after evaluating the finally block.
  TryAfterFinally { pending: RootedCompletion },

  /// Continue a `catch` clause after binding its parameter pattern (which may suspend due to
  /// `await` inside destructuring defaults/computed keys).
  CatchAfterParamBind {
    catch: *const CatchBlock,
    outer: GcEnv,
  },

  /// Continue evaluating a unary `await` after its operand expression completes (nested await).
  AwaitAfterOperand,
  /// Continue evaluating a unary `yield` after its operand expression completes (nested yield).
  YieldAfterOperand,
  /// Continue evaluating a delegated `yield*` after its operand expression completes.
  YieldStarAfterOperand,
  /// Continue delegated `yield*` iteration.
  YieldStar {
    yield_star: crate::async_generator::AsyncYieldStar,
    iterator_root: RootId,
    next_method_root: RootId,
  },
  /// Continue evaluating a non-`await` unary expression after its operand completes.
  UnaryAfterArgument { expr: *const UnaryExpr },

  /// Continue evaluating a `new` expression after evaluating the constructor value.
  NewAfterCallee { expr: *const UnaryExpr },
  /// Continue evaluating a `new` expression while evaluating arguments.
  NewArgs {
    expr: *const UnaryExpr,
    callee_root: RootId,
    arg_roots: Vec<RootId>,
    arg_index: usize,
  },

  /// Continue evaluating a `delete` expression after evaluating its operand.
  DeleteAfterArgument,
  /// Continue evaluating a `delete` member expression after evaluating its base.
  DeleteMemberAfterBase { expr: *const MemberExpr },
  /// Continue evaluating a `delete` computed member expression after evaluating its base.
  DeleteComputedMemberAfterBase { expr: *const ComputedMemberExpr },
  /// Continue evaluating a `delete` computed member expression after evaluating its member key
  /// expression.
  DeleteComputedMemberAfterMember {
    expr: *const ComputedMemberExpr,
    base_root: RootId,
  },
  /// Continue evaluating a `delete super[expr]` after evaluating its computed member key expression.
  ///
  /// Per ECMA-262, `delete` of a Super Reference must throw a ReferenceError, but for computed
  /// property references the key expression (including `ToPropertyKey`) is still evaluated first.
  DeleteSuperComputedMemberAfterMember,

  /// Continue a member access after evaluating the base value.
  MemberAfterBase { expr: *const MemberExpr },
  /// Continue a computed member access after evaluating the base value.
  ComputedMemberAfterBase { expr: *const ComputedMemberExpr },
  /// Continue a computed member access after evaluating the member expression.
  ComputedMemberAfterMember {
    expr: *const ComputedMemberExpr,
    base_root: RootId,
  },
  /// Continue a `super[expr]` computed member access after evaluating the member expression.
  ///
  /// Unlike ordinary computed members, `super[expr]` does not evaluate a base expression; instead
  /// it resolves a Super Reference using `[[HomeObject]].[[Prototype]]` and the current `this`
  /// binding as the receiver.
  SuperComputedMemberAfterMember { expr: *const ComputedMemberExpr },

  /// Continue class evaluation after evaluating the class heritage (`extends`) expression.
  ///
  /// This allows `extends` to suspend on `await` and resume once the superclass value is available.
  ClassAfterHeritage {
    members: *const Vec<Node<ClassMember>>,
    binding_name: Option<*const str>,
    func_name: *const str,
  },

  /// Continue class evaluation after evaluating a computed member key.
  ClassAfterComputedKey {
    members: *const Vec<Node<ClassMember>>,
    member_index: usize,
    func_root: RootId,
  },

  /// Continue class evaluation after a static block statement list completes.
  ///
  /// Static blocks run after the element definition pass and may contain `await`, so they can
  /// suspend and resume. This frame restores the outer class evaluation context and continues
  /// executing any remaining static blocks.
  ClassAfterStaticBlock {
    members: *const Vec<Node<ClassMember>>,
    next_index: usize,
    func_root: RootId,
    saved_this_root: RootId,
    saved_new_target_root: RootId,
    saved_home_object_root: RootId,
    saved_lex: GcEnv,
    saved_var_env: VarEnv,
    saved_meta_property_context: MetaPropertyContext,
  },

  /// Continue a conditional expression after evaluating the test.
  CondAfterTest { expr: *const CondExpr },

  /// Continue a binary expression after evaluating the left operand.
  BinaryAfterLeft { expr: *const BinaryExpr },
  /// Continue a binary expression after evaluating the right operand.
  BinaryAfterRight {
    expr: *const BinaryExpr,
    left_root: RootId,
  },
  /// Continue a private `#x in <expr>` brand check after evaluating the RHS.
  PrivateInAfterRight {
    expr: *const BinaryExpr,
  },

  /// Continue a call expression while evaluating arguments.
  CallAfterCallee { expr: *const CallExpr },
  CallMemberAfterBase {
    expr: *const CallExpr,
    member: *const MemberExpr,
  },
  CallComputedMemberAfterBase {
    expr: *const CallExpr,
    member: *const ComputedMemberExpr,
  },
  CallComputedMemberAfterMember {
    expr: *const CallExpr,
    member: *const ComputedMemberExpr,
    base_root: RootId,
  },
  CallArgs {
    expr: *const CallExpr,
    callee_root: RootId,
    this_root: RootId,
    arg_roots: Vec<RootId>,
    arg_index: usize,
  },

  /// Continue an array literal after evaluating an element expression.
  LitArrAfterSingle {
    expr: *const LitArrExpr,
    arr_root: RootId,
    next_elem_index: usize,
    next_index: u32,
    idx: u32,
  },
  /// Continue an array literal after evaluating a spread expression.
  LitArrAfterSpread {
    expr: *const LitArrExpr,
    arr_root: RootId,
    next_elem_index: usize,
    next_index: u32,
  },

  /// Continue an object literal after evaluating a computed key expression.
  LitObjAfterComputedKey {
    expr: *const LitObjExpr,
    obj_root: RootId,
    member_index: usize,
  },
  /// Continue an object literal after evaluating a property value expression.
  LitObjAfterPropValue {
    expr: *const LitObjExpr,
    obj_root: RootId,
    next_member_index: usize,
    key_root: RootId,
  },
  /// Continue an object literal after evaluating a spread source expression.
  LitObjAfterSpread {
    expr: *const LitObjExpr,
    obj_root: RootId,
    next_member_index: usize,
  },

  /// Continue a template literal after evaluating a substitution.
  LitTemplateAfterSubstitution {
    expr: *const LitTemplateExpr,
    next_part_index: usize,
    units: Vec<u16>,
  },

  /// Continue a tagged template after evaluating the tag expression.
  TaggedTemplateAfterFunction {
    expr: *const Node<TaggedTemplateExpr>,
  },
  /// Continue a tagged template after evaluating a member base expression.
  TaggedTemplateMemberAfterBase {
    expr: *const Node<TaggedTemplateExpr>,
  },
  /// Continue a tagged template after evaluating a computed member base expression.
  TaggedTemplateComputedMemberAfterBase {
    expr: *const Node<TaggedTemplateExpr>,
  },
  /// Continue a tagged template after evaluating a computed member key expression.
  TaggedTemplateComputedMemberAfterMember {
    expr: *const Node<TaggedTemplateExpr>,
    base_root: RootId,
  },
  /// Continue a tagged template while evaluating substitutions.
  TaggedTemplateAfterSubstitution {
    expr: *const Node<TaggedTemplateExpr>,
    callee_root: RootId,
    this_root: RootId,
    arg_roots: Vec<RootId>,
    next_part_index: usize,
  },

  /// Continue a dynamic `import()` expression after evaluating the specifier.
  ImportAfterSpecifier { expr: *const ImportExpr },
  /// Continue a dynamic `import()` expression after evaluating the options.
  ImportAfterOptions {
    expr: *const ImportExpr,
    specifier_root: RootId,
  },

  /// Continue an assignment expression after evaluating the RHS for a destructuring pattern.
  AssignPatternAfterRhs { expr: *const BinaryExpr },
  /// Finish a destructuring assignment after binding the pattern (used when the pattern evaluation
  /// itself contains `await` and can suspend). Restores the assignment expression result to the
  /// original RHS value.
  AssignPatternAfterBind { result_root: RootId },
  /// Continue an assignment expression after evaluating a member base expression.
  AssignMemberAfterBase {
    expr: *const BinaryExpr,
    member: *const MemberExpr,
  },
  /// Continue an assignment expression after evaluating a computed member base expression.
  AssignComputedMemberAfterBase {
    expr: *const BinaryExpr,
    member: *const ComputedMemberExpr,
  },
  /// Continue an assignment expression after evaluating a computed member key expression.
  AssignComputedMemberAfterMember {
    expr: *const BinaryExpr,
    member: *const ComputedMemberExpr,
    base_root: RootId,
  },
  /// Continue an assignment expression to a `super[expr]` computed member target after evaluating
  /// the member key expression.
  ///
  /// Unlike ordinary computed members, `super[expr]` does not evaluate a base expression; instead
  /// it resolves a Super Reference using `[[HomeObject]].[[Prototype]]` and the current `this`
  /// binding as the receiver.
  AssignSuperComputedMemberAfterMember {
    expr: *const BinaryExpr,
    member: *const ComputedMemberExpr,
  },
  /// Continue a simple assignment after evaluating the RHS.
  AssignAfterRhs {
    expr: *const BinaryExpr,
    base_root: Option<RootId>,
    key_root: Option<RootId>,
    receiver_root: Option<RootId>,
  },
  /// Continue an `+=` assignment after evaluating the RHS.
  AssignAddAfterRhs {
    expr: *const BinaryExpr,
    base_root: Option<RootId>,
    key_root: Option<RootId>,
    receiver_root: Option<RootId>,
    left_root: RootId,
  },

  /// Continue an update expression after evaluating a member base expression.
  UpdateMemberAfterBase {
    member: *const MemberExpr,
    delta: i8,
    prefix: bool,
  },
  /// Continue an update expression after evaluating a computed member base expression.
  UpdateComputedMemberAfterBase {
    member: *const ComputedMemberExpr,
    delta: i8,
    prefix: bool,
  },
  /// Continue an update expression after evaluating a computed member key expression.
  UpdateComputedMemberAfterMember {
    member: *const ComputedMemberExpr,
    base_root: RootId,
    delta: i8,
    prefix: bool,
  },
  /// Continue an update expression on a `super[expr]` computed member target after evaluating the
  /// member key expression.
  ///
  /// Unlike ordinary computed members, `super[expr]` does not evaluate a base expression; instead
  /// it resolves a Super Reference using `[[HomeObject]].[[Prototype]]` and the current `this`
  /// binding as the receiver.
  UpdateSuperComputedMemberAfterMember {
    member: *const ComputedMemberExpr,
    delta: i8,
    prefix: bool,
  },
}

#[derive(Debug)]
#[derive(Clone, Copy, PartialEq, Eq)]
pub(crate) enum AsyncSuspendKind {
  /// A suspension that should be resumed by awaiting `await_value` using the spec's `Await`
  /// semantics (`PromiseResolve(%Promise%, await_value)` + `PerformPromiseThen`).
  Await,
  /// Like [`AsyncSuspendKind::Await`], but `await_value` is already the *Promise* returned from the
  /// `Await` operation's internal `PromiseResolve` step.
  ///
  /// Some internal algorithms (notably `AsyncIteratorClose`) must perform the `PromiseResolve` step
  /// themselves so they can apply ECMA-262 suppression rules for throw completions. In those cases,
  /// the outer async suspension machinery must not `PromiseResolve` the value again, or it would
  /// observe `promise.constructor` twice.
  AwaitResolved,
  /// A suspension produced by `yield` in an async generator body.
  ///
  /// Async generator execution distinguishes these from internal `await` suspensions: the awaited
  /// value is delivered to the consumer, and the generator resumes from the next request.
  Yield,
  /// A `yield*` suspension that yields an iterator result object directly to the consumer.
  ///
  /// This mirrors vm-js's sync-generator `yield*` semantics: the delegate iterator result object is
  /// delivered without eagerly accessing its `.value`.
  YieldIteratorResult,
}

#[derive(Debug)]
struct AsyncSuspend {
  kind: AsyncSuspendKind,
  await_value: Value,
  frames: VecDeque<AsyncFrame>,
}

#[derive(Debug)]
enum AsyncEval<T> {
  Complete(T),
  Suspend(AsyncSuspend),
}

/// Persistent continuation frames for generator function execution.
///
/// This is an explicit reification of the evaluator call stack needed to resume execution after a
/// `yield` suspension point.
#[derive(Debug)]
pub(crate) enum GenFrame {
  /// Root frame for block-bodied generator functions (`function* f(){...}`).
  RootBlockBody,
  /// Converts the internal optional-chaining sentinel value to `undefined`.
  ///
  /// This frame is injected by `gen_eval_expr` so the generator continuation evaluator can
  /// propagate optional-chain short-circuits through non-optional chain segments, while ensuring
  /// the sentinel never becomes observable from user code when an expression completes.
  ConvertOptionalChainShortCircuit,

  /// Resume statement-list evaluation after a suspended statement completes.
  StmtList {
    stmts: *const Vec<Node<Stmt>>,
    next_index: usize,
    last_value: Option<Value>,
  },

  /// Best-effort stack trace capture for throw completions leaving a generator statement evaluation.
  FinalizeThrowAtStmt { stmt: *const Node<Stmt> },

  /// Restore the outer lexical environment after finishing a block/catch/finally body.
  RestoreLexEnv { outer: GcEnv },

  /// Continue a `with` statement after evaluating its object expression.
  WithAfterObject {
    stmt: *const WithStmt,
    label_set: Vec<String>,
    outer: GcEnv,
  },

  /// Finish a return statement after its value expression is evaluated.
  Return,

  /// Finish a throw statement after its value expression is evaluated.
  Throw { stmt: *const Node<ThrowStmt> },

  /// Continue a `var`/`let`/`const` declaration after a declarator initializer completes.
  VarDecl {
    decl: *const VarDecl,
    next_declarator_index: usize,
  },
  /// Continue a `var`/`let`/`const` declaration after binding a declarator value suspends.
  ///
  /// This is used when a destructuring binding pattern contains `yield` (e.g. default initializers
  /// or computed property keys) and therefore needs to suspend mid-binding.
  VarDeclAfterBind {
    decl: *const VarDecl,
    next_declarator_index: usize,
  },

  /// Continue an `if` statement after evaluating the test expression.
  IfAfterTest {
    consequent: *const Node<Stmt>,
    alternate: Option<*const Node<Stmt>>,
  },

  /// Continue a labelled statement after evaluating the wrapped statement.
  LabelAfterStmt { name: String },

  /// Continue a `while` loop after evaluating the test expression.
  WhileAfterTest {
    stmt: *const WhileStmt,
    label_set: Vec<String>,
    v: Value,
  },
  /// Continue a `while` loop after evaluating the body statement.
  WhileAfterBody {
    stmt: *const WhileStmt,
    label_set: Vec<String>,
    v: Value,
  },

  /// Continue a `do...while` loop after evaluating the body statement.
  DoWhileAfterBody {
    stmt: *const DoWhileStmt,
    label_set: Vec<String>,
    v: Value,
  },
  /// Continue a `do...while` loop after evaluating the test expression.
  DoWhileAfterTest {
    stmt: *const DoWhileStmt,
    label_set: Vec<String>,
    v: Value,
  },

  /// Continue a `for (init; cond; post) { ... }` loop after evaluating the initializer.
  ForTripleAfterInit {
    stmt: *const ForTripleStmt,
    label_set: Vec<String>,
    v: Value,
    outer_lex: Option<GcEnv>,
  },
  /// Continue a `for (init; cond; post) { ... }` loop after evaluating the test expression.
  ForTripleAfterTest {
    stmt: *const ForTripleStmt,
    label_set: Vec<String>,
    v: Value,
    outer_lex: Option<GcEnv>,
  },
  /// Continue a `for (init; cond; post) { ... }` loop after evaluating the body statement list.
  ForTripleAfterBody {
    stmt: *const ForTripleStmt,
    label_set: Vec<String>,
    v: Value,
    outer_lex: Option<GcEnv>,
  },
  /// Continue a `for (init; cond; post) { ... }` loop after evaluating the post expression.
  ForTripleAfterPost {
    stmt: *const ForTripleStmt,
    label_set: Vec<String>,
    v: Value,
    outer_lex: Option<GcEnv>,
  },

  /// Continue a `for..in` loop after evaluating the RHS expression.
  ForInAfterRhs {
    stmt: *const ForInStmt,
    label_set: Vec<String>,
  },
  /// Continue a `for..in` loop after binding the current iteration value suspends.
  ///
  /// This is used when the loop's LHS binding/assignment pattern contains `yield` (e.g. in a
  /// default initializer or computed property key).
  ForInAfterBind {
    stmt: *const ForInStmt,
    label_set: Vec<String>,
    enumerator: ForInEnumerator,
    outer_lex: GcEnv,
    v: Value,
    iter_env_created: bool,
  },
  /// Continue a `for..in` loop after evaluating the body statement list.
  ForInAfterBody {
    stmt: *const ForInStmt,
    label_set: Vec<String>,
    enumerator: ForInEnumerator,
    outer_lex: GcEnv,
    v: Value,
  },

  /// Continue a `for..of` loop after evaluating the RHS iterable expression.
  ForOfAfterRhs {
    stmt: *const ForOfStmt,
    label_set: Vec<String>,
  },
  /// Continue a `for..of` loop after binding the next iteration value suspends.
  ///
  /// This is used when the loop's LHS binding/assignment pattern contains `yield` (e.g. in a
  /// default initializer or computed property key).
  ForOfAfterBind {
    stmt: *const ForOfStmt,
    label_set: Vec<String>,
    iterator_record: iterator::IteratorRecord,
    outer_lex: GcEnv,
    v: Value,
  },
  /// Continue a `for..of` loop after evaluating the body statement list.
  ForOfAfterBody {
    stmt: *const ForOfStmt,
    label_set: Vec<String>,
    iterator_record: iterator::IteratorRecord,
    v: Value,
  },

  /// Continue a `switch` statement after evaluating its discriminant expression.
  SwitchAfterDiscriminant { stmt: *const SwitchStmt },
  /// Continue switch case scanning after evaluating a case selector expression.
  SwitchAfterCaseExpr {
    stmt: *const SwitchStmt,
    discriminant: Value,
    v: Value,
    default_index: Option<usize>,
    branch_index: usize,
  },
  /// Continue switch clause evaluation after evaluating a clause body statement list.
  SwitchAfterBody {
    stmt: *const SwitchStmt,
    v: Value,
    next_branch_index: usize,
  },

  /// Continue a `try` statement after evaluating the wrapped block.
  TryAfterWrapped { stmt: *const TryStmt },
  /// Continue a `try` statement after evaluating the catch block.
  TryAfterCatch { stmt: *const TryStmt },
  /// Continue a `try` statement after evaluating the finally block.
  TryAfterFinally { pending: Completion },

  /// Continue a `catch` clause after binding its parameter pattern (which may suspend due to
  /// `yield` inside destructuring defaults/computed keys).
  CatchAfterParamBind {
    catch: *const CatchBlock,
    outer: GcEnv,
  },

  /// Continue evaluating a unary `yield` after its operand expression completes (nested yield).
  YieldAfterOperand,
  /// Continue evaluating a unary `yield*` after its operand expression completes (nested yield).
  YieldStarAfterOperand,
  /// Continue delegating a `yield*` expression to an iterator.
  ///
  /// The delegate iterator record is stored directly in the generator continuation so the backing
  /// iterator object and `next` method remain GC-reachable across yields.
  YieldStar {
    iterator_record: iterator::IteratorRecord,
    returning: bool,
  },
  /// Continue evaluating a non-`yield` unary expression after its operand completes.
  UnaryAfterArgument { expr: *const UnaryExpr },

  /// Continue evaluating a `new` expression after evaluating the constructor value.
  NewAfterCallee { expr: *const UnaryExpr },
  /// Continue evaluating a `new` expression while evaluating arguments.
  NewArgs {
    expr: *const UnaryExpr,
    callee: Value,
    args: Vec<Value>,
    arg_index: usize,
  },

  /// Continue evaluating a `delete` expression after evaluating its operand.
  DeleteAfterArgument,
  /// Continue evaluating a `delete` member expression after evaluating its base.
  DeleteMemberAfterBase { expr: *const MemberExpr },
  /// Continue evaluating a `delete` computed member expression after evaluating its base.
  DeleteComputedMemberAfterBase { expr: *const ComputedMemberExpr },
  /// Continue evaluating a `delete` computed member expression after evaluating its member key
  /// expression.
  DeleteComputedMemberAfterMember {
    expr: *const ComputedMemberExpr,
    base: Value,
  },
  /// Continue evaluating a `delete super[expr]` after evaluating its computed member key expression.
  ///
  /// Per ECMA-262, `delete` of a Super Reference must throw a ReferenceError, but for computed
  /// property references the key expression (including `ToPropertyKey`) is still evaluated first.
  DeleteSuperComputedMemberAfterMember,

  /// Continue an update expression after evaluating a member base expression.
  UpdateMemberAfterBase {
    expr: *const MemberExpr,
    delta: i8,
    prefix: bool,
  },
  /// Continue an update expression after evaluating a computed member base expression.
  UpdateComputedMemberAfterBase {
    expr: *const ComputedMemberExpr,
    delta: i8,
    prefix: bool,
  },
  /// Continue an update expression after evaluating a computed member key expression.
  UpdateComputedMemberAfterMember {
    expr: *const ComputedMemberExpr,
    base: Value,
    delta: i8,
    prefix: bool,
  },
  /// Continue an update expression on a `super[expr]` reference after evaluating the computed member
  /// key expression.
  UpdateSuperComputedMemberAfterMember {
    expr: *const ComputedMemberExpr,
    delta: i8,
    prefix: bool,
  },

  /// Continue a member access after evaluating the base value.
  MemberAfterBase { expr: *const MemberExpr },
  /// Continue a computed member access after evaluating the base value.
  ComputedMemberAfterBase { expr: *const ComputedMemberExpr },
  /// Continue a computed member access after evaluating the member expression.
  ComputedMemberAfterMember {
    expr: *const ComputedMemberExpr,
    base: Value,
  },
  /// Continue evaluating a `super[expr]` computed member access after evaluating the member key
  /// expression.
  SuperComputedMemberAfterMember { expr: *const ComputedMemberExpr },

  /// Continue a conditional expression after evaluating the test.
  CondAfterTest { expr: *const CondExpr },

  /// Continue a binary expression after evaluating the left operand.
  BinaryAfterLeft { expr: *const BinaryExpr },
  /// Continue a binary expression after evaluating the right operand.
  BinaryAfterRight {
    expr: *const BinaryExpr,
    left: Value,
  },
  /// Continue a private `#x in <expr>` brand check after evaluating the RHS.
  PrivateInAfterRight { expr: *const BinaryExpr },

  /// Continue a simple assignment after evaluating the RHS (binding target).
  AssignAfterRhsBinding { name: *const String },
  /// Continue a destructuring assignment after evaluating the RHS.
  AssignAfterRhsPattern { expr: *const BinaryExpr },

  /// Finish a destructuring assignment after binding the pattern.
  ///
  /// Restores the assignment expression result to the original RHS value (ECMA-262 assignment
  /// expressions evaluate to the RHS even for destructuring).
  AssignPatternAfterBind { result: Value },

  /// Continue object destructuring after evaluating a computed property key.
  BindObjAfterKey {
    pat: *const ObjPat,
    prop_index: usize,
    value: Value,
    excluded: Vec<PropertyKey>,
    kind: BindingKind,
  },
  /// Continue object destructuring after evaluating a default initializer expression.
  BindObjAfterDefault {
    pat: *const ObjPat,
    prop_index: usize,
    value: Value,
    excluded: Vec<PropertyKey>,
    kind: BindingKind,
  },
  /// Continue object destructuring after binding a property target pattern.
  BindObjContinue {
    pat: *const ObjPat,
    next_prop_index: usize,
    value: Value,
    excluded: Vec<PropertyKey>,
    kind: BindingKind,
  },

  /// Continue array destructuring after evaluating a default initializer expression.
  BindArrAfterDefault {
    pat: *const ArrPat,
    elem_index: usize,
    array_index: u32,
    len: u32,
    value: Value,
    kind: BindingKind,
  },
  /// Continue array destructuring after binding an element target pattern.
  BindArrContinue {
    pat: *const ArrPat,
    elem_index: usize,
    array_index: u32,
    len: u32,
    value: Value,
    kind: BindingKind,
  },

  /// Continue binding an assignment target `obj.prop` after evaluating the base expression.
  BindAssignMemberAfterBase {
    member: *const MemberExpr,
    value: Value,
  },
  /// Continue binding an assignment target `obj[expr]` after evaluating the base expression.
  BindAssignComputedMemberAfterBase {
    member: *const ComputedMemberExpr,
    value: Value,
  },
  /// Continue binding an assignment target `obj[expr]` after evaluating the computed key
  /// expression.
  BindAssignComputedMemberAfterMember {
    member: *const ComputedMemberExpr,
    base: Value,
    value: Value,
  },
  /// Continue binding an assignment target `super[expr]` after evaluating the computed key
  /// expression.
  BindAssignSuperComputedMemberAfterMember {
    member: *const ComputedMemberExpr,
    value: Value,
  },
  /// Continue an assignment expression after evaluating a member base expression.
  AssignMemberAfterBase {
    expr: *const BinaryExpr,
    member: *const MemberExpr,
  },
  /// Continue an assignment expression after evaluating a computed member base expression.
  AssignComputedMemberAfterBase {
    expr: *const BinaryExpr,
    member: *const ComputedMemberExpr,
  },
  /// Continue an assignment expression after evaluating a computed member key expression.
  AssignComputedMemberAfterMember {
    expr: *const BinaryExpr,
    member: *const ComputedMemberExpr,
    base: Value,
  },
  /// Continue an assignment expression to a `super[expr]` computed member target after evaluating
  /// the member key expression.
  ///
  /// Unlike ordinary computed members, `super[expr]` does not evaluate a base expression; instead
  /// it resolves a Super Reference using `[[HomeObject]].[[Prototype]]` and the current `this`
  /// binding as the receiver.
  AssignSuperComputedMemberAfterMember {
    expr: *const BinaryExpr,
    member: *const ComputedMemberExpr,
  },
  /// Continue a simple assignment after evaluating the RHS.
  AssignAfterRhs {
    expr: *const BinaryExpr,
    base: Option<Value>,
    key: Option<Value>,
    /// Receiver (`this` value) for `super` property references.
    ///
    /// When present, `base`/`key` represent the super base + property key, and `receiver` is used as
    /// the `this` binding / setter receiver for `super.x` / `super[expr]`.
    receiver: Option<Value>,
  },
  /// Continue a compound assignment after evaluating the RHS.
  AssignAddAfterRhs {
    expr: *const BinaryExpr,
    base: Option<Value>,
    key: Option<Value>,
    receiver: Option<Value>,
    left: Value,
  },
  /// Continue a call expression while evaluating arguments.
  CallAfterCallee { expr: *const CallExpr },
  CallMemberAfterBase {
    expr: *const CallExpr,
    member: *const MemberExpr,
  },
  CallComputedMemberAfterBase {
    expr: *const CallExpr,
    member: *const ComputedMemberExpr,
  },
  CallComputedMemberAfterMember {
    expr: *const CallExpr,
    member: *const ComputedMemberExpr,
    base: Value,
  },
  /// Continue evaluating a `super[expr](...)` call after evaluating the computed member key
  /// expression.
  CallSuperComputedMemberAfterMember {
    expr: *const CallExpr,
    member: *const ComputedMemberExpr,
  },
  CallArgs {
    expr: *const CallExpr,
    callee: Value,
    this: Value,
    args: Vec<Value>,
    arg_index: usize,
  },

  /// Continue evaluating an array literal after a single element expression completes.
  LitArrAfterSingle {
    expr: *const LitArrExpr,
    arr: GcObject,
    next_elem_index: usize,
    next_index: u32,
    idx: u32,
  },
  /// Continue evaluating an array literal after a spread element expression completes.
  LitArrAfterSpread {
    expr: *const LitArrExpr,
    arr: GcObject,
    next_elem_index: usize,
    next_index: u32,
  },

  /// Continue evaluating an object literal after a computed key expression completes.
  LitObjAfterComputedKey {
    expr: *const LitObjExpr,
    obj: GcObject,
    member_index: usize,
  },
  /// Continue evaluating an object literal after a property value expression completes.
  LitObjAfterPropValue {
    expr: *const LitObjExpr,
    obj: GcObject,
    next_member_index: usize,
    key: PropertyKey,
    is_proto_setter: bool,
  },
  /// Continue evaluating an object literal after a spread property expression completes.
  LitObjAfterSpread {
    expr: *const LitObjExpr,
    obj: GcObject,
    next_member_index: usize,
  },

  /// Continue evaluating a template literal after evaluating a substitution.
  LitTemplateAfterSubstitution {
    expr: *const LitTemplateExpr,
    next_part_index: usize,
    units: Vec<u16>,
  },

  /// Continue a tagged template after evaluating the tag expression.
  TaggedTemplateAfterFunction {
    expr: *const Node<TaggedTemplateExpr>,
  },
  /// Continue a tagged template after evaluating a member base expression.
  TaggedTemplateMemberAfterBase {
    expr: *const Node<TaggedTemplateExpr>,
  },
  /// Continue a tagged template after evaluating a computed member base expression.
  TaggedTemplateComputedMemberAfterBase {
    expr: *const Node<TaggedTemplateExpr>,
  },
  /// Continue a tagged template after evaluating a `super[expr]` computed member key expression.
  TaggedTemplateSuperComputedMemberAfterMember {
    expr: *const Node<TaggedTemplateExpr>,
  },
  /// Continue a tagged template after evaluating a computed member key expression.
  TaggedTemplateComputedMemberAfterMember {
    expr: *const Node<TaggedTemplateExpr>,
    base: Value,
  },
  /// Continue a tagged template while evaluating substitutions.
  TaggedTemplateAfterSubstitution {
    expr: *const Node<TaggedTemplateExpr>,
    callee: Value,
    this: Value,
    args: Vec<Value>,
    next_part_index: usize,
  },

  /// Continue a dynamic `import()` expression after evaluating the specifier expression.
  ImportAfterSpecifier { expr: *const ImportExpr },
  /// Continue a dynamic `import()` expression after evaluating the options expression.
  ImportAfterOptions {
    expr: *const ImportExpr,
    specifier: Value,
  },
}

impl Trace for GenFrame {
  fn trace(&self, tracer: &mut Tracer<'_>) {
    match self {
      GenFrame::StmtList { last_value, .. } => {
        if let Some(v) = last_value {
          tracer.trace_value(*v);
        }
      }
      GenFrame::RestoreLexEnv { outer }
      | GenFrame::WithAfterObject { outer, .. }
      | GenFrame::CatchAfterParamBind { outer, .. } => tracer.trace_env(*outer),
      GenFrame::WhileAfterTest { v, .. }
      | GenFrame::WhileAfterBody { v, .. }
      | GenFrame::DoWhileAfterBody { v, .. }
      | GenFrame::DoWhileAfterTest { v, .. } => tracer.trace_value(*v),
      GenFrame::ForTripleAfterInit { v, outer_lex, .. }
      | GenFrame::ForTripleAfterTest { v, outer_lex, .. }
      | GenFrame::ForTripleAfterBody { v, outer_lex, .. }
      | GenFrame::ForTripleAfterPost { v, outer_lex, .. } => {
        tracer.trace_value(*v);
        if let Some(outer) = outer_lex {
          tracer.trace_env(*outer)
        }
      }
      GenFrame::ForInAfterBind {
        enumerator,
        outer_lex,
        v,
        ..
      } => {
        enumerator.trace(tracer);
        tracer.trace_value(*v);
        tracer.trace_env(*outer_lex);
      }
      GenFrame::ForInAfterBody {
        enumerator,
        outer_lex,
        v,
        ..
      } => {
        enumerator.trace(tracer);
        tracer.trace_value(*v);
        tracer.trace_env(*outer_lex);
      }
      GenFrame::ForOfAfterBind {
        iterator_record,
        outer_lex,
        v,
        ..
      } => {
        tracer.trace_value(iterator_record.iterator);
        tracer.trace_value(iterator_record.next_method);
        tracer.trace_value(*v);
        tracer.trace_env(*outer_lex);
      }
      GenFrame::ForOfAfterBody {
        iterator_record, v, ..
      } => {
        tracer.trace_value(iterator_record.iterator);
        tracer.trace_value(iterator_record.next_method);
        tracer.trace_value(*v);
      }
      GenFrame::SwitchAfterCaseExpr {
        discriminant, v, ..
      } => {
        tracer.trace_value(*discriminant);
        tracer.trace_value(*v);
      }
      GenFrame::SwitchAfterBody { v, .. } => tracer.trace_value(*v),
      GenFrame::TryAfterFinally { pending } => pending.trace(tracer),
      GenFrame::ComputedMemberAfterMember { base, .. }
      | GenFrame::DeleteComputedMemberAfterMember { base, .. }
      | GenFrame::UpdateComputedMemberAfterMember { base, .. }
      | GenFrame::CallComputedMemberAfterMember { base, .. } => tracer.trace_value(*base),
      GenFrame::BinaryAfterRight { left, .. } => tracer.trace_value(*left),
      GenFrame::AssignComputedMemberAfterMember { base, .. } => tracer.trace_value(*base),
      GenFrame::AssignAfterRhs {
        base,
        key,
        receiver,
        ..
      } => {
        if let Some(b) = base {
          tracer.trace_value(*b);
        }
        if let Some(k) = key {
          tracer.trace_value(*k);
        }
        if let Some(r) = receiver {
          tracer.trace_value(*r);
        }
      }
      GenFrame::AssignAddAfterRhs {
        base,
        key,
        receiver,
        left,
        ..
      } => {
        if let Some(b) = base {
          tracer.trace_value(*b);
        }
        if let Some(k) = key {
          tracer.trace_value(*k);
        }
        if let Some(r) = receiver {
          tracer.trace_value(*r);
        }
        tracer.trace_value(*left);
      }
      GenFrame::CallArgs {
        callee, this, args, ..
      } => {
        tracer.trace_value(*callee);
        tracer.trace_value(*this);
        for v in args.iter().copied() {
          tracer.trace_value(v);
        }
      }
      GenFrame::NewArgs { callee, args, .. } => {
        tracer.trace_value(*callee);
        for v in args.iter().copied() {
          tracer.trace_value(v);
        }
      }
      GenFrame::TaggedTemplateComputedMemberAfterMember { base, .. } => tracer.trace_value(*base),
      GenFrame::TaggedTemplateAfterSubstitution {
        callee, this, args, ..
      } => {
        tracer.trace_value(*callee);
        tracer.trace_value(*this);
        for v in args.iter().copied() {
          tracer.trace_value(v);
        }
      }
      GenFrame::AssignPatternAfterBind { result } => tracer.trace_value(*result),
      GenFrame::BindObjAfterKey { value, excluded, .. }
      | GenFrame::BindObjAfterDefault { value, excluded, .. }
      | GenFrame::BindObjContinue { value, excluded, .. } => {
        tracer.trace_value(*value);
        for key in excluded {
          key.trace(tracer);
        }
      }
      GenFrame::BindArrAfterDefault { value, .. } | GenFrame::BindArrContinue { value, .. } => {
        tracer.trace_value(*value);
      }
      GenFrame::BindAssignMemberAfterBase { value, .. }
      | GenFrame::BindAssignComputedMemberAfterBase { value, .. }
      | GenFrame::BindAssignSuperComputedMemberAfterMember { value, .. } => {
        tracer.trace_value(*value);
      }
      GenFrame::BindAssignComputedMemberAfterMember { base, value, .. } => {
        tracer.trace_value(*base);
        tracer.trace_value(*value);
      }
      GenFrame::LitArrAfterSingle { arr, .. } | GenFrame::LitArrAfterSpread { arr, .. } => {
        tracer.trace_value(Value::Object(*arr));
      }
      GenFrame::LitObjAfterComputedKey { obj, .. } | GenFrame::LitObjAfterSpread { obj, .. } => {
        tracer.trace_value(Value::Object(*obj));
      }
      GenFrame::LitObjAfterPropValue { obj, key, .. } => {
        tracer.trace_value(Value::Object(*obj));
        match key {
          PropertyKey::String(s) => tracer.trace_value(Value::String(*s)),
          PropertyKey::Symbol(s) => tracer.trace_value(Value::Symbol(*s)),
        }
      }
      GenFrame::ImportAfterOptions { specifier, .. } => tracer.trace_value(*specifier),
      GenFrame::YieldStar {
        iterator_record, ..
      } => {
        tracer.trace_value(iterator_record.iterator);
        tracer.trace_value(iterator_record.next_method);
      }
      _ => {}
    }
  }
}

#[derive(Debug)]
enum GenYield {
  Value(Value),
  IteratorResult(Value),
}

#[derive(Debug)]
struct GenSuspend {
  yielded: GenYield,
  frames: VecDeque<GenFrame>,
}

#[derive(Debug)]
enum GenEval<T> {
  Complete(T),
  Suspend(GenSuspend),
}

#[derive(Debug)]
struct RootedCompletion {
  kind: RootedCompletionKind,
}

#[derive(Debug)]
enum RootedCompletionKind {
  Normal(Option<RootId>),
  Throw {
    value_root: RootId,
    stack: Vec<StackFrame>,
  },
  Return(RootId),
  Break(Option<String>, Option<RootId>),
  Continue(Option<String>, Option<RootId>),
}

impl RootedCompletion {
  fn new(scope: &mut Scope<'_>, completion: Completion) -> Result<Self, VmError> {
    let mut root_value = |v: Value| -> Result<RootId, VmError> {
      let mut root_scope = scope.reborrow();
      root_scope.push_root(v)?;
      root_scope.heap_mut().add_root(v)
    };

    let kind = match completion {
      Completion::Normal(v) => RootedCompletionKind::Normal(v.map(root_value).transpose()?),
      Completion::Return(v) => RootedCompletionKind::Return(root_value(v)?),
      Completion::Throw(thrown) => RootedCompletionKind::Throw {
        value_root: root_value(thrown.value)?,
        stack: thrown.stack,
      },
      Completion::Break(target, v) => {
        RootedCompletionKind::Break(target, v.map(root_value).transpose()?)
      }
      Completion::Continue(target, v) => {
        RootedCompletionKind::Continue(target, v.map(root_value).transpose()?)
      }
    };
    Ok(Self { kind })
  }

  fn to_completion(&self, heap: &Heap) -> Result<Completion, VmError> {
    let get = |root: RootId| {
      heap.get_root(root).ok_or(VmError::InvariantViolation(
        "missing rooted completion value",
      ))
    };
    Ok(match &self.kind {
      RootedCompletionKind::Normal(v) => Completion::Normal(v.map(|id| get(id)).transpose()?),
      RootedCompletionKind::Return(id) => Completion::Return(get(*id)?),
      RootedCompletionKind::Throw { value_root, stack } => Completion::Throw(Thrown {
        value: get(*value_root)?,
        stack: stack.clone(),
      }),
      RootedCompletionKind::Break(target, v) => {
        Completion::Break(target.clone(), v.map(|id| get(id)).transpose()?)
      }
      RootedCompletionKind::Continue(target, v) => {
        Completion::Continue(target.clone(), v.map(|id| get(id)).transpose()?)
      }
    })
  }

  fn teardown(&mut self, heap: &mut Heap) {
    let mut remove_opt = |id: &mut Option<RootId>| {
      if let Some(id) = id.take() {
        heap.remove_root(id);
      }
    };

    match &mut self.kind {
      RootedCompletionKind::Normal(v) => remove_opt(v),
      RootedCompletionKind::Return(id) => heap.remove_root(*id),
      RootedCompletionKind::Throw { value_root, .. } => heap.remove_root(*value_root),
      RootedCompletionKind::Break(_, v) => remove_opt(v),
      RootedCompletionKind::Continue(_, v) => remove_opt(v),
    }
  }
}

fn async_teardown_frame(heap: &mut Heap, frame: &mut AsyncFrame) {
  match frame {
    AsyncFrame::HirAsync { state } => state.teardown(heap),
    AsyncFrame::StmtList {
      last_value_root, ..
    } => heap.remove_root(*last_value_root),
    AsyncFrame::WhileAfterTest { v_root, .. }
    | AsyncFrame::WhileAfterBody { v_root, .. }
    | AsyncFrame::DoWhileAfterBody { v_root, .. }
    | AsyncFrame::DoWhileAfterTest { v_root, .. }
    | AsyncFrame::ForTripleAfterInit { v_root, .. }
    | AsyncFrame::ForTripleAfterTest { v_root, .. }
    | AsyncFrame::ForTripleAfterBody { v_root, .. }
    | AsyncFrame::ForTripleAfterPost { v_root, .. } => heap.remove_root(*v_root),
    AsyncFrame::ForInAfterBind {
      object_root,
      key_roots,
      v_root,
      ..
    }
    | AsyncFrame::ForInAfterBody {
      object_root,
      key_roots,
      v_root,
      ..
    } => {
      heap.remove_root(*object_root);
      heap.remove_root(*v_root);
      for id in key_roots.drain(..) {
        heap.remove_root(id);
      }
    }
    AsyncFrame::ForOfAfterBind {
      iterator_root,
      next_method_root,
      v_root,
      ..
    }
    | AsyncFrame::ForOfAfterBody {
      iterator_root,
      next_method_root,
      v_root,
      ..
    } => {
      heap.remove_root(*iterator_root);
      heap.remove_root(*next_method_root);
      heap.remove_root(*v_root);
    }
    AsyncFrame::YieldStar {
      iterator_root,
      next_method_root,
      ..
    } => {
      heap.remove_root(*iterator_root);
      heap.remove_root(*next_method_root);
    }
    AsyncFrame::ForAwaitOfAfterRhs { v_root, .. } => heap.remove_root(*v_root),
    AsyncFrame::ForAwaitOfAfterNext {
      v_root,
      iterator_root,
      next_method_root,
      ..
    }
    | AsyncFrame::ForAwaitOfAfterBind {
      v_root,
      iterator_root,
      next_method_root,
      ..
    }
    | AsyncFrame::ForAwaitOfAfterBody {
      v_root,
      iterator_root,
      next_method_root,
      ..
    } => {
      heap.remove_root(*v_root);
      heap.remove_root(*iterator_root);
      heap.remove_root(*next_method_root);
    }
    AsyncFrame::ForAwaitOfAfterClose {
      pending,
      iterator_root,
      next_method_root,
    } => {
      pending.teardown(heap);
      heap.remove_root(*iterator_root);
      heap.remove_root(*next_method_root);
    }
    AsyncFrame::SwitchAfterCaseExpr {
      discriminant_root,
      v_root,
      ..
    }
    | AsyncFrame::SwitchAfterBody {
      discriminant_root,
      v_root,
      ..
    } => {
      heap.remove_root(*discriminant_root);
      heap.remove_root(*v_root);
    }
    AsyncFrame::TryAfterFinally { pending } => pending.teardown(heap),
    AsyncFrame::ComputedMemberAfterMember { base_root, .. } => heap.remove_root(*base_root),
    AsyncFrame::ClassAfterComputedKey { func_root, .. } => heap.remove_root(*func_root),
    AsyncFrame::ClassAfterStaticBlock {
      func_root,
      saved_this_root,
      saved_new_target_root,
      saved_home_object_root,
      ..
    } => {
      heap.remove_root(*func_root);
      heap.remove_root(*saved_this_root);
      heap.remove_root(*saved_new_target_root);
      heap.remove_root(*saved_home_object_root);
    }
    AsyncFrame::CallComputedMemberAfterMember { base_root, .. } => heap.remove_root(*base_root),
    AsyncFrame::BinaryAfterRight { left_root, .. } => heap.remove_root(*left_root),
    AsyncFrame::DeleteComputedMemberAfterMember { base_root, .. } => heap.remove_root(*base_root),
    AsyncFrame::CallArgs {
      callee_root,
      this_root,
      arg_roots,
      ..
    } => {
      heap.remove_root(*callee_root);
      heap.remove_root(*this_root);
      for id in arg_roots.drain(..) {
        heap.remove_root(id);
      }
    }
    AsyncFrame::NewArgs {
      callee_root,
      arg_roots,
      ..
    } => {
      heap.remove_root(*callee_root);
      for id in arg_roots.drain(..) {
        heap.remove_root(id);
      }
    }
    AsyncFrame::WithAfterObject { .. } | AsyncFrame::FinalizeThrowAtStmt { .. } => {}
    AsyncFrame::BindObjAfterKey {
      value_root,
      excluded,
      ..
    }
    | AsyncFrame::BindObjAfterDefault {
      value_root,
      excluded,
      ..
    }
    | AsyncFrame::BindObjContinue {
      value_root,
      excluded,
      ..
    } => {
      heap.remove_root(*value_root);
      for key in excluded.drain(..) {
        heap.remove_root(key.root);
      }
    }
    AsyncFrame::BindArrAfterDefault { value_root, .. }
    | AsyncFrame::BindArrContinue { value_root, .. } => {
      heap.remove_root(*value_root);
    }
    AsyncFrame::LitArrAfterSingle { arr_root, .. }
    | AsyncFrame::LitArrAfterSpread { arr_root, .. } => heap.remove_root(*arr_root),
    AsyncFrame::LitObjAfterComputedKey { obj_root, .. }
    | AsyncFrame::LitObjAfterSpread { obj_root, .. } => heap.remove_root(*obj_root),
    AsyncFrame::LitObjAfterPropValue {
      obj_root, key_root, ..
    } => {
      heap.remove_root(*obj_root);
      heap.remove_root(*key_root);
    }
    AsyncFrame::TaggedTemplateComputedMemberAfterMember { base_root, .. } => {
      heap.remove_root(*base_root)
    }
    AsyncFrame::TaggedTemplateAfterSubstitution {
      callee_root,
      this_root,
      arg_roots,
      ..
    } => {
      heap.remove_root(*callee_root);
      heap.remove_root(*this_root);
      for id in arg_roots.drain(..) {
        heap.remove_root(id);
      }
    }
    AsyncFrame::ImportAfterOptions { specifier_root, .. } => heap.remove_root(*specifier_root),
    AsyncFrame::AssignPatternAfterBind { result_root } => heap.remove_root(*result_root),
    AsyncFrame::AssignComputedMemberAfterMember { base_root, .. } => heap.remove_root(*base_root),
    AsyncFrame::AssignAfterRhs {
      base_root,
      key_root,
      receiver_root,
      ..
    } => {
      if let Some(id) = base_root.take() {
        heap.remove_root(id);
      }
      if let Some(id) = key_root.take() {
        heap.remove_root(id);
      }
      if let Some(id) = receiver_root.take() {
        heap.remove_root(id);
      }
    }
    AsyncFrame::AssignAddAfterRhs {
      base_root,
      key_root,
      receiver_root,
      left_root,
      ..
    } => {
      if let Some(id) = base_root.take() {
        heap.remove_root(id);
      }
      if let Some(id) = key_root.take() {
        heap.remove_root(id);
      }
      if let Some(id) = receiver_root.take() {
        heap.remove_root(id);
      }
      heap.remove_root(*left_root);
    }
    AsyncFrame::UpdateComputedMemberAfterMember { base_root, .. } => heap.remove_root(*base_root),
    _ => {}
  }
}

#[derive(Debug)]
pub(crate) struct AsyncContinuation {
  pub(crate) env: RuntimeEnv,
  pub(crate) strict: bool,
  /// Optional execution context to install while resuming the async continuation.
  ///
  /// This is primarily used for top-level await in modules: module evaluation must provide an
  /// active `ScriptOrModule::Module` so `import.meta` and dynamic `import()` can observe the active
  /// module during each resumed execution segment (ECMA-262 `AsyncBlockStart` behaviour).
  pub(crate) exec_ctx: Option<ExecutionContext>,
  /// Keeps the parsed script AST alive when resuming an async classic script (top-level
  /// `for await...of`).
  ///
  /// Async frames store raw pointers into the parsed `TopLevel` AST; classic scripts normally parse
  /// and evaluate synchronously so dropping the AST is fine, but async classic scripts return a
  /// Promise and continue execution from microtasks after this entrypoint returns.
  pub(crate) script_ast: Option<Arc<Node<parse_js::ast::stx::TopLevel>>>,
  /// External heap memory token for [`AsyncContinuation::script_ast`].
  ///
  /// `parse-js` AST nodes are allocated outside the GC heap. Async classic scripts can suspend and
  /// retain the full parsed script AST across microtasks; holding this token ensures that retained
  /// AST memory is accounted for against `HeapLimits` and released when the continuation completes
  /// or is aborted.
  #[allow(dead_code)]
  pub(crate) script_ast_memory: Option<ExternalMemoryToken>,
  pub(crate) this_root: RootId,
  pub(crate) new_target_root: RootId,
  pub(crate) home_object_root: RootId,
  pub(crate) promise_root: RootId,
  pub(crate) resolve_root: RootId,
  pub(crate) reject_root: RootId,
  pub(crate) awaited_promise_root: Option<RootId>,
  pub(crate) frames: VecDeque<AsyncFrame>,
}

#[derive(Debug)]
pub(crate) struct AsyncGeneratorRuntimeState {
  frames: VecDeque<AsyncFrame>,
  awaited_promise_root: Option<RootId>,
}

pub(crate) fn async_generator_teardown_runtime_state(
  scope: &mut Scope<'_>,
  mut state: AsyncGeneratorRuntimeState,
) {
  if let Some(root) = state.awaited_promise_root.take() {
    scope.heap_mut().remove_root(root);
  }
  for mut frame in state.frames {
    async_teardown_frame(scope.heap_mut(), &mut frame);
  }
}

pub(crate) fn async_teardown_continuation(scope: &mut Scope<'_>, mut cont: AsyncContinuation) {
  cont.env.teardown(scope.heap_mut());
  scope.heap_mut().remove_root(cont.this_root);
  scope.heap_mut().remove_root(cont.new_target_root);
  scope.heap_mut().remove_root(cont.home_object_root);
  scope.heap_mut().remove_root(cont.promise_root);
  scope.heap_mut().remove_root(cont.resolve_root);
  scope.heap_mut().remove_root(cont.reject_root);
  if let Some(root) = cont.awaited_promise_root.take() {
    scope.heap_mut().remove_root(root);
  }
  for mut frame in cont.frames {
    async_teardown_frame(scope.heap_mut(), &mut frame);
  }
}


fn async_handle_body_result(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  id: u32,
  mut cont: AsyncContinuation,
  resolve: Value,
  reject: Value,
  result: Result<AsyncBodyResult, VmError>,
) -> Result<Value, VmError> {
  let global_object = cont.env.global_object();

  match result {
    Ok(AsyncBodyResult::CompleteOk(v)) => {
      let mut call_scope = scope.reborrow();
      if let Err(err) = call_scope.push_roots(&[resolve, v]) {
        async_teardown_continuation(&mut call_scope, cont);
        return Err(err);
      }
      let res = vm.call_with_host_and_hooks(
        host,
        &mut call_scope,
        hooks,
        resolve,
        Value::Undefined,
        &[v],
      );
      async_teardown_continuation(&mut call_scope, cont);
      res.map(|_| Value::Undefined)
    }
    Ok(AsyncBodyResult::CompleteThrow(reason)) => {
      let mut call_scope = scope.reborrow();
      if let Err(err) = call_scope.push_roots(&[reject, reason]) {
        async_teardown_continuation(&mut call_scope, cont);
        return Err(err);
      }
      let res = vm.call_with_host_and_hooks(
        host,
        &mut call_scope,
        hooks,
        reject,
        Value::Undefined,
        &[reason],
      );
      async_teardown_continuation(&mut call_scope, cont);
      res.map(|_| Value::Undefined)
    }
    Ok(AsyncBodyResult::Await {
      kind,
      await_value,
      frames,
    }) => {
      // Suspend again: `Await` (`PromiseResolve` + `PerformPromiseThen`).
      cont.frames = frames;

      let mut await_scope = scope.reborrow();
      if let Err(err) = await_scope.push_roots(&[await_value]) {
        async_teardown_continuation(&mut await_scope, cont);
        return Err(err);
      }

      let awaited_promise_res: Result<Value, VmError> = match kind {
        AsyncSuspendKind::Await => {
          // `await` must not trigger Promise species side effects. In particular, coercing a Promise
          // via `PromiseResolve(%Promise%, promise)` can (via thenable resolution jobs) call
          // `promise.then`, which creates a derived promise using `promise.constructor[Symbol.species]`.
          //
          // We still need to perform `Get(promise, \"constructor\")` for side effects/throws (per
          // `PromiseResolve`), but we intentionally do **not** wrap the Promise: for await, attaching
          // reactions directly to the original Promise using `PerformPromiseThen(..., resultCapability =
          // undefined)` is sufficient and avoids Promise species side effects.
          let resolve_res = promise_resolve_for_await_with_host_and_hooks(
            vm,
            &mut await_scope,
            host,
            hooks,
            await_value,
          );
          resolve_res.map_err(|err| coerce_error_to_throw_for_async(vm, &mut await_scope, err))
        }
        AsyncSuspendKind::AwaitResolved => Ok(await_value),
        AsyncSuspendKind::Yield | AsyncSuspendKind::YieldIteratorResult => Err(VmError::InvariantViolation(
          "unexpected async generator yield suspension in async continuation",
        )),
      };

      let awaited_promise = match awaited_promise_res {
        Ok(p) => p,
        Err(err) if err.is_throw_completion() => {
          // `Await` uses `? PromiseResolve(%Promise%, value)`. If that throws, the async function
          // promise must be rejected (and the resume callback must not throw synchronously).
          //
          // Note: many VM operations use internal helper errors (e.g. `VmError::TypeError`) that are
          // coerced into JS throw completions at evaluator boundaries. `await` is such a boundary:
          // an abrupt completion must become a promise rejection, not a host error.
          let (source, offset) = source_offset_for_async_frames_best_effort(&cont.env, &cont.frames);
          let err =
            finalize_throw_with_stack_at_source_offset_best_effort(vm, &mut await_scope, source.as_ref(), offset, err);
          let reason = match err {
            VmError::Throw(reason) | VmError::ThrowWithStack { value: reason, .. } => reason,
            other => {
              async_teardown_continuation(&mut await_scope, cont);
              return Err(other);
            }
          };
          let mut call_scope = await_scope.reborrow();
          if let Err(err) = call_scope.push_roots(&[reject, reason]) {
            async_teardown_continuation(&mut call_scope, cont);
            return Err(err);
          }
          let res = vm.call_with_host_and_hooks(
            host,
            &mut call_scope,
            hooks,
            reject,
            Value::Undefined,
            &[reason],
          );
          async_teardown_continuation(&mut call_scope, cont);
          return res.map(|_| Value::Undefined);
        }
        Err(err) => {
          async_teardown_continuation(&mut await_scope, cont);
          return Err(err);
        }
      };
      if let Err(err) = await_scope.push_root(awaited_promise) {
        async_teardown_continuation(&mut await_scope, cont);
        return Err(err);
      }

      let awaited_root = match await_scope.heap_mut().add_root(awaited_promise) {
        Ok(root) => root,
        Err(err) => {
          async_teardown_continuation(&mut await_scope, cont);
          return Err(err);
        }
      };
      cont.awaited_promise_root = Some(awaited_root);

      // Reinsert continuation before scheduling any resumption callbacks.
      if let Err(err) = vm.reserve_async_continuations(1) {
        async_teardown_continuation(&mut await_scope, cont);
        return Err(err);
      }
      vm.replace_async_continuation(id, VmAsyncContinuation::Ast(cont))?;

      let then_res = (|| -> Result<(), VmError> {
        let call_id = vm.async_resume_call_id()?;
        let intr = vm
          .intrinsics()
          .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;
        let job_realm = vm.current_realm();
        let script_or_module_token = match vm.get_active_script_or_module() {
          Some(sm) => Some(vm.intern_script_or_module(sm)?),
          None => None,
        };

        let name = await_scope.alloc_string("")?;
        let slots_fulfill = [Value::Number(id as f64), Value::Bool(false)];
        let on_fulfilled =
          await_scope.alloc_native_function_with_slots(call_id, None, name, 1, &slots_fulfill)?;
        await_scope.push_root(Value::Object(on_fulfilled))?;

        let name = await_scope.alloc_string("")?;
        let slots_reject = [Value::Number(id as f64), Value::Bool(true)];
        let on_rejected =
          await_scope.alloc_native_function_with_slots(call_id, None, name, 1, &slots_reject)?;
        await_scope.push_root(Value::Object(on_rejected))?;

        for cb in [on_fulfilled, on_rejected] {
          await_scope
            .heap_mut()
            .object_set_prototype(cb, Some(intr.function_prototype()))?;
          await_scope
            .heap_mut()
            .set_function_realm(cb, global_object)?;
          if let Some(realm) = job_realm {
            await_scope.heap_mut().set_function_job_realm(cb, realm)?;
          }
          if let Some(token) = script_or_module_token {
            await_scope
              .heap_mut()
              .set_function_script_or_module_token(cb, Some(token))?;
          }
        }

        let _ =
          crate::promise_ops::perform_promise_then_with_result_capability_with_host_and_hooks(
            vm,
            &mut await_scope,
            host,
            hooks,
            awaited_promise,
            Value::Object(on_fulfilled),
            Value::Object(on_rejected),
            None,
          )?;
        Ok(())
      })();

      if let Err(err) = then_res {
        if let Some(cont) = vm.take_async_continuation(id) {
          match cont {
            VmAsyncContinuation::Ast(cont) => async_teardown_continuation(&mut await_scope, cont),
            VmAsyncContinuation::Hir(cont) => {
              crate::hir_exec::hir_async_teardown_continuation(&mut await_scope, cont)
            }
          }
        }
        return Err(err);
      }

      Ok(Value::Undefined)
    }
    Err(err) => {
      // Fatal error during resumption: clean up roots/env to avoid leaks.
      async_teardown_continuation(scope, cont);
      Err(err)
    }
  }
}

pub(crate) fn arguments_param_map_getter_call(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  callee: GcObject,
  _this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  let env = scope
    .heap()
    .get_function_closure_env(callee)?
    .ok_or(VmError::InvariantViolation(
      "arguments parameter map getter missing closure env",
    ))?;
  let slots = scope.heap().get_function_native_slots(callee)?;
  let name_s = match slots.get(0).copied().unwrap_or(Value::Undefined) {
    Value::String(s) => s,
    _ => {
      return Err(VmError::InvariantViolation(
        "arguments parameter map getter missing parameter name",
      ))
    }
  };

  match scope.heap().env_get_binding_value_by_gc_string(env, name_s) {
    Ok(v) => Ok(v),
    // TDZ sentinel from `Heap::env_get_binding_value`.
    Err(VmError::Throw(Value::Null)) => {
      let name = scope.heap().get_string(name_s)?.to_utf8_lossy();
      let msg = crate::fallible_format::try_format_error_message(
        "Cannot access '",
        name.as_ref(),
        "' before initialization",
      )?;
      Err(throw_reference_error(vm, scope, &msg)?)
    }
    Err(err) => Err(err),
  }
}

pub(crate) fn arguments_param_map_setter_call(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  callee: GcObject,
  _this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let env = scope
    .heap()
    .get_function_closure_env(callee)?
    .ok_or(VmError::InvariantViolation(
      "arguments parameter map setter missing closure env",
    ))?;
  let slots = scope.heap().get_function_native_slots(callee)?;
  let name_s = match slots.get(0).copied().unwrap_or(Value::Undefined) {
    Value::String(s) => s,
    _ => {
      return Err(VmError::InvariantViolation(
        "arguments parameter map setter missing parameter name",
      ))
    }
  };
  let value = args.get(0).copied().unwrap_or(Value::Undefined);

  match scope
    .heap_mut()
    .env_set_mutable_binding_by_gc_string(env, name_s, value, false)
  {
    Ok(()) => Ok(Value::Undefined),
    // TDZ sentinel from `Heap::env_set_mutable_binding`.
    Err(VmError::Throw(Value::Null)) => {
      let name = scope.heap().get_string(name_s)?.to_utf8_lossy();
      let msg = crate::fallible_format::try_format_error_message(
        "Cannot access '",
        name.as_ref(),
        "' before initialization",
      )?;
      Err(throw_reference_error(vm, scope, &msg)?)
    }
    // `const` assignment sentinel from `Heap::env_set_mutable_binding`.
    Err(VmError::Throw(Value::Undefined)) => Err(throw_type_error(
      vm,
      scope,
      "Assignment to constant variable.",
    )?),
    Err(err) => Err(err),
  }
}

pub(crate) fn async_resume_call(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  callee: GcObject,
  _this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let slots = scope.heap().get_function_native_slots(callee)?;
  let id = match slots.get(0).copied().unwrap_or(Value::Undefined) {
    Value::Number(n) => n as u32,
    _ => {
      return Err(VmError::InvariantViolation(
        "async resume callback missing continuation id",
      ))
    }
  };
  let is_reject = match slots.get(1).copied().unwrap_or(Value::Undefined) {
    Value::Bool(b) => b,
    _ => {
      return Err(VmError::InvariantViolation(
        "async resume callback missing reject flag",
      ))
    }
  };

  let arg0 = args.get(0).copied().unwrap_or(Value::Undefined);

  let Some(cont) = vm.take_async_continuation(id) else {
    // Embeddings can abort in-progress async evaluation by tearing down continuations. In that
    // case, previously-registered resume callbacks must no-op.
    return Ok(Value::Undefined);
  };

  match cont {
    VmAsyncContinuation::Ast(mut cont) => {
      // The awaited promise has settled; it no longer needs to be rooted by the continuation.
      if let Some(root) = cont.awaited_promise_root.take() {
        scope.heap_mut().remove_root(root);
      }

      let resolve = match scope.heap().get_root(cont.resolve_root) {
        Some(v) => v,
        None => {
          async_teardown_continuation(scope, cont);
          return Err(VmError::InvariantViolation(
            "async continuation missing resolve root",
          ));
        }
      };
      let reject = match scope.heap().get_root(cont.reject_root) {
        Some(v) => v,
        None => {
          async_teardown_continuation(scope, cont);
          return Err(VmError::InvariantViolation(
            "async continuation missing reject root",
          ));
        }
      };

      let this = match scope.heap().get_root(cont.this_root) {
        Some(v) => v,
        None => {
          async_teardown_continuation(scope, cont);
          return Err(VmError::InvariantViolation(
            "async continuation missing this root",
          ));
        }
      };
      let new_target = match scope.heap().get_root(cont.new_target_root) {
        Some(v) => v,
        None => {
          async_teardown_continuation(scope, cont);
          return Err(VmError::InvariantViolation(
            "async continuation missing new.target root",
          ));
        }
      };
      let home_object = {
        let value = match scope.heap().get_root(cont.home_object_root) {
          Some(v) => v,
          None => {
            async_teardown_continuation(scope, cont);
            return Err(VmError::InvariantViolation(
              "async continuation missing home object root",
            ));
          }
        };
        match value {
          Value::Object(o) => Some(o),
          Value::Undefined => None,
          _ => {
            async_teardown_continuation(scope, cont);
            return Err(VmError::InvariantViolation(
              "async continuation home object root is not an object or undefined",
            ));
          }
        }
      };

      // If this continuation carries an execution context (used by top-level await in modules),
      // install it for the duration of the resumed evaluation segment so `import.meta` and dynamic
      // `import()` can observe the active module.
      if let Some(exec_ctx) = cont.exec_ctx {
        let mut vm_ctx = match vm.execution_context_guard(exec_ctx) {
          Ok(g) => g,
          Err(err) => {
            async_teardown_continuation(scope, cont);
            return Err(err);
          }
        };
        let prev_state = match vm_ctx.load_realm_state(scope.heap_mut(), exec_ctx.realm) {
          Ok(s) => s,
          Err(err) => {
            async_teardown_continuation(scope, cont);
            return Err(err);
          }
        };

        let res = (|| {
          let mut evaluator = Evaluator {
            vm: &mut *vm_ctx,
            host,
            hooks,
            env: &mut cont.env,
            strict: cont.strict,
            this,
            new_target,
            home_object,
            class_constructor: None,
            derived_constructor: false,
            this_initialized: true,
            this_root_idx: None,
          };

          let frames = mem::take(&mut cont.frames);
          let resume_input = if is_reject {
            AsyncResumeInput::Throw(arg0)
          } else {
            AsyncResumeInput::Next(arg0)
          };
          let result = async_resume_from_frames(&mut evaluator, scope, frames, resume_input);
          // `Evaluator::strict` can change temporarily during evaluation (e.g. class definition
          // evaluation forces strict mode). Persist the current strictness into the continuation so it
          // is restored correctly across subsequent `await` suspensions.
          cont.strict = evaluator.strict;
          // `this` / `new.target` can also be overridden temporarily by nested constructs that can
          // suspend (e.g. class static blocks). Persist them so resumed execution observes the correct
          // values.
          scope.heap_mut().set_root(cont.this_root, evaluator.this);
          scope
            .heap_mut()
            .set_root(cont.new_target_root, evaluator.new_target);
          scope.heap_mut().set_root(
            cont.home_object_root,
            evaluator
              .home_object
              .map(Value::Object)
              .unwrap_or(Value::Undefined),
          );

          async_handle_body_result(&mut *vm_ctx, scope, host, hooks, id, cont, resolve, reject, result)
        })();

        drop(vm_ctx);
        let restore_res = vm.restore_realm_state(scope.heap_mut(), prev_state);
        return match (res, restore_res) {
          (Ok(v), Ok(())) => Ok(v),
          (Err(err), Ok(())) => Err(err),
          (Ok(_), Err(err)) => Err(err),
          (Err(err), Err(_)) => Err(err),
        };
      }

      let mut evaluator = Evaluator {
        vm,
        host,
        hooks,
        env: &mut cont.env,
        strict: cont.strict,
        this,
        new_target,
        home_object,
        class_constructor: None,
        derived_constructor: false,
        this_initialized: true,
        this_root_idx: None,
      };

      let frames = mem::take(&mut cont.frames);
      let resume_input = if is_reject {
        AsyncResumeInput::Throw(arg0)
      } else {
        AsyncResumeInput::Next(arg0)
      };
      let result = async_resume_from_frames(&mut evaluator, scope, frames, resume_input);
      // `Evaluator::strict` can change temporarily during evaluation (e.g. class definition
      // evaluation forces strict mode). Persist the current strictness into the continuation so it
      // is restored correctly across subsequent `await` suspensions.
      cont.strict = evaluator.strict;
      // Persist `this` / `new.target` across suspensions (see comment in the exec_ctx branch above).
      scope.heap_mut().set_root(cont.this_root, evaluator.this);
      scope
        .heap_mut()
        .set_root(cont.new_target_root, evaluator.new_target);
      scope.heap_mut().set_root(
        cont.home_object_root,
        evaluator
          .home_object
          .map(Value::Object)
          .unwrap_or(Value::Undefined),
      );

      async_handle_body_result(vm, scope, host, hooks, id, cont, resolve, reject, result)
    }
    VmAsyncContinuation::Hir(cont) => crate::hir_exec::hir_async_resume_continuation(
      vm, scope, host, hooks, id, cont, is_reject, arg0,
    ),
  }
}

enum AsyncBodyResult {
  CompleteOk(Value),
  CompleteThrow(Value),
  Await {
    kind: AsyncSuspendKind,
    await_value: Value,
    frames: VecDeque<AsyncFrame>,
  },
}

#[derive(Debug, Clone, Copy)]
enum AsyncResumeInput {
  Next(Value),
  Throw(Value),
  Return(Value),
}

pub(crate) fn coerce_error_to_throw_for_async(vm: &Vm, scope: &mut Scope<'_>, err: VmError) -> VmError {
  match err {
    VmError::Throw(_) | VmError::ThrowWithStack { .. } => err,
    VmError::TypeError(message) => throw_type_error(vm, scope, message).unwrap_or_else(|e| e),
    VmError::RangeError(message) => throw_range_error(vm, scope, message).unwrap_or_else(|e| e),
    VmError::NotCallable => {
      throw_type_error(vm, scope, "value is not callable").unwrap_or_else(|e| e)
    }
    VmError::NotConstructable => {
      throw_type_error(vm, scope, "value is not a constructor").unwrap_or_else(|e| e)
    }
    VmError::PrototypeCycle => throw_type_error(vm, scope, "prototype cycle").unwrap_or_else(|e| e),
    VmError::PrototypeChainTooDeep => {
      throw_type_error(vm, scope, "prototype chain too deep").unwrap_or_else(|e| e)
    }
    VmError::InvalidPropertyDescriptorPatch => throw_type_error(
      vm,
      scope,
      "invalid property descriptor patch: cannot mix data and accessor fields",
    )
    .unwrap_or_else(|e| e),
    other => other,
  }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum AsyncGeneratorResumeKind {
  Await = 0,
  Yield = 1,
  Return = 2,
}

impl AsyncGeneratorResumeKind {
  #[inline]
  fn to_slot(self) -> Value {
    Value::Number(self as u8 as f64)
  }

  fn from_slot(value: Value) -> Result<Self, VmError> {
    match value {
      Value::Number(n) if n == Self::Await as u8 as f64 => Ok(Self::Await),
      Value::Number(n) if n == Self::Yield as u8 as f64 => Ok(Self::Yield),
      Value::Number(n) if n == Self::Return as u8 as f64 => Ok(Self::Return),
      _ => Err(VmError::InvariantViolation(
        "async generator resume callback missing/invalid kind slot",
      )),
    }
  }
}

fn async_generator_extract_throw_reason(
  vm: &Vm,
  scope: &mut Scope<'_>,
  err: VmError,
) -> Result<Value, VmError> {
  let err = coerce_error_to_throw_for_async(vm, scope, err);
  match err {
    VmError::Throw(reason) | VmError::ThrowWithStack { value: reason, .. } => Ok(reason),
    other => Err(other),
  }
}

fn async_generator_create_iterator_result_object(
  vm: &Vm,
  scope: &mut Scope<'_>,
  value: Value,
  done: bool,
) -> Result<Value, VmError> {
  let intr = vm
    .intrinsics()
    .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;

  // Root inputs across allocation and property definition.
  let mut scope = scope.reborrow();
  scope.push_root(value)?;

  let obj = scope.alloc_object_with_prototype(Some(intr.object_prototype()))?;
  scope.push_root(Value::Object(obj))?;

  let value_key_s = scope.alloc_string("value")?;
  scope.push_root(Value::String(value_key_s))?;
  let done_key_s = scope.alloc_string("done")?;
  scope.push_root(Value::String(done_key_s))?;

  let value_key = PropertyKey::from_string(value_key_s);
  let done_key = PropertyKey::from_string(done_key_s);

  let value_desc = PropertyDescriptor {
    enumerable: true,
    configurable: true,
    kind: PropertyKind::Data {
      value,
      writable: true,
    },
  };
  let done_desc = PropertyDescriptor {
    enumerable: true,
    configurable: true,
    kind: PropertyKind::Data {
      value: Value::Bool(done),
      writable: true,
    },
  };

  scope.define_property(obj, value_key, value_desc)?;
  scope.define_property(obj, done_key, done_desc)?;

  Ok(Value::Object(obj))
}

fn async_generator_call_promise_handler(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  handler: Value,
  arg0: Value,
) -> Result<(), VmError> {
  let mut scope = scope.reborrow();
  scope.push_roots(&[handler, arg0])?;
  let _ = vm.call_with_host_and_hooks(host, &mut scope, hooks, handler, Value::Undefined, &[arg0])?;
  Ok(())
}

fn async_generator_resolve_request_promise(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  req: crate::heap::AsyncGeneratorRequest,
  result: Value,
) -> Result<(), VmError> {
  async_generator_call_promise_handler(vm, scope, host, hooks, req.capability.resolve, result)
}

fn async_generator_reject_request_promise(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  req: crate::heap::AsyncGeneratorRequest,
  reason: Value,
) -> Result<(), VmError> {
  async_generator_call_promise_handler(vm, scope, host, hooks, req.capability.reject, reason)
}

fn async_gen_root_values_for_continuation(
  scope: &mut Scope<'_>,
  cont: &AsyncGeneratorContinuation,
) -> Result<(), VmError> {
  let mut values: Vec<Value> = Vec::new();
  values
    .try_reserve_exact(
      2usize
        .saturating_add(cont.args.len())
        .saturating_add(if cont.home_object.is_some() { 1 } else { 0 }),
    )
    .map_err(|_| VmError::OutOfMemory)?;
  values.push(cont.this);
  values.push(cont.new_target);
  if let Some(home_object) = cont.home_object {
    values.push(Value::Object(home_object));
  }
  values.extend_from_slice(&cont.args);

  // Ensure the lexical environment is treated as a root while growing the root stack. The env
  // itself is rooted via `RuntimeEnv::lexical_root` during execution.
  scope.push_roots_with_extra_roots(&values, &[], &[cont.env.lexical_env()])?;
  Ok(())
}

fn async_generator_attach_resume_callbacks(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  gen_obj: GcObject,
  awaited_promise: Value,
  kind: AsyncGeneratorResumeKind,
) -> Result<(), VmError> {
  let call_id = vm.async_generator_resume_call_id()?;
  let intr = vm
    .intrinsics()
    .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;

  // Promise jobs run under a captured JobRealm and ScriptOrModule token so dynamic import and
  // `import.meta` can observe the active module/script when needed.
  let job_realm = vm.current_realm();
  let script_or_module_token = match vm.get_active_script_or_module() {
    Some(sm) => Some(vm.intern_script_or_module(sm)?),
    None => None,
  };

  let mut scope = scope.reborrow();
  scope.push_root(Value::Object(gen_obj))?;
  scope.push_root(awaited_promise)?;

  let name = scope.alloc_string("")?;
  let slots_fulfill = [Value::Object(gen_obj), Value::Bool(false), kind.to_slot()];
  let on_fulfilled = scope.alloc_native_function_with_slots(call_id, None, name, 1, &slots_fulfill)?;
  scope.push_root(Value::Object(on_fulfilled))?;

  let name = scope.alloc_string("")?;
  let slots_reject = [Value::Object(gen_obj), Value::Bool(true), kind.to_slot()];
  let on_rejected = scope.alloc_native_function_with_slots(call_id, None, name, 1, &slots_reject)?;
  scope.push_root(Value::Object(on_rejected))?;

  for cb in [on_fulfilled, on_rejected] {
    scope
      .heap_mut()
      .object_set_prototype(cb, Some(intr.function_prototype()))?;
    if let Some(realm) = job_realm {
      scope.heap_mut().set_function_job_realm(cb, realm)?;
    }
    if let Some(token) = script_or_module_token {
      scope
        .heap_mut()
        .set_function_script_or_module_token(cb, Some(token))?;
    }
  }

  crate::promise_ops::perform_promise_then_no_capability_with_host_and_hooks(
    vm,
    &mut scope,
    host,
    hooks,
    awaited_promise,
    Value::Object(on_fulfilled),
    Value::Object(on_rejected),
  )?;

  Ok(())
}

fn async_generator_schedule_await(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  gen_obj: GcObject,
  awaited_promise: Value,
  kind: AsyncGeneratorResumeKind,
  mut state: AsyncGeneratorRuntimeState,
) -> Result<(), VmError> {
  let mut scope = scope.reborrow();
  scope.push_root(awaited_promise)?;

  let root = scope.heap_mut().add_root(awaited_promise)?;
  state.awaited_promise_root = Some(root);

  vm.reserve_async_generator_continuations(1)?;
  vm.replace_async_generator_continuation(gen_obj, state)?;

  let then_res =
    async_generator_attach_resume_callbacks(vm, &mut scope, host, hooks, gen_obj, awaited_promise, kind);
  if let Err(err) = then_res {
    if let Some(state) = vm.take_async_generator_continuation(gen_obj) {
      async_generator_teardown_runtime_state(&mut scope, state);
    }
    return Err(err);
  }

  Ok(())
}

fn async_generator_resume_frames(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _gen_obj: GcObject,
  mut cont: Box<AsyncGeneratorContinuation>,
  frames: VecDeque<AsyncFrame>,
  resume_input: AsyncResumeInput,
) -> Result<(AsyncBodyResult, Box<AsyncGeneratorContinuation>), VmError> {
  // Root `this`, `new.target`, home object, and args while the continuation is moved out of the heap.
  async_gen_root_values_for_continuation(scope, &cont)?;
  cont.env.lexical_root = Some(scope.heap_mut().add_env_root(cont.env.lexical_env())?);

  let this = cont.this;
  let new_target = cont.new_target;
  let home_object = cont.home_object;

  let mut evaluator = Evaluator {
    vm,
    host,
    hooks,
    env: &mut cont.env,
    strict: cont.strict,
    this,
    new_target,
    home_object,
    class_constructor: None,
    derived_constructor: false,
    this_initialized: true,
    this_root_idx: None,
  };

  let result = async_resume_from_frames(&mut evaluator, scope, frames, resume_input)?;
  // Persist strictness and `this`/`new.target`/`home_object` overrides across suspensions.
  cont.strict = evaluator.strict;
  cont.this = evaluator.this;
  cont.new_target = evaluator.new_target;
  cont.home_object = evaluator.home_object;

  Ok((result, cont))
}

fn async_generator_start(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _gen_obj: GcObject,
  mut cont: Box<AsyncGeneratorContinuation>,
) -> Result<(AsyncBodyResult, Box<AsyncGeneratorContinuation>), VmError> {
  async_gen_root_values_for_continuation(scope, &cont)?;
  cont.env.lexical_root = Some(scope.heap_mut().add_env_root(cont.env.lexical_env())?);

  let this = cont.this;
  let new_target = cont.new_target;
  let home_object = cont.home_object;
  let func = cont.func.clone();
  let args: &[Value] = &cont.args;

  let mut evaluator = Evaluator {
    vm,
    host,
    hooks,
    env: &mut cont.env,
    strict: cont.strict,
    this,
    new_target,
    home_object,
    class_constructor: None,
    derived_constructor: false,
    this_initialized: true,
    this_root_idx: None,
  };

  if let Err(err) = evaluator.instantiate_function(scope, func.as_ref(), args) {
    let err = coerce_error_to_throw_for_async(vm, scope, err);
    match err {
      VmError::Throw(reason) | VmError::ThrowWithStack { value: reason, .. } => {
        return Ok((AsyncBodyResult::CompleteThrow(reason), cont))
      }
      other => return Err(other),
    }
  }

  let result = async_start_body(&mut evaluator, scope, &func)?;
  // Persist strictness and `this`/`new.target`/`home_object` overrides across suspensions.
  cont.strict = evaluator.strict;
  cont.this = evaluator.this;
  cont.new_target = evaluator.new_target;
  cont.home_object = evaluator.home_object;

  Ok((result, cont))
}

fn async_generator_handle_execution_result(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  gen_obj: GcObject,
  mut cont: Box<AsyncGeneratorContinuation>,
  mut state: AsyncGeneratorRuntimeState,
  mut result: AsyncBodyResult,
) -> Result<bool, VmError> {
  loop {
    match result {
      AsyncBodyResult::Await {
        kind: AsyncSuspendKind::Await,
        await_value,
        frames,
      } => {
        state.frames = frames;

        // `await` in an async generator uses the same semantics as `await` in async functions:
        // `PromiseResolve(%Promise%, value)` with no derived promise/species side effects.
        let awaited_promise = match promise_resolve_for_await_with_host_and_hooks(
          vm,
          scope,
          host,
          hooks,
          await_value,
        ) {
          Ok(p) => p,
          Err(err) if err.is_throw_completion() => {
            let reason = async_generator_extract_throw_reason(vm, scope, err)?;
            // Resume the suspended `await` as a throw completion so generator code can catch it.
            let frames = mem::take(&mut state.frames);
            let (r, c) = async_generator_resume_frames(
              vm,
              scope,
              host,
              hooks,
              gen_obj,
              cont,
              frames,
              AsyncResumeInput::Throw(reason),
            )?;
            cont = c;
            result = r;
            continue;
          }
          Err(err) => return Err(err),
        };

        // Suspend: store frames in the VM and wire a Promise job to resume.
        cont.env.teardown(scope.heap_mut());
        scope
          .heap_mut()
          .async_generator_set_continuation(gen_obj, Some(cont))?;

        async_generator_schedule_await(
          vm,
          scope,
          host,
          hooks,
          gen_obj,
          awaited_promise,
          AsyncGeneratorResumeKind::Await,
          state,
        )?;
        return Ok(false);
      }
      AsyncBodyResult::Await {
        kind: AsyncSuspendKind::AwaitResolved,
        await_value: awaited_promise,
        frames,
      } => {
        state.frames = frames;

        // `AwaitResolved` means the internal `PromiseResolve` step of `Await` has already happened
        // (e.g. `AsyncIteratorClose` during `for await..of`), so we must not call `PromiseResolve`
        // again or we'd observe `promise.constructor` twice.
        debug_assert!(
          matches!(awaited_promise, Value::Object(obj) if scope.heap().is_promise_object(obj)),
          "AwaitResolved suspension must carry a Promise object"
        );
        cont.env.teardown(scope.heap_mut());
        scope
          .heap_mut()
          .async_generator_set_continuation(gen_obj, Some(cont))?;

        async_generator_schedule_await(
          vm,
          scope,
          host,
          hooks,
          gen_obj,
          awaited_promise,
          AsyncGeneratorResumeKind::Await,
          state,
        )?;
        return Ok(false);
      }

      AsyncBodyResult::Await {
        kind: AsyncSuspendKind::AwaitResolved,
        await_value: awaited_promise,
        frames,
      } => {
        state.frames = frames;

        // The `PromiseResolve` step for `Await` was already performed by an internal algorithm (e.g.
        // `AsyncIteratorClose`). Do not call `PromiseResolve` again or we'd observe
        // `promise.constructor` twice.
        cont.env.teardown(scope.heap_mut());
        scope
          .heap_mut()
          .async_generator_set_continuation(gen_obj, Some(cont))?;

        async_generator_schedule_await(
          vm,
          scope,
          host,
          hooks,
          gen_obj,
          awaited_promise,
          AsyncGeneratorResumeKind::Await,
          state,
        )?;
        return Ok(false);
      }

      AsyncBodyResult::Await {
        kind: AsyncSuspendKind::Yield,
        await_value,
        frames,
      } => {
        state.frames = frames;

        // `yield` awaits its operand, but then suspends awaiting the *next request* (consumer-driven).
        // We await the operand with immediate thenable assimilation so `then` is called synchronously.
        let awaited_promise = match crate::promise_ops::promise_resolve_thenable_immediate_with_host_and_hooks(
          vm,
          scope,
          host,
          hooks,
          await_value,
        ) {
          Ok(p) => p,
          Err(err) if err.is_throw_completion() => {
            let reason = async_generator_extract_throw_reason(vm, scope, err)?;
            // Treat PromiseResolve errors as an exception thrown from the yield expression.
            let frames = mem::take(&mut state.frames);
            let (r, c) = async_generator_resume_frames(
              vm,
              scope,
              host,
              hooks,
              gen_obj,
              cont,
              frames,
              AsyncResumeInput::Throw(reason),
            )?;
            cont = c;
            result = r;
            continue;
          }
          Err(err) => return Err(err),
        };

        cont.env.teardown(scope.heap_mut());
        scope
          .heap_mut()
          .async_generator_set_continuation(gen_obj, Some(cont))?;

        async_generator_schedule_await(
          vm,
          scope,
          host,
          hooks,
          gen_obj,
          awaited_promise,
          AsyncGeneratorResumeKind::Yield,
          state,
        )?;
        return Ok(false);
      }

      AsyncBodyResult::Await {
        kind: AsyncSuspendKind::YieldIteratorResult,
        await_value: iter_result,
        frames,
      } => {
        // Yield the delegate iterator result object directly.
        state.frames = frames;
        state.awaited_promise_root = None;

        // Resolve the current request with the iterator result object and suspend.
        let req = scope
          .heap()
          .async_generator_request_queue_peek(gen_obj)?
          .ok_or(VmError::InvariantViolation(
            "async generator yield without a pending request",
          ))?;

        cont.env.teardown(scope.heap_mut());
        scope
          .heap_mut()
          .async_generator_set_continuation(gen_obj, Some(cont))?;

        // Store continuation frames for the next request.
        vm.reserve_async_generator_continuations(1)?;
        vm.replace_async_generator_continuation(gen_obj, state)?;

        async_generator_resolve_request_promise(vm, scope, host, hooks, req, iter_result)?;
        let _ = scope.heap_mut().async_generator_request_queue_pop(gen_obj)?;

        scope
          .heap_mut()
          .async_generator_set_state(gen_obj, AsyncGeneratorState::SuspendedYield)?;

        return Ok(true);
      }

      AsyncBodyResult::CompleteOk(v) => {
        // Generator completed: await the final return value (done: true) before resolving the
        // current request.
        cont.env.teardown(scope.heap_mut());
        scope.heap_mut().async_generator_set_continuation(gen_obj, None)?;
        scope
          .heap_mut()
          .async_generator_set_state(gen_obj, AsyncGeneratorState::AwaitingReturn)?;

        state.frames = VecDeque::new();

        let awaited_promise = match crate::promise_ops::promise_resolve_thenable_immediate_with_host_and_hooks(
          vm,
          scope,
          host,
          hooks,
          v,
        ) {
          Ok(p) => p,
          Err(err) if err.is_throw_completion() => {
            let reason = async_generator_extract_throw_reason(vm, scope, err)?;
            // Awaiting the final return value failed: reject the current request and complete.
            let req = scope
              .heap()
              .async_generator_request_queue_peek(gen_obj)?
              .ok_or(VmError::InvariantViolation(
                "async generator completed without a pending request",
              ))?;
            async_generator_reject_request_promise(vm, scope, host, hooks, req, reason)?;
            let _ = scope.heap_mut().async_generator_request_queue_pop(gen_obj)?;
            scope
              .heap_mut()
              .async_generator_set_state(gen_obj, AsyncGeneratorState::Completed)?;
            return Ok(true);
          }
          Err(err) => return Err(err),
        };

        async_generator_schedule_await(
          vm,
          scope,
          host,
          hooks,
          gen_obj,
          awaited_promise,
          AsyncGeneratorResumeKind::Return,
          state,
        )?;
        return Ok(false);
      }

      AsyncBodyResult::CompleteThrow(reason) => {
        // Uncaught exception: reject the current request and complete the generator.
        cont.env.teardown(scope.heap_mut());
        scope.heap_mut().async_generator_set_continuation(gen_obj, None)?;
        scope
          .heap_mut()
          .async_generator_set_state(gen_obj, AsyncGeneratorState::Completed)?;

        let req = scope
          .heap()
          .async_generator_request_queue_peek(gen_obj)?
          .ok_or(VmError::InvariantViolation(
            "async generator threw without a pending request",
          ))?;
        async_generator_reject_request_promise(vm, scope, host, hooks, req, reason)?;
        let _ = scope.heap_mut().async_generator_request_queue_pop(gen_obj)?;
        return Ok(true);
      }
    }
  }
}

pub(crate) fn async_generator_resume_next(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  gen_obj: GcObject,
) -> Result<(), VmError> {
  let mut scope = scope.reborrow();
  scope.push_root(Value::Object(gen_obj))?;

  loop {
    let state = scope.heap().async_generator_state(gen_obj)?;
    if matches!(state, AsyncGeneratorState::Executing | AsyncGeneratorState::AwaitingReturn) {
      return Ok(());
    }

    let Some(req) = scope.heap().async_generator_request_queue_peek(gen_obj)? else {
      return Ok(());
    };

    match state {
      AsyncGeneratorState::Completed => match req.kind {
        crate::heap::AsyncGeneratorRequestKind::Next(_) => {
          let req = scope
            .heap_mut()
            .async_generator_request_queue_pop(gen_obj)?
            .ok_or(VmError::InvariantViolation(
              "async generator request queue became empty unexpectedly",
            ))?;
          let iter_result =
            async_generator_create_iterator_result_object(vm, &mut scope, Value::Undefined, true)?;
          async_generator_resolve_request_promise(vm, &mut scope, host, hooks, req, iter_result)?;
          continue;
        }
        crate::heap::AsyncGeneratorRequestKind::Throw(reason) => {
          let req = scope
            .heap_mut()
            .async_generator_request_queue_pop(gen_obj)?
            .ok_or(VmError::InvariantViolation(
              "async generator request queue became empty unexpectedly",
            ))?;
          async_generator_reject_request_promise(vm, &mut scope, host, hooks, req, reason)?;
          continue;
        }
        crate::heap::AsyncGeneratorRequestKind::Return(v) => {
          // Await the return argument and resolve to `{ value: awaited, done: true }`.
          scope
            .heap_mut()
            .async_generator_set_state(gen_obj, AsyncGeneratorState::AwaitingReturn)?;
          // Schedule the await with an empty runtime state.
          let awaited_promise =
            crate::promise_ops::promise_resolve_thenable_immediate_with_host_and_hooks(vm, &mut scope, host, hooks, v);
          let awaited_promise = match awaited_promise {
            Ok(p) => p,
            Err(err) if err.is_throw_completion() => {
              // PromiseResolve threw: reject the `return()` promise and complete.
              let reason = async_generator_extract_throw_reason(vm, &mut scope, err)?;
              let req = scope
                .heap()
                .async_generator_request_queue_peek(gen_obj)?
                .ok_or(VmError::InvariantViolation(
                  "async generator return without a pending request",
                ))?;
              async_generator_reject_request_promise(vm, &mut scope, host, hooks, req, reason)?;
              let _ = scope.heap_mut().async_generator_request_queue_pop(gen_obj)?;
              scope
                .heap_mut()
                .async_generator_set_state(gen_obj, AsyncGeneratorState::Completed)?;
              continue;
            }
            Err(err) => return Err(err),
          };

          let state = AsyncGeneratorRuntimeState {
            frames: VecDeque::new(),
            awaited_promise_root: None,
          };
          async_generator_schedule_await(
            vm,
            &mut scope,
            host,
            hooks,
            gen_obj,
            awaited_promise,
            AsyncGeneratorResumeKind::Return,
            state,
          )?;
          return Ok(());
        }
      },

      AsyncGeneratorState::SuspendedStart => match req.kind {
        crate::heap::AsyncGeneratorRequestKind::Throw(reason) => {
          // Throw on SuspendedStart rejects the request and completes without executing the body.
          let req = scope
            .heap_mut()
            .async_generator_request_queue_pop(gen_obj)?
            .ok_or(VmError::InvariantViolation(
              "async generator request queue became empty unexpectedly",
            ))?;
          scope.heap_mut().async_generator_set_continuation(gen_obj, None)?;
          scope
            .heap_mut()
            .async_generator_set_state(gen_obj, AsyncGeneratorState::Completed)?;
          async_generator_reject_request_promise(vm, &mut scope, host, hooks, req, reason)?;
          continue;
        }
        crate::heap::AsyncGeneratorRequestKind::Return(v) => {
          // Return on SuspendedStart resolves to done:true without executing the body.
          scope
            .heap_mut()
            .async_generator_set_continuation(gen_obj, None)?;
          scope
            .heap_mut()
            .async_generator_set_state(gen_obj, AsyncGeneratorState::AwaitingReturn)?;

          let awaited_promise =
            crate::promise_ops::promise_resolve_thenable_immediate_with_host_and_hooks(vm, &mut scope, host, hooks, v);
          let awaited_promise = match awaited_promise {
            Ok(p) => p,
            Err(err) if err.is_throw_completion() => {
              let reason = async_generator_extract_throw_reason(vm, &mut scope, err)?;
              let req = scope
                .heap()
                .async_generator_request_queue_peek(gen_obj)?
                .ok_or(VmError::InvariantViolation(
                  "async generator return without a pending request",
                ))?;
              async_generator_reject_request_promise(vm, &mut scope, host, hooks, req, reason)?;
              let _ = scope.heap_mut().async_generator_request_queue_pop(gen_obj)?;
              scope
                .heap_mut()
                .async_generator_set_state(gen_obj, AsyncGeneratorState::Completed)?;
              continue;
            }
            Err(err) => return Err(err),
          };

          let state = AsyncGeneratorRuntimeState {
            frames: VecDeque::new(),
            awaited_promise_root: None,
          };
          async_generator_schedule_await(
            vm,
            &mut scope,
            host,
            hooks,
            gen_obj,
            awaited_promise,
            AsyncGeneratorResumeKind::Return,
            state,
          )?;
          return Ok(());
        }
        crate::heap::AsyncGeneratorRequestKind::Next(_) => {
          // Start execution (first `next` argument is ignored).
          scope
            .heap_mut()
            .async_generator_set_state(gen_obj, AsyncGeneratorState::Executing)?;

          let cont = scope
            .heap_mut()
            .async_generator_take_continuation(gen_obj)?
            .ok_or(VmError::InvariantViolation(
              "async generator missing continuation in suspendedStart",
            ))?;

          let state = AsyncGeneratorRuntimeState {
            frames: VecDeque::new(),
            awaited_promise_root: None,
          };

          let (result, cont) = async_generator_start(vm, &mut scope, host, hooks, gen_obj, cont)?;
          let should_continue =
            async_generator_handle_execution_result(vm, &mut scope, host, hooks, gen_obj, cont, state, result)?;
          if !should_continue {
            return Ok(());
          }
          continue;
        }
      },

      AsyncGeneratorState::SuspendedYield => {
        scope
          .heap_mut()
          .async_generator_set_state(gen_obj, AsyncGeneratorState::Executing)?;

        let mut state = vm
          .take_async_generator_continuation(gen_obj)
          .ok_or(VmError::InvariantViolation(
            "async generator missing runtime state in suspendedYield",
          ))?;
        let frames = mem::take(&mut state.frames);

        let cont = scope
          .heap_mut()
          .async_generator_take_continuation(gen_obj)?
          .ok_or(VmError::InvariantViolation(
            "async generator missing continuation in suspendedYield",
          ))?;

        let resume_input = match req.kind {
          crate::heap::AsyncGeneratorRequestKind::Next(v) => AsyncResumeInput::Next(v),
          crate::heap::AsyncGeneratorRequestKind::Throw(reason) => AsyncResumeInput::Throw(reason),
          crate::heap::AsyncGeneratorRequestKind::Return(v) => AsyncResumeInput::Return(v),
        };

        let (result, cont) =
          async_generator_resume_frames(vm, &mut scope, host, hooks, gen_obj, cont, frames, resume_input)?;

        let should_continue =
          async_generator_handle_execution_result(vm, &mut scope, host, hooks, gen_obj, cont, state, result)?;
        if !should_continue {
          return Ok(());
        }
        continue;
      }

      AsyncGeneratorState::Executing | AsyncGeneratorState::AwaitingReturn => unreachable!(),
    }
  }
}

pub(crate) fn async_generator_resume_call(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  callee: GcObject,
  _this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let slots = scope.heap().get_function_native_slots(callee)?;
  let gen_obj = match slots.get(0).copied().unwrap_or(Value::Undefined) {
    Value::Object(o) => o,
    _ => {
      return Err(VmError::InvariantViolation(
        "async generator resume callback missing generator object slot",
      ))
    }
  };
  let is_reject = match slots.get(1).copied().unwrap_or(Value::Undefined) {
    Value::Bool(b) => b,
    _ => {
      return Err(VmError::InvariantViolation(
        "async generator resume callback missing reject flag",
      ))
    }
  };
  let kind = AsyncGeneratorResumeKind::from_slot(slots.get(2).copied().unwrap_or(Value::Undefined))?;

  let Some(mut state) = vm.take_async_generator_continuation(gen_obj) else {
    // Embeddings can abort in-progress async generator evaluation by tearing down microtasks. In
    // that case, previously-registered resume callbacks must no-op.
    return Ok(Value::Undefined);
  };

  if let Some(root) = state.awaited_promise_root.take() {
    scope.heap_mut().remove_root(root);
  }

  let arg0 = args.get(0).copied().unwrap_or(Value::Undefined);

  match kind {
    AsyncGeneratorResumeKind::Return => {
      // Final return value has settled; resolve/reject the current request and complete.
      let req = scope
        .heap()
        .async_generator_request_queue_peek(gen_obj)?
        .ok_or(VmError::InvariantViolation(
          "async generator return resume without a pending request",
        ))?;

      if is_reject {
        async_generator_reject_request_promise(vm, scope, host, hooks, req, arg0)?;
      } else {
        let iter_result = async_generator_create_iterator_result_object(vm, scope, arg0, true)?;
        async_generator_resolve_request_promise(vm, scope, host, hooks, req, iter_result)?;
      }
      let _ = scope.heap_mut().async_generator_request_queue_pop(gen_obj)?;

      scope
        .heap_mut()
        .async_generator_set_state(gen_obj, AsyncGeneratorState::Completed)?;
      scope.heap_mut().async_generator_set_continuation(gen_obj, None)?;

      // Tear down any stored frames/roots (should be empty in return-await).
      async_generator_teardown_runtime_state(scope, state);

      async_generator_resume_next(vm, scope, host, hooks, gen_obj)?;
      return Ok(Value::Undefined);
    }

    AsyncGeneratorResumeKind::Yield => {
      if !is_reject {
        // Yield operand fulfilled: resolve the current request and suspend awaiting next request.
        let req = scope
          .heap()
          .async_generator_request_queue_peek(gen_obj)?
          .ok_or(VmError::InvariantViolation(
            "async generator yield resume without a pending request",
          ))?;
        let iter_result = async_generator_create_iterator_result_object(vm, scope, arg0, false)?;
        async_generator_resolve_request_promise(vm, scope, host, hooks, req, iter_result)?;
        let _ = scope.heap_mut().async_generator_request_queue_pop(gen_obj)?;

        scope
          .heap_mut()
          .async_generator_set_state(gen_obj, AsyncGeneratorState::SuspendedYield)?;

        // Store frames for the next request.
        vm.reserve_async_generator_continuations(1)?;
        vm.replace_async_generator_continuation(gen_obj, state)?;

        async_generator_resume_next(vm, scope, host, hooks, gen_obj)?;
        return Ok(Value::Undefined);
      }

      // Yield operand rejected: resume generator execution as if the yield expression threw.
      let frames = mem::take(&mut state.frames);
      let cont = scope
        .heap_mut()
        .async_generator_take_continuation(gen_obj)?
        .ok_or(VmError::InvariantViolation(
          "async generator missing continuation while resuming yield rejection",
        ))?;
      let (result, cont) = async_generator_resume_frames(
        vm,
        scope,
        host,
        hooks,
        gen_obj,
        cont,
        frames,
        AsyncResumeInput::Throw(arg0),
      )?;
      // Generator is already in `Executing`.
      let _ = async_generator_handle_execution_result(vm, scope, host, hooks, gen_obj, cont, state, result)?;
      async_generator_resume_next(vm, scope, host, hooks, gen_obj)?;
      return Ok(Value::Undefined);
    }

    AsyncGeneratorResumeKind::Await => {
      let frames = mem::take(&mut state.frames);
      let cont = scope
        .heap_mut()
        .async_generator_take_continuation(gen_obj)?
        .ok_or(VmError::InvariantViolation(
          "async generator missing continuation while resuming await",
        ))?;

      let resume_input = if is_reject {
        AsyncResumeInput::Throw(arg0)
      } else {
        AsyncResumeInput::Next(arg0)
      };

      let (result, cont) =
        async_generator_resume_frames(vm, scope, host, hooks, gen_obj, cont, frames, resume_input)?;
      let _ = async_generator_handle_execution_result(vm, scope, host, hooks, gen_obj, cont, state, result)?;
      async_generator_resume_next(vm, scope, host, hooks, gen_obj)?;
      return Ok(Value::Undefined);
    }
  }
}

#[inline]
fn optional_chain_sentinel_value(vm: &Vm) -> Result<Value, VmError> {
  let intr = vm
    .intrinsics()
    .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;
  Ok(Value::Symbol(intr.optional_chain_sentinel()))
}

#[inline]
fn is_optional_chain_sentinel(vm: &Vm, value: Value) -> bool {
  let Some(intr) = vm.intrinsics() else {
    return false;
  };
  value == Value::Symbol(intr.optional_chain_sentinel())
}

#[inline]
fn convert_optional_chain_sentinel_to_undefined(vm: &Vm, value: Value) -> Value {
  if is_optional_chain_sentinel(vm, value) {
    Value::Undefined
  } else {
    value
  }
}

fn expr_contains_await(expr: &Node<Expr>) -> bool {
  match &*expr.stx {
    Expr::Unary(unary) => {
      matches!(
        unary.stx.operator,
        OperatorName::Await | OperatorName::Yield | OperatorName::YieldDelegated
      ) || expr_contains_await(&unary.stx.argument)
    }
    Expr::UnaryPostfix(unary) => expr_contains_await(&unary.stx.argument),
    Expr::Binary(binary) => {
      expr_contains_await(&binary.stx.left) || expr_contains_await(&binary.stx.right)
    }
    Expr::Cond(cond) => {
      expr_contains_await(&cond.stx.test)
        || expr_contains_await(&cond.stx.consequent)
        || expr_contains_await(&cond.stx.alternate)
    }
    Expr::Member(member) => expr_contains_await(&member.stx.left),
    Expr::ComputedMember(member) => {
      expr_contains_await(&member.stx.object) || expr_contains_await(&member.stx.member)
    }
    Expr::Call(call) => {
      expr_contains_await(&call.stx.callee)
        || call
          .stx
          .arguments
          .iter()
          .any(|arg| expr_contains_await(&arg.stx.value))
    }
    Expr::Import(import) => {
      expr_contains_await(&import.stx.module)
        || import
          .stx
          .attributes
          .as_ref()
          .is_some_and(|attrs| expr_contains_await(attrs))
    }
    Expr::TaggedTemplate(tag) => {
      expr_contains_await(&tag.stx.function)
        || tag.stx.parts.iter().any(|part| match part {
          LitTemplatePart::Substitution(expr) => expr_contains_await(expr),
          LitTemplatePart::String(_) => false,
        })
    }
    Expr::LitArr(arr) => arr.stx.elements.iter().any(|elem| match elem {
      LitArrElem::Single(expr) | LitArrElem::Rest(expr) => expr_contains_await(expr),
      LitArrElem::Empty => false,
    }),
    Expr::LitObj(obj) => obj.stx.members.iter().any(|member| match &member.stx.typ {
      ObjMemberType::Valued { key, val } => {
        let key_has_await = match key {
          ClassOrObjKey::Direct(_) => false,
          ClassOrObjKey::Computed(expr) => expr_contains_await(expr),
        };

        let val_has_await = match val {
          ClassOrObjVal::Prop(Some(expr)) => expr_contains_await(expr),
          ClassOrObjVal::Prop(None) => false,
          // Function-valued members: the function body is not evaluated at object creation time.
          ClassOrObjVal::Getter(_)
          | ClassOrObjVal::Setter(_)
          | ClassOrObjVal::Method(_)
          | ClassOrObjVal::IndexSignature(_)
          | ClassOrObjVal::StaticBlock(_) => false,
        };

        key_has_await || val_has_await
      }
      ObjMemberType::Shorthand { .. } => false,
      ObjMemberType::Rest { val } => expr_contains_await(val),
    }),
    Expr::LitTemplate(tpl) => tpl.stx.parts.iter().any(|part| match part {
      LitTemplatePart::Substitution(expr) => expr_contains_await(expr),
      LitTemplatePart::String(_) => false,
    }),

    Expr::ArrPat(arr) => arr_pat_contains_await(&arr.stx),
    Expr::ObjPat(obj) => obj_pat_contains_await(&obj.stx),

    // Nested functions are not evaluated when the function value is created.
    Expr::Func(_) | Expr::ArrowFunc(_) => false,

    Expr::Class(class) => {
      class.stx.extends.as_ref().is_some_and(expr_contains_await)
        || class.stx.members.iter().any(|member| {
          let key_has_await = match &member.stx.key {
            ClassOrObjKey::Direct(_) => false,
            ClassOrObjKey::Computed(expr) => expr_contains_await(expr),
          };
          if key_has_await {
            return true;
          }

          match &member.stx.val {
            // Static blocks execute during class definition evaluation and may contain `await`.
            ClassOrObjVal::StaticBlock(block) => block.stx.body.iter().any(stmt_contains_await),
            // Function-valued members: the body is not evaluated at class creation time.
            _ => false,
          }
        })
    }

    // TypeScript-only nodes: only the wrapped expression is evaluated.
    Expr::Instantiation(inst) => expr_contains_await(&inst.stx.expression),
    Expr::TypeAssertion(expr) => expr_contains_await(&expr.stx.expression),
    Expr::NonNullAssertion(expr) => expr_contains_await(&expr.stx.expression),
    Expr::SatisfiesExpr(expr) => expr_contains_await(&expr.stx.expression),

    _ => false,
  }
}

fn pat_contains_await(pat: &Pat) -> bool {
  match pat {
    Pat::Id(_) => false,
    Pat::Obj(obj) => obj_pat_contains_await(&obj.stx),
    Pat::Arr(arr) => arr_pat_contains_await(&arr.stx),
    Pat::AssignTarget(expr) => expr_contains_await(expr),
  }
}

fn obj_pat_contains_await(pat: &ObjPat) -> bool {
  pat.properties.iter().any(|prop| {
    let key_has_await = match &prop.stx.key {
      ClassOrObjKey::Direct(_) => false,
      ClassOrObjKey::Computed(expr) => expr_contains_await(expr),
    };
    key_has_await
      || pat_contains_await(&prop.stx.target.stx)
      || prop
        .stx
        .default_value
        .as_ref()
        .is_some_and(expr_contains_await)
  }) || pat
    .rest
    .as_ref()
    .is_some_and(|rest| pat_contains_await(&rest.stx))
}

fn arr_pat_contains_await(pat: &ArrPat) -> bool {
  pat.elements.iter().any(|elem| match elem {
    Some(elem) => {
      pat_contains_await(&elem.target.stx)
        || elem.default_value.as_ref().is_some_and(expr_contains_await)
    }
    None => false,
  }) || pat
    .rest
    .as_ref()
    .is_some_and(|rest| pat_contains_await(&rest.stx))
}

fn for_in_of_lhs_contains_await(lhs: &ForInOfLhs) -> bool {
  match lhs {
    ForInOfLhs::Decl((mode, pat_decl)) => {
      matches!(*mode, VarDeclMode::AwaitUsing) || pat_contains_await(&pat_decl.stx.pat.stx)
    }
    ForInOfLhs::Assign(pat) => pat_contains_await(&pat.stx),
  }
}

fn for_in_of_lhs_contains_yield(lhs: &ForInOfLhs) -> bool {
  match lhs {
    ForInOfLhs::Decl((_, pat_decl)) => pat_contains_yield(&pat_decl.stx.pat.stx),
    ForInOfLhs::Assign(pat) => pat_contains_yield(&pat.stx),
  }
}

fn pat_contains_yield(pat: &Pat) -> bool {
  match pat {
    Pat::Id(_) => false,
    Pat::Obj(obj) => obj_pat_contains_yield(&obj.stx),
    Pat::Arr(arr) => arr_pat_contains_yield(&arr.stx),
    Pat::AssignTarget(expr) => expr_contains_yield(expr),
  }
}

fn obj_pat_contains_yield(pat: &ObjPat) -> bool {
  pat.properties.iter().any(|prop| {
    let key_has_yield = match &prop.stx.key {
      ClassOrObjKey::Direct(_) => false,
      ClassOrObjKey::Computed(expr) => expr_contains_yield(expr),
    };
    key_has_yield
      || pat_contains_yield(&prop.stx.target.stx)
      || prop
        .stx
        .default_value
        .as_ref()
        .is_some_and(expr_contains_yield)
  }) || pat
    .rest
    .as_ref()
    .is_some_and(|rest| pat_contains_yield(&rest.stx))
}

fn arr_pat_contains_yield(pat: &ArrPat) -> bool {
  pat.elements.iter().any(|elem| match elem {
    Some(elem) => {
      pat_contains_yield(&elem.target.stx)
        || elem.default_value.as_ref().is_some_and(expr_contains_yield)
    }
    None => false,
  }) || pat
    .rest
    .as_ref()
    .is_some_and(|rest| pat_contains_yield(&rest.stx))
}

fn expr_contains_yield(expr: &Node<Expr>) -> bool {
  match &*expr.stx {
    Expr::Unary(unary) => {
      matches!(
        unary.stx.operator,
        OperatorName::Yield | OperatorName::YieldDelegated
      ) || expr_contains_yield(&unary.stx.argument)
    }
    Expr::UnaryPostfix(unary) => expr_contains_yield(&unary.stx.argument),
    Expr::Binary(binary) => {
      expr_contains_yield(&binary.stx.left) || expr_contains_yield(&binary.stx.right)
    }
    Expr::Cond(cond) => {
      expr_contains_yield(&cond.stx.test)
        || expr_contains_yield(&cond.stx.consequent)
        || expr_contains_yield(&cond.stx.alternate)
    }
    Expr::Member(member) => expr_contains_yield(&member.stx.left),
    Expr::ComputedMember(member) => {
      expr_contains_yield(&member.stx.object) || expr_contains_yield(&member.stx.member)
    }
    Expr::Call(call) => {
      expr_contains_yield(&call.stx.callee)
        || call
          .stx
          .arguments
          .iter()
          .any(|arg| expr_contains_yield(&arg.stx.value))
    }
    Expr::Import(import) => {
      expr_contains_yield(&import.stx.module)
        || import
          .stx
          .attributes
          .as_ref()
          .is_some_and(|attrs| expr_contains_yield(attrs))
    }
    Expr::TaggedTemplate(tag) => {
      expr_contains_yield(&tag.stx.function)
        || tag.stx.parts.iter().any(|part| match part {
          LitTemplatePart::Substitution(expr) => expr_contains_yield(expr),
          LitTemplatePart::String(_) => false,
        })
    }
    Expr::LitArr(arr) => arr.stx.elements.iter().any(|elem| match elem {
      LitArrElem::Single(expr) | LitArrElem::Rest(expr) => expr_contains_yield(expr),
      LitArrElem::Empty => false,
    }),
    Expr::LitObj(obj) => obj.stx.members.iter().any(|member| match &member.stx.typ {
      ObjMemberType::Valued { key, val } => {
        let key_has_yield = match key {
          ClassOrObjKey::Direct(_) => false,
          ClassOrObjKey::Computed(expr) => expr_contains_yield(expr),
        };

        let val_has_yield = match val {
          ClassOrObjVal::Prop(Some(expr)) => expr_contains_yield(expr),
          ClassOrObjVal::Prop(None) => false,
          // Function-valued members: the function body is not evaluated at object creation time.
          ClassOrObjVal::Getter(_)
          | ClassOrObjVal::Setter(_)
          | ClassOrObjVal::Method(_)
          | ClassOrObjVal::IndexSignature(_)
          | ClassOrObjVal::StaticBlock(_) => false,
        };

        key_has_yield || val_has_yield
      }
      ObjMemberType::Shorthand { .. } => false,
      ObjMemberType::Rest { val } => expr_contains_yield(val),
    }),
    Expr::LitTemplate(tpl) => tpl.stx.parts.iter().any(|part| match part {
      LitTemplatePart::Substitution(expr) => expr_contains_yield(expr),
      LitTemplatePart::String(_) => false,
    }),

    Expr::ArrPat(arr) => arr_pat_contains_yield(&arr.stx),
    Expr::ObjPat(obj) => obj_pat_contains_yield(&obj.stx),

    // Nested functions are not evaluated when the function value is created.
    Expr::Func(_) | Expr::ArrowFunc(_) => false,

    Expr::Class(class) => {
      class.stx.extends.as_ref().is_some_and(expr_contains_yield)
        || class
          .stx
          .members
          .iter()
          .any(|member| match &member.stx.key {
            ClassOrObjKey::Direct(_) => false,
            ClassOrObjKey::Computed(expr) => expr_contains_yield(expr),
          })
    }

    // TypeScript-only nodes: only the wrapped expression is evaluated.
    Expr::Instantiation(inst) => expr_contains_yield(&inst.stx.expression),
    Expr::TypeAssertion(expr) => expr_contains_yield(&expr.stx.expression),
    Expr::NonNullAssertion(expr) => expr_contains_yield(&expr.stx.expression),
    Expr::SatisfiesExpr(expr) => expr_contains_yield(&expr.stx.expression),

    _ => false,
  }
}

fn stmt_contains_await(stmt: &Node<Stmt>) -> bool {
  match &*stmt.stx {
    Stmt::Empty(_)
    | Stmt::Debugger(_)
    | Stmt::Import(_)
    | Stmt::ExportList(_)
    | Stmt::FunctionDecl(_)
    | Stmt::Break(_)
    | Stmt::Continue(_) => false,
    Stmt::ExportDefaultExpr(stmt) => expr_contains_await(&stmt.stx.expression),
    Stmt::ClassDecl(class) => {
      class.stx.extends.as_ref().is_some_and(expr_contains_await)
        || class.stx.members.iter().any(|member| {
          let key_has_await = match &member.stx.key {
            ClassOrObjKey::Direct(_) => false,
            ClassOrObjKey::Computed(expr) => expr_contains_await(expr),
          };
          if key_has_await {
            return true;
          }

          match &member.stx.val {
            ClassOrObjVal::StaticBlock(block) => block.stx.body.iter().any(stmt_contains_await),
            _ => false,
          }
        })
    }
    Stmt::Expr(expr_stmt) => expr_contains_await(&expr_stmt.stx.expr),
    Stmt::Return(ret) => ret.stx.value.as_ref().is_some_and(expr_contains_await),
    Stmt::Throw(throw_stmt) => expr_contains_await(&throw_stmt.stx.value),
    Stmt::VarDecl(decl) => {
      if decl.stx.mode == VarDeclMode::AwaitUsing {
        return true;
      }
      decl.stx.declarators.iter().any(|d| {
        d.initializer.as_ref().is_some_and(expr_contains_await)
          || pat_contains_await(&d.pattern.stx.pat.stx)
      })
    }
    Stmt::Block(block) => block.stx.body.iter().any(stmt_contains_await),
    Stmt::If(if_stmt) => {
      expr_contains_await(&if_stmt.stx.test)
        || stmt_contains_await(&if_stmt.stx.consequent)
        || if_stmt
          .stx
          .alternate
          .as_ref()
          .is_some_and(stmt_contains_await)
    }
    Stmt::Try(try_stmt) => {
      let catch_has_await = try_stmt.stx.catch.as_ref().is_some_and(|c| {
        c.stx
          .parameter
          .as_ref()
          .is_some_and(|p| pat_contains_await(&p.stx.pat.stx))
          || c.stx.body.iter().any(stmt_contains_await)
      });

      try_stmt
        .stx
        .wrapped
        .stx
        .body
        .iter()
        .any(stmt_contains_await)
        || catch_has_await
        || try_stmt
          .stx
          .finally
          .as_ref()
          .is_some_and(|f| f.stx.body.iter().any(stmt_contains_await))
    }
    Stmt::With(with_stmt) => {
      expr_contains_await(&with_stmt.stx.object) || stmt_contains_await(&with_stmt.stx.body)
    }
    Stmt::While(while_stmt) => {
      expr_contains_await(&while_stmt.stx.condition) || stmt_contains_await(&while_stmt.stx.body)
    }
    Stmt::DoWhile(do_while) => {
      expr_contains_await(&do_while.stx.condition) || stmt_contains_await(&do_while.stx.body)
    }
    Stmt::ForTriple(for_stmt) => {
      let init_has_await = match &for_stmt.stx.init {
        parse_js::ast::stmt::ForTripleStmtInit::None => false,
        parse_js::ast::stmt::ForTripleStmtInit::Expr(expr) => expr_contains_await(expr),
        parse_js::ast::stmt::ForTripleStmtInit::Decl(decl) => {
          if decl.stx.mode == VarDeclMode::AwaitUsing {
            true
          } else {
            decl.stx.declarators.iter().any(|d| {
              d.initializer.as_ref().is_some_and(expr_contains_await)
                || pat_contains_await(&d.pattern.stx.pat.stx)
            })
          }
        }
      };

      init_has_await
        || for_stmt.stx.cond.as_ref().is_some_and(expr_contains_await)
        || for_stmt.stx.post.as_ref().is_some_and(expr_contains_await)
        || for_stmt.stx.body.stx.body.iter().any(stmt_contains_await)
    }
    Stmt::ForIn(for_in) => {
      for_in_of_lhs_contains_await(&for_in.stx.lhs)
        || expr_contains_await(&for_in.stx.rhs)
        || for_in.stx.body.stx.body.iter().any(stmt_contains_await)
    }
    Stmt::ForOf(for_of) => {
      for_of.stx.await_
        || for_in_of_lhs_contains_await(&for_of.stx.lhs)
        || expr_contains_await(&for_of.stx.rhs)
        || for_of.stx.body.stx.body.iter().any(stmt_contains_await)
    }
    Stmt::Switch(switch_stmt) => {
      expr_contains_await(&switch_stmt.stx.test)
        || switch_stmt.stx.branches.iter().any(|branch| {
          branch.stx.case.as_ref().is_some_and(expr_contains_await)
            || branch.stx.body.iter().any(stmt_contains_await)
        })
    }
    Stmt::Label(label) => stmt_contains_await(&label.stx.statement),
    // Conservatively assume unsupported statement kinds do not contain await so we preserve the
    // existing synchronous evaluator behaviour for them.
    _ => false,
  }
}

fn stmt_is_module_only(stmt: &Node<Stmt>) -> bool {
  match &*stmt.stx {
    Stmt::Import(_) | Stmt::ExportList(_) | Stmt::ExportDefaultExpr(_) => true,
    Stmt::FunctionDecl(decl) => decl.stx.export || decl.stx.export_default,
    Stmt::ClassDecl(decl) => decl.stx.export || decl.stx.export_default,
    Stmt::VarDecl(decl) => decl.stx.export,
    _ => false,
  }
}

fn stmt_contains_yield(stmt: &Node<Stmt>) -> bool {
  match &*stmt.stx {
    Stmt::Empty(_)
    | Stmt::Debugger(_)
    | Stmt::Import(_)
    | Stmt::ExportList(_)
    | Stmt::FunctionDecl(_)
    | Stmt::Break(_)
    | Stmt::Continue(_) => false,
    Stmt::ClassDecl(class) => {
      class.stx.extends.as_ref().is_some_and(expr_contains_yield)
        || class.stx.members.iter().any(|member| {
          let key_has_yield = match &member.stx.key {
            ClassOrObjKey::Direct(_) => false,
            ClassOrObjKey::Computed(expr) => expr_contains_yield(expr),
          };
          if key_has_yield {
            return true;
          }

          match &member.stx.val {
            ClassOrObjVal::Prop(Some(expr)) if member.stx.static_ => expr_contains_yield(expr),
            ClassOrObjVal::StaticBlock(block) => block.stx.body.iter().any(stmt_contains_yield),
            _ => false,
          }
        })
    }
    Stmt::Expr(expr_stmt) => expr_contains_yield(&expr_stmt.stx.expr),
    Stmt::Return(ret) => ret.stx.value.as_ref().is_some_and(expr_contains_yield),
    Stmt::Throw(throw_stmt) => expr_contains_yield(&throw_stmt.stx.value),
    Stmt::VarDecl(decl) => decl.stx.declarators.iter().any(|d| {
      d.initializer.as_ref().is_some_and(expr_contains_yield)
        || pat_contains_yield(&d.pattern.stx.pat.stx)
    }),
    Stmt::Block(block) => block.stx.body.iter().any(stmt_contains_yield),
    Stmt::If(if_stmt) => {
      expr_contains_yield(&if_stmt.stx.test)
        || stmt_contains_yield(&if_stmt.stx.consequent)
        || if_stmt
          .stx
          .alternate
          .as_ref()
          .is_some_and(stmt_contains_yield)
    }
    Stmt::Try(try_stmt) => {
      let catch_has_yield = try_stmt.stx.catch.as_ref().is_some_and(|c| {
        c.stx
          .parameter
          .as_ref()
          .is_some_and(|p| pat_contains_yield(&p.stx.pat.stx))
          || c.stx.body.iter().any(stmt_contains_yield)
      });

      try_stmt
        .stx
        .wrapped
        .stx
        .body
        .iter()
        .any(stmt_contains_yield)
        || catch_has_yield
        || try_stmt
          .stx
          .finally
          .as_ref()
          .is_some_and(|f| f.stx.body.iter().any(stmt_contains_yield))
    }
    Stmt::With(with_stmt) => {
      expr_contains_yield(&with_stmt.stx.object) || stmt_contains_yield(&with_stmt.stx.body)
    }
    Stmt::While(while_stmt) => {
      expr_contains_yield(&while_stmt.stx.condition) || stmt_contains_yield(&while_stmt.stx.body)
    }
    Stmt::DoWhile(do_while) => {
      expr_contains_yield(&do_while.stx.condition) || stmt_contains_yield(&do_while.stx.body)
    }
    Stmt::ForTriple(for_stmt) => {
      let init_has_yield = match &for_stmt.stx.init {
        parse_js::ast::stmt::ForTripleStmtInit::None => false,
        parse_js::ast::stmt::ForTripleStmtInit::Expr(expr) => expr_contains_yield(expr),
        parse_js::ast::stmt::ForTripleStmtInit::Decl(decl) => {
          decl.stx.declarators.iter().any(|d| {
            d.initializer.as_ref().is_some_and(expr_contains_yield)
              || pat_contains_yield(&d.pattern.stx.pat.stx)
          })
        }
      };

      init_has_yield
        || for_stmt.stx.cond.as_ref().is_some_and(expr_contains_yield)
        || for_stmt.stx.post.as_ref().is_some_and(expr_contains_yield)
        || for_stmt.stx.body.stx.body.iter().any(stmt_contains_yield)
    }
    Stmt::ForIn(for_in) => {
      for_in_of_lhs_contains_yield(&for_in.stx.lhs)
        || expr_contains_yield(&for_in.stx.rhs)
        || for_in.stx.body.stx.body.iter().any(stmt_contains_yield)
    }
    Stmt::ForOf(for_of) => {
      for_in_of_lhs_contains_yield(&for_of.stx.lhs)
        || expr_contains_yield(&for_of.stx.rhs)
        || for_of.stx.body.stx.body.iter().any(stmt_contains_yield)
    }
    Stmt::Switch(switch_stmt) => {
      expr_contains_yield(&switch_stmt.stx.test)
        || switch_stmt.stx.branches.iter().any(|branch| {
          branch.stx.case.as_ref().is_some_and(expr_contains_yield)
            || branch.stx.body.iter().any(stmt_contains_yield)
        })
    }
    Stmt::Label(label) => stmt_contains_yield(&label.stx.statement),
    // Conservatively assume unsupported statement kinds do not contain yield so we preserve the
    // existing synchronous evaluator behaviour for them.
    _ => false,
  }
}

fn vecdeque_try_push_back<T>(deque: &mut VecDeque<T>, value: T) -> Result<(), VmError> {
  deque.try_reserve(1).map_err(|_| VmError::OutOfMemory)?;
  deque.push_back(value);
  Ok(())
}

fn vecdeque_try_append<T>(dst: &mut VecDeque<T>, src: &mut VecDeque<T>) -> Result<(), VmError> {
  dst
    .try_reserve(src.len())
    .map_err(|_| VmError::OutOfMemory)?;
  dst.append(src);
  Ok(())
}

fn async_frames_push(frames: &mut VecDeque<AsyncFrame>, frame: AsyncFrame) -> Result<(), VmError> {
  vecdeque_try_push_back(frames, frame)
}

fn async_frames_try_append(
  heap: &mut Heap,
  dst: &mut VecDeque<AsyncFrame>,
  src: &mut VecDeque<AsyncFrame>,
) -> Result<(), VmError> {
  if vecdeque_try_append(dst, src).is_err() {
    for mut frame in dst.drain(..) {
      async_teardown_frame(heap, &mut frame);
    }
    for mut frame in src.drain(..) {
      async_teardown_frame(heap, &mut frame);
    }
    return Err(VmError::OutOfMemory);
  }
  Ok(())
}

fn completion_from_expr_result(expr: Result<Value, VmError>) -> Result<Completion, VmError> {
  match expr {
    Ok(v) => Ok(Completion::normal(v)),
    Err(VmError::Throw(value)) => Ok(Completion::Throw(Thrown {
      value,
      stack: Vec::new(),
    })),
    Err(VmError::ThrowWithStack { value, stack }) => Ok(Completion::Throw(Thrown { value, stack })),
    Err(VmError::Return(v)) => Ok(Completion::Return(v)),
    Err(other) => Err(other),
  }
}

fn completion_from_expr_result_for_return(
  expr: Result<Value, VmError>,
) -> Result<Completion, VmError> {
  match expr {
    Ok(v) => Ok(Completion::Return(v)),
    Err(VmError::Throw(value)) => Ok(Completion::Throw(Thrown {
      value,
      stack: Vec::new(),
    })),
    Err(VmError::ThrowWithStack { value, stack }) => Ok(Completion::Throw(Thrown { value, stack })),
    Err(VmError::Return(v)) => Ok(Completion::Return(v)),
    Err(other) => Err(other),
  }
}

#[inline]
fn patch_stack_top_frame_best_effort(
  stack: &mut Vec<StackFrame>,
  source: Arc<str>,
  line: u32,
  col: u32,
) {
  if let Some(top) = stack.first_mut() {
    top.source = source;
    top.line = line;
    top.col = col;
    return;
  }

  // `Vec::push` can abort on OOM; reserve fallibly.
  if stack.try_reserve(1).is_ok() {
    stack.push(StackFrame {
      function: None,
      source,
      line,
      col,
    });
  }
}

fn finalize_thrown_for_stmt(
  evaluator: &mut Evaluator<'_>,
  scope: &mut Scope<'_>,
  stmt: &Node<Stmt>,
  mut thrown: Thrown,
) -> Thrown {
  let source = evaluator.env.source();
  let rel_start = stmt.loc.start_u32().saturating_sub(evaluator.env.prefix_len());
  let abs_offset = evaluator.env.base_offset().saturating_add(rel_start);
  let (line, col) = source.line_col(abs_offset);

  // If the throw completion is missing a captured stack (implicit throw), capture one now. This is
  // best-effort: `capture_stack` can return an empty vector under allocator pressure.
  let mut should_patch_top = false;
  if thrown.stack.is_empty() {
    thrown.stack = evaluator.vm.capture_stack();
    should_patch_top = true;
  }

  // If the stack was captured while executing a native builtin, the top frame will typically have
  // a `<native>:0:0` location. Patch it to this statement location so user code sees where the
  // exception was triggered.
  if !should_patch_top && thrown.stack.first().is_some_and(|top| top.line == 0) {
    should_patch_top = true;
  }

  if should_patch_top {
    patch_stack_top_frame_best_effort(&mut thrown.stack, source.name.clone(), line, col);
  }

  crate::error_object::attach_stack_property_for_throw(scope, thrown.value, &thrown.stack);
  thrown
}

fn source_offset_for_async_frames_best_effort(
  env: &RuntimeEnv,
  frames: &VecDeque<AsyncFrame>,
) -> (Arc<SourceText>, u32) {
  // HIR async execution can suspend without AST node pointers in its frame stack. In that case, use
  // the compiled source and the statement offset tracked by the HIR async state machine.
  for frame in frames {
    if let AsyncFrame::HirAsync { state } = frame {
      return (state.script_source(), state.await_stmt_offset());
    }
  }

  let source = env.source();
  let base_offset = env.base_offset();
  let prefix_len = env.prefix_len();

  // Prefer the first statement-level finalizer frame, which corresponds to the innermost statement
  // that suspended at this `await`.
  for frame in frames {
    match frame {
      AsyncFrame::FinalizeThrowAtStmt { stmt } => {
        // Safety: the async continuation keeps the AST alive across suspensions.
        let stmt = unsafe { &**stmt };
        let rel_start = stmt.loc.start_u32().saturating_sub(prefix_len);
        return (source, base_offset.saturating_add(rel_start));
      }
      AsyncFrame::Throw { stmt } => {
        // Safety: the async continuation keeps the AST alive across suspensions.
        let stmt = unsafe { &**stmt };
        let rel_start = stmt.loc.start_u32().saturating_sub(prefix_len);
        return (source, base_offset.saturating_add(rel_start));
      }
      AsyncFrame::RootExprBody { expr } => {
        // Safety: the async continuation keeps the AST alive across suspensions.
        let expr = unsafe { &**expr };
        let rel_start = expr.loc.start_u32().saturating_sub(prefix_len);
        return (source, base_offset.saturating_add(rel_start));
      }
      _ => {}
    }
  }

  // Fallback: attribute the throw to the start of the current environment's source slice.
  (source, base_offset)
}

fn finalize_throw_with_stack_at_source_offset_best_effort(
  vm: &Vm,
  scope: &mut Scope<'_>,
  source: &SourceText,
  offset: u32,
  err: VmError,
) -> VmError {
  if !err.is_throw_completion() {
    return err;
  }

  let (line, col) = source.line_col(offset);
  let err = coerce_error_to_throw_for_async(vm, scope, err);
  match err {
    VmError::Throw(value) => {
      let mut stack = vm.capture_stack();
      patch_stack_top_frame_best_effort(&mut stack, source.name.clone(), line, col);
      crate::error_object::attach_stack_property_for_throw(scope, value, &stack);
      VmError::ThrowWithStack { value, stack }
    }
    VmError::ThrowWithStack { value, mut stack } => {
      if stack.first().is_none() || stack.first().is_some_and(|top| top.line == 0) {
        patch_stack_top_frame_best_effort(&mut stack, source.name.clone(), line, col);
      }
      crate::error_object::attach_stack_property_for_throw(scope, value, &stack);
      VmError::ThrowWithStack { value, stack }
    }
    other => other,
  }
}

fn finalize_throw_completion_for_stmt(
  evaluator: &mut Evaluator<'_>,
  scope: &mut Scope<'_>,
  stmt: &Node<Stmt>,
  completion: Completion,
) -> Completion {
  match completion {
    Completion::Throw(thrown) => Completion::Throw(finalize_thrown_for_stmt(
      evaluator, scope, stmt, thrown,
    )),
    other => other,
  }
}

fn finalize_throw_value_for_expr_best_effort(
  evaluator: &mut Evaluator<'_>,
  scope: &mut Scope<'_>,
  expr: &Node<Expr>,
  value: Value,
  mut stack: Vec<StackFrame>,
) -> Value {
  let source = evaluator.env.source();
  let rel_start = expr.loc.start_u32().saturating_sub(evaluator.env.prefix_len());
  let abs_offset = evaluator.env.base_offset().saturating_add(rel_start);
  let (line, col) = source.line_col(abs_offset);

  // If the throw is missing a captured stack (implicit throw), capture one now.
  //
  // This is best-effort: `capture_stack` can return an empty vector under allocator pressure.
  let mut should_patch_top = false;
  if stack.is_empty() {
    stack = evaluator.vm.capture_stack();
    should_patch_top = true;
  }

  // If the stack was captured while executing a native builtin, the top frame will typically have
  // a `<native>:0:0` location. Patch it to this expression location so user code sees where the
  // exception was triggered.
  if !should_patch_top && stack.first().is_some_and(|top| top.line == 0) {
    should_patch_top = true;
  }

  if should_patch_top {
    patch_stack_top_frame_best_effort(&mut stack, source.name.clone(), line, col);
  }

  crate::error_object::attach_stack_property_for_throw(scope, value, &stack);
  value
}

fn async_eval_stmt_list(
  evaluator: &mut Evaluator<'_>,
  scope: &mut Scope<'_>,
  stmts: &Vec<Node<Stmt>>,
) -> Result<AsyncEval<Completion>, VmError> {
  // Mirror the synchronous evaluator's approach: use a persistent root for the running completion
  // value so it remains GC-safe across statement evaluation and across `await` suspensions.
  let last_root = scope.heap_mut().add_root(Value::Undefined)?;
  async_eval_stmt_list_from(evaluator, scope, stmts, 0, last_root, false)
}

fn async_eval_stmt_list_from(
  evaluator: &mut Evaluator<'_>,
  scope: &mut Scope<'_>,
  stmts: &Vec<Node<Stmt>>,
  start_index: usize,
  last_value_root: RootId,
  mut last_value_is_set: bool,
) -> Result<AsyncEval<Completion>, VmError> {
  let mut last_value: Option<Value> = if last_value_is_set {
    Some(
      scope
        .heap()
        .get_root(last_value_root)
        .ok_or(VmError::InvariantViolation(
          "missing stmt-list last value root",
        ))?,
    )
  } else {
    None
  };

  for (idx, stmt) in stmts.iter().enumerate().skip(start_index) {
    let completion_eval = async_eval_stmt_labelled(evaluator, scope, stmt, &[]);
    let completion = match completion_eval? {
      AsyncEval::Complete(c) => c,
      AsyncEval::Suspend(mut suspend) => {
        async_frames_push(
          &mut suspend.frames,
          AsyncFrame::StmtList {
            stmts: stmts as *const Vec<Node<Stmt>>,
            next_index: idx.saturating_add(1),
            last_value_root,
            last_value_is_set,
          },
        )?;
        return Ok(AsyncEval::Suspend(suspend));
      }
    };

    let completion = completion.update_empty(last_value);
    match completion {
      Completion::Normal(v) => {
        if let Some(v) = v {
          last_value = Some(v);
          last_value_is_set = true;
          scope.heap_mut().set_root(last_value_root, v);
        }
      }
      abrupt => {
        scope.heap_mut().remove_root(last_value_root);
        return Ok(AsyncEval::Complete(abrupt));
      }
    }
  }

  scope.heap_mut().remove_root(last_value_root);
  Ok(AsyncEval::Complete(Completion::Normal(last_value)))
}

fn async_eval_block_stmt(
  evaluator: &mut Evaluator<'_>,
  scope: &mut Scope<'_>,
  block: &BlockStmt,
) -> Result<AsyncEval<Completion>, VmError> {
  if block.body.is_empty() {
    return Ok(AsyncEval::Complete(Completion::empty()));
  }

  let needs_lexical_env = block.body.iter().any(|stmt| match &*stmt.stx {
    Stmt::VarDecl(var)
      if matches!(
        var.stx.mode,
        VarDeclMode::Let | VarDeclMode::Const | VarDeclMode::Using | VarDeclMode::AwaitUsing
      ) =>
    {
      true
    }
    Stmt::ClassDecl(_) => true,
    Stmt::FunctionDecl(_) => true,
    _ => false,
  });
  if !needs_lexical_env {
    return async_eval_stmt_list(evaluator, scope, &block.body);
  }

  let outer = evaluator.env.lexical_env;
  let block_env = scope.env_create(Some(outer))?;
  evaluator.env.set_lexical_env(scope.heap_mut(), block_env);

  if let Err(err) = evaluator.instantiate_block_decls_in_stmt_list(scope, block_env, &block.body) {
    evaluator.env.set_lexical_env(scope.heap_mut(), outer);
    return Err(err);
  }

  match async_eval_stmt_list(evaluator, scope, &block.body)? {
    AsyncEval::Complete(c) => {
      evaluator.env.set_lexical_env(scope.heap_mut(), outer);
      Ok(AsyncEval::Complete(c))
    }
    AsyncEval::Suspend(mut suspend) => {
      async_frames_push(&mut suspend.frames, AsyncFrame::RestoreLexEnv { outer })?;
      Ok(AsyncEval::Suspend(suspend))
    }
  }
}

fn async_eval_catch(
  evaluator: &mut Evaluator<'_>,
  scope: &mut Scope<'_>,
  catch: &CatchBlock,
  thrown: Value,
) -> Result<AsyncEval<Completion>, VmError> {
  let outer = evaluator.env.lexical_env;

  // Root thrown across environment setup and binding instantiation which may allocate.
  {
    let mut catch_scope = scope.reborrow();
    catch_scope.push_root(thrown)?;

    if let Some(param) = &catch.parameter {
      // --- Catch parameter binding (paramEnv) ---
      let param_env = catch_scope.env_create(Some(outer))?;
      evaluator
        .env
        .set_lexical_env(catch_scope.heap_mut(), param_env);

      evaluator.instantiate_lexical_names_from_pat(
        &mut catch_scope,
        param_env,
        &param.stx.pat.stx,
        param.stx.pat.loc,
        /* mutable */ true,
      )?;

      let pat = &param.stx.pat.stx;
      if pat_contains_await(pat) {
        match async_bind_pattern(evaluator, &mut catch_scope, pat, thrown, BindingKind::Let) {
          Ok(AsyncEval::Complete(())) => {}
          Ok(AsyncEval::Suspend(mut suspend)) => {
            // Parameter binding suspended; continue catch evaluation after the binding finishes.
            if let Err(err) = async_frames_push(
              &mut suspend.frames,
              AsyncFrame::CatchAfterParamBind {
                catch: catch as *const CatchBlock,
                outer,
              },
            ) {
              for mut frame in suspend.frames {
                async_teardown_frame(catch_scope.heap_mut(), &mut frame);
              }
              evaluator.env.set_lexical_env(catch_scope.heap_mut(), outer);
              return Err(err);
            }
            return Ok(AsyncEval::Suspend(suspend));
          }
          Err(err) => {
            evaluator.env.set_lexical_env(catch_scope.heap_mut(), outer);
            return Err(err);
          }
        }
      } else if let Err(err) =
        evaluator.bind_catch_param(&mut catch_scope, &param.stx, thrown, param_env)
      {
        evaluator.env.set_lexical_env(catch_scope.heap_mut(), outer);
        return Err(err);
      }

      // --- Catch block evaluation (blockEnv) ---
      let block_env = catch_scope.env_create(Some(param_env))?;
      evaluator
        .env
        .set_lexical_env(catch_scope.heap_mut(), block_env);
      if let Err(err) =
        evaluator.instantiate_block_decls_in_stmt_list(&mut catch_scope, block_env, &catch.body)
      {
        evaluator.env.set_lexical_env(catch_scope.heap_mut(), outer);
        return Err(err);
      }
    } else {
      // Optional catch binding (`catch { ... }`): evaluate the catch body as a normal block.
      let needs_lexical_env = catch.body.iter().any(|stmt| match &*stmt.stx {
        Stmt::VarDecl(var)
          if matches!(
            var.stx.mode,
            VarDeclMode::Let | VarDeclMode::Const | VarDeclMode::Using | VarDeclMode::AwaitUsing
          ) =>
        {
          true
        }
        Stmt::ClassDecl(_) => true,
        Stmt::FunctionDecl(_) => true,
        _ => false,
      });
      if needs_lexical_env {
        let block_env = catch_scope.env_create(Some(outer))?;
        evaluator
          .env
          .set_lexical_env(catch_scope.heap_mut(), block_env);
        if let Err(err) =
          evaluator.instantiate_block_decls_in_stmt_list(&mut catch_scope, block_env, &catch.body)
        {
          evaluator.env.set_lexical_env(catch_scope.heap_mut(), outer);
          return Err(err);
        }
      }
    }
  }

  match async_eval_stmt_list(evaluator, scope, &catch.body)? {
    AsyncEval::Complete(c) => {
      evaluator.env.set_lexical_env(scope.heap_mut(), outer);
      Ok(AsyncEval::Complete(c))
    }
    AsyncEval::Suspend(mut suspend) => {
      async_frames_push(&mut suspend.frames, AsyncFrame::RestoreLexEnv { outer })?;
      Ok(AsyncEval::Suspend(suspend))
    }
  }
}

fn async_eval_try(
  evaluator: &mut Evaluator<'_>,
  scope: &mut Scope<'_>,
  stmt: &TryStmt,
) -> Result<AsyncEval<Completion>, VmError> {
  match async_eval_block_stmt(evaluator, scope, &stmt.wrapped.stx)? {
    AsyncEval::Complete(c) => async_try_after_wrapped(evaluator, scope, stmt, c),
    AsyncEval::Suspend(mut suspend) => {
      async_frames_push(
        &mut suspend.frames,
        AsyncFrame::TryAfterWrapped {
          stmt: stmt as *const TryStmt,
        },
      )?;
      Ok(AsyncEval::Suspend(suspend))
    }
  }
}

fn async_eval_with(
  evaluator: &mut Evaluator<'_>,
  scope: &mut Scope<'_>,
  stmt: &WithStmt,
  label_set: &[String],
) -> Result<AsyncEval<Completion>, VmError> {
  match async_eval_expr(evaluator, scope, &stmt.object)? {
    AsyncEval::Complete(object_value) => {
      let outer = evaluator.env.lexical_env;
      async_with_after_object(evaluator, scope, stmt, label_set, outer, object_value)
    }
    AsyncEval::Suspend(mut suspend) => {
      let outer = evaluator.env.lexical_env;

      let mut label_vec: Vec<String> = Vec::new();
      label_vec
        .try_reserve_exact(label_set.len())
        .map_err(|_| VmError::OutOfMemory)?;
      label_vec.extend_from_slice(label_set);

      async_frames_push(
        &mut suspend.frames,
        AsyncFrame::WithAfterObject {
          stmt: stmt as *const WithStmt,
          label_set: label_vec,
          outer,
        },
      )?;
      Ok(AsyncEval::Suspend(suspend))
    }
  }
}

fn async_with_after_object(
  evaluator: &mut Evaluator<'_>,
  scope: &mut Scope<'_>,
  stmt: &WithStmt,
  label_set: &[String],
  outer: GcEnv,
  object_value: Value,
) -> Result<AsyncEval<Completion>, VmError> {
  // Minimal ECMA-262 `WithStatement` evaluation (mirroring `Evaluator::eval_with`):
  //
  // - Evaluate the object expression, then `ToObject` it.
  // - Create an ObjectEnvironmentRecord with `with_environment = true`.
  // - Evaluate the body with that env record as the current lexical environment.
  //
  // This helper assumes the object expression has already been evaluated (possibly after an `await`
  // resumption) and handles the remaining environment setup + body evaluation.
  {
    // Root the object value across `ToObject` and env allocation in case they trigger GC.
    let mut with_scope = scope.reborrow();
    with_scope.push_root(object_value)?;

    let binding_object = with_scope
      .to_object(
        evaluator.vm,
        &mut *evaluator.host,
        &mut *evaluator.hooks,
        object_value,
      )
      .map_err(|err| coerce_error_to_throw_for_async(evaluator.vm, &mut with_scope, err))?;
    with_scope.push_root(Value::Object(binding_object))?;

    let with_env = with_scope.alloc_object_env_record(binding_object, Some(outer), true)?;
    evaluator
      .env
      .set_lexical_env(with_scope.heap_mut(), with_env);
  }

  let body_res = async_eval_stmt_labelled(evaluator, scope, &stmt.body, label_set);
  match body_res {
    Ok(AsyncEval::Complete(c)) => {
      evaluator.env.set_lexical_env(scope.heap_mut(), outer);
      Ok(AsyncEval::Complete(c))
    }
    Ok(AsyncEval::Suspend(mut suspend)) => {
      // Ensure we restore the outer lexical environment after the body completes (even if it
      // suspends at an `await` point).
      if let Err(err) = async_frames_push(&mut suspend.frames, AsyncFrame::RestoreLexEnv { outer })
      {
        evaluator.env.set_lexical_env(scope.heap_mut(), outer);
        return Err(err);
      }
      Ok(AsyncEval::Suspend(suspend))
    }
    Err(err) => {
      evaluator.env.set_lexical_env(scope.heap_mut(), outer);
      Err(err)
    }
  }
}

fn async_try_after_wrapped(
  evaluator: &mut Evaluator<'_>,
  scope: &mut Scope<'_>,
  stmt: &TryStmt,
  mut result: Completion,
) -> Result<AsyncEval<Completion>, VmError> {
  if matches!(result, Completion::Throw(_)) {
    if let Some(catch) = &stmt.catch {
      let (thrown_value, thrown_stack) = match result {
        Completion::Throw(thrown) => (thrown.value, thrown.stack),
        _ => {
          return Err(VmError::InvariantViolation(
            "async try expected throw completion when entering catch",
          ));
        }
      };
      crate::error_object::attach_stack_property_for_throw(scope, thrown_value, &thrown_stack);
      match async_eval_catch(evaluator, scope, &catch.stx, thrown_value)? {
        AsyncEval::Complete(c) => result = c,
        AsyncEval::Suspend(mut suspend) => {
          async_frames_push(
            &mut suspend.frames,
            AsyncFrame::TryAfterCatch {
              stmt: stmt as *const TryStmt,
            },
          )?;
          return Ok(AsyncEval::Suspend(suspend));
        }
      }
    }
  }

  async_try_after_catch(evaluator, scope, stmt, result)
}

fn async_try_after_catch(
  evaluator: &mut Evaluator<'_>,
  scope: &mut Scope<'_>,
  stmt: &TryStmt,
  result: Completion,
) -> Result<AsyncEval<Completion>, VmError> {
  let Some(finally) = &stmt.finally else {
    return Ok(AsyncEval::Complete(
      result.update_empty(Some(Value::Undefined)),
    ));
  };

  let pending = RootedCompletion::new(scope, result)?;
  match async_eval_block_stmt(evaluator, scope, &finally.stx)? {
    AsyncEval::Complete(finally_result) => {
      let pending_completion = pending.to_completion(scope.heap())?;
      let mut pending = pending;
      pending.teardown(scope.heap_mut());

      let result = if finally_result.is_abrupt() {
        finally_result
      } else {
        pending_completion
      };
      Ok(AsyncEval::Complete(
        result.update_empty(Some(Value::Undefined)),
      ))
    }
    AsyncEval::Suspend(mut suspend) => {
      async_frames_push(&mut suspend.frames, AsyncFrame::TryAfterFinally { pending })?;
      Ok(AsyncEval::Suspend(suspend))
    }
  }
}

fn async_eval_stmt_labelled(
  evaluator: &mut Evaluator<'_>,
  scope: &mut Scope<'_>,
  stmt: &Node<Stmt>,
  label_set: &[String],
) -> Result<AsyncEval<Completion>, VmError> {
  // One tick per statement.
  evaluator.tick()?;

  if !stmt_contains_await(stmt) {
    return Ok(AsyncEval::Complete(
      evaluator.eval_stmt_labelled(scope, stmt, label_set)?,
    ));
  }

  let res = match &*stmt.stx {
    Stmt::Empty(_) => Ok(AsyncEval::Complete(Completion::empty())),
    Stmt::Expr(expr_stmt) => match async_eval_expr(evaluator, scope, &expr_stmt.stx.expr) {
      Ok(AsyncEval::Complete(v)) => Ok(AsyncEval::Complete(Completion::normal(v))),
      Ok(AsyncEval::Suspend(mut suspend)) => {
        async_frames_push(&mut suspend.frames, AsyncFrame::ExprStmt)?;
        Ok(AsyncEval::Suspend(suspend))
      }
      Err(err) => Ok(AsyncEval::Complete(completion_from_expr_result(Err(err))?)),
    },
    Stmt::ExportDefaultExpr(stmt) => {
      // `ExportDefaultDeclaration` performs `SetFunctionName` for anonymous function/class
      // definitions. For anonymous class expressions, this must happen *during* class construction
      // (before defining class elements) so a `static name() {}` element or static block can observe
      // or override the inferred name.
      //
      // The synchronous evaluator handles this via `eval_expr_named`; mirror that behaviour for the
      // async evaluator when the export expression itself can suspend on `await` (e.g. `extends
      // await ...`).
      let expr_eval = match stmt.stx.expression.stx.as_ref() {
        Expr::Class(class_expr) if class_expr.stx.name.is_none() => {
          async_eval_class_expr_inferred_name(evaluator, scope, class_expr, "default")
        }
        _ => async_eval_expr(evaluator, scope, &stmt.stx.expression),
      };

      match expr_eval {
        Ok(AsyncEval::Complete(v)) => {
          let binding_name = "*default*";
          if !scope
            .heap()
            .env_has_binding(evaluator.env.lexical_env, binding_name)?
          {
            return Err(VmError::InvariantViolation(
              "export default expression missing *default* binding",
            ));
          }
          scope
            .heap_mut()
            .env_initialize_binding(evaluator.env.lexical_env, binding_name, v)?;
          Ok(AsyncEval::Complete(Completion::empty()))
        }
        Ok(AsyncEval::Suspend(mut suspend)) => {
          async_frames_push(&mut suspend.frames, AsyncFrame::ExportDefaultExpr)?;
          Ok(AsyncEval::Suspend(suspend))
        }
        Err(err) => Ok(AsyncEval::Complete(completion_from_expr_result(Err(err))?)),
      }
    }
    Stmt::Return(ret) => match &ret.stx.value {
      Some(value_expr) => match async_eval_expr(evaluator, scope, value_expr) {
        Ok(AsyncEval::Complete(v)) => Ok(AsyncEval::Complete(Completion::Return(v))),
        Ok(AsyncEval::Suspend(mut suspend)) => {
          async_frames_push(&mut suspend.frames, AsyncFrame::Return)?;
          Ok(AsyncEval::Suspend(suspend))
        }
        Err(err) => Ok(AsyncEval::Complete(completion_from_expr_result_for_return(
          Err(err),
        )?)),
      },
      None => Ok(AsyncEval::Complete(Completion::Return(Value::Undefined))),
    },
    Stmt::Throw(stmt) => async_eval_throw_stmt(evaluator, scope, stmt),
    Stmt::VarDecl(decl) => async_eval_var_decl(evaluator, scope, &decl.stx, 0),
    Stmt::Debugger(_) => Ok(AsyncEval::Complete(Completion::empty())),
    Stmt::ClassDecl(class_decl) => async_eval_class_decl(evaluator, scope, class_decl),
    Stmt::Block(block) => async_eval_block_stmt(evaluator, scope, &block.stx),
    Stmt::If(if_stmt) => match async_eval_expr(evaluator, scope, &if_stmt.stx.test) {
      Ok(AsyncEval::Complete(v)) => {
        if to_boolean(scope.heap(), v)? {
          async_eval_stmt_labelled(evaluator, scope, &if_stmt.stx.consequent, label_set)
        } else if let Some(alt) = &if_stmt.stx.alternate {
          async_eval_stmt_labelled(evaluator, scope, alt, label_set)
        } else {
          Ok(AsyncEval::Complete(Completion::empty()))
        }
      }
      Ok(AsyncEval::Suspend(mut suspend)) => {
        async_frames_push(
          &mut suspend.frames,
          AsyncFrame::IfAfterTest {
            consequent: &if_stmt.stx.consequent as *const Node<Stmt>,
            alternate: if_stmt
              .stx
              .alternate
              .as_ref()
              .map(|alt| alt as *const Node<Stmt>),
          },
        )?;
        Ok(AsyncEval::Suspend(suspend))
      }
      Err(err) => Ok(AsyncEval::Complete(completion_from_expr_result(Err(err))?)),
    },
    Stmt::With(with_stmt) => async_eval_with(evaluator, scope, &with_stmt.stx, label_set),
    Stmt::Try(try_stmt) => async_eval_try(evaluator, scope, &try_stmt.stx),
    Stmt::While(while_stmt) => async_eval_while(evaluator, scope, &while_stmt.stx, label_set),
    Stmt::DoWhile(do_while) => async_eval_do_while(evaluator, scope, &do_while.stx, label_set),
    Stmt::ForTriple(for_stmt) => async_eval_for_triple(evaluator, scope, &for_stmt.stx, label_set),
    Stmt::ForIn(for_stmt) => async_eval_for_in(evaluator, scope, &for_stmt.stx, label_set),
    Stmt::ForOf(for_stmt) if for_stmt.stx.await_ => {
      async_eval_for_await_of(evaluator, scope, &for_stmt.stx, label_set)
    }
    Stmt::ForOf(for_stmt) => async_eval_for_of(evaluator, scope, &for_stmt.stx, label_set),
    Stmt::Switch(switch_stmt) => async_eval_switch(evaluator, scope, &switch_stmt.stx),
    Stmt::Label(label_stmt) => async_eval_label(evaluator, scope, &label_stmt.stx, label_set),
    Stmt::Break(break_stmt) => Ok(AsyncEval::Complete(Completion::Break(
      break_stmt.stx.label.clone(),
      None,
    ))),
    Stmt::Continue(cont_stmt) => Ok(AsyncEval::Complete(Completion::Continue(
      cont_stmt.stx.label.clone(),
      None,
    ))),
    _ => Err(VmError::Unimplemented("await in statement type")),
  };

  // Async statement evaluation does not go through `Evaluator::eval_stmt_labelled`, so we must
  // ensure `VmError::Throw(..)` propagates as a JS throw completion (catchable by `try/catch`)
  // rather than bubbling out as a fatal internal error.
  let eval = match res {
    Ok(v) => v,
    Err(err) => {
      let err = coerce_error_to_throw_for_async(evaluator.vm, scope, err);
      match err {
        VmError::Throw(_) | VmError::ThrowWithStack { .. } => {
          AsyncEval::Complete(completion_from_expr_result(Err(err))?)
        }
        other => return Err(other),
      }
    }
  };

  match eval {
    AsyncEval::Complete(c) => Ok(AsyncEval::Complete(finalize_throw_completion_for_stmt(
      evaluator, scope, stmt, c,
    ))),
    AsyncEval::Suspend(mut suspend) => {
      // Best-effort: stack trace capture must never change execution semantics under OOM.
      let _ = async_frames_push(
        &mut suspend.frames,
        AsyncFrame::FinalizeThrowAtStmt { stmt: stmt as *const _ },
      );
      Ok(AsyncEval::Suspend(suspend))
    }
  }
}

fn async_throw_completion(
  evaluator: &mut Evaluator<'_>,
  scope: &mut Scope<'_>,
  stmt: &Node<ThrowStmt>,
  value: Value,
) -> Completion {
  // Capture a stack trace at the throw site. Mirrors `Evaluator::eval_throw`.
  let source = evaluator.env.source();
  let rel_start = stmt
    .loc
    .start_u32()
    .saturating_sub(evaluator.env.prefix_len());
  let abs_offset = evaluator.env.base_offset().saturating_add(rel_start);
  let (line, col) = source.line_col(abs_offset);

  let mut stack = evaluator.vm.capture_stack();
  if let Some(top) = stack.first_mut() {
    top.source = source.name.clone();
    top.line = line;
    top.col = col;
  } else {
    stack.push(StackFrame {
      function: None,
      source: source.name.clone(),
      line,
      col,
    });
  }

  crate::error_object::attach_stack_property_for_throw(scope, value, &stack);
  Completion::Throw(Thrown { value, stack })
}

fn async_eval_throw_stmt(
  evaluator: &mut Evaluator<'_>,
  scope: &mut Scope<'_>,
  stmt: &Node<ThrowStmt>,
) -> Result<AsyncEval<Completion>, VmError> {
  match async_eval_expr(evaluator, scope, &stmt.stx.value) {
    Ok(AsyncEval::Complete(v)) => Ok(AsyncEval::Complete(async_throw_completion(
      evaluator, scope, stmt, v,
    ))),
    Ok(AsyncEval::Suspend(mut suspend)) => {
      async_frames_push(
        &mut suspend.frames,
        AsyncFrame::Throw {
          stmt: stmt as *const Node<ThrowStmt>,
        },
      )?;
      Ok(AsyncEval::Suspend(suspend))
    }
    Err(err) => Ok(AsyncEval::Complete(completion_from_expr_result(Err(err))?)),
  }
}

fn async_eval_label(
  evaluator: &mut Evaluator<'_>,
  scope: &mut Scope<'_>,
  stmt: &LabelStmt,
  label_set: &[String],
) -> Result<AsyncEval<Completion>, VmError> {
  let mut new_label_set = label_set.to_vec();
  new_label_set.push(stmt.name.clone());

  match async_eval_stmt_labelled(evaluator, scope, &stmt.statement, &new_label_set)? {
    AsyncEval::Complete(result) => Ok(AsyncEval::Complete(match result {
      Completion::Break(Some(target), value) if target == stmt.name => Completion::Normal(value),
      other => other,
    })),
    AsyncEval::Suspend(mut suspend) => {
      async_frames_push(
        &mut suspend.frames,
        AsyncFrame::LabelAfterStmt {
          label: stmt.name.clone(),
        },
      )?;
      Ok(AsyncEval::Suspend(suspend))
    }
  }
}

fn async_eval_var_decl(
  evaluator: &mut Evaluator<'_>,
  scope: &mut Scope<'_>,
  decl: &VarDecl,
  start_declarator_index: usize,
) -> Result<AsyncEval<Completion>, VmError> {
  for (idx, declarator) in decl
    .declarators
    .iter()
    .enumerate()
    .skip(start_declarator_index)
  {
    let Some(init) = &declarator.initializer else {
      match decl.mode {
        VarDeclMode::Var => {
          evaluator.tick()?;
          if !matches!(&*declarator.pattern.stx.pat.stx, Pat::Id(_)) {
            return Err(VmError::Unimplemented(
              "destructuring var without initializer",
            ));
          }
          continue;
        }
        VarDeclMode::Let => {
          let Pat::Id(id) = &*declarator.pattern.stx.pat.stx else {
            return Err(VmError::Unimplemented(
              "destructuring let without initializer",
            ));
          };
          evaluator.tick()?;
          let name = id.stx.name.as_str();
          if !scope
            .heap()
            .env_has_binding(evaluator.env.lexical_env, name)?
          {
            scope.env_create_mutable_binding(evaluator.env.lexical_env, name)?;
          }
          scope.heap_mut().env_initialize_binding(
            evaluator.env.lexical_env,
            name,
            Value::Undefined,
          )?;
          continue;
        }
        VarDeclMode::Const => {
          return Err(syntax_error(
            declarator.pattern.loc,
            "Missing initializer in const declaration",
          ));
        }
        VarDeclMode::Using | VarDeclMode::AwaitUsing => {
          let message = match decl.mode {
            VarDeclMode::Using => "Missing initializer in using declaration",
            VarDeclMode::AwaitUsing => "Missing initializer in await using declaration",
            _ => unreachable!(),
          };
          return Err(syntax_error(declarator.pattern.loc, message));
        }
      }
    };

    match async_eval_expr(evaluator, scope, init) {
      Ok(AsyncEval::Complete(v)) => {
        match async_bind_var_declarator_value(evaluator, scope, decl, idx, v)? {
           AsyncEval::Complete(()) => {}
           AsyncEval::Suspend(mut suspend) => {
            if let Err(err) = async_frames_push(
              &mut suspend.frames,
              AsyncFrame::VarDeclAfterBinding {
                decl: decl as *const VarDecl,
                next_declarator_index: idx.saturating_add(1),
              },
            ) {
              for mut frame in suspend.frames {
                async_teardown_frame(scope.heap_mut(), &mut frame);
              }
              return Err(err);
            }
            return Ok(AsyncEval::Suspend(suspend));
           }
         }
       }
      Ok(AsyncEval::Suspend(mut suspend)) => {
        async_frames_push(
          &mut suspend.frames,
          AsyncFrame::VarDecl {
            decl: decl as *const VarDecl,
            next_declarator_index: idx,
          },
        )?;
        return Ok(AsyncEval::Suspend(suspend));
      }
      Err(err) => {
        return Ok(AsyncEval::Complete(completion_from_expr_result(Err(err))?));
      }
    }
  }

  Ok(AsyncEval::Complete(Completion::empty()))
}

fn async_bind_var_declarator_value(
  evaluator: &mut Evaluator<'_>,
  scope: &mut Scope<'_>,
  decl: &VarDecl,
  declarator_index: usize,
  value: Value,
) -> Result<AsyncEval<()>, VmError> {
  let declarator = decl
    .declarators
    .get(declarator_index)
    .ok_or(VmError::InvariantViolation(
      "async var decl continuation out of bounds",
    ))?;

  match decl.mode {
    VarDeclMode::Var => async_bind_pattern(
      evaluator,
      scope,
      &declarator.pattern.stx.pat.stx,
      value,
      BindingKind::Var,
    ),
    VarDeclMode::Let => {
      let Pat::Id(id) = &*declarator.pattern.stx.pat.stx else {
        return async_bind_pattern(
          evaluator,
          scope,
          &declarator.pattern.stx.pat.stx,
          value,
          BindingKind::Let,
        );
      };

      let name = id.stx.name.as_str();
      if !scope
        .heap()
        .env_has_binding(evaluator.env.lexical_env, name)?
      {
        scope.env_create_mutable_binding(evaluator.env.lexical_env, name)?;
      }
      scope
        .heap_mut()
        .env_initialize_binding(evaluator.env.lexical_env, name, value)?;
      Ok(AsyncEval::Complete(()))
    }
    VarDeclMode::Const => {
      if !matches!(&*declarator.pattern.stx.pat.stx, Pat::Id(_)) {
        return async_bind_pattern(
          evaluator,
          scope,
          &declarator.pattern.stx.pat.stx,
          value,
          BindingKind::Const,
        );
      }

      let Pat::Id(id) = &*declarator.pattern.stx.pat.stx else {
        return Err(VmError::InvariantViolation(
          "internal error: const declaration pattern mismatch",
        ));
      };
      let name = id.stx.name.as_str();
      if !scope
        .heap()
        .env_has_binding(evaluator.env.lexical_env, name)?
      {
        scope.env_create_immutable_binding(evaluator.env.lexical_env, name)?;
      }
      scope
        .heap_mut()
        .env_initialize_binding(evaluator.env.lexical_env, name, value)?;
      Ok(AsyncEval::Complete(()))
    }
    VarDeclMode::Using | VarDeclMode::AwaitUsing => {
      // `using` and `await using` declarations introduce immutable lexical bindings and register
      // disposable resources.
      if !matches!(&*declarator.pattern.stx.pat.stx, Pat::Id(_)) {
        // `using` does not allow binding patterns, but handle defensively.
        let bind_res = async_bind_pattern(
          evaluator,
          scope,
          &declarator.pattern.stx.pat.stx,
          value,
          BindingKind::Const,
        )?;
        match bind_res {
          AsyncEval::Complete(()) => {
            check_disposable_resource_value(evaluator.vm, scope, value)?;
            Ok(AsyncEval::Complete(()))
          }
          AsyncEval::Suspend(_) => Err(VmError::Unimplemented(
            "await in using declaration binding pattern",
          )),
        }
      } else {
        let Pat::Id(id) = &*declarator.pattern.stx.pat.stx else {
          return Err(VmError::InvariantViolation(
            "internal error: using declaration pattern mismatch",
          ));
        };
        let name = id.stx.name.as_str();
        if !scope
          .heap()
          .env_has_binding(evaluator.env.lexical_env, name)?
        {
          scope.env_create_immutable_binding(evaluator.env.lexical_env, name)?;
        }
        scope
          .heap_mut()
          .env_initialize_binding(evaluator.env.lexical_env, name, value)?;
        check_disposable_resource_value(evaluator.vm, scope, value)?;
        Ok(AsyncEval::Complete(()))
      }
    }
  }
}

#[derive(Debug)]
struct RootedPropertyKey {
  key: PropertyKey,
  root: RootId,
}

fn async_root_value(scope: &mut Scope<'_>, value: Value) -> Result<RootId, VmError> {
  // Root `value` across root-table growth in case it triggers GC.
  let mut root_scope = scope.reborrow();
  root_scope.push_root(value)?;
  root_scope.heap_mut().add_root(value)
}

fn async_root_property_key(
  scope: &mut Scope<'_>,
  key: PropertyKey,
) -> Result<RootedPropertyKey, VmError> {
  let v = match key {
    PropertyKey::String(s) => Value::String(s),
    PropertyKey::Symbol(s) => Value::Symbol(s),
  };
  let root = async_root_value(scope, v)?;
  Ok(RootedPropertyKey { key, root })
}

fn async_cleanup_rooted_property_keys(heap: &mut Heap, keys: &mut Vec<RootedPropertyKey>) {
  for key in keys.drain(..) {
    heap.remove_root(key.root);
  }
}

fn async_bind_pattern(
  evaluator: &mut Evaluator<'_>,
  scope: &mut Scope<'_>,
  pat: &Pat,
  value: Value,
  kind: BindingKind,
) -> Result<AsyncEval<()>, VmError> {
  // Fast path: if the pattern doesn't contain `await`, reuse the synchronous binder.
  if !pat_contains_await(pat) {
    let res = bind_pattern(
      evaluator.vm,
      &mut *evaluator.host,
      &mut *evaluator.hooks,
      scope,
      evaluator.env,
      pat,
      value,
      kind,
      evaluator.strict,
      evaluator.this,
    )
    .map_err(|err| coerce_error_to_throw_for_async(evaluator.vm, scope, err));
    return match res {
      Ok(()) => Ok(AsyncEval::Complete(())),
      Err(err) => Err(err),
    };
  }

  // Root the input value so it survives across `await` suspensions inside the pattern.
  let value_root = async_root_value(scope, value)?;

  match pat {
    Pat::Obj(obj) => async_bind_object_pattern(evaluator, scope, &obj.stx, value_root, kind),
    Pat::Arr(arr) => async_bind_array_pattern(evaluator, scope, &arr.stx, value_root, kind),
    Pat::AssignTarget(target) => {
      if !matches!(kind, BindingKind::Assignment) {
        scope.heap_mut().remove_root(value_root);
        return Err(VmError::Unimplemented(
          "assignment target pattern in binding context",
        ));
      }
      async_bind_assignment_target(evaluator, scope, target, value_root)
    }
    // `Pat::Id` cannot contain an `await`, but handle it defensively.
    Pat::Id(_) => {
      scope.heap_mut().remove_root(value_root);
      let res = bind_pattern(
        evaluator.vm,
        &mut *evaluator.host,
        &mut *evaluator.hooks,
        scope,
        evaluator.env,
        pat,
        value,
        kind,
        evaluator.strict,
        evaluator.this,
      )
      .map_err(|err| coerce_error_to_throw_for_async(evaluator.vm, scope, err));
      match res {
        Ok(()) => Ok(AsyncEval::Complete(())),
        Err(err) => Err(err),
      }
    }
  }
}

fn async_bind_assignment_target(
  evaluator: &mut Evaluator<'_>,
  scope: &mut Scope<'_>,
  target: &Node<Expr>,
  value_root: RootId,
) -> Result<AsyncEval<()>, VmError> {
  match &*target.stx {
    Expr::ObjPat(obj) => async_bind_object_pattern(
      evaluator,
      scope,
      &obj.stx,
      value_root,
      BindingKind::Assignment,
    ),
    Expr::ArrPat(arr) => async_bind_array_pattern(
      evaluator,
      scope,
      &arr.stx,
      value_root,
      BindingKind::Assignment,
    ),
    _ => {
      // Today we only support suspension points inside destructuring patterns (computed keys,
      // defaults, nested patterns). Other assignment targets that contain `await` remain
      // unimplemented.
      scope.heap_mut().remove_root(value_root);
      Err(VmError::Unimplemented("await in assignment target"))
    }
  }
}

fn resolve_obj_pat_direct_key(
  scope: &mut Scope<'_>,
  direct: &Node<parse_js::ast::class_or_object::ClassOrObjMemberDirectKey>,
) -> Result<PropertyKey, VmError> {
  let s = if let Some(units) = literal_string_code_units(&direct.assoc) {
    scope.alloc_string_from_code_units(units)?
  } else if direct.stx.tt == TT::LiteralNumber {
    let n = direct
      .stx
      .key
      .parse::<f64>()
      .map_err(|_| VmError::Unimplemented("numeric literal property name parse"))?;
    scope.heap_mut().to_string(Value::Number(n))?
  } else {
    scope.alloc_string(&direct.stx.key)?
  };
  Ok(PropertyKey::from_string(s))
}

fn async_bind_object_pattern(
  evaluator: &mut Evaluator<'_>,
  scope: &mut Scope<'_>,
  pat: &ObjPat,
  value_root: RootId,
  kind: BindingKind,
) -> Result<AsyncEval<()>, VmError> {
  let mut excluded: Vec<RootedPropertyKey> = Vec::new();
  if let Err(_) = excluded.try_reserve_exact(pat.properties.len()) {
    // Allocation failure: make sure we don't leak the persistent value root.
    scope.heap_mut().remove_root(value_root);
    return Err(VmError::OutOfMemory);
  }
  async_bind_object_pattern_from(evaluator, scope, pat, value_root, excluded, 0, kind)
}

fn async_bind_object_pattern_from(
  evaluator: &mut Evaluator<'_>,
  scope: &mut Scope<'_>,
  pat: &ObjPat,
  value_root: RootId,
  mut excluded: Vec<RootedPropertyKey>,
  start_prop_index: usize,
  kind: BindingKind,
) -> Result<AsyncEval<()>, VmError> {
  // Keep the boxed object wrapper (for primitive source values) rooted only for the duration of
  // this binding step; if we suspend, we'll re-box on resume.
  let mut scope = scope.reborrow();

  let src_value = match scope.heap().get_root(value_root) {
    Some(v) => v,
    None => {
      // The root has been removed unexpectedly; avoid leaking any excluded-key roots.
      scope.heap_mut().remove_root(value_root);
      async_cleanup_rooted_property_keys(scope.heap_mut(), &mut excluded);
      return Err(VmError::InvariantViolation(
        "missing destructuring value root",
      ));
    }
  };

  let cleanup = |scope: &mut Scope<'_>, excluded: &mut Vec<RootedPropertyKey>| {
    scope.heap_mut().remove_root(value_root);
    async_cleanup_rooted_property_keys(scope.heap_mut(), excluded);
  };

  // Object destructuring follows `GetV` semantics: property lookup uses `ToObject(value)`, but
  // accessors must observe `this = value` (the original RHS value), not the boxed object.
  let obj = match scope.to_object(
    evaluator.vm,
    &mut *evaluator.host,
    &mut *evaluator.hooks,
    src_value,
  ) {
    Ok(obj) => obj,
    Err(err) => {
      cleanup(&mut scope, &mut excluded);
      return Err(coerce_error_to_throw_for_async(
        evaluator.vm,
        &mut scope,
        err,
      ));
    }
  };
  if let Err(err) = scope.push_root(Value::Object(obj)) {
    cleanup(&mut scope, &mut excluded);
    return Err(err);
  }

  let receiver = src_value;

  for (idx, prop) in pat.properties.iter().enumerate().skip(start_prop_index) {
    // Budget object destructuring by pattern size.
    if let Err(err) = evaluator.tick() {
      cleanup(&mut scope, &mut excluded);
      return Err(err);
    }

    let prop = &prop.stx;
    let key = match &prop.key {
      ClassOrObjKey::Direct(direct) => match resolve_obj_pat_direct_key(&mut scope, direct) {
        Ok(key) => key,
        Err(err) => {
          cleanup(&mut scope, &mut excluded);
          return Err(err);
        }
      },
      ClassOrObjKey::Computed(expr) => {
        let key_eval = match async_eval_expr(evaluator, &mut scope, expr) {
          Ok(v) => v,
          Err(err) => {
            cleanup(&mut scope, &mut excluded);
            return Err(err);
          }
        };
        match key_eval {
          AsyncEval::Complete(key_value) => {
            let key = match evaluator
              .to_property_key_operator(&mut scope, key_value)
              .map_err(|err| coerce_error_to_throw_for_async(evaluator.vm, &mut scope, err))
            {
              Ok(key) => key,
              Err(err) => {
                cleanup(&mut scope, &mut excluded);
                return Err(err);
              }
            };
            key
          }
           AsyncEval::Suspend(mut suspend) => {
             if let Err(_) = suspend.frames.try_reserve(1) {
               for mut frame in suspend.frames {
                 async_teardown_frame(scope.heap_mut(), &mut frame);
               }
               cleanup(&mut scope, &mut excluded);
               return Err(VmError::OutOfMemory);
             }
            async_frames_push(
              &mut suspend.frames,
              AsyncFrame::BindObjAfterKey {
                pat: pat as *const ObjPat,
                prop_index: idx,
                value_root,
                excluded,
                kind,
              },
            )
            .expect("async_frames_push should not fail after try_reserve");
             return Ok(AsyncEval::Suspend(suspend));
           }
         }
       }
    };

    let rooted_key = match async_root_property_key(&mut scope, key) {
      Ok(k) => k,
      Err(err) => {
        scope.heap_mut().remove_root(value_root);
        async_cleanup_rooted_property_keys(scope.heap_mut(), &mut excluded);
        return Err(err);
      }
    };
    excluded.push(rooted_key);

    let mut prop_value = match scope
      .get_with_host_and_hooks(
        evaluator.vm,
        &mut *evaluator.host,
        &mut *evaluator.hooks,
        obj,
        key,
        receiver,
      )
      .map_err(|err| coerce_error_to_throw_for_async(evaluator.vm, &mut scope, err))
    {
      Ok(v) => v,
      Err(err) => {
        cleanup(&mut scope, &mut excluded);
        return Err(err);
      }
    };

    if matches!(prop_value, Value::Undefined) {
      if let Some(default_expr) = &prop.default_value {
        let default_eval = match async_eval_expr(evaluator, &mut scope, default_expr) {
          Ok(v) => v,
          Err(err) => {
            cleanup(&mut scope, &mut excluded);
            return Err(err);
          }
        };
        match default_eval {
          AsyncEval::Complete(v) => prop_value = v,
           AsyncEval::Suspend(mut suspend) => {
             if let Err(_) = suspend.frames.try_reserve(1) {
               for mut frame in suspend.frames {
                 async_teardown_frame(scope.heap_mut(), &mut frame);
               }
               cleanup(&mut scope, &mut excluded);
               return Err(VmError::OutOfMemory);
             }
            async_frames_push(
              &mut suspend.frames,
              AsyncFrame::BindObjAfterDefault {
                pat: pat as *const ObjPat,
                prop_index: idx,
                value_root,
                excluded,
                kind,
              },
            )
            .expect("async_frames_push should not fail after try_reserve");
             return Ok(AsyncEval::Suspend(suspend));
           }
         }
       }
      }

    let target_bind =
      match async_bind_pattern(evaluator, &mut scope, &prop.target.stx, prop_value, kind) {
        Ok(v) => v,
        Err(err) => {
          cleanup(&mut scope, &mut excluded);
          return Err(err);
        }
      };
    match target_bind {
      AsyncEval::Complete(()) => {}
      AsyncEval::Suspend(mut suspend) => {
        if let Err(_) = suspend.frames.try_reserve(1) {
          for mut frame in suspend.frames {
            async_teardown_frame(scope.heap_mut(), &mut frame);
          }
          cleanup(&mut scope, &mut excluded);
          return Err(VmError::OutOfMemory);
        }
        async_frames_push(
          &mut suspend.frames,
          AsyncFrame::BindObjContinue {
            pat: pat as *const ObjPat,
            next_prop_index: idx.saturating_add(1),
            value_root,
            excluded,
            kind,
          },
        )
        .expect("async_frames_push should not fail after try_reserve");
        return Ok(AsyncEval::Suspend(suspend));
      }
    }
  }

  let Some(rest_pat) = &pat.rest else {
    scope.heap_mut().remove_root(value_root);
    async_cleanup_rooted_property_keys(scope.heap_mut(), &mut excluded);
    return Ok(AsyncEval::Complete(()));
  };

  let rest_obj = match scope.alloc_object() {
    Ok(obj) => obj,
    Err(err) => {
      cleanup(&mut scope, &mut excluded);
      return Err(err);
    }
  };
  // Root the rest object only for the duration of this operation (including any nested
  // allocations triggered by binding `rest_pat`).
  let mut rest_scope = scope.reborrow();
  if let Err(err) = rest_scope.push_root(Value::Object(rest_obj)) {
    cleanup(&mut rest_scope, &mut excluded);
    return Err(err);
  }

  let keys = match rest_scope.object_own_property_keys_with_host_and_hooks(
    evaluator.vm,
    &mut *evaluator.host,
    &mut *evaluator.hooks,
    obj,
  ) {
    Ok(keys) => keys,
    Err(err) => {
      let err = coerce_error_to_throw_for_async(evaluator.vm, &mut rest_scope, err);
      cleanup(&mut rest_scope, &mut excluded);
      return Err(err);
    }
  };
  for key in keys {
    // Budget rest-property copying.
    if let Err(err) = evaluator.tick() {
      cleanup(&mut rest_scope, &mut excluded);
      return Err(err);
    }

    if excluded
      .iter()
      .any(|excluded_key| rest_scope.heap().property_key_eq(&excluded_key.key, &key))
    {
      continue;
    }

    let desc = match rest_scope
      .object_get_own_property_with_host_and_hooks(
        evaluator.vm,
        &mut *evaluator.host,
        &mut *evaluator.hooks,
        obj,
        key,
      )
      .map_err(|err| coerce_error_to_throw_for_async(evaluator.vm, &mut rest_scope, err))
    {
      Ok(Some(desc)) => desc,
      Ok(None) => continue,
      Err(err) => {
        cleanup(&mut rest_scope, &mut excluded);
        return Err(err);
      }
    };
    if !desc.enumerable {
      continue;
    }

    let v = match rest_scope
      .get_with_host_and_hooks(
        evaluator.vm,
        &mut *evaluator.host,
        &mut *evaluator.hooks,
        obj,
        key,
        Value::Object(obj),
      )
      .map_err(|err| coerce_error_to_throw_for_async(evaluator.vm, &mut rest_scope, err))
    {
      Ok(v) => v,
      Err(err) => {
        cleanup(&mut rest_scope, &mut excluded);
        return Err(err);
      }
    };
    if let Err(err) = rest_scope
      .create_data_property(rest_obj, key, v)
      .map_err(|err| coerce_error_to_throw_for_async(evaluator.vm, &mut rest_scope, err))
    {
      cleanup(&mut rest_scope, &mut excluded);
      return Err(err);
    }
  }

  // We no longer need the base object or excluded keys once the rest object has been created.
  rest_scope.heap_mut().remove_root(value_root);
  async_cleanup_rooted_property_keys(rest_scope.heap_mut(), &mut excluded);

  async_bind_pattern(
    evaluator,
    &mut rest_scope,
    &rest_pat.stx,
    Value::Object(rest_obj),
    kind,
  )
}

fn async_array_like_length(
  evaluator: &mut Evaluator<'_>,
  scope: &mut Scope<'_>,
  obj: GcObject,
) -> Result<u32, VmError> {
  let key_s = scope.alloc_string("length")?;
  scope.push_root(Value::String(key_s))?;
  let key = PropertyKey::from_string(key_s);
  let v = scope
    .get_with_host_and_hooks(
      evaluator.vm,
      &mut *evaluator.host,
      &mut *evaluator.hooks,
      obj,
      key,
      Value::Object(obj),
    )
    .map_err(|err| coerce_error_to_throw_for_async(evaluator.vm, scope, err))?;
  match v {
    Value::Number(n) if n.is_finite() && n >= 0.0 => Ok(n as u32),
    Value::Undefined => Ok(0),
    _ => Err(VmError::Unimplemented("array-like length")),
  }
}

fn async_array_like_get(
  evaluator: &mut Evaluator<'_>,
  scope: &mut Scope<'_>,
  obj: GcObject,
  idx: u32,
) -> Result<Value, VmError> {
  let key_s = scope.alloc_u32_index_string(idx)?;
  scope.push_root(Value::String(key_s))?;
  let key = PropertyKey::from_string(key_s);
  scope
    .get_with_host_and_hooks(
      evaluator.vm,
      &mut *evaluator.host,
      &mut *evaluator.hooks,
      obj,
      key,
      Value::Object(obj),
    )
    .map_err(|err| coerce_error_to_throw_for_async(evaluator.vm, scope, err))
}

fn async_bind_array_pattern(
  evaluator: &mut Evaluator<'_>,
  scope: &mut Scope<'_>,
  pat: &ArrPat,
  value_root: RootId,
  kind: BindingKind,
) -> Result<AsyncEval<()>, VmError> {
  let value = match scope.heap().get_root(value_root) {
    Some(v) => v,
    None => {
      scope.heap_mut().remove_root(value_root);
      return Err(VmError::InvariantViolation(
        "missing destructuring value root",
      ));
    }
  };
  let obj = match value {
    Value::Object(obj) => obj,
    other => {
      let obj = match scope.to_object(
        evaluator.vm,
        &mut *evaluator.host,
        &mut *evaluator.hooks,
        other,
      ) {
        Ok(obj) => obj,
        Err(err) => {
          scope.heap_mut().remove_root(value_root);
          return Err(coerce_error_to_throw_for_async(evaluator.vm, scope, err));
        }
      };
      scope.heap_mut().set_root(value_root, Value::Object(obj));
      obj
    }
  };

  let len = match async_array_like_length(evaluator, scope, obj) {
    Ok(len) => len,
    Err(err) => {
      scope.heap_mut().remove_root(value_root);
      return Err(err);
    }
  };
  async_bind_array_pattern_from(evaluator, scope, pat, value_root, kind, 0, 0, len)
}

fn async_bind_array_pattern_from(
  evaluator: &mut Evaluator<'_>,
  scope: &mut Scope<'_>,
  pat: &ArrPat,
  value_root: RootId,
  kind: BindingKind,
  start_elem_index: usize,
  start_array_index: u32,
  len: u32,
) -> Result<AsyncEval<()>, VmError> {
  let value = match scope.heap().get_root(value_root) {
    Some(v) => v,
    None => {
      scope.heap_mut().remove_root(value_root);
      return Err(VmError::InvariantViolation(
        "missing destructuring value root",
      ));
    }
  };
  let Value::Object(obj) = value else {
    scope.heap_mut().remove_root(value_root);
    return Err(
      throw_type_error(evaluator.vm, scope, "array destructuring requires object")
        .unwrap_or_else(|e| e),
    );
  };

  let cleanup = |scope: &mut Scope<'_>| {
    scope.heap_mut().remove_root(value_root);
  };

  let mut array_index = start_array_index;
  for (elem_index, elem) in pat.elements.iter().enumerate().skip(start_elem_index) {
    // Budget array destructuring by pattern size.
    if let Err(err) = evaluator.tick() {
      cleanup(scope);
      return Err(err);
    }

    let Some(elem) = elem else {
      array_index = array_index.saturating_add(1);
      continue;
    };

    let mut item = if array_index < len {
      match async_array_like_get(evaluator, scope, obj, array_index) {
        Ok(v) => v,
        Err(err) => {
          cleanup(scope);
          return Err(err);
        }
      }
    } else {
      Value::Undefined
    };

    if matches!(item, Value::Undefined) {
      if let Some(default_expr) = &elem.default_value {
        let default_eval = match async_eval_expr(evaluator, scope, default_expr) {
          Ok(v) => v,
          Err(err) => {
            cleanup(scope);
            return Err(err);
          }
        };
        match default_eval {
          AsyncEval::Complete(v) => item = v,
           AsyncEval::Suspend(mut suspend) => {
             if let Err(_) = suspend.frames.try_reserve(1) {
               for mut frame in suspend.frames {
                 async_teardown_frame(scope.heap_mut(), &mut frame);
               }
               cleanup(scope);
               return Err(VmError::OutOfMemory);
             }
            async_frames_push(
              &mut suspend.frames,
              AsyncFrame::BindArrAfterDefault {
                pat: pat as *const ArrPat,
                elem_index,
                array_index,
                len,
                value_root,
                kind,
              },
            )
            .expect("async_frames_push should not fail after try_reserve");
             return Ok(AsyncEval::Suspend(suspend));
           }
         }
       }
    }

    let elem_bind = match async_bind_pattern(evaluator, scope, &elem.target.stx, item, kind) {
      Ok(v) => v,
      Err(err) => {
        cleanup(scope);
        return Err(err);
      }
    };
    match elem_bind {
      AsyncEval::Complete(()) => {}
      AsyncEval::Suspend(mut suspend) => {
        if let Err(_) = suspend.frames.try_reserve(1) {
          for mut frame in suspend.frames {
            async_teardown_frame(scope.heap_mut(), &mut frame);
          }
          cleanup(scope);
          return Err(VmError::OutOfMemory);
        }
        async_frames_push(
          &mut suspend.frames,
          AsyncFrame::BindArrContinue {
            pat: pat as *const ArrPat,
            elem_index: elem_index.saturating_add(1),
            array_index: array_index.saturating_add(1),
            len,
            value_root,
            kind,
          },
        )
        .expect("async_frames_push should not fail after try_reserve");
        return Ok(AsyncEval::Suspend(suspend));
      }
    }

    array_index = array_index.saturating_add(1);
  }

  let Some(rest_pat) = &pat.rest else {
    scope.heap_mut().remove_root(value_root);
    return Ok(AsyncEval::Complete(()));
  };

  let rest_arr = match scope.alloc_object() {
    Ok(obj) => obj,
    Err(err) => {
      cleanup(scope);
      return Err(err);
    }
  };
  let mut rest_scope = scope.reborrow();
  if let Err(err) = rest_scope.push_root(Value::Object(rest_arr)) {
    cleanup(&mut rest_scope);
    return Err(err);
  }

  let mut rest_idx: u32 = 0;
  while array_index < len {
    // Budget rest-element copying.
    if let Err(err) = evaluator.tick() {
      cleanup(&mut rest_scope);
      return Err(err);
    }

    let v = match async_array_like_get(evaluator, &mut rest_scope, obj, array_index) {
      Ok(v) => v,
      Err(err) => {
        cleanup(&mut rest_scope);
        return Err(err);
      }
    };
    // Root the element value while allocating the property key and defining the property.
    let res = {
      let mut elem_scope = rest_scope.reborrow();
      (|| -> Result<(), VmError> {
        let v = elem_scope.push_root(v)?;
        let key_s = elem_scope.alloc_u32_index_string(rest_idx)?;
        let key = PropertyKey::from_string(key_s);
        let _ = elem_scope
          .create_data_property(rest_arr, key, v)
          .map_err(|err| coerce_error_to_throw_for_async(evaluator.vm, &mut elem_scope, err))?;
        Ok(())
      })()
    };
    if let Err(err) = res {
      cleanup(&mut rest_scope);
      return Err(err);
    }

    array_index = array_index.saturating_add(1);
    rest_idx = rest_idx.saturating_add(1);
  }

  // Define `length` as non-enumerable to match real arrays closely enough for rest patterns.
  let length_s = match rest_scope.alloc_string("length") {
    Ok(s) => s,
    Err(err) => {
      cleanup(&mut rest_scope);
      return Err(err);
    }
  };
  let length_key = PropertyKey::from_string(length_s);
  let length_desc = PropertyDescriptor {
    enumerable: false,
    configurable: true,
    kind: PropertyKind::Data {
      value: Value::Number(rest_idx as f64),
      writable: true,
    },
  };
  if let Err(err) = rest_scope
    .define_property(rest_arr, length_key, length_desc)
    .map_err(|err| coerce_error_to_throw_for_async(evaluator.vm, &mut rest_scope, err))
  {
    cleanup(&mut rest_scope);
    return Err(err);
  }

  // We no longer need the base array once the rest array has been created.
  rest_scope.heap_mut().remove_root(value_root);

  async_bind_pattern(
    evaluator,
    &mut rest_scope,
    &rest_pat.stx,
    Value::Object(rest_arr),
    kind,
  )
}

fn async_eval_class_decl(
  evaluator: &mut Evaluator<'_>,
  scope: &mut Scope<'_>,
  decl: &Node<ClassDecl>,
) -> Result<AsyncEval<Completion>, VmError> {
  if !decl.stx.decorators.is_empty() {
    return Err(VmError::Unimplemented("class decorators"));
  }
  if decl.stx.type_parameters.is_some() {
    return Err(VmError::Unimplemented("class type parameters"));
  }
  if !decl.stx.implements.is_empty() {
    return Err(VmError::Unimplemented("class implements"));
  }
  if decl.stx.declare || decl.stx.abstract_ {
    return Err(VmError::Unimplemented("class modifiers"));
  }

  let binding_name = match decl.stx.name.as_ref() {
    Some(name) => name.stx.name.as_str(),
    None => "*default*",
  };
  let func_name = match decl.stx.name.as_ref() {
    Some(name) => name.stx.name.as_str(),
    None => "default",
  };

  // Per ECMAScript, class declarations are evaluated within a fresh lexical environment whose
  // outer is the surrounding lexical environment. When the class has a name, that environment
  // contains an immutable binding for the class name so class element functions can reference the
  // class even if the outer binding is later reassigned.
  let outer = evaluator.env.lexical_env;
  let class_env = scope.env_create(Some(outer))?;
  evaluator.env.set_lexical_env(scope.heap_mut(), class_env);

  let inner_binding = match decl.stx.name.as_ref() {
    Some(name) => ClassBinding::Immutable(name.stx.name.as_str()),
    None => ClassBinding::None,
  };

  let result = async_eval_class(
    evaluator,
    scope,
    inner_binding,
    func_name,
    &decl.stx.members,
    decl.stx.extends.as_ref(),
  );

  match result {
    Ok(AsyncEval::Complete(func_value)) => {
      // Restore outer environment regardless of how binding initialization completes.
      evaluator.env.set_lexical_env(scope.heap_mut(), outer);

      // Initialize the outer (mutable) class binding in the surrounding environment.
      //
      // Root the class constructor object first: creating the binding may allocate and trigger GC.
      let mut init_scope = scope.reborrow();
      init_scope.push_root(func_value)?;

      if !init_scope.heap().env_has_binding(outer, binding_name)? {
        // Non-block statement contexts may not have performed lexical hoisting yet.
        init_scope.env_create_mutable_binding(outer, binding_name)?;
      }
      init_scope
        .heap_mut()
        .env_initialize_binding(outer, binding_name, func_value)?;
      Ok(AsyncEval::Complete(Completion::empty()))
    }
    Ok(AsyncEval::Suspend(mut suspend)) => {
      // Preserve the class environment across suspension; restore the outer env and initialize the
      // surrounding binding on completion.
      if let Err(err) = async_frames_push(
        &mut suspend.frames,
        AsyncFrame::ClassDecl {
          decl: decl as *const Node<ClassDecl>,
          outer,
        },
      ) {
        evaluator.env.set_lexical_env(scope.heap_mut(), outer);
        return Err(err);
      }
      Ok(AsyncEval::Suspend(suspend))
    }
    Err(err) => {
      // Restore outer environment regardless of how class evaluation completes.
      evaluator.env.set_lexical_env(scope.heap_mut(), outer);
      Err(err)
    }
  }
}

fn async_eval_class_expr_inferred_name(
  evaluator: &mut Evaluator<'_>,
  scope: &mut Scope<'_>,
  expr: &Node<ClassExpr>,
  inferred_func_name: &'static str,
) -> Result<AsyncEval<Value>, VmError> {
  // Only apply inferred names to *anonymous* class expressions. If the class has an explicit name,
  // that name must be used both as the constructor name and as the inner binding identifier.
  if expr.stx.name.is_some() {
    return async_eval_class_expr(evaluator, scope, expr);
  }

  if !expr.stx.decorators.is_empty() {
    return Err(VmError::Unimplemented("class decorators"));
  }
  if expr.stx.type_parameters.is_some() {
    return Err(VmError::Unimplemented("class type parameters"));
  }
  if !expr.stx.implements.is_empty() {
    return Err(VmError::Unimplemented("class implements"));
  }

  async_eval_class(
    evaluator,
    scope,
    ClassBinding::None,
    inferred_func_name,
    &expr.stx.members,
    expr.stx.extends.as_ref(),
  )
}

fn async_eval_class_expr(
  evaluator: &mut Evaluator<'_>,
  scope: &mut Scope<'_>,
  expr: &Node<ClassExpr>,
) -> Result<AsyncEval<Value>, VmError> {
  if !expr.stx.decorators.is_empty() {
    return Err(VmError::Unimplemented("class decorators"));
  }
  if expr.stx.type_parameters.is_some() {
    return Err(VmError::Unimplemented("class type parameters"));
  }
  if !expr.stx.implements.is_empty() {
    return Err(VmError::Unimplemented("class implements"));
  }

  // Named class expressions introduce an inner immutable binding for the class name.
  let outer = evaluator.env.lexical_env;
  let result = (|| {
    let Some(name) = expr.stx.name.as_ref() else {
      return async_eval_class(
        evaluator,
        scope,
        ClassBinding::None,
        "",
        &expr.stx.members,
        expr.stx.extends.as_ref(),
      );
    };

    let class_env = scope.env_create(Some(outer))?;
    evaluator.env.set_lexical_env(scope.heap_mut(), class_env);
    async_eval_class(
      evaluator,
      scope,
      ClassBinding::Immutable(name.stx.name.as_str()),
      name.stx.name.as_str(),
      &expr.stx.members,
      expr.stx.extends.as_ref(),
    )
  })();

  match result {
    Ok(AsyncEval::Complete(v)) => {
      if expr.stx.name.is_some() {
        evaluator.env.set_lexical_env(scope.heap_mut(), outer);
      }
      Ok(AsyncEval::Complete(v))
    }
    Ok(AsyncEval::Suspend(mut suspend)) => {
      // Preserve the class environment across suspension; restore the outer env on completion.
      if expr.stx.name.is_some() {
        async_frames_push(&mut suspend.frames, AsyncFrame::RestoreLexEnv { outer })?;
      }
      Ok(AsyncEval::Suspend(suspend))
    }
    Err(err) => {
      if expr.stx.name.is_some() {
        evaluator.env.set_lexical_env(scope.heap_mut(), outer);
      }
      Err(err)
    }
  }
}

fn async_eval_class(
  evaluator: &mut Evaluator<'_>,
  scope: &mut Scope<'_>,
  binding: ClassBinding<'_>,
  func_name: &str,
  members: &Vec<Node<ClassMember>>,
  extends: Option<&Node<Expr>>,
) -> Result<AsyncEval<Value>, VmError> {
  // Per ECMA-262, class definitions are always strict mode code, regardless of whether they
  // appear in a sloppy script/function body.
  //
  // This matters for runtime semantics (not just early errors). For example, in sloppy mode,
  // `unbound = 1` creates a global property, but in class bodies it must throw a ReferenceError.
  //
  // Mirror `Evaluator::eval_class`: temporarily force strict mode for the entire class definition
  // evaluation, restoring it afterwards (including across `await` suspensions).
  let saved_strict = evaluator.strict;
  evaluator.strict = true;

  let result = (|| {
    let class_env = evaluator.env.lexical_env;

    // Ensure the requested class binding exists before creating any class element closures that may
    // reference it.
    match binding {
      ClassBinding::None => {}
      ClassBinding::Immutable(name) => {
        if scope.heap().env_has_binding(class_env, name)? {
          return Err(VmError::InvariantViolation(
            "class binding already exists in class environment",
          ));
        }
        scope.env_create_immutable_binding(class_env, name)?;
      }
    }

    // Create the class's private-name environment.
    //
    // `parse-js` represents private names as strings like `"#x"`. To enforce per-class privacy, we
    // allocate a fresh internal symbol for each declared private name and store the mapping on the
    // class's lexical environment record. All class element bodies capture that environment, so
    // private member expressions can resolve the correct symbol even if the class binding is passed
    // around.
    //
    // This must happen before any possible `await` suspension so the mapping persists across async
    // continuations.
    let mut private_names: Vec<String> = Vec::new();
    let mut private_name_set: HashSet<&str> = HashSet::new();
    for member in members {
      if let ClassOrObjKey::Direct(key) = &member.stx.key {
        if key.stx.tt == TT::PrivateMember {
          let name = key.stx.key.as_str();
          if private_name_set.contains(name) {
            continue;
          }
          private_name_set
            .try_reserve(1)
            .map_err(|_| VmError::OutOfMemory)?;
          private_name_set.insert(name);
          private_names
            .try_reserve(1)
            .map_err(|_| VmError::OutOfMemory)?;
          private_names.push(try_clone_string(name)?);
        }
      }
    }
    if !private_names.is_empty() {
      let mut entries: Vec<crate::env::PrivateNameEntry> = Vec::new();
      entries
        .try_reserve_exact(private_names.len())
        .map_err(|_| VmError::OutOfMemory)?;
      // Keep all allocated symbols rooted until the mapping is installed into the class environment
      // record, so intermediate allocations cannot collect them.
      let mut priv_scope = scope.reborrow();
      for name in private_names {
        let desc = priv_scope.alloc_string(&name)?;
        let sym = priv_scope.new_internal_symbol(Some(desc))?;
        priv_scope.push_root(Value::Symbol(sym))?;
        entries.push(crate::env::PrivateNameEntry {
          name: name.into_boxed_str(),
          sym,
        });
      }
      priv_scope
        .heap_mut()
        .env_set_private_names(class_env, entries.into_boxed_slice())?;
    }

    // Evaluate `extends` (class heritage), if present.
    let super_value = match extends {
      None => Value::Undefined,
      Some(extends_expr) => match async_eval_expr(evaluator, scope, extends_expr)? {
        AsyncEval::Complete(v) => async_class_heritage_value_to_super_value(evaluator, scope, v)?,
        AsyncEval::Suspend(mut suspend) => {
          let binding_name = match binding {
            ClassBinding::None => None,
            ClassBinding::Immutable(name) => Some(name as *const str),
          };

          let push_res = async_frames_push(
            &mut suspend.frames,
            AsyncFrame::ClassAfterHeritage {
              members: members as *const Vec<Node<ClassMember>>,
              binding_name,
              func_name: func_name as *const str,
            },
          );
          if let Err(err) = push_res {
            // Best-effort cleanup: tear down any rooted frames so we don't leak GC roots on OOM.
            for mut frame in suspend.frames {
              async_teardown_frame(scope.heap_mut(), &mut frame);
            }
            return Err(err);
          }
          return Ok(AsyncEval::Suspend(suspend));
        }
      },
    };

    async_eval_class_after_super(evaluator, scope, binding, func_name, members, super_value)
  })();

  match result {
    Ok(AsyncEval::Complete(v)) => {
      evaluator.strict = saved_strict;
      Ok(AsyncEval::Complete(v))
    }
    Ok(AsyncEval::Suspend(mut suspend)) => {
      // Preserve strict-mode semantics across the suspension; restore strictness only after the
      // class definition evaluation completes.
      if let Err(err) = async_frames_push(&mut suspend.frames, AsyncFrame::RestoreStrict { saved_strict }) {
        // Best-effort cleanup: tear down any rooted frames so we don't leak GC roots on OOM.
        for mut frame in suspend.frames {
          async_teardown_frame(scope.heap_mut(), &mut frame);
        }
        evaluator.strict = saved_strict;
        return Err(err);
      }
      Ok(AsyncEval::Suspend(suspend))
    }
    Err(err) => {
      evaluator.strict = saved_strict;
      Err(err)
    }
  }
}

fn async_class_heritage_value_to_super_value(
  evaluator: &mut Evaluator<'_>,
  scope: &mut Scope<'_>,
  heritage_value: Value,
) -> Result<Value, VmError> {
  match heritage_value {
    Value::Undefined => Err(throw_type_error(
      evaluator.vm,
      scope,
      "Class extends value is not a constructor",
    )?),
    Value::Null => Ok(Value::Null),
    Value::Object(_) => {
      if !scope.heap().is_constructor(heritage_value)? {
        return Err(throw_type_error(
          evaluator.vm,
          scope,
          "Class extends value is not a constructor",
        )?);
      }
      Ok(heritage_value)
    }
    _ => Err(throw_type_error(
      evaluator.vm,
      scope,
      "Class extends value is not a constructor",
    )?),
  }
}

fn async_eval_class_after_super(
  evaluator: &mut Evaluator<'_>,
  scope: &mut Scope<'_>,
  binding: ClassBinding<'_>,
  func_name: &str,
  members: &Vec<Node<ClassMember>>,
  super_value: Value,
) -> Result<AsyncEval<Value>, VmError> {
  let class_env = evaluator.env.lexical_env;

  // Root `super_value` across class-constructor allocation so it cannot be collected even if it is
  // not otherwise reachable (e.g. `class B extends (class {}) {}`).
  let mut class_scope = scope.reborrow();
  class_scope.push_root(super_value)?;

  // Find an explicit `constructor(...) { ... }` method, if present.
  let mut ctor_method: Option<(&Node<Func>, u32, parse_js::loc::Loc)> = None;
  for member in members {
    evaluator.tick()?;

    if !member.stx.decorators.is_empty() {
      return Err(VmError::Unimplemented("class member decorators"));
    }
    if member.stx.declare || member.stx.abstract_ {
      return Err(VmError::Unimplemented("class member modifiers"));
    }
    if member.stx.readonly
      || member.stx.accessor
      || member.stx.optional
      || member.stx.override_
      || member.stx.definite_assignment
    {
      return Err(VmError::Unimplemented("class member modifiers"));
    }
    if member.stx.accessibility.is_some() || member.stx.type_annotation.is_some() {
      return Err(VmError::Unimplemented("class member type annotations"));
    }

    if member.stx.static_ {
      continue;
    }
    let ClassOrObjKey::Direct(direct) = &member.stx.key else {
      continue;
    };
    if direct.stx.key != "constructor" {
      continue;
    }

    let ClassOrObjVal::Method(method) = &member.stx.val else {
      continue;
    };

    if ctor_method.is_some() {
      return Err(syntax_error(
        member.loc,
        "A class may only have one constructor",
      ));
    }
    ctor_method = Some((&method.stx.func, member.loc.start_u32(), member.loc));
  }

  let mut ctor_length: u32 = 0;
  let ctor_body_func = if let Some((func_node, member_loc_start, loc)) = ctor_method {
    if func_node.stx.generator {
      return Err(syntax_error(
        loc,
        "Class constructor may not be a generator",
      ));
    }

    ctor_length = evaluator.function_length(&func_node.stx)?;

    let rel_start = member_loc_start.saturating_sub(evaluator.env.prefix_len());
    let rel_end = func_node
      .loc
      .end_u32()
      .saturating_sub(evaluator.env.prefix_len());
    let span_start = evaluator.env.base_offset().saturating_add(rel_start);
    let span_end = evaluator.env.base_offset().saturating_add(rel_end);

      let code = evaluator.vm.register_ecma_function(
        evaluator.env.source(),
        span_start,
        span_end,
        EcmaFunctionKind::ClassMember,
      )?;

      // Class constructor bodies are always strict mode.
      let is_strict = true;
      let this_mode = if func_node.stx.arrow {
        ThisMode::Lexical
      } else {
        ThisMode::Strict
      };
      let closure_env = Some(evaluator.env.lexical_env);

      let mut ctor_scope = class_scope.reborrow();
      let name_string = ctor_scope.alloc_string("constructor")?;
      let func_obj = ctor_scope.alloc_ecma_function(
        code,
        /* is_constructable */ true,
        name_string,
        ctor_length,
        this_mode,
        is_strict,
        closure_env,
      )?;

    let intr = evaluator
      .vm
      .intrinsics()
      .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;
    ctor_scope
      .heap_mut()
      .object_set_prototype(func_obj, Some(intr.function_prototype()))?;
    ctor_scope
      .heap_mut()
      .set_function_realm(func_obj, evaluator.env.global_object())?;
    if let Some(realm) = evaluator.vm.current_realm() {
      ctor_scope.heap_mut().set_function_job_realm(func_obj, realm)?;
    }
    if let Some(script_or_module) = evaluator.vm.get_active_script_or_module() {
      let token = evaluator.vm.intern_script_or_module(script_or_module)?;
      ctor_scope
        .heap_mut()
        .set_function_script_or_module_token(func_obj, Some(token))?;
    }
    Some(func_obj)
  } else {
    None
  };

  let func_obj = evaluator.create_class_constructor_object(
    &mut class_scope,
    func_name,
    ctor_length,
    ctor_body_func,
    super_value,
    /* instance_field_count */ 0,
  )?;

  // Create a persistent root for the class constructor object so it remains GC-safe across `await`
  // suspensions during computed member key evaluation.
  let func_root = {
    let mut root_scope = class_scope.reborrow();
    root_scope.push_root(Value::Object(func_obj))?;
    root_scope.heap_mut().add_root(Value::Object(func_obj))?
  };

  // If the class has an explicit `constructor(...) { ... }` body, annotate that hidden function
  // object so `[[Construct]]` can implement derived `super()` semantics.
  if let Some(body_func) = ctor_body_func {
    if let Err(err) = class_scope.heap_mut().set_function_data(
      body_func,
      FunctionData::ClassConstructorBody {
        class_constructor: func_obj,
      },
    ) {
      class_scope.heap_mut().remove_root(func_root);
      return Err(err);
    }
  }

  // Initialize the requested binding now that the class constructor object exists.
  if let Some(binding_name) = match binding {
    ClassBinding::None => None,
    ClassBinding::Immutable(name) => Some(name),
  } {
    let init_res = (|| -> Result<(), VmError> {
      let mut init_scope = class_scope.reborrow();
      init_scope.push_root(Value::Object(func_obj))?;
      init_scope
        .heap_mut()
        .env_initialize_binding(class_env, binding_name, Value::Object(func_obj))?;
      Ok(())
    })();
    if let Err(err) = init_res {
      class_scope.heap_mut().remove_root(func_root);
      return Err(err);
    }
  }

  // Extract the prototype object created by `make_constructor`.
  let (prototype_key, prototype_obj) =
    match (|| -> Result<(PropertyKey, GcObject), VmError> {
      let mut proto_scope = class_scope.reborrow();
      proto_scope.push_root(Value::Object(func_obj))?;
      let prototype_key_s = proto_scope.alloc_string("prototype")?;
      proto_scope.push_root(Value::String(prototype_key_s))?;
      let prototype_key = PropertyKey::from_string(prototype_key_s);
      let Some(prototype_desc) = proto_scope.heap().get_own_property(func_obj, prototype_key)? else {
        return Err(VmError::InvariantViolation(
          "class constructor missing prototype property",
        ));
      };
      let PropertyKind::Data { value, .. } = prototype_desc.kind else {
        return Err(VmError::InvariantViolation(
          "class constructor prototype property is not a data property",
        ));
      };
      let Value::Object(prototype_obj) = value else {
        return Err(VmError::InvariantViolation(
          "class constructor prototype property is not an object",
        ));
      };
      Ok((prototype_key, prototype_obj))
    })() {
      Ok(v) => v,
      Err(e) => {
        class_scope.heap_mut().remove_root(func_root);
        return Err(e);
      }
    };

  // Class constructor bodies (the hidden function object invoked via `[[Construct]]`) use the
  // prototype object as their `[[HomeObject]]` so `super.prop` can resolve against
  // `super.prototype`.
  if let Some(body_func) = ctor_body_func {
    if let Err(err) = class_scope
      .heap_mut()
      .set_function_home_object(body_func, Some(prototype_obj))
    {
      class_scope.heap_mut().remove_root(func_root);
      return Err(err);
    }
  }

  // Per ECMAScript, class constructors have a non-writable `prototype` property.
  let patch_res = (|| -> Result<(), VmError> {
    let mut patch_scope = class_scope.reborrow();
    patch_scope.push_root(Value::Object(func_obj))?;
    patch_scope.push_root(Value::Object(prototype_obj))?;
    match prototype_key {
      PropertyKey::String(s) => patch_scope.push_root(Value::String(s))?,
      PropertyKey::Symbol(s) => patch_scope.push_root(Value::Symbol(s))?,
    };
    patch_scope
      .define_property_or_throw(
        func_obj,
        prototype_key,
        PropertyDescriptorPatch {
          writable: Some(false),
          ..Default::default()
        },
      )
      .map_err(|err| coerce_error_to_throw_for_async(evaluator.vm, &mut patch_scope, err))?;
    Ok(())
  })();
  if let Err(err) = patch_res {
    class_scope.heap_mut().remove_root(func_root);
    return Err(err);
  }

  // Wire the instance prototype chain.
  //
  // - base class: `prototype.[[Prototype]] = %Object.prototype%`
  // - `extends null`: `prototype.[[Prototype]] = null`
  // - derived class: `prototype.[[Prototype]] = super.prototype`
  let intr = evaluator
    .vm
    .intrinsics()
    .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;
  let proto_set_res: Result<(), VmError> = (|| {
    match super_value {
      Value::Undefined => class_scope
        .heap_mut()
        .object_set_prototype(prototype_obj, Some(intr.object_prototype())),
      Value::Null => class_scope.heap_mut().object_set_prototype(prototype_obj, None),
      Value::Object(super_ctor) => {
        let proto_parent: Option<GcObject> = {
          let mut proto_scope = class_scope.reborrow();
          proto_scope.push_root(Value::Object(super_ctor))?;
          let proto_key_s = proto_scope.alloc_string("prototype")?;
          proto_scope.push_root(Value::String(proto_key_s))?;
          let proto_key = PropertyKey::from_string(proto_key_s);
          let proto_value = proto_scope
            .ordinary_get_with_host_and_hooks(
              evaluator.vm,
              &mut *evaluator.host,
              &mut *evaluator.hooks,
              super_ctor,
              proto_key,
              Value::Object(super_ctor),
            )
            .map_err(|err| coerce_error_to_throw_for_async(evaluator.vm, &mut proto_scope, err))?;
          match proto_value {
            Value::Object(o) => Some(o),
            Value::Null => None,
            _ => {
              return Err(throw_type_error(
                evaluator.vm,
                &mut proto_scope,
                "Class extends value does not have a valid prototype property",
              )?)
            }
          }
        };
        class_scope
          .heap_mut()
          .object_set_prototype(prototype_obj, proto_parent)
      }
      _ => Err(VmError::InvariantViolation(
        "class constructor super value is not undefined, null, or object",
      )),
    }?;
    Ok(())
  })();
  if let Err(err) = proto_set_res {
    class_scope.heap_mut().remove_root(func_root);
    return Err(err);
  }

  // Define prototype and static methods.
  async_eval_class_members_from(evaluator, &mut class_scope, members, 0, func_root)
}

fn async_eval_class_members_from(
  evaluator: &mut Evaluator<'_>,
  scope: &mut Scope<'_>,
  members: &Vec<Node<ClassMember>>,
  start_index: usize,
  func_root: RootId,
) -> Result<AsyncEval<Value>, VmError> {
  let res: Result<AsyncEval<Value>, VmError> = (|| {
    let class_env = evaluator.env.lexical_env;
    let func_value = scope
      .heap()
      .get_root(func_root)
      .ok_or(VmError::InvariantViolation(
        "missing class constructor root",
      ))?;
    let Value::Object(func_obj) = func_value else {
      return Err(VmError::InvariantViolation(
        "class constructor root is not an object",
      ));
    };

    let prototype_obj = {
      let mut class_scope = scope.reborrow();
      class_scope.push_root(Value::Object(func_obj))?;
      let prototype_key_s = class_scope.alloc_string("prototype")?;
      class_scope.push_root(Value::String(prototype_key_s))?;
      let prototype_key = PropertyKey::from_string(prototype_key_s);
      let Some(prototype_desc) = class_scope
        .heap()
        .get_own_property(func_obj, prototype_key)?
      else {
        return Err(VmError::InvariantViolation(
          "class constructor missing prototype property",
        ));
      };
      let PropertyKind::Data { value, .. } = prototype_desc.kind else {
        return Err(VmError::InvariantViolation(
          "class constructor prototype property is not a data property",
        ));
      };
      let Value::Object(prototype_obj) = value else {
        return Err(VmError::InvariantViolation(
          "class constructor prototype property is not an object",
        ));
      };
      prototype_obj
    };

    for (idx, member) in members.iter().enumerate().skip(start_index) {
      evaluator.tick()?;

      if !member.stx.decorators.is_empty() {
        return Err(VmError::Unimplemented("class member decorators"));
      }
      if member.stx.declare || member.stx.abstract_ {
        return Err(VmError::Unimplemented("class member modifiers"));
      }
      if member.stx.readonly
        || member.stx.accessor
        || member.stx.optional
        || member.stx.override_
        || member.stx.definite_assignment
      {
        return Err(VmError::Unimplemented("class member modifiers"));
      }
      if member.stx.accessibility.is_some() || member.stx.type_annotation.is_some() {
        return Err(VmError::Unimplemented("class member type annotations"));
      }

      // Skip the actual `constructor(...) { ... }` method: it's represented by the class
      // constructor object itself (and its hidden body function).
      let is_constructor_method = !member.stx.static_
        && matches!(&member.stx.key, ClassOrObjKey::Direct(direct) if direct.stx.key == "constructor")
        && matches!(&member.stx.val, ClassOrObjVal::Method(_));
      if is_constructor_method {
        continue;
      }

      // Static initialization blocks are not properties on the class/prototype. They are evaluated
      // after the element definition pass completes, in source order. Per ECMAScript, they must
      // not evaluate a key.
      if matches!(&member.stx.val, ClassOrObjVal::StaticBlock(_)) {
        continue;
      }

      let target_obj = if member.stx.static_ {
        func_obj
      } else {
        prototype_obj
      };

      let key = match &member.stx.key {
        ClassOrObjKey::Direct(direct) => {
          if direct.stx.tt == TT::PrivateMember {
            let sym = scope
              .heap()
              .resolve_private_name_symbol(class_env, &direct.stx.key)?
              .ok_or(VmError::InvariantViolation("unresolved private name"))?;
            PropertyKey::from_symbol(sym)
          } else {
            let mut key_scope = scope.reborrow();
            key_scope.push_root(Value::Object(target_obj))?;
            let key_s = if let Some(units) = literal_string_code_units(&direct.assoc) {
              key_scope.alloc_string_from_code_units(units)?
            } else if direct.stx.tt == TT::LiteralNumber {
              let n = direct
                .stx
                .key
                .parse::<f64>()
                .map_err(|_| VmError::Unimplemented("numeric literal property name parse"))?;
              key_scope.heap_mut().to_string(Value::Number(n))?
            } else {
              key_scope.alloc_string(&direct.stx.key)?
            };
            PropertyKey::from_string(key_s)
          }
        }
        ClassOrObjKey::Computed(expr) => match async_eval_expr(evaluator, scope, expr)? {
          AsyncEval::Complete(value) => {
            let mut key_scope = scope.reborrow();
            key_scope.push_root(Value::Object(target_obj))?;
            key_scope.push_root(value)?;
            evaluator
              .to_property_key_operator(&mut key_scope, value)
              .map_err(|err| coerce_error_to_throw_for_async(evaluator.vm, &mut key_scope, err))?
          }
          AsyncEval::Suspend(mut suspend) => {
            async_frames_push(
              &mut suspend.frames,
              AsyncFrame::ClassAfterComputedKey {
                members: members as *const Vec<Node<ClassMember>>,
                member_index: idx,
                func_root,
              },
            )?;
            return Ok(AsyncEval::Suspend(suspend));
          }
        },
      };

      async_define_class_member(
        evaluator,
        scope,
        member,
        func_obj,
        prototype_obj,
        target_obj,
        key,
      )?;
    }

    // Evaluate class static blocks in source order.
    async_eval_class_static_blocks_from(evaluator, scope, members, 0, func_root)
  })();

  match res {
    Ok(AsyncEval::Suspend(suspend)) => Ok(AsyncEval::Suspend(suspend)),
    Ok(AsyncEval::Complete(v)) => {
      scope.heap_mut().remove_root(func_root);
      Ok(AsyncEval::Complete(v))
    }
    Err(err) => {
      scope.heap_mut().remove_root(func_root);
      Err(err)
    }
  }
}

fn async_eval_class_static_blocks_from(
  evaluator: &mut Evaluator<'_>,
  scope: &mut Scope<'_>,
  members: &Vec<Node<ClassMember>>,
  start_index: usize,
  func_root: RootId,
) -> Result<AsyncEval<Value>, VmError> {
  let func_value = scope
    .heap()
    .get_root(func_root)
    .ok_or(VmError::InvariantViolation(
      "missing class constructor root",
    ))?;
  let Value::Object(func_obj) = func_value else {
    return Err(VmError::InvariantViolation(
      "class constructor root is not an object",
    ));
  };

  for (idx, member) in members.iter().enumerate().skip(start_index) {
    evaluator.tick()?;

    let ClassOrObjVal::StaticBlock(block) = &member.stx.val else {
      continue;
    };

    // Static blocks are evaluated as strict-mode "method" bodies with:
    // - `this` bound to the class constructor object, and
    // - `new.target` set to `undefined`.
    //
    // We implement this by:
    // - saving the current evaluator context (`this`, `new.target`, lexical env, var env),
    // - creating a fresh var env whose outer is the class lexical env,
    // - creating a function-body lexical env whose outer is that var env,
    // - instantiating + evaluating the statement list (which may suspend if it contains `await`),
    // - restoring the outer context afterwards.
    let mut block_scope = scope.reborrow();
    block_scope.push_root(Value::Object(func_obj))?;

    let saved_this = evaluator.this;
    let saved_new_target = evaluator.new_target;
    let saved_home_object_value = evaluator
      .home_object
      .map(Value::Object)
      .unwrap_or(Value::Undefined);
    let saved_lex = evaluator.env.lexical_env;
    let saved_var_env = evaluator.env.var_env();
    let saved_meta_property_context = evaluator.env.meta_property_context();

    // Root the saved values so they remain GC-safe even if we suspend (the async continuation's
    // `this_root` / `new_target_root` / `home_object_root` will be updated to the block's
    // overridden values).
    block_scope.push_root(saved_this)?;
    block_scope.push_root(saved_new_target)?;
    block_scope.push_root(saved_home_object_value)?;
    let saved_this_root = block_scope.heap_mut().add_root(saved_this)?;
    let saved_new_target_root = block_scope.heap_mut().add_root(saved_new_target)?;
    let saved_home_object_root = block_scope.heap_mut().add_root(saved_home_object_value)?;

    evaluator.this = Value::Object(func_obj);
    evaluator.new_target = Value::Undefined;
    evaluator.home_object = Some(func_obj);
    evaluator
      .env
      .set_meta_property_context(MetaPropertyContext::METHOD);

    let var_env = block_scope.env_create(Some(saved_lex))?;
    let body_lex = block_scope.env_create(Some(var_env))?;
    evaluator.env.set_var_env(VarEnv::Env(var_env));
    evaluator
      .env
      .set_lexical_env(block_scope.heap_mut(), body_lex);

    // Hoist var/lexical/function declarations within the block before evaluating it.
    evaluator.instantiate_stmt_list(&mut block_scope, &block.stx.body)?;

    match async_eval_stmt_list(evaluator, &mut block_scope, &block.stx.body) {
      Ok(AsyncEval::Complete(completion)) => {
        // Restore outer context before continuing (static block execution is synchronous at the
        // statement-list boundary regardless of completion type).
        evaluator
          .env
          .set_lexical_env(block_scope.heap_mut(), saved_lex);
        evaluator.env.set_var_env(saved_var_env);
        evaluator
          .env
          .set_meta_property_context(saved_meta_property_context);
        evaluator.this = saved_this;
        evaluator.new_target = saved_new_target;
        evaluator.home_object = match saved_home_object_value {
          Value::Object(o) => Some(o),
          _ => None,
        };
        block_scope.heap_mut().remove_root(saved_this_root);
        block_scope.heap_mut().remove_root(saved_new_target_root);
        block_scope.heap_mut().remove_root(saved_home_object_root);

        match completion {
          Completion::Normal(_) => continue,
          Completion::Throw(thrown) => {
            return Err(VmError::ThrowWithStack {
              value: thrown.value,
              stack: thrown.stack,
            })
          }
          Completion::Return(_) => {
            return Err(VmError::InvariantViolation(
              "class static block produced Return completion (early errors should prevent this)",
            ))
          }
          Completion::Break(..) => {
            return Err(VmError::InvariantViolation(
              "class static block produced Break completion (early errors should prevent this)",
            ))
          }
          Completion::Continue(..) => {
            return Err(VmError::InvariantViolation(
              "class static block produced Continue completion (early errors should prevent this)",
            ))
          }
        }
      }
      Ok(AsyncEval::Suspend(mut suspend)) => {
        // Preserve the static-block execution context across suspension; restore + continue only
        // after the statement list completes.
        let push_res = async_frames_push(
          &mut suspend.frames,
          AsyncFrame::ClassAfterStaticBlock {
            members: members as *const Vec<Node<ClassMember>>,
            next_index: idx.saturating_add(1),
            func_root,
            saved_this_root,
            saved_new_target_root,
            saved_home_object_root,
            saved_lex,
            saved_var_env,
            saved_meta_property_context,
          },
        );
        if let Err(err) = push_res {
          // Best-effort cleanup: tear down any rooted frames and restore the evaluator context so
          // we don't leak roots or leave the evaluator in a mutated state when bubbling up OOM.
          for mut frame in suspend.frames {
            async_teardown_frame(block_scope.heap_mut(), &mut frame);
          }
          evaluator
            .env
            .set_lexical_env(block_scope.heap_mut(), saved_lex);
          evaluator.env.set_var_env(saved_var_env);
          evaluator
            .env
            .set_meta_property_context(saved_meta_property_context);
          evaluator.this = saved_this;
          evaluator.new_target = saved_new_target;
          evaluator.home_object = match saved_home_object_value {
            Value::Object(o) => Some(o),
            _ => None,
          };
          block_scope.heap_mut().remove_root(saved_this_root);
          block_scope.heap_mut().remove_root(saved_new_target_root);
          block_scope.heap_mut().remove_root(saved_home_object_root);
          return Err(err);
        }
        return Ok(AsyncEval::Suspend(suspend));
      }
      Err(err) => {
        // Fatal error: restore context and drop temporary roots before bubbling the error up.
        evaluator
          .env
          .set_lexical_env(block_scope.heap_mut(), saved_lex);
        evaluator.env.set_var_env(saved_var_env);
        evaluator
          .env
          .set_meta_property_context(saved_meta_property_context);
        evaluator.this = saved_this;
        evaluator.new_target = saved_new_target;
        evaluator.home_object = match saved_home_object_value {
          Value::Object(o) => Some(o),
          _ => None,
        };
        block_scope.heap_mut().remove_root(saved_this_root);
        block_scope.heap_mut().remove_root(saved_new_target_root);
        block_scope.heap_mut().remove_root(saved_home_object_root);
        return Err(err);
      }
    }
  }

  Ok(AsyncEval::Complete(Value::Object(func_obj)))
}

fn async_define_class_member(
  evaluator: &mut Evaluator<'_>,
  scope: &mut Scope<'_>,
  member: &Node<ClassMember>,
  _func_obj: GcObject,
  _prototype_obj: GcObject,
  target_obj: GcObject,
  key: PropertyKey,
) -> Result<(), VmError> {
  let is_private_key =
    matches!(&member.stx.key, ClassOrObjKey::Direct(direct) if direct.stx.tt == TT::PrivateMember);

  let mut member_scope = scope.reborrow();
  member_scope.push_root(Value::Object(target_obj))?;
  match key {
    PropertyKey::String(s) => member_scope.push_root(Value::String(s))?,
    PropertyKey::Symbol(s) => member_scope.push_root(Value::Symbol(s))?,
  };

  let member_loc_start = member.loc.start_u32();
  let (key_loc_start, key_is_computed) = match &member.stx.key {
    ClassOrObjKey::Direct(direct) => (direct.loc.start_u32(), false),
    ClassOrObjKey::Computed(expr) => (expr.loc.start_u32(), true),
  };

  match &member.stx.val {
    ClassOrObjVal::Method(method) => {
      let func_node = &method.stx.func;
      let length = evaluator.function_length(&func_node.stx)?;

      let span_start = evaluator.class_member_span_start(
        member_loc_start,
        key_loc_start,
        key_is_computed,
        Some(&func_node.stx),
        None,
      );
      let rel_end = func_node
        .loc
        .end_u32()
        .saturating_sub(evaluator.env.prefix_len());
      let span_end = evaluator.env.base_offset().saturating_add(rel_end);

      let code = evaluator.vm.register_ecma_function(
        evaluator.env.source(),
        span_start,
        span_end,
        EcmaFunctionKind::ClassMember,
      )?;

      // Class methods are always strict mode.
      let is_strict = true;
      let this_mode = if func_node.stx.arrow {
        ThisMode::Lexical
      } else {
        ThisMode::Strict
      };
      let closure_env = Some(evaluator.env.lexical_env);

      let name_string = match key {
        PropertyKey::String(s) => s,
        PropertyKey::Symbol(_) => member_scope.alloc_string("")?,
      };

      let func_obj = member_scope.alloc_ecma_function(
        code,
        /* is_constructable */ false,
        name_string,
        length,
        this_mode,
        is_strict,
        closure_env,
      )?;
      member_scope
        .heap_mut()
        .set_function_meta_property_context(func_obj, MetaPropertyContext::METHOD)?;

      let intr = evaluator
        .vm
        .intrinsics()
        .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;
      member_scope
        .heap_mut()
        .object_set_prototype(func_obj, Some(intr.function_prototype()))?;
      member_scope
        .heap_mut()
        .set_function_realm(func_obj, evaluator.env.global_object())?;
      if let Some(realm) = evaluator.vm.current_realm() {
        member_scope
          .heap_mut()
          .set_function_job_realm(func_obj, realm)?;
      }
      if let Some(script_or_module) = evaluator.vm.get_active_script_or_module() {
        let token = evaluator.vm.intern_script_or_module(script_or_module)?;
        member_scope
          .heap_mut()
          .set_function_script_or_module_token(func_obj, Some(token))?;
      }
      member_scope
        .heap_mut()
        .set_function_home_object(func_obj, Some(target_obj))?;
      member_scope.push_root(Value::Object(func_obj))?;

      // Methods use the property key as the function `name` if possible.
      if !matches!(key, PropertyKey::String(_)) {
        crate::function_properties::set_function_name(&mut member_scope, func_obj, key, None)
          .map_err(|err| coerce_error_to_throw_for_async(evaluator.vm, &mut member_scope, err))?;
      }

      member_scope
        .define_property_or_throw(
          target_obj,
          key,
          PropertyDescriptorPatch {
            value: Some(Value::Object(func_obj)),
            writable: Some(!is_private_key),
            enumerable: Some(false),
            configurable: Some(!is_private_key),
            ..Default::default()
          },
        )
        .map_err(|err| coerce_error_to_throw_for_async(evaluator.vm, &mut member_scope, err))?;
    }
    ClassOrObjVal::Getter(getter) => {
      let func_node = &getter.stx.func;
      let length = evaluator.function_length(&func_node.stx)?;

      let span_start = evaluator.class_member_span_start(
        member_loc_start,
        key_loc_start,
        key_is_computed,
        None,
        Some(b"get"),
      );
      let rel_end = func_node
        .loc
        .end_u32()
        .saturating_sub(evaluator.env.prefix_len());
      let span_end = evaluator.env.base_offset().saturating_add(rel_end);

      let code = evaluator.vm.register_ecma_function(
        evaluator.env.source(),
        span_start,
        span_end,
        EcmaFunctionKind::ClassMember,
      )?;

      // Class accessors are always strict mode.
      let is_strict = true;
      let this_mode = if func_node.stx.arrow {
        ThisMode::Lexical
      } else {
        ThisMode::Strict
      };
      let closure_env = Some(evaluator.env.lexical_env);

      let name_string = member_scope.alloc_string("")?;
      let func_obj = member_scope.alloc_ecma_function(
        code,
        /* is_constructable */ false,
        name_string,
        length,
        this_mode,
        is_strict,
        closure_env,
      )?;
      member_scope
        .heap_mut()
        .set_function_meta_property_context(func_obj, MetaPropertyContext::METHOD)?;

      let intr = evaluator
        .vm
        .intrinsics()
        .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;
      member_scope
        .heap_mut()
        .object_set_prototype(func_obj, Some(intr.function_prototype()))?;
      member_scope
        .heap_mut()
        .set_function_realm(func_obj, evaluator.env.global_object())?;
      if let Some(realm) = evaluator.vm.current_realm() {
        member_scope
          .heap_mut()
          .set_function_job_realm(func_obj, realm)?;
      }
      if let Some(script_or_module) = evaluator.vm.get_active_script_or_module() {
        let token = evaluator.vm.intern_script_or_module(script_or_module)?;
        member_scope
          .heap_mut()
          .set_function_script_or_module_token(func_obj, Some(token))?;
      }
      member_scope
        .heap_mut()
        .set_function_home_object(func_obj, Some(target_obj))?;
      member_scope.push_root(Value::Object(func_obj))?;

      crate::function_properties::set_function_name(&mut member_scope, func_obj, key, Some("get"))
        .map_err(|err| coerce_error_to_throw_for_async(evaluator.vm, &mut member_scope, err))?;

      member_scope
        .define_property_or_throw(
          target_obj,
          key,
          PropertyDescriptorPatch {
            get: Some(Value::Object(func_obj)),
            enumerable: Some(false),
            configurable: Some(true),
            ..Default::default()
          },
        )
        .map_err(|err| coerce_error_to_throw_for_async(evaluator.vm, &mut member_scope, err))?;
    }
    ClassOrObjVal::Setter(setter) => {
      let func_node = &setter.stx.func;
      let length = evaluator.function_length(&func_node.stx)?;

      let span_start = evaluator.class_member_span_start(
        member_loc_start,
        key_loc_start,
        key_is_computed,
        None,
        Some(b"set"),
      );
      let rel_end = func_node
        .loc
        .end_u32()
        .saturating_sub(evaluator.env.prefix_len());
      let span_end = evaluator.env.base_offset().saturating_add(rel_end);

      let code = evaluator.vm.register_ecma_function(
        evaluator.env.source(),
        span_start,
        span_end,
        EcmaFunctionKind::ClassMember,
      )?;

      // Class accessors are always strict mode.
      let is_strict = true;
      let this_mode = if func_node.stx.arrow {
        ThisMode::Lexical
      } else {
        ThisMode::Strict
      };
      let closure_env = Some(evaluator.env.lexical_env);

      let name_string = member_scope.alloc_string("")?;
      let func_obj = member_scope.alloc_ecma_function(
        code,
        /* is_constructable */ false,
        name_string,
        length,
        this_mode,
        is_strict,
        closure_env,
      )?;
      member_scope
        .heap_mut()
        .set_function_meta_property_context(func_obj, MetaPropertyContext::METHOD)?;

      let intr = evaluator
        .vm
        .intrinsics()
        .ok_or(VmError::Unimplemented("intrinsics not initialized"))?;
      member_scope
        .heap_mut()
        .object_set_prototype(func_obj, Some(intr.function_prototype()))?;
      member_scope
        .heap_mut()
        .set_function_realm(func_obj, evaluator.env.global_object())?;
      if let Some(realm) = evaluator.vm.current_realm() {
        member_scope
          .heap_mut()
          .set_function_job_realm(func_obj, realm)?;
      }
      if let Some(script_or_module) = evaluator.vm.get_active_script_or_module() {
        let token = evaluator.vm.intern_script_or_module(script_or_module)?;
        member_scope
          .heap_mut()
          .set_function_script_or_module_token(func_obj, Some(token))?;
      }
      member_scope
        .heap_mut()
        .set_function_home_object(func_obj, Some(target_obj))?;
      member_scope.push_root(Value::Object(func_obj))?;

      crate::function_properties::set_function_name(&mut member_scope, func_obj, key, Some("set"))
        .map_err(|err| coerce_error_to_throw_for_async(evaluator.vm, &mut member_scope, err))?;

      member_scope
        .define_property_or_throw(
          target_obj,
          key,
          PropertyDescriptorPatch {
            set: Some(Value::Object(func_obj)),
            enumerable: Some(false),
            configurable: Some(true),
            ..Default::default()
          },
        )
        .map_err(|err| coerce_error_to_throw_for_async(evaluator.vm, &mut member_scope, err))?;
    }
    ClassOrObjVal::Prop(_) => {
      return Err(VmError::Unimplemented("class fields"));
    }
    ClassOrObjVal::IndexSignature(_) => {
      return Err(VmError::Unimplemented("class index signature"));
    }
    // Class static blocks are handled in `async_eval_class_members_from` after the element loop.
    ClassOrObjVal::StaticBlock(_) => {
      return Err(VmError::InvariantViolation(
        "static blocks should be evaluated after class member definition pass",
      ));
    }
  }

  Ok(())
}

fn async_class_after_computed_key(
  evaluator: &mut Evaluator<'_>,
  scope: &mut Scope<'_>,
  members: &Vec<Node<ClassMember>>,
  member_index: usize,
  func_root: RootId,
  key_value: Value,
) -> Result<AsyncEval<Value>, VmError> {
  let prep_res: Result<(), VmError> = (|| {
    let func_value = scope
      .heap()
      .get_root(func_root)
      .ok_or(VmError::InvariantViolation(
        "missing class constructor root",
      ))?;
    let Value::Object(func_obj) = func_value else {
      return Err(VmError::InvariantViolation(
        "class constructor root is not an object",
      ));
    };

    let prototype_obj = {
      let mut class_scope = scope.reborrow();
      class_scope.push_root(Value::Object(func_obj))?;
      let prototype_key_s = class_scope.alloc_string("prototype")?;
      class_scope.push_root(Value::String(prototype_key_s))?;
      let prototype_key = PropertyKey::from_string(prototype_key_s);
      let Some(prototype_desc) = class_scope
        .heap()
        .get_own_property(func_obj, prototype_key)?
      else {
        return Err(VmError::InvariantViolation(
          "class constructor missing prototype property",
        ));
      };
      let PropertyKind::Data { value, .. } = prototype_desc.kind else {
        return Err(VmError::InvariantViolation(
          "class constructor prototype property is not a data property",
        ));
      };
      let Value::Object(prototype_obj) = value else {
        return Err(VmError::InvariantViolation(
          "class constructor prototype property is not an object",
        ));
      };
      prototype_obj
    };

    let member = members
      .get(member_index)
      .ok_or(VmError::InvariantViolation(
        "async class continuation out of bounds",
      ))?;

    if matches!(&member.stx.val, ClassOrObjVal::StaticBlock(_)) {
      return Err(VmError::InvariantViolation(
        "async class computed key frame resumed for static block",
      ));
    }

    let target_obj = if member.stx.static_ {
      func_obj
    } else {
      prototype_obj
    };

    if !matches!(&member.stx.key, ClassOrObjKey::Computed(_)) {
      return Err(VmError::InvariantViolation(
        "class computed key frame resumed for non-computed key",
      ));
    }

    let key = {
      let mut key_scope = scope.reborrow();
      key_scope.push_root(Value::Object(target_obj))?;
      key_scope.push_root(key_value)?;
      evaluator
        .to_property_key_operator(&mut key_scope, key_value)
        .map_err(|err| coerce_error_to_throw_for_async(evaluator.vm, &mut key_scope, err))?
    };

    async_define_class_member(
      evaluator,
      scope,
      member,
      func_obj,
      prototype_obj,
      target_obj,
      key,
    )?;

    Ok(())
  })();

  if let Err(err) = prep_res {
    scope.heap_mut().remove_root(func_root);
    return Err(err);
  }

  async_eval_class_members_from(
    evaluator,
    scope,
    members,
    member_index.saturating_add(1),
    func_root,
  )
}

fn async_eval_while(
  evaluator: &mut Evaluator<'_>,
  scope: &mut Scope<'_>,
  stmt: &WhileStmt,
  label_set: &[String],
) -> Result<AsyncEval<Completion>, VmError> {
  let v_root = scope.heap_mut().add_root(Value::Undefined)?;
  let mut label_vec: Vec<String> = Vec::new();
  label_vec
    .try_reserve_exact(label_set.len())
    .map_err(|_| VmError::OutOfMemory)?;
  label_vec.extend_from_slice(label_set);

  match async_eval_expr(evaluator, scope, &stmt.condition) {
    Ok(AsyncEval::Complete(test)) => {
      async_while_after_test(evaluator, scope, stmt, label_vec, v_root, test)
    }
    Ok(AsyncEval::Suspend(mut suspend)) => {
      async_frames_push(
        &mut suspend.frames,
        AsyncFrame::WhileAfterTest {
          stmt: stmt as *const WhileStmt,
          label_set: label_vec,
          v_root,
        },
      )?;
      Ok(AsyncEval::Suspend(suspend))
    }
    Err(err) => {
      scope.heap_mut().remove_root(v_root);
      Ok(AsyncEval::Complete(completion_from_expr_result(Err(err))?))
    }
  }
}

fn async_while_after_test(
  evaluator: &mut Evaluator<'_>,
  scope: &mut Scope<'_>,
  stmt: &WhileStmt,
  label_set: Vec<String>,
  v_root: RootId,
  test_value: Value,
) -> Result<AsyncEval<Completion>, VmError> {
  let v = scope
    .heap()
    .get_root(v_root)
    .ok_or(VmError::InvariantViolation("missing while loop value root"))?;

  if !to_boolean(scope.heap(), test_value)? {
    scope.heap_mut().remove_root(v_root);
    let result = Evaluator::normalise_iteration_break(Completion::normal(v));
    return Ok(AsyncEval::Complete(result));
  }

  match async_eval_stmt_labelled(evaluator, scope, &stmt.body, &[])? {
    AsyncEval::Complete(c) => async_while_after_body(evaluator, scope, stmt, label_set, v_root, c),
    AsyncEval::Suspend(mut suspend) => {
      async_frames_push(
        &mut suspend.frames,
        AsyncFrame::WhileAfterBody {
          stmt: stmt as *const WhileStmt,
          label_set,
          v_root,
        },
      )?;
      Ok(AsyncEval::Suspend(suspend))
    }
  }
}

fn async_while_after_body(
  evaluator: &mut Evaluator<'_>,
  scope: &mut Scope<'_>,
  stmt: &WhileStmt,
  label_set: Vec<String>,
  v_root: RootId,
  stmt_result: Completion,
) -> Result<AsyncEval<Completion>, VmError> {
  let mut v = scope
    .heap()
    .get_root(v_root)
    .ok_or(VmError::InvariantViolation("missing while loop value root"))?;

  if !Evaluator::loop_continues(&stmt_result, &label_set) {
    scope.heap_mut().remove_root(v_root);
    let result = Evaluator::normalise_iteration_break(stmt_result.update_empty(Some(v)));
    return Ok(AsyncEval::Complete(result));
  }

  if let Some(value) = stmt_result.value() {
    v = value;
    scope.heap_mut().set_root(v_root, v);
  }

  match async_eval_expr(evaluator, scope, &stmt.condition) {
    Ok(AsyncEval::Complete(test)) => {
      async_while_after_test(evaluator, scope, stmt, label_set, v_root, test)
    }
    Ok(AsyncEval::Suspend(mut suspend)) => {
      async_frames_push(
        &mut suspend.frames,
        AsyncFrame::WhileAfterTest {
          stmt: stmt as *const WhileStmt,
          label_set,
          v_root,
        },
      )?;
      Ok(AsyncEval::Suspend(suspend))
    }
    Err(err) => {
      scope.heap_mut().remove_root(v_root);
      Ok(AsyncEval::Complete(completion_from_expr_result(Err(err))?))
    }
  }
}

