  #[test]
  fn async_frame_stack_push_returns_out_of_memory_instead_of_aborting() -> Result<(), VmError> {
    // Parse an async arrow function whose expression body suspends immediately. This triggers an
    // async frame push when wrapping the `await` suspension (`RootExprBody`).
    let opts = ParseOptions {
      dialect: Dialect::Ecma,
      source_type: SourceType::Script,
    };
    let top = parse_js::parse_with_options("async () => await 0;", opts).expect("parse");
    let stmt = top
      .stx
      .body
      .into_iter()
      .next()
      .expect("expected one statement");
    let Stmt::Expr(expr_stmt) = *stmt.stx else {
      panic!("expected ExprStmt");
    };
    let ExprStmt { expr } = *expr_stmt.stx;
    let Expr::ArrowFunc(arrow) = *expr.stx else {
      panic!("expected ArrowFunc expr");
    };
    let parse_js::ast::expr::ArrowFuncExpr { func } = *arrow.stx;
    let func = Arc::new(func);

    let vm = Vm::new(VmOptions::default());
    let heap = Heap::new(HeapLimits::new(1024 * 1024, 1024 * 1024));
    let mut rt = JsRuntime::new(vm, heap)?;
    let (vm, realm, heap) = rt.vm_realm_and_heap_mut();

    let global_object = realm.global_object();

    // Create a minimal lexical environment for the async evaluator.
    let mut scope = heap.scope();
    let lexical_env = scope.env_create(None)?;
    let mut env = RuntimeEnv::new_with_lexical_env(scope.heap_mut(), global_object, lexical_env)?;

    // Provide a minimal host hook implementation; the test does not execute any promise jobs.
    #[derive(Default)]
    struct NoopHooks;
    impl VmHostHooks for NoopHooks {
      fn host_enqueue_promise_job(&mut self, _job: crate::Job, _realm: Option<RealmId>) {}
    }
    let mut host = ();
    let mut hooks = NoopHooks::default();

    let mut evaluator = Evaluator {
      vm,
      host: &mut host,
      hooks: &mut hooks,
      env: &mut env,
      strict: false,
      this: Value::Undefined,
      new_target: Value::Undefined,
      home_object: None,
      class_constructor: None,
      derived_constructor: false,
      this_initialized: true,
      this_root_idx: None,
    };

    // Fail all allocation requests on this thread: the frame stack push must surface as
    // `VmError::OutOfMemory` instead of aborting the process.
    let _guard = FailAllocsGuard::new();
    let err = match async_start_body(&mut evaluator, &mut scope, &func) {
      Ok(_) => panic!("expected OOM"),
      Err(err) => err,
    };
    assert!(matches!(err, VmError::OutOfMemory));
    Ok(())
  }

  #[test]
  fn super_property_reference_roots_home_object_across_gc() -> Result<(), VmError> {
    use parse_js::ast::expr::SuperExpr;
    use parse_js::loc::Loc;

    let vm = Vm::new(VmOptions::default());
    // Force a GC before every allocation to deterministically catch missing-root bugs.
    let heap = Heap::new(HeapLimits::new(8 * 1024 * 1024, 0));
    let mut rt = JsRuntime::new(vm, heap)?;
    let (vm, realm, heap) = rt.vm_realm_and_heap_mut();
    let global_object = realm.global_object();

    let mut scope = heap.scope();
    let lexical_env = scope.env_create(None)?;
    let mut env = RuntimeEnv::new_with_lexical_env(scope.heap_mut(), global_object, lexical_env)?;

    #[derive(Default)]
    struct NoopHooks;
    impl VmHostHooks for NoopHooks {
      fn host_enqueue_promise_job(&mut self, _job: crate::Job, _realm: Option<RealmId>) {}
    }
    let mut host = ();
    let mut hooks = NoopHooks::default();

    let loc = Loc(0, 0);
    let super_expr = Node::new(loc, Expr::Super(Node::new(loc, SuperExpr {})));
    let expr = Node::new(
      loc,
      Expr::Member(Node::new(
        loc,
        MemberExpr {
          optional_chaining: false,
          left: super_expr,
          right: String::from("x"),
        },
      )),
    );

    // Allocate a home object that is only referenced from `Evaluator::home_object` on the Rust
    // stack. If `super.x` does not root it before allocating the property key string / calling
    // `GetSuperBase`, a forced GC can collect it and make the handle invalid.
    let home_object = scope.alloc_object()?;

    {
      let mut evaluator = Evaluator {
        vm,
        host: &mut host,
        hooks: &mut hooks,
        env: &mut env,
        strict: false,
        this: Value::Object(global_object),
        new_target: Value::Undefined,
        home_object: Some(home_object),
        class_constructor: None,
        derived_constructor: false,
        this_initialized: true,
        this_root_idx: None,
      };

      let reference = evaluator.eval_reference(&mut scope, &expr)?;
      assert!(
        matches!(reference, Reference::SuperProperty { .. }),
        "expected super property reference, got {reference:?}"
      );
    }

    env.teardown(scope.heap_mut());
    Ok(())
  }

  #[test]
  fn super_property_value_roots_home_object_across_gc() -> Result<(), VmError> {
    use parse_js::ast::expr::SuperExpr;
    use parse_js::loc::Loc;

    let vm = Vm::new(VmOptions::default());
    // Force a GC before every allocation to deterministically catch missing-root bugs.
    let heap = Heap::new(HeapLimits::new(8 * 1024 * 1024, 0));
    let mut rt = JsRuntime::new(vm, heap)?;
    let (vm, realm, heap) = rt.vm_realm_and_heap_mut();
    let global_object = realm.global_object();

    let mut scope = heap.scope();
    let lexical_env = scope.env_create(None)?;
    let mut env = RuntimeEnv::new_with_lexical_env(scope.heap_mut(), global_object, lexical_env)?;

    #[derive(Default)]
    struct NoopHooks;
    impl VmHostHooks for NoopHooks {
      fn host_enqueue_promise_job(&mut self, _job: crate::Job, _realm: Option<RealmId>) {}
    }
    let mut host = ();
    let mut hooks = NoopHooks::default();

    let loc = Loc(0, 0);
    let super_expr = Node::new(loc, Expr::Super(Node::new(loc, SuperExpr {})));
    let expr = Node::new(
      loc,
      Expr::Member(Node::new(
        loc,
        MemberExpr {
          optional_chaining: false,
          left: super_expr,
          right: String::from("x"),
        },
      )),
    );

    // Allocate a home object that is only referenced from `Evaluator::home_object` on the Rust
    // stack. If `super.x` does not root it before allocating the property key string / calling
    // `GetSuperBase`, a forced GC can collect it and make the handle invalid.
    let home_object = scope.alloc_object()?;
    {
      // Ensure `GetSuperBase()` sees a non-null prototype to avoid throwing in the test body.
      let mut proto_scope = scope.reborrow();
      proto_scope.push_root(Value::Object(home_object))?;
      proto_scope
        .heap_mut()
        .object_set_prototype(home_object, Some(global_object))?;
    }

    // Ensure the next root push grows `root_stack` so it can trigger a GC.
    scope.heap_mut().root_stack = Vec::new();

    {
      let mut evaluator = Evaluator {
        vm,
        host: &mut host,
        hooks: &mut hooks,
        env: &mut env,
        strict: false,
        this: Value::Object(global_object),
        new_target: Value::Undefined,
        home_object: Some(home_object),
        class_constructor: None,
        derived_constructor: false,
        this_initialized: true,
        this_root_idx: None,
      };

      let value = evaluator.eval_expr(&mut scope, &expr)?;
      assert_eq!(value, Value::Undefined);
    }

    env.teardown(scope.heap_mut());
    Ok(())
  }

