  #[test]
  fn class_static_block_contains_arguments_is_syntax_error() -> Result<(), VmError> {
    let vm = Vm::new(VmOptions::default());
    let heap = Heap::new(HeapLimits::new(1024 * 1024, 1024 * 1024));
    let mut rt = JsRuntime::new(vm, heap)?;
    let err = rt
      .exec_script(
        r#"
        class C {
          static {
            (class { [arguments]() {} });
          }
        }
      "#,
      )
      .unwrap_err();
    match err {
      VmError::Syntax(diags) => {
        let has_engine_early_error = diags.iter().any(|d| d.code.as_str() == "VMJS0004");
        let has_parser_error = diags.iter().any(|d| {
          if d.code.as_str() != "PS0002" {
            return false;
          }
          // Be tolerant to where `parse-js` surfaces the message (`message` vs `notes`) while still
          // being strict about the actual failure mode.
          let mut haystacks = std::iter::once(d.message.as_str())
            .chain(d.notes.iter().map(|s| s.as_str()));
          haystacks.any(|s| {
            // `parse-js` may render the token name with quotes or backticks depending on which layer
            // surfaces the diagnostic.
            (s.contains("'arguments'") || s.contains("`arguments`") || s.contains("arguments"))
              && s.contains("not allowed")
              && s.contains("class field")
              && s.contains("static initialization block")
          })
        });
        assert!(
          has_engine_early_error || has_parser_error,
          "expected early error VMJS0004 or parser error PS0002 about disallowed 'arguments', got {diags:?}"
        );
        Ok(())
      }
      other => panic!("expected VmError::Syntax, got {other:?}"),
    }
  }

