  #[test]
  fn logical_assignment_with_await_short_circuiting() -> Result<(), VmError> {
    let vm = Vm::new(VmOptions::default());
    // The async evaluator can allocate more than a simple sync script; use a larger heap to avoid
    // spurious OOMs when running microtasks.
    let heap = Heap::new(HeapLimits::new(2 * 1024 * 1024, 2 * 1024 * 1024));
    let mut rt = JsRuntime::new(vm, heap)?;
    let value = rt.exec_script(
      r#"
      var out;
      async function f() {
        const log = [];
        let stored = 1;
        const obj = {
          get a() { log.push("get"); return stored; },
          set a(v) { log.push("set:" + v); stored = v; },
        };
        function key() { log.push("key"); return "a"; }
        async function rhs() { log.push("rhs"); return 2; }

        // `&&=` short-circuits when the LHS is falsy.
        let res = (obj[key()] &&= await rhs());
        if (res !== 2 || stored !== 2 || log.join(",") !== "key,get,rhs,set:2") return false;

        log.length = 0;
        stored = 0;
        res = (obj[key()] &&= await rhs());
        if (res !== 0 || stored !== 0 || log.join(",") !== "key,get") return false;

        // `||=` short-circuits when the LHS is truthy.
        log.length = 0;
        stored = 0;
        res = (obj[key()] ||= await rhs());
        if (res !== 2 || stored !== 2 || log.join(",") !== "key,get,rhs,set:2") return false;

        log.length = 0;
        stored = 5;
        res = (obj[key()] ||= await rhs());
        if (res !== 5 || stored !== 5 || log.join(",") !== "key,get") return false;

        // `??=` short-circuits only on non-nullish values, even when falsy.
        log.length = 0;
        stored = 0;
        res = (obj[key()] ??= await rhs());
        if (res !== 0 || stored !== 0 || log.join(",") !== "key,get") return false;

        log.length = 0;
        stored = undefined;
        res = (obj[key()] ??= await rhs());
        if (res !== 2 || stored !== 2 || log.join(",") !== "key,get,rhs,set:2") return false;

        return true;
      }
      f().then(function (v) { out = v; });
      out
    "#,
    )?;
    assert_eq!(value, Value::Undefined);

    rt.vm.perform_microtask_checkpoint(&mut rt.heap)?;

    let value = rt.exec_script("out")?;
    assert_eq!(value, Value::Bool(true));
    Ok(())
  }

  #[test]
  fn prototype_cycle_throw_captures_statement_location() -> Result<(), VmError> {
    let vm = Vm::new(VmOptions::default());
    let heap = Heap::new(HeapLimits::new(1024 * 1024, 1024 * 1024));
    let mut rt = JsRuntime::new(vm, heap)?;

    let err = rt
      // Ensure the statement isn't on line 1 so the test verifies location capture.
      .exec_script("let a = {};\n\nObject.setPrototypeOf(a, a);")
      .unwrap_err();
    match err {
      VmError::ThrowWithStack { stack, .. } => {
        assert!(
          !stack.is_empty(),
          "ThrowWithStack must include at least one frame"
        );
        assert_eq!(stack[0].line, 3);
        assert_eq!(stack[0].col, 1);
      }
      other => panic!("expected ThrowWithStack, got {other:?}"),
    }

    Ok(())
  }

  #[test]
  fn yield_star_throw_without_throw_method_closes_and_throws_type_error() -> Result<(), VmError> {
    let vm = Vm::new(VmOptions::default());
    let heap = Heap::new(HeapLimits::new(1024 * 1024, 1024 * 1024));
    let mut rt = JsRuntime::new(vm, heap)?;

    let value = rt.exec_script(
      r#"
      (function () {
        let closed = false;
        const iter = {
          i: 0,
          next() {
            if (this.i < 2) return { value: this.i++, done: false };
            return { value: undefined, done: true };
          },
          return() {
            closed = true;
            return { value: undefined, done: true };
          },
        };

        const iterable = {
          [Symbol.iterator]() {
            return iter;
          },
        };

        function* gen() {
          try {
            yield* iterable;
            return "unexpected";
          } catch (e) {
            return e;
          }
        }

        const it = gen();
        const first = it.next();
        if (first.value !== 0 || first.done !== false) return false;

        const res = it.throw(42);
        // ECMA-262 `yield*` protocol violation: if the delegate iterator lacks a `throw` method,
        // the iterator is closed (via `return`) and a TypeError is thrown.
        return res.value instanceof TypeError && res.done === true && closed;
      })()
    "#,
    )?;

    assert_eq!(
      value,
      Value::Bool(true),
      "expected yield* throw to close the iterator and produce a TypeError when the delegate lacks a throw method"
    );

    Ok(())
  }

  #[test]
  fn yield_star_missing_throw_non_object_return_result_overrides_protocol_violation(
  ) -> Result<(), VmError> {
    let vm = Vm::new(VmOptions::default());
    let heap = Heap::new(HeapLimits::new(1024 * 1024, 1024 * 1024));
    let mut rt = JsRuntime::new(vm, heap)?;

    let value = rt.exec_script(
      r#"
      (function () {
        let closed = false;
        const iter = {
          next() {
            return { value: 0, done: false };
          },
          // Missing `throw`; `yield*` should close the iterator via IteratorClose.
          // Returning a non-object from `return` should throw a TypeError that overrides the
          // protocol-violation TypeError.
          return() {
            closed = true;
            return 1;
          },
        };

        const iterable = {
          [Symbol.iterator]() {
            return iter;
          },
        };

        function* gen() {
          try {
            yield* iterable;
            return "unexpected";
          } catch (e) {
            return e && e.message;
          }
        }

        const it = gen();
        const first = it.next();
        if (first.value !== 0 || first.done !== false) return false;

        const res = it.throw(42);
        return (
          closed === true &&
          res.done === true &&
          res.value === "IteratorClose: iterator.return did not return an object"
        );
      })()
    "#,
    )?;

    assert_eq!(
      value,
      Value::Bool(true),
      "expected IteratorClose return-result TypeError to override the yield* missing-throw TypeError"
    );

    Ok(())
  }

