  #[test]
  fn logical_assignment_anonymous_function_name_inference() -> Result<(), VmError> {
    let vm = Vm::new(VmOptions::default());
    let heap = Heap::new(HeapLimits::new(1024 * 1024, 1024 * 1024));
    let mut rt = JsRuntime::new(vm, heap)?;

    let value = rt.exec_script(
      r#"
      (() => {
        // Binding refs.
        let x = 0;
        x ||= function () {};
        if (x.name !== "x") return false;

        let y = 1;
        y &&= function () {};
        if (y.name !== "y") return false;

        let z;
        z ??= function () {};
        if (z.name !== "z") return false;

        // Property refs.
        const o = {};
        o.p ||= function () {};
        if (o.p.name !== "p") return false;

        o.q = 1;
        o.q &&= function () {};
        if (o.q.name !== "q") return false;

        o.r = null;
        o.r ??= function () {};
        if (o.r.name !== "r") return false;

        // Computed refs.
        const prop = "comp";
        o[prop] ||= function () {};
        if (o[prop].name !== "comp") return false;

        // Private refs: assignment works, but private fields do not participate in name inference.
        //
        // Note: private *instance* fields are not yet supported by this execution path, so use a
        // private static field to exercise `Reference::Private`.
        class C {
          static #f = 1;
          static test() {
            C.#f &&= function () {};
            return C.#f.name;
          }
        }
        if (C.test() !== "") return false;

        return true;
      })()
    "#,
    )?;

    assert_eq!(value, Value::Bool(true));
    Ok(())
  }

  #[test]
  fn typed_array_constructor_roots_args_across_gc_in_toindex() -> Result<(), VmError> {
    let vm = Vm::new(VmOptions::default());
    // Use a tiny GC threshold so allocations inside `valueOf()` reliably trigger a collection
    // during argument coercion. The max size needs to be large enough for the transient
    // ArrayBuffer churn.
    let heap = Heap::new(HeapLimits::new(1024 * 1024, 16 * 1024));
    let mut rt = JsRuntime::new(vm, heap)?;

    let value = rt.exec_script(
      r#"
      const byteOffset = {
        valueOf() {
          // Trigger at least one GC during `ToIndex(byteOffset)`.
          for (let i = 0; i < 16; i++) new ArrayBuffer(4096);
          return 0;
        }
      };

      const buf = new ArrayBuffer(8);
      const ta = new Uint8Array(buf, byteOffset, { valueOf() { return 1; } });
      ta[0] = 123;
      ta.byteOffset + ta.byteLength + ta[0] + ta[0];
    "#,
    )?;

    assert_eq!(value, Value::Number(247.0));
    Ok(())
  }

  #[test]
  fn dataview_constructor_roots_args_across_gc_in_toindex() -> Result<(), VmError> {
    let vm = Vm::new(VmOptions::default());
    // Same rooting regression test as above, but for DataView's `byteLength` argument.
    let heap = Heap::new(HeapLimits::new(1024 * 1024, 16 * 1024));
    let mut rt = JsRuntime::new(vm, heap)?;

    let value = rt.exec_script(
      r#"
      const byteOffset = {
        valueOf() {
          // Trigger at least one GC during `ToIndex(byteOffset)`.
          for (let i = 0; i < 16; i++) new ArrayBuffer(4096);
          return 0;
        }
      };

      const buf = new ArrayBuffer(8);
      const dv = new DataView(buf, byteOffset, { valueOf() { return 1; } });
      dv.setUint8(0, 77);
      dv.byteOffset + dv.byteLength + dv.getUint8(0) + dv.getUint8(0);
    "#,
    )?;

    assert_eq!(value, Value::Number(155.0));
    Ok(())
  }

  #[test]
  fn global_typed_array_and_data_view_survive_host_gc_between_exec_script_calls(
  ) -> Result<(), VmError> {
    let vm = Vm::new(VmOptions::default());
    // A relatively small heap to stress GC. Note: `JsRuntime::new` needs enough space for realm
    // initialization in debug builds, so keep the max modest but non-trivial.
    let heap = Heap::new(HeapLimits::new(1024 * 1024, 64 * 1024));
    let mut rt = JsRuntime::new(vm, heap)?;

    rt.exec_script(
      r#"
      globalThis.ab = new ArrayBuffer(16);
      globalThis.ta = new Uint8Array(globalThis.ab);
      ta[0] = 42;
      globalThis.dv = new DataView(globalThis.ab);
    "#,
    )?;

    // Force host-side GC between `exec_script` calls to ensure the runtime object graph keeps the
    // backing buffer alive (global object → typed array / DataView → ArrayBuffer).
    rt.heap.collect_garbage();
    rt.heap.collect_garbage();

    let mut eval = |src: &str| -> Result<Value, VmError> {
      match rt.exec_script(src) {
        Ok(v) => Ok(v),
        Err(err @ VmError::InvalidHandle { .. }) => {
          panic!("unexpected InvalidHandle from `{src}`: {err:?}");
        }
        Err(err) => Err(err),
      }
    };

    assert_eq!(eval("ta.byteLength")?, Value::Number(16.0));
    assert_eq!(eval("ta.buffer.byteLength")?, Value::Number(16.0));
    assert_eq!(eval("ta[0]")?, Value::Number(42.0));
    assert_eq!(eval("dv.byteLength")?, Value::Number(16.0));
    assert_eq!(eval("dv.buffer.byteLength")?, Value::Number(16.0));

    Ok(())
  }

  fn eval_script_interpreter(source: &str) -> Result<Value, VmError> {
    let vm = Vm::new(VmOptions::default());
    let heap = Heap::new(HeapLimits::new(1024 * 1024, 1024 * 1024));
    let mut rt = JsRuntime::new(vm, heap)?;
    rt.exec_script(source)
  }

  fn eval_script_compiled(source: &str) -> Result<Value, VmError> {
    let vm = Vm::new(VmOptions::default());
    let heap = Heap::new(HeapLimits::new(1024 * 1024, 1024 * 1024));
    let mut rt = JsRuntime::new(vm, heap)?;
    let script = CompiledScript::compile_script(&mut rt.heap, "<inline>", source)?;
    assert!(
      !script.requires_ast_fallback && !script.contains_top_level_await,
      "expected test script to run in compiled (HIR) executor"
    );
    rt.exec_compiled_script(script)
  }

